type LangMap = { en: string; ms: string; tur: string; urd: string; ben: string; fas: string; zh: string; yue: string; ja: string; ru: string; es: string; ko: string; ta: string; si: string };
export type SalaatFardKey = keyof typeof SALAAT_FARD_CONTENT;

/**
 * Per-prayer keys (for each of the 5 fard) follow this naming:
 *   <id>_name, <id>_when, <id>_structure, <id>_story, <id>_significance,
 *   <id>_proof_q, <id>_proof_h, <id>_recitation, <id>_fard_say,
 *   <id>_sunnah_say, <id>_extras_say, <id>_virtues, <id>_timing_notes
 * Universal keys (the things said in EVERY prayer regardless of which fard):
 *   uni_section_h, uni_fard_h, uni_fard_body,
 *   uni_wajib_h, uni_wajib_body, uni_sunnah_h, uni_sunnah_body,
 *   uni_extras_h, uni_extras_body
 */
export const SALAAT_FARD_CONTENT = {
  /* ── Page section header ──────────────────────────────────── */
  section_h: { en: `The Five Daily Prayers (Salawat al-Khams)`, ms: `Lima Solat Fardu (Solat al-Khams)`, tur: `Beş Vakit Namaz (Salavâtü'l-Hams)`, urd: `پانچ فرض نمازیں (صلوات الخمس)`, ben: `পাঁচ ওয়াক্ত নামাজ (সালাওয়াত আল-খামস)`, fas: `پنج نماز فرض (صلوات الخمس)`, zh: `五次主命拜功（Salawat al-Khams）`, yue: `五次主命拜功（Salawat al-Khams）`, ja: `五時の義務礼拝（サラワート・アル＝ハムス）`, ru: `Пять обязательных молитв (Салават аль-Хамс)`, es: `Las cinco oraciones obligatorias (Salawat al-Khams)`, ko: `다섯 의무 예배 (살라와트 알함스)`, ta: `ஐந்து கடமைத் தொழுகைகள் (ஸலவாத் அல்-கம்ஸ்)`, si: `පංච අනිවාර්ය සලාත (සලවාත් අල්-කම්ස්)` },
  section_intro: { en: `The five daily prayers are the second pillar of Islam and the first deed a servant will be questioned about on the Day of Judgement. They were ordained directly from Allah to the Prophet ﷺ on the Night of the Ascension (Al-Mi'raj) without any intermediary  –  a distinction held by no other act of worship.`, ms: `Lima solat sehari semalam adalah rukun Islam yang kedua dan amalan pertama yang akan ditanyakan kepada hamba pada Hari Pembalasan. Ia diwajibkan terus daripada Allah kepada Nabi ﷺ pada malam Isra' dan Mi'raj tanpa sebarang perantara  –  suatu kelebihan yang tidak dimiliki oleh sebarang ibadah lain.`, tur: `Beş vakit namaz, İslam'ın ikinci şartıdır ve Kıyamet Günü kuldan ilk sorulacak ameldir. Mi'rac gecesinde aracısız olarak doğrudan Allah'tan Peygamber'e ﷺ farz kılınmıştır  –  başka hiçbir ibadetin sahip olmadığı bir ayrıcalıktır.`, urd: `پانچ وقت کی نمازیں اسلام کا دوسرا رکن ہیں اور قیامت کے دن بندے سے سب سے پہلے جس عمل کا سوال ہو گا۔ یہ شب معراج میں اللہ نے بغیر کسی واسطے کے براہِ راست نبی ﷺ کو عطا کیں  –  ایک امتیاز جو کسی اور عبادت کو حاصل نہیں۔`, ben: `পাঁচ ওয়াক্ত নামাজ ইসলামের দ্বিতীয় স্তম্ভ এবং কিয়ামতের দিনে বান্দার কাছে যে আমলের কথা প্রথম জিজ্ঞাসা করা হবে। এগুলো মেরাজের রাতে কোনো মাধ্যম ছাড়াই সরাসরি আল্লাহ থেকে নবী ﷺ-কে ফরজ করা হয়েছিল  –  এমন বৈশিষ্ট্য আর কোনো ইবাদতের নেই।`, fas: `پنج نماز روزانه دومین رکن اسلام و نخستین عملی است که در روز قیامت از بنده پرسیده می‌شود. این نمازها در شب معراج، بدون هیچ واسطه، مستقیماً از خداوند بر پیامبر ﷺ فرض شد  –  امتیازی که هیچ عبادت دیگری ندارد.`, zh: `五次日常拜功是伊斯兰的第二支柱，也是仆人在审判日首先被问及的功修。它们在登霄之夜由真主无任何中介直接降命于先知ﷺ  –  此为其他功修所未享之殊荣。`, yue: `五次日常拜功係伊斯蘭嘅第二支柱，亦係僕人喺審判日首先被問及嘅功修。佢哋喺登霄之夜由真主無任何中介直接降命於先知ﷺ  –  此為其他功修所未享之殊榮。`, ja: `五時の毎日礼拝はイスラムの第二の柱であり、審判の日にしもべが最初に問われる行為です。ミウラージ（昇天）の夜に、いかなる仲介者もなく直接アッラーから預言者ﷺに義務として課されました  –  他のいかなる崇拝行為にも与えられていない栄誉です。`, ru: `Пять ежедневных молитв  –  второй столп ислама и первое, о чём раб будет спрошен в Судный день. Они были предписаны напрямую от Аллаха Пророку ﷺ в Ночь Вознесения (аль-Мирадж) без какого-либо посредника  –  отличие, которого не имеет ни одно другое богослужение.`, es: `Las cinco oraciones diarias son el segundo pilar del islam y la primera obra por la que se preguntará al siervo el Día del Juicio. Fueron ordenadas directamente por Allah al Profeta ﷺ en la Noche de la Ascensión (Al-Mi'raj) sin intermediario alguno  –  un honor que no tiene ningún otro acto de adoración.`, ko: `다섯 번의 일일 예배는 이슬람의 두 번째 기둥이며 심판의 날에 종이 가장 먼저 질문받게 될 행위입니다. 미으라즈(승천)의 밤에 어떠한 중개자도 없이 알라께서 직접 예언자 ﷺ께 의무로 정하셨습니다  –  그 어떤 다른 예배 행위에도 없는 영예입니다.`, ta: `ஐந்து வேளைத் தொழுகைகள் இஸ்லாத்தின் இரண்டாவது தூணும், மறுமை நாளில் அடியானிடம் முதலில் கேட்கப்படும் செயலும் ஆகும். மிஃராஜ் இரவில் எவ்வித இடைத்தரகனுமின்றி அல்லாஹ்விடமிருந்து நேரடியாக நபி ﷺ அவர்களுக்கு கடமையாக்கப்பட்டது  –  வேறு எந்த வணக்கத்திற்கும் இல்லாத ஒரு சிறப்பு.`, si: `පංච දෛනික සලාත ඉස්ලාමයේ දෙවන කණුව වන අතර, විනිශ්චය දිනයේ දාසයාගෙන් මුලින්ම විමසනු ලබන ක්‍රියාවද වේ. මිඃරාජ් (ස්වර්ගාරෝහණ) රාත්‍රියේදී කිසිදු මැදිහත්කරුවෙකු නොමැතිව අල්ලාහ්ගෙන් සෘජුවම නබි ﷺ වෙත අනිවාර්ය කෙරුණි  –  වෙනත් කිසිදු නැමදුම් ක්‍රියාවකට නොලැබුණු ගෞරවයකි.` },

  /* ── Universal: what is said in every prayer ──────────────── */
  uni_section_h: { en: `What Is Said in Every Prayer`, ms: `Apa yang Dibaca dalam Setiap Solat`, tur: `Her Namazda Okunanlar`, urd: `ہر نماز میں کیا پڑھا جاتا ہے`, ben: `প্রতিটি নামাজে যা পড়া হয়`, fas: `آنچه در هر نماز خوانده می‌شود`, zh: `每次拜功中所诵读的内容`, yue: `每次拜功中所誦讀嘅內容`, ja: `すべての礼拝で唱えること`, ru: `Что произносится в каждой молитве`, es: `Lo que se recita en cada oración`, ko: `모든 예배에서 낭송하는 것`, ta: `ஒவ்வொரு தொழுகையிலும் ஓதப்படுவன`, si: `සෑම සලාතයකම කියවන දෑ` },

  uni_fard_h: { en: `Fard (Compulsory)  –  the prayer is invalid without these`, ms: `Fardu (Wajib mutlak)  –  solat tidak sah tanpa ini`, tur: `Farz (Mutlaka yapılması gereken)  –  bunlar olmadan namaz geçersizdir`, urd: `فرض (لازمی)  –  ان کے بغیر نماز باطل ہے`, ben: `ফরজ (অপরিহার্য)  –  এগুলো ছাড়া নামাজ বাতিল`, fas: `فرض (واجب قطعی)  –  بدون اینها نماز باطل است`, zh: `主命（绝对必行）  –  缺此则拜功无效`, yue: `主命（絕對必行）  –  缺此則拜功無效`, ja: `ファルド（絶対の義務）  –  これらがなければ礼拝は無効`, ru: `Фард (обязательное)  –  без этого молитва недействительна`, es: `Fard (obligatorio)  –  sin esto la oración es inválida`, ko: `파르드(필수)  –  이것 없이는 예배가 무효`, ta: `ஃபர்ள் (கட்டாயம்)  –  இவையின்றி தொழுகை செல்லாது`, si: `ෆර්ද් (අත්‍යවශ්‍ය)  –  මේවා නැතිව සලාතය වලංගු නොවේ` },
  uni_fard_body: { en: `1) Standing (qiyam) if able. 2) Opening Takbir (Allahu Akbar)  –  the prayer begins with it. 3) Reciting Surah al-Fatihah in every rak'ah. 4) Bowing (ruku') with reassurance (tuma'ninah). 5) Standing erect after ruku' (i'tidal). 6) Two prostrations (sujud) on the seven body parts: forehead with nose, two palms, two knees, and the toes of both feet. 7) Sitting briefly between the two prostrations (jalsah). 8) The final sitting and the testimony (tashahhud al-akhir). 9) The closing salam to the right and left. 10) Proper order (tartib) of all these. Any one of these omitted invalidates the prayer.`, ms: `1) Berdiri (qiyam) jika mampu. 2) Takbir pembukaan (Allahu Akbar)  –  solat bermula dengannya. 3) Membaca Surah al-Fatihah dalam setiap rakaat. 4) Rukuk dengan tenang (tumakninah). 5) Berdiri tegak selepas rukuk (i'tidal). 6) Dua kali sujud di atas tujuh anggota: dahi bersama hidung, dua tapak tangan, dua lutut, dan jari-jari kedua kaki. 7) Duduk seketika antara dua sujud (jalsah). 8) Duduk akhir dan membaca tasyahhud akhir. 9) Memberi salam ke kanan dan ke kiri. 10) Tertib semua ini. Jika satu daripadanya tertinggal, solat menjadi batal.`, tur: `1) Gücü yeten için kıyam. 2) İftitah tekbiri (Allahu Ekber)  –  namaz onunla başlar. 3) Her rekâtta Fâtiha okumak. 4) Tumâninetle rükû. 5) Rükûdan doğrularak dik durmak (i'tidâl). 6) Yedi azâ üzerine secde: burunla birlikte alın, iki avuç, iki diz ve iki ayağın parmakları. 7) İki secde arasında kısa oturuş (celse). 8) Son oturuş ve son tahiyyât. 9) Sağa ve sola selam vermek. 10) Bunların hepsinin tertibi. Birinin terki namazı batıl kılar.`, urd: `(۱) قدرت ہو تو قیام۔ (۲) تکبیرِ تحریمہ (اللہ اکبر)  –  نماز اسی سے شروع ہوتی ہے۔ (۳) ہر رکعت میں سورۃ الفاتحہ پڑھنا۔ (۴) اطمینان کے ساتھ رکوع۔ (۵) رکوع کے بعد سیدھا کھڑا ہونا (اعتدال)۔ (۶) سات اعضاء پر سجدہ: ناک کے ساتھ پیشانی، دونوں ہتھیلیاں، دونوں گھٹنے، اور دونوں پاؤں کی انگلیاں۔ (۷) دو سجدوں کے درمیان مختصر بیٹھنا (جلسہ)۔ (۸) آخری قعدہ اور تشہّدِ آخر۔ (۹) دائیں اور بائیں سلام پھیرنا۔ (۱۰) ان سب کی ترتیب۔ ان میں سے کوئی ایک بھی چھوٹ جائے تو نماز باطل۔`, ben: `১) সক্ষম হলে দাঁড়ানো (কিয়াম)। ২) তাকবিরে তাহরিমা (আল্লাহু আকবার)  –  নামাজ এর দ্বারা শুরু হয়। ৩) প্রতি রাকাতে সূরা আল-ফাতিহা পড়া। ৪) তুমানিনার সাথে রুকু। ৫) রুকুর পর সোজা দাঁড়ানো (ই'তিদাল)। ৬) সাত অঙ্গে সিজদা: নাকসহ কপাল, দুই হাতের তালু, দুই হাঁটু এবং উভয় পায়ের আঙুল। ৭) দুই সিজদার মাঝে সংক্ষিপ্ত বসা (জলসা)। ৮) শেষ বৈঠক ও শেষ তাশাহহুদ। ৯) ডানে ও বামে সালাম ফেরানো। ১০) এসবের ক্রমধারা (তরতীব)। এর কোনো একটি ছুটে গেলে নামাজ বাতিল।`, fas: `۱) قیام در صورت توان. ۲) تکبیرة الاحرام (الله اکبر)  –  نماز با آن آغاز می‌شود. ۳) خواندن سوره فاتحه در هر رکعت. ۴) رکوع با اطمینان (طمأنینه). ۵) ایستادن راست پس از رکوع (اعتدال). ۶) دو سجده بر هفت عضو: پیشانی همراه بینی، دو کف دست، دو زانو و انگشتان دو پا. ۷) نشستن کوتاه میان دو سجده (جلسه). ۸) نشستن آخر و تشهد آخر. ۹) سلام به راست و چپ. ۱۰) ترتیب همه اینها. ترک یکی، نماز را باطل می‌کند.`, zh: `(一)能立则立（吉亚姆）。(二)开始的大赞词（安拉至大）  –  拜功由此开始。(三)每一拜中诵读《开端章》。(四)从容地鞠躬（鲁库）。(五)鞠躬后挺立（伊提达勒）。(六)以七处叩头：额并鼻、两掌、两膝、两足趾。(七)两次叩头之间短暂端坐（杰勒赛）。(八)末次端坐与末次的作证词（塔沙胡德）。(九)向右与向左道平安。(十)以上的顺序（特尔提卜）。缺其中一项则拜功无效。`, yue: `(一)能立則立（吉亞姆）。(二)開始嘅大讚詞（安拉至大）  –  拜功由此開始。(三)每一拜中誦讀《開端章》。(四)從容噉鞠躬（魯庫）。(五)鞠躬後挺立（伊提達勒）。(六)以七處叩頭：額連鼻、兩掌、兩膝、兩足趾。(七)兩次叩頭之間短暫端坐（傑勒賽）。(八)末次端坐同末次嘅作證詞（塔沙胡德）。(九)向右與向左道平安。(十)以上嘅順序（特爾提卜）。缺其中一項則拜功無效。`, ja: `(1) 可能であれば立つこと（キヤーム）。(2) 開始のタクビール（アッラーフ・アクバル）  –  礼拝はこれにより始まる。(3) 各ラクアでファーティハ章を朗誦。(4) 落ち着いて立礼（ルクー）。(5) ルクー後に真っ直ぐ立つ（イーティダール）。(6) 七つの部位での平伏（スジュード）：鼻とともに額、両手のひら、両膝、両足のつま先。(7) 二度の平伏の間の短い座（ジャルサ）。(8) 最後の座と最後のタシャフード。(9) 右と左へのサラーム。(10) これらすべての順序（タルティーブ）。一つでも欠けると礼拝は無効。`, ru: `1) Стояние (кыям), если способен. 2) Открывающий такбир (Аллаху Акбар)  –  молитва начинается с него. 3) Чтение суры аль-Фатиха в каждом ракате. 4) Поясной поклон (руку') с упокоением (тумаъанина). 5) Прямое стояние после руку' (и'тидаль). 6) Два земных поклона (суджуд) на семи частях тела: лоб с носом, две ладони, два колена и пальцы обеих стоп. 7) Краткое сидение между двумя суджудами (джалса). 8) Окончательное сидение и последнее свидетельство (ташаххуд). 9) Завершающий салам направо и налево. 10) Должный порядок (тартиб) всего этого. Пропуск любого из них делает молитву недействительной.`, es: `1) Estar de pie (qiyam) si se puede. 2) Takbir de apertura (Allahu Akbar)  –  la oración comienza con él. 3) Recitar la Sura al-Fatiha en cada rak'ah. 4) Inclinación (ruku') con sosiego (tuma'ninah). 5) Erguirse tras el ruku' (i'tidal). 6) Dos prosternaciones (sujud) sobre siete miembros: frente con la nariz, las dos palmas, las dos rodillas y los dedos de ambos pies. 7) Sentarse brevemente entre las dos prosternaciones (jalsah). 8) Sentada final y el testimonio (tashahhud al-akhir). 9) Salam final a derecha e izquierda. 10) Orden adecuado (tartib) de todo ello. Omitir cualquiera invalida la oración.`, ko: `1) 가능하면 서기(끼얌). 2) 시작의 타크비르(알라후 아크바르)  –  예배는 이것으로 시작된다. 3) 각 라카에서 알파티하 장 낭송. 4) 안정함(투마으니나)을 가진 절(루쿠으). 5) 루쿠으 뒤에 곧게 서기(이으티달). 6) 일곱 부위로 엎드림(수주드): 코와 함께 이마, 두 손바닥, 두 무릎, 양발의 발가락. 7) 두 엎드림 사이의 짧은 앉음(잘사). 8) 마지막 앉음과 최후의 증언(타샤후드). 9) 오른쪽과 왼쪽으로 마치는 살람. 10) 이 모두의 순서(타르티브). 어느 하나라도 빠지면 예배는 무효.`, ta: `1) இயலுமாயின் நிற்றல் (கியாம்). 2) தொடக்கத் தக்பீர் (அல்லாஹு அக்பர்)  –  தொழுகை இதனால் தொடங்குகிறது. 3) ஒவ்வொரு ரக்அத்திலும் சூரத்துல் ஃபாதிஹா ஓதுதல். 4) நிதானத்துடன் (துமஃனீனா) ருகூஉ. 5) ருகூஉவுக்குப் பின் நேராக நிற்றல் (இஃதிதால்). 6) ஏழு உறுப்புகளில் சுஜூத்: மூக்குடன் நெற்றி, இரு உள்ளங்கைகள், இரு முழங்கால்கள், இரு கால்களின் விரல்கள். 7) இரு சுஜூதுகளுக்கு இடையே குறுகிய இருப்பு (ஜல்ஸா). 8) இறுதி இருப்பு மற்றும் இறுதி தஷஹ்ஹுத். 9) வலதிலும் இடதிலும் முடிவுச் ஸலாம். 10) இவ்வனைத்தின் ஒழுங்கு (தர்த்தீப்). எதையேனும் விட்டால் தொழுகை செல்லாது.`, si: `1) හැකි නම් සිටගැනීම (කියාම්). 2) ආරම්භක තක්බීර (අල්ලාහු අක්බර්)  –  සලාතය එයින් ආරම්භ වේ. 3) සෑම රකඅතකම අල්-ෆාතිහා සූරාව කියවීම. 4) සන්සුන්කමින් (තුමඃනීනා) රුකූඃ. 5) රුකූඃ පසු සෘජුව සිටගැනීම (ඉඃතිදාල්). 6) අංග හතක් මත සජ්දා: නාසය සමඟ නළල, දෑත් අල්ල, දෙදන, දෙපාදයේ ඇඟිලි. 7) සජ්දා දෙක අතර කෙටි ඉඳීම (ජල්සා). 8) අවසන් ඉඳීම සහ අවසන් තශහ්හුද්. 9) දකුණට හා වමට අවසන් සලාම්. 10) මේ සියල්ලෙහි පිළිවෙළ (තර්තීබ්). කවරයක් හෝ අත්හැරියහොත් සලාතය වලංගු නොවේ.` },

  uni_wajib_h: { en: `Wajib  –  necessary; omission requires sajdat al-sahw`, ms: `Wajib  –  perlu; jika tertinggal hendaklah sujud sahwi`, tur: `Vacip  –  gerekli; terki sehiv secdesini gerektirir`, urd: `واجب  –  ضروری؛ ترک پر سجدہ سہو لازم`, ben: `ওয়াজিব  –  জরুরি; ছুটে গেলে সিজদা সাহু আবশ্যক`, fas: `واجب  –  لازم؛ ترک آن، سجده سهو می‌خواهد`, zh: `当然（Wajib）  –  必要的；遗漏须行忘记叩头（萨乎叩头）`, yue: `當然（Wajib）  –  必要嘅；遺漏須行忘記叩頭（薩乎叩頭）`, ja: `ワージブ  –  必要；省略時はサジダ・アッ＝サハウ（忘却の平伏）が必要`, ru: `Ваджиб  –  необходимое; пропуск требует саджда ас-сахв (земной поклон забывчивости)`, es: `Wajib  –  necesario; su omisión exige la sajdat al-sahw (prosternación del olvido)`, ko: `와집  –  필수; 누락 시 사즈다 사후(망각의 엎드림) 요구됨`, ta: `வாஜிப்  –  அவசியம்; தவறினால் ஸஜ்தத்துல் ஸஹ்வ் தேவை`, si: `වාජිබ්  –  අවශ්‍ය; අත්හැරියහොත් සජ්දත් අස්-සහ්ව් අවශ්‍යය` },
  uni_wajib_body: { en: `1) Reciting a surah or three short verses after Fatihah in the first two rak'ahs. 2) The opening hand-raising and the takbirs of transition between postures. 3) Saying "Sami'allahu liman hamidah" (the imam and the lone worshipper) and "Rabbana wa lakal-hamd" (everyone) when rising from ruku'. 4) The tasbih in ruku' ("Subhana Rabbiyal-'Azim") and sujud ("Subhana Rabbiyal-A'la") at least once  –  three times being the minimum sunnah. 5) The first tashahhud (in 3- or 4-rak'ah prayers). 6) Salawat upon the Prophet ﷺ in the final tashahhud. 7) Both salams. If a wajib is forgotten, the prayer is still valid, and the worshipper performs two extra prostrations of forgetfulness (sajdat al-sahw) before or after the salam.`, ms: `1) Membaca surah atau tiga ayat pendek selepas Fatihah pada dua rakaat pertama. 2) Mengangkat tangan pembukaan dan takbir-takbir intiqal (peralihan posisi). 3) Mengucap "Sami'allahu liman hamidah" (imam dan munfarid) serta "Rabbana wa lakal-hamd" (semua) ketika bangkit dari rukuk. 4) Tasbih dalam rukuk ("Subhana Rabbiyal-'Azim") dan sujud ("Subhana Rabbiyal-A'la") sekurang-kurangnya sekali  –  tiga kali adalah sunnah minimum. 5) Tasyahhud awal (dalam solat 3 atau 4 rakaat). 6) Selawat ke atas Nabi ﷺ pada tasyahhud akhir. 7) Kedua-dua salam. Jika satu wajib tertinggal, solat tetap sah dan dilakukan dua sujud sahwi sebelum atau selepas salam.`, tur: `1) İlk iki rekâtta Fâtiha'dan sonra bir sure veya üç kısa âyet okumak. 2) İftitahta el kaldırmak ve duruşlar arasındaki intikal tekbirleri. 3) Rükûdan kalkarken (imam ve munferid) "Semi'allâhu limen hamideh" ve (herkes) "Rabbenâ ve lekel-hamd" demek. 4) Rükûda ("Sübhâne Rabbiyel-Azîm") ve secdede ("Sübhâne Rabbiyel-A'lâ") en az bir kere tesbih  –  asgari sünnet üç defadır. 5) İlk tahiyyât (3 veya 4 rekâtlı namazlarda). 6) Son tahiyyâtta Peygamber'e ﷺ salavât. 7) Her iki selam. Vacip terkedilirse namaz yine geçerlidir; selamdan önce veya sonra iki sehiv secdesi yapılır.`, urd: `(۱) پہلی دو رکعتوں میں فاتحہ کے بعد ایک سورت یا تین چھوٹی آیات پڑھنا۔ (۲) تکبیرِ تحریمہ پر ہاتھ اٹھانا اور انتقال کی تکبیرات۔ (۳) رکوع سے اٹھتے ہوئے (امام و منفرد) "سمع اللہ لمن حمدہ" اور (سب) "ربنا و لک الحمد" کہنا۔ (۴) رکوع میں "سبحان ربی العظیم" اور سجدہ میں "سبحان ربی الاعلیٰ" کم از کم ایک بار  –  تین بار ادنیٰ سنت ہے۔ (۵) قعدہ اولیٰ (تین یا چار رکعتی نماز میں)۔ (۶) قعدہ اخیرہ میں نبی ﷺ پر درود۔ (۷) دونوں سلام۔ کوئی واجب رہ جائے تو نماز صحیح رہتی ہے، سلام سے پہلے یا بعد دو سجدہ سہو کیے جاتے ہیں۔`, ben: `১) প্রথম দুই রাকাতে ফাতিহার পরে একটি সূরা বা তিনটি ছোট আয়াত পড়া। ২) তাকবিরে তাহরিমার সময় হাত উঠানো ও অবস্থান পরিবর্তনের তাকবির। ৩) রুকু থেকে উঠার সময় (ইমাম ও একা পড়নেওয়ালা) "সামি'আল্লাহু লিমান হামিদাহ" এবং (সকলে) "রব্বানা ওয়া লাকাল-হামদ" বলা। ৪) রুকুতে "সুবহানা রব্বিয়াল-আজীম" ও সিজদায় "সুবহানা রব্বিয়াল-আ'লা" অন্তত একবার  –  তিনবার সর্বনিম্ন সুন্নাহ। ৫) প্রথম তাশাহহুদ (৩ বা ৪ রাকাতের নামাজে)। ৬) শেষ তাশাহহুদে নবী ﷺ-এর প্রতি দরুদ। ৭) উভয় সালাম। ওয়াজিব ছুটে গেলে নামাজ বহাল থাকে, সালামের আগে বা পরে দুটি সিজদা সাহু করতে হয়।`, fas: `۱) خواندن یک سوره یا سه آیه کوتاه پس از فاتحه در دو رکعت اول. ۲) بلندکردن دست در تکبیرة الاحرام و تکبیرات انتقال میان حالات. ۳) گفتن "سمع الله لمن حمده" (امام و منفرد) و "ربنا و لک الحمد" (همه) هنگام برخاستن از رکوع. ۴) تسبیح در رکوع ("سبحان ربی العظیم") و سجده ("سبحان ربی الأعلی") دست‌کم یک بار  –  سه بار حداقل سنت است. ۵) تشهد اول (در نماز سه یا چهار رکعتی). ۶) صلوات بر پیامبر ﷺ در تشهد آخر. ۷) هر دو سلام. اگر واجبی ترک شود نماز صحیح است و دو سجده سهو پیش یا پس از سلام انجام می‌گیرد.`, zh: `(一)前两拜中在《开端章》后诵读一章或三节短经。(二)开始的举手与转换体态时的大赞词。(三)起身于鞠躬时（伊玛目与独自礼者）念"赛米阿拉胡列曼哈米达"，（所有人）念"拉布巴那瓦勒卡勒哈姆德"。(四)鞠躬中念"苏布哈那拉比耶勒阿则姆"，叩头中念"苏布哈那拉比耶勒阿俩"至少一次  –  三次为最低圣行。(五)初次端坐之作证词（三拜或四拜的拜功中）。(六)末次端坐时向先知ﷺ的赞祷。(七)两次平安词。若遗漏某当然，拜功仍有效，礼者于平安词前或后行两次"忘记叩头"。`, yue: `(一)前兩拜中喺《開端章》後誦讀一章或三節短經。(二)開始嘅舉手同轉換體態時嘅大讚詞。(三)起身於鞠躬時（伊瑪目同獨自禮者）念"賽米阿拉胡列曼哈米達"，（所有人）念"拉布巴那瓦勒卡勒哈姆德"。(四)鞠躬中念"蘇布哈那拉比耶勒阿則姆"，叩頭中念"蘇布哈那拉比耶勒阿倆"至少一次  –  三次為最低聖行。(五)初次端坐之作證詞（三拜或四拜嘅拜功中）。(六)末次端坐時向先知ﷺ嘅讚禱。(七)兩次平安詞。若遺漏某當然，拜功仍有效，禮者於平安詞前或後行兩次「忘記叩頭」。`, ja: `(1) 最初の二ラクアでファーティハの後に章または短い三節を朗誦。(2) 開始の挙手と体勢移行のタクビール。(3) ルクーから起き上がる際、（イマームと単独礼拝者は）「サミアッラーフ・リマン・ハミダ」、（皆は）「ラッバナー・ワ・ラカル＝ハムド」と唱える。(4) ルクーでは「スブハーナ・ラッビヤル＝アズィーム」、スジュードでは「スブハーナ・ラッビヤル＝アアラー」を少なくとも一回  –  最低限のスンナは三回。(5) 第一タシャフード（三または四ラクアの礼拝で）。(6) 最後のタシャフードでの預言者ﷺへのサラワート。(7) 両方のサラーム。ワージブが省略されても礼拝は有効で、サラームの前後に二回のサジダ・アッ＝サハウ（忘却の平伏）を行う。`, ru: `1) Чтение суры или трёх коротких аятов после Фатихи в первых двух ракатах. 2) Открывающее воздевание рук и такбиры перехода между положениями. 3) Произнесение "Сами' Аллаху лиман хамидах" (имам и индивидуально молящийся) и "Раббана ва лакаль-хамд" (все) при подъёме из руку'. 4) Тасбих в руку' ("Субхана Рабби-аль-'Азим") и суджуде ("Субхана Рабби-аль-А'ля") хотя бы один раз  –  три раза  –  минимальная сунна. 5) Первый ташаххуд (в молитвах из 3 или 4 ракатов). 6) Салават Пророку ﷺ в последнем ташаххуде. 7) Оба салама. Если ваджиб забыт, молитва действительна; молящийся совершает два дополнительных земных поклона забывчивости (саджда ас-сахв) до или после салама.`, es: `1) Recitar una sura o tres versículos cortos tras la Fatiha en los dos primeros rak'ahs. 2) El alzar de manos de apertura y los takbires de transición entre posturas. 3) Decir "Sami'allahu liman hamidah" (el imam y el orante solitario) y "Rabbana wa lakal-hamd" (todos) al incorporarse del ruku'. 4) El tasbih en ruku' ("Subhana Rabbiyal-'Azim") y en sujud ("Subhana Rabbiyal-A'la") al menos una vez  –  tres veces es la sunnah mínima. 5) El primer tashahhud (en oraciones de 3 o 4 rak'ahs). 6) Salawat al Profeta ﷺ en el tashahhud final. 7) Ambos salames. Si se olvida un wajib, la oración sigue siendo válida y el orante realiza dos prosternaciones de olvido (sajdat al-sahw) antes o después del salam.`, ko: `1) 처음 두 라카에서 파티하 후 한 장 또는 짧은 세 구절 낭송. 2) 시작의 손 들기와 자세 전환의 타크비르. 3) 루쿠으에서 일어설 때 (이맘과 단독 예배자는) "사미알라후 리만 하미다", (모두는) "랍바나 와 라칼-함드"를 말함. 4) 루쿠으에서 "수브하나 랍비얄-아짐", 수주드에서 "수브하나 랍비얄-아을라"를 적어도 한 번  –  세 번이 최소 순나. 5) 첫 타샤후드(3 또는 4 라카의 예배에서). 6) 마지막 타샤후드에서 예언자 ﷺ에 대한 살라와트. 7) 두 살람. 와집을 잊으면 예배는 여전히 유효하며, 살람 전후로 두 번의 망각의 엎드림(사즈다 사후)을 행함.`, ta: `1) முதல் இரு ரக்அத்களில் ஃபாதிஹாவுக்குப் பின் ஒரு சூரா அல்லது மூன்று குறு வசனங்கள் ஓதுதல். 2) தொடக்கத்தில் கைகளை உயர்த்துதல் மற்றும் நிலை மாற்ற தக்பீர்கள். 3) ருகூஉவிலிருந்து எழும்போது (இமாமும் தனியாகத் தொழுபவரும்) "ஸமிஅல்லாஹு லிமன் ஹமிதஹ்" மற்றும் (அனைவரும்) "ரப்பனா வ லகல்-ஹம்த்" எனல். 4) ருகூஉவில் "ஸுப்ஹான ரப்பியல்-அழீம்" மற்றும் சுஜூதில் "ஸுப்ஹான ரப்பியல்-அஃலா" குறைந்தது ஒருமுறை  –  மூன்று முறை குறைந்தபட்ச சுன்னா. 5) முதல் தஷஹ்ஹுத் (3 அல்லது 4 ரக்அத் தொழுகைகளில்). 6) இறுதி தஷஹ்ஹுதில் நபி ﷺ மீது ஸலவாத். 7) இரண்டு ஸலாம்களும். வாஜிபை மறந்தால் தொழுகை செல்லும், ஸலாமுக்கு முன் அல்லது பின் இரு மறதிச் சுஜூதுகள் (ஸஜ்தத்துல் ஸஹ்வ்) செய்யப்படுகின்றன.`, si: `1) පළමු රකඅත් දෙකේදී ෆාතිහා පසු සූරාවක් හෝ කෙටි වැකි තුනක් කියවීම. 2) ආරම්භක අත් ඔසවීම සහ ඉරියව් මාරුවේ තක්බීර. 3) රුකූඃ වෙතින් නැගිට්ටවන විට (ඉමාම් සහ තනිව සලාත් කරන්නා) "සමි අල්ලාහු ලිමන් හමිදහ්", (සියලුදෙනා) "රබ්බනා ව ලකල්-හම්ද්" කීම. 4) රුකූඃ වලදී "සුබ්හාන රබ්බියල්-අසීම්" සහ සජ්දාවේදී "සුබ්හාන රබ්බියල්-අඃලා" අවම වශයෙන් එක් වරක්  –  තුන් වරක් අවම සුන්නාව. 5) පළමු තශහ්හුද් (රකඅත් 3 හෝ 4ක සලාතයේදී). 6) අවසන් තශහ්හුදේදී නබි ﷺ වෙත සලවාත්. 7) සලාම් දෙකම. වාජිබයක් අමතක වුණොත් සලාතය වලංගුව පවතී; සලාම් වලට පෙර හෝ පසු අමතකවීමේ සජ්දා දෙකක් (සජ්දත් අස්-සහ්ව්) කරයි.` },

  uni_sunnah_h: { en: `Sunnah  –  recommended; abundant reward in performing them, no sin in omitting`, ms: `Sunnah  –  digalakkan; pahala besar bila dilakukan, tiada dosa bila ditinggalkan`, tur: `Sünnet  –  müstehab; yapana büyük sevap, terkinde günah yoktur`, urd: `سنّت  –  مستحب؛ ادا کرنے پر بڑا اجر، ترک پر گناہ نہیں`, ben: `সুন্নাহ  –  মুস্তাহাব; পালনে অপরিসীম সওয়াব, ছাড়লে গুনাহ নেই`, fas: `سنت  –  مستحب؛ پاداش فراوان در انجام، گناهی در ترک نیست`, zh: `圣行  –  受嘉许；行之大有回赐，遗之无罪`, yue: `聖行  –  受嘉許；行之大有回賜，遺之無罪`, ja: `スンナ  –  推奨；行えば大いなる報奨、省略しても罪はない`, ru: `Сунна  –  желательное; обильная награда за исполнение, нет греха за пропуск`, es: `Sunnah  –  recomendado; abundante recompensa al realizarlo, sin pecado al omitirlo`, ko: `순나  –  권장; 행하면 풍성한 보상, 빠뜨려도 죄가 아님`, ta: `சுன்னா  –  பரிந்துரைக்கப்பட்டது; செய்தால் அதிக நற்கூலி, விட்டாலும் பாவமில்லை`, si: `සුන්නා  –  නිර්දේශිත; ඉටු කළොත් මහත් කුසල්, අත්හැරියත් පාපයක් නැත` },
  uni_sunnah_body: { en: `1) Opening supplication (du'a al-istiftah)  –  most commonly "Subhanaka Allahumma...". 2) Saying "A'udhu billahi minash-shaytanir-rajim" and "Bismillah" silently before Fatihah in the first rak'ah. 3) Saying "Ameen" after Fatihah  –  aloud in audible prayers, silently in silent ones. 4) Lengthening the recitation in Fajr, medium length in Dhuhr and Asr, shorter in Maghrib, medium in Isha. 5) Looking at the place of sujud throughout the standing portions, and at the index finger during tashahhud. 6) Spreading the fingers in ruku' to grip the knees; keeping the back straight and parallel to the ground. 7) Reciting "Rabbighfir li" between the two prostrations. 8) Du'a in the final sujud and after the final tashahhud before the salam.`, ms: `1) Doa iftitah  –  yang paling masyhur "Subhanaka Allahumma...". 2) Membaca "A'udhu billahi minas-syaitanir-rajim" dan "Bismillah" secara perlahan sebelum Fatihah pada rakaat pertama. 3) Mengucap "Amin" selepas Fatihah  –  kuat pada solat jahriah, perlahan pada solat sirriah. 4) Memanjangkan bacaan dalam Subuh, sederhana dalam Zuhur dan Asar, lebih pendek dalam Maghrib, dan sederhana dalam Isyak. 5) Memandang ke tempat sujud sepanjang qiyam, dan ke jari telunjuk semasa tasyahhud. 6) Membuka jari-jari semasa rukuk untuk memegang lutut; mengekalkan belakang lurus selari dengan tanah. 7) Membaca "Rabbighfir li" antara dua sujud. 8) Doa pada sujud akhir dan selepas tasyahhud akhir sebelum salam.`, tur: `1) İftitah duası  –  en yaygını "Sübhâneke Allahümme...". 2) İlk rekâtta Fâtiha'dan önce sessizce "Eûzü billâhi mineşşeytânirracîm" ve "Bismillâh" demek. 3) Fâtiha'dan sonra "Âmîn" demek  –  cehrî namazlarda sesli, sirrî namazlarda sessiz. 4) Sabah'ta uzun, Öğle ve İkindi'de orta, Akşam'da kısa, Yatsı'da orta uzunlukta kıraat. 5) Kıyamda secde yerine, tahiyyâtta şehadet parmağına bakmak. 6) Rükûda parmakları açıp dizleri tutmak; sırtı düz ve yerle paralel tutmak. 7) İki secde arasında "Rabbiğfir lî" demek. 8) Son secdede ve son tahiyyât sonrası selamdan önce dua.`, urd: `(۱) دعائے استفتاح  –  مشہور "سبحانک اللھم..."۔ (۲) پہلی رکعت میں فاتحہ سے پہلے آہستہ "أعوذ باللہ من الشیطان الرجیم" اور "بسم اللہ" پڑھنا۔ (۳) فاتحہ کے بعد "آمین" کہنا  –  جہری نماز میں بلند، سری میں آہستہ۔ (۴) فجر میں طویل قراءت، ظہر و عصر میں متوسط، مغرب میں مختصر، عشاء میں متوسط۔ (۵) قیام میں سجدے کی جگہ پر اور تشہد میں شہادت کی انگلی پر نظر۔ (۶) رکوع میں انگلیاں کھول کر گھٹنوں کو پکڑنا؛ پیٹھ سیدھی اور زمین کے متوازی۔ (۷) دو سجدوں کے درمیان "رب اغفر لی"۔ (۸) آخری سجدے میں اور آخری تشہد کے بعد سلام سے قبل دعا۔`, ben: `১) দোয়ায়ে ইস্তিফতাহ  –  সর্বাধিক প্রচলিত "সুবহানাকা আল্লাহুম্মা..."। ২) প্রথম রাকাতে ফাতিহার আগে "আউযু বিল্লাহি মিনাশ-শাইতানির-রাজীম" ও "বিসমিল্লাহ" নীরবে পড়া। ৩) ফাতিহার পরে "আমীন" বলা  –  জোরে পড়ার নামাজে উচ্চস্বরে, নীরবের নামাজে নীরবে। ৪) ফজরে দীর্ঘ কেরাত, যোহর ও আসরে মাঝারি, মাগরিবে সংক্ষিপ্ত, ইশায় মাঝারি। ৫) দাঁড়ানো অবস্থায় সিজদার স্থানে এবং তাশাহহুদে শাহাদাত আঙুলের দিকে দৃষ্টি। ৬) রুকুতে আঙুল ফাঁক করে হাঁটু ধরা; পিঠ সোজা ও মাটির সমান্তরাল। ৭) দুই সিজদার মাঝে "রব্বিগফির লি"। ৮) শেষ সিজদায় এবং শেষ তাশাহহুদের পরে সালামের আগে দোয়া।`, fas: `۱) دعای استفتاح  –  مشهورترین "سبحانک اللهم...". ۲) خواندن آرامِ "أعوذ بالله من الشیطان الرجیم" و "بسم الله" پیش از فاتحه در رکعت اول. ۳) گفتن "آمین" پس از فاتحه  –  در نمازهای جهری بلند، در سرّی آرام. ۴) قرائت طولانی در فجر، متوسط در ظهر و عصر، کوتاه‌تر در مغرب، متوسط در عشاء. ۵) نگاه به جای سجده در قیام، و به انگشت شهادت در تشهد. ۶) باز کردن انگشتان در رکوع برای گرفتن زانوها؛ نگه داشتن پشت صاف و موازی زمین. ۷) "رب اغفر لی" میان دو سجده. ۸) دعا در سجده آخر و پس از تشهد آخر پیش از سلام.`, zh: `(一)开经祈祷（祈祷启）  –  最常见为「Subhanaka Allahumma…」。(二)首拜中在《开端章》前低声诵「我求护于真主免遭被驱逐的恶魔」与「奉真主之名」。(三)《开端章》后念「阿敏」  –  应高声之拜中高声，应默念之拜中低声。(四)晨礼诵长经，晌礼与晡礼中等，昏礼较短，宵礼中等。(五)立时凝视叩头之处，作证时凝视食指。(六)鞠躬时张开手指握住膝盖；背部挺直与地面平行。(七)两次叩头之间念「我的主啊，请赦免我」。(八)末次叩头中及末次作证后、平安词前作祈祷。`, yue: `(一)開經祈禱（祈禱啟）  –  最常見為「Subhanaka Allahumma…」。(二)首拜中喺《開端章》前低聲誦「我求護於真主免遭被驅逐嘅惡魔」與「奉真主之名」。(三)《開端章》後念「阿敏」  –  應高聲之拜中高聲，應默念之拜中低聲。(四)晨禮誦長經，晌禮與晡禮中等，昏禮較短，宵禮中等。(五)立時凝視叩頭之處，作證時凝視食指。(六)鞠躬時張開手指握住膝蓋；背部挺直與地面平行。(七)兩次叩頭之間念「我的主啊，請赦免我」。(八)末次叩頭中及末次作證後、平安詞前作祈禱。`, ja: `(1) 開始の祈願（ドゥア・アル＝イスティフターハ）  –  最も一般的なのは「スブハーナカ・アッラーフマ…」。(2) 第一ラクアでファーティハの前に「アウーズ・ビッラーヒ・ミナッシャイターニル＝ラジーム」と「ビスミッラー」を密かに唱える。(3) ファーティハの後に「アーミーン」を唱える  –  音読の礼拝では声に出し、無音の礼拝では密かに。(4) ファジュルで長く、ズフルとアスルで中程度、マグリブで短く、イシャーで中程度の朗誦。(5) 立位中はスジュードの場所を、タシャフードの間は人差し指を見る。(6) ルクー時は指を広げて膝を掴み、背を真っ直ぐ地面と平行に保つ。(7) 二度の平伏の間に「ラッビグフィル・リー」と唱える。(8) 最後のスジュードでと、最後のタシャフード後サラームの前にドゥア。`, ru: `1) Открывающая мольба (ду'а аль-истифтах)  –  чаще всего "Субханака Аллахумма...". 2) Произнесение "А'узу биллахи мина-ш-шайтани-р-раджим" и "Бисмиллах" про себя перед Фатихой в первом ракате. 3) Произнесение "Амин" после Фатихи  –  вслух в громких молитвах, про себя в тихих. 4) Удлинение чтения в Фаджре, средней длины в Зухре и Асре, короче в Магрибе, средней длины в Иша. 5) Взгляд на место суджуда во время стояния и на указательный палец во время ташаххуда. 6) Расставление пальцев в руку' для обхвата колен; спина прямая и параллельна земле. 7) "Рабби-гфир ли" между двумя суджудами. 8) Дуа в последнем суджуде и после последнего ташаххуда перед саламом.`, es: `1) Súplica de apertura (du'a al-istiftah)  –  la más común "Subhanaka Allahumma...". 2) Decir "A'udhu billahi minash-shaytanir-rajim" y "Bismillah" en voz baja antes de la Fatiha en el primer rak'ah. 3) Decir "Ameen" tras la Fatiha  –  en voz alta en oraciones audibles, en silencio en las silenciosas. 4) Alargar la recitación en Fajr, longitud media en Dhuhr y Asr, más breve en Maghrib, media en Isha. 5) Mirar el lugar del sujud durante las partes de pie y al índice durante el tashahhud. 6) Separar los dedos en ruku' para asir las rodillas; mantener la espalda recta y paralela al suelo. 7) Recitar "Rabbighfir li" entre las dos prosternaciones. 8) Du'a en el sujud final y tras el tashahhud final antes del salam.`, ko: `1) 시작의 기원(두아 알이스티프타하)  –  가장 일반적으로 "수브하나카 알라훔마…". 2) 첫 라카에서 파티하 전에 "아우두 빌라히 미나샤이타닐 라짐"과 "비스밀라"를 조용히 말함. 3) 파티하 후에 "아민" 말하기  –  소리 내는 예배에서는 소리 내어, 조용한 예배에서는 조용히. 4) 파즈르에서 길게, 주흐르와 아스르에서 중간, 마그립에서 짧게, 이샤에서 중간 길이로 낭송. 5) 서 있는 동안에는 수주드 자리를, 타샤후드 중에는 검지손가락을 응시. 6) 루쿠으에서 손가락을 벌려 무릎을 잡고, 등을 곧고 바닥과 평행하게 유지. 7) 두 엎드림 사이에 "랍비그피르 리". 8) 마지막 수주드와 마지막 타샤후드 후 살람 전에 두아.`, ta: `1) தொடக்க துஆ (துஆ அல்-இஸ்திஃப்தாஹ்)  –  மிகவும் பொதுவானது "ஸுப்ஹானக அல்லாஹும்ம...". 2) முதல் ரக்அத்தில் ஃபாதிஹாவுக்கு முன் "அஊது பில்லாஹி மினஷ்-ஷைதானிர்-ரஜீம்" மற்றும் "பிஸ்மில்லாஹ்" அமைதியாக ஓதுதல். 3) ஃபாதிஹாவுக்குப் பின் "ஆமீன்" சொல்லுதல்  –  ஜஹ்ரியான தொழுகைகளில் சத்தமாக, ஸிர்ரியான தொழுகைகளில் அமைதியாக. 4) ஃபஜ்ரில் நீண்ட ஓதல், ளுஹர் மற்றும் அஸ்ரில் நடுத்தர, மக்ரிபில் குறுகியது, இஷாவில் நடுத்தரம். 5) நிற்கையில் சுஜூத் இடத்தையும், தஷஹ்ஹுதின்போது ஆட்காட்டி விரலையும் பார்த்தல். 6) ருகூஉவில் விரல்களை விரித்து முழங்கால்களைப் பிடித்தல்; முதுகை நேராக, தரைக்கு இணையாக வைத்தல். 7) இரு சுஜூதுகளுக்கு இடையே "ரப்பிக்ஃபிர் லீ". 8) இறுதி சுஜூதில் மற்றும் இறுதி தஷஹ்ஹுதுக்குப் பின் ஸலாமுக்கு முன் துஆ.`, si: `1) ආරම්භක ප්‍රාර්ථනය (දුආ අල්-ඉස්තිෆ්තාහා)  –  වඩාත් සුලභව "සුබ්හානක අල්ලාහුම්ම...". 2) පළමු රකඅතේ ෆාතිහා පෙර "අඃ-උදු බිල්ලාහි මිනෂ්-ෂෛතානිර්-රජීම්" සහ "බිස්මිල්ලාහ්" නිහඬව කීම. 3) ෆාතිහා පසු "ආමීන්" කීම  –  හඬ ඇති සලාතවල හඬ නඟා, නිහඬ සලාතවල නිහඬව. 4) ෆජ්ර්හි දිගු කියවීම, ලුහර් හා අස්ර්හි මධ්‍යම, මග්රිබ්හි කෙටි, ඉෂාහි මධ්‍යම. 5) සිටගෙන සිටින අවස්ථාවලදී සජ්දා ස්ථානය දෙසත්, තශහ්හුද් අතරතුර අතගත ඇඟිල්ල දෙසත් බැලීම. 6) රුකූඃවේදී ඇඟිලි විදහා දන හිස් අල්ලාගනීම; පිට කෙළින් හා බිමට සමාන්තරව තබාගැනීම. 7) සජ්දා දෙක අතර "රබ්බිග්ෆිර් ලී". 8) අවසන් සජ්දාවේදී සහ අවසන් තශහ්හුද් පසු සලාම් වලට පෙර දුආ.` },

  uni_extras_h: { en: `Extras  –  added rewards from established Sunnah`, ms: `Tambahan  –  pahala bonus daripada Sunnah yang sabit`, tur: `Ekstralar  –  sabit sünnetten ek sevaplar`, urd: `اضافی اعمال  –  ثابت سنّت سے زائد اجر`, ben: `অতিরিক্ত  –  সাব্যস্ত সুন্নাহ থেকে অতিরিক্ত সওয়াব`, fas: `موارد اضافی  –  پاداش‌های افزون از سنت ثابت`, zh: `附加  –  从确证圣行中获得的额外回赐`, yue: `附加  –  從確證聖行中獲得嘅額外回賜`, ja: `追加事項  –  確立されたスンナによる追加の報奨`, ru: `Дополнительные  –  добавочные награды из установленной Сунны`, es: `Extras  –  recompensas añadidas de la Sunnah establecida`, ko: `추가 행위  –  확립된 순나로부터의 추가 보상`, ta: `கூடுதல்கள்  –  நிறுவப்பட்ட சுன்னாவின் கூடுதல் கூலி`, si: `අමතර  –  ස්ථාපිත සුන්නාවෙන් අමතර කුසල්` },
  uni_extras_body: { en: `1) After the closing salam: three times "Astaghfirullah", then "Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram". 2) "La ilaha illallahu wahdahu la sharika lahu...". 3) Tasbih, tahmid and takbir 33-33-34 times (Subhanallah, Alhamdulillah, Allahu Akbar). 4) Recitation of Ayat al-Kursi (2:255), Surah al-Ikhlas, al-Falaq and an-Nas after each fard prayer. 5) Du'a in one's own words at the end of each prayer  –  the Prophet ﷺ said "between the call to prayer and the iqamah, du'a is not rejected." 6) For Fajr and Maghrib specifically: ten times the testimony of faith with "lahul-mulku wa lahul-hamd...". The Prophet ﷺ said whoever does this is granted enormous reward and protection from Shaytan until evening.`, ms: `1) Selepas salam: tiga kali "Astaghfirullah", kemudian "Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram". 2) "La ilaha illallahu wahdahu la sharika lahu...". 3) Tasbih, tahmid, dan takbir 33-33-34 kali (Subhanallah, Alhamdulillah, Allahu Akbar). 4) Membaca Ayat al-Kursi (2:255), Surah al-Ikhlas, al-Falaq dan an-Nas selepas setiap solat fardu. 5) Doa dengan kata-kata sendiri pada akhir setiap solat  –  Nabi ﷺ bersabda "antara azan dan iqamah, doa tidak ditolak". 6) Khusus Subuh dan Maghrib: sepuluh kali kalimah syahadah dengan "lahul-mulku wa lahul-hamd...". Nabi ﷺ bersabda sesiapa yang melakukannya diberi pahala besar dan perlindungan daripada Syaitan sehingga petang.`, tur: `1) Selamdan sonra: üç kez "Estağfirullah", ardından "Allahümme entes-selâm ve minkes-selâm tebârakte yâ zel-celâli vel-ikrâm". 2) "Lâ ilâhe illallâhu vahdehû lâ şerîke leh...". 3) Tesbih, tahmid ve tekbir 33-33-34 (Sübhânallah, Elhamdülillâh, Allahu Ekber). 4) Her farz namazdan sonra Âyetü'l-Kürsî (2:255), İhlâs, Felak ve Nâs surelerini okumak. 5) Her namazın sonunda kendi sözleriyle dua  –  Peygamber ﷺ "Ezan ile kâmet arasında yapılan dua reddedilmez." buyurdu. 6) Özellikle Sabah ve Akşam'da: on kez kelime-i şehadeti "lehül-mülkü ve lehül-hamd..." ile söylemek. Peygamber ﷺ bunu yapan kişiye büyük sevap ve akşama kadar şeytandan korunma vaad etmiştir.`, urd: `(۱) سلام کے بعد: تین بار "أستغفر اللہ"، پھر "اللہم انت السلام ومنک السلام تبارکت یا ذا الجلال والإکرام"۔ (۲) "لا إلہ إلا اللہ وحدہ لا شریک لہ..."۔ (۳) تسبیح، تحمید اور تکبیر ۳۳-۳۳-۳۴ بار (سبحان اللہ، الحمد للہ، اللہ اکبر)۔ (۴) ہر فرض کے بعد آیت الکرسی (۲:۲۵۵)، سورۃ الاخلاص، الفلق اور الناس پڑھنا۔ (۵) ہر نماز کے آخر میں اپنی زبان میں دعا  –  نبی ﷺ نے فرمایا "اذان اور اقامت کے درمیان دعا رد نہیں ہوتی"۔ (۶) خاص طور پر فجر و مغرب کے بعد: دس مرتبہ کلمہ شہادت "لہ الملک ولہ الحمد..." کے ساتھ۔ نبی ﷺ نے فرمایا یہ کرنے والے کو بڑا اجر اور شام تک شیطان سے حفاظت ملتی ہے۔`, ben: `১) সালামের পর: তিনবার "আস্তাগফিরুল্লাহ", তারপর "আল্লাহুম্মা আনতাস-সালাম ওয়া মিনকাস-সালাম তাবারাকতা ইয়া যাল-জালালি ওয়াল-ইকরাম"। ২) "লা ইলাহা ইল্লাল্লাহু ওয়াহদাহু লা শরীকা লাহু..."। ৩) তাসবিহ, তাহমিদ ও তাকবির ৩৩-৩৩-৩৪ বার (সুবহানাল্লাহ, আলহামদুলিল্লাহ, আল্লাহু আকবার)। ৪) প্রতি ফরজ নামাজের পর আয়াতুল কুরসী (২:২৫৫), সূরা ইখলাস, ফালাক ও নাস পড়া। ৫) প্রতি নামাজের শেষে নিজের ভাষায় দোয়া  –  নবী ﷺ বলেছেন "আযান ও ইকামতের মাঝে দোয়া প্রত্যাখ্যাত হয় না"। ৬) বিশেষত ফজর ও মাগরিবে: দশবার শাহাদাতের কালেমা "লাহুল-মুলকু ওয়া লাহুল-হামদ..." সহ। নবী ﷺ বলেছেন যে এটি করে তাকে বিরাট সওয়াব ও সন্ধ্যা পর্যন্ত শয়তান থেকে সুরক্ষা দেওয়া হয়।`, fas: `۱) پس از سلام: سه بار "أستغفر الله"، سپس "اللهم أنت السلام و منک السلام تبارکت یا ذا الجلال و الإکرام". ۲) "لا إله إلا الله وحده لا شریک له...". ۳) تسبیح، تحمید و تکبیر ۳۳-۳۳-۳۴ بار (سبحان الله، الحمد لله، الله أکبر). ۴) خواندن آیة الکرسی (۲:۲۵۵)، سوره اخلاص، فلق و ناس پس از هر نماز فرض. ۵) دعا با کلمات خود در پایان هر نماز  –  پیامبر ﷺ فرمود "میان اذان و اقامه، دعا رد نمی‌شود". ۶) به‌ویژه پس از فجر و مغرب: ده بار شهادتین با "له الملک و له الحمد...". پیامبر ﷺ فرمود انجام‌دهنده آن، پاداش بزرگ و حفاظت از شیطان تا شب می‌یابد.`, zh: `(一)平安词后：三遍「我向真主求恕」（Astaghfirullah），随后「Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram」。(二)「La ilaha illallahu wahdahu la sharika lahu…」。(三)赞美词、感赞词、大赞词各33-33-34遍（Subhanallah、Alhamdulillah、Allahu Akbar）。(四)每次主命拜后诵《宝座经》（2:255）、忠诚章、黎明章与世人章。(五)每次拜功末以自己的话祈祷  –  先知ﷺ言「宣礼与起立之间的祈祷不被拒绝」。(六)特别于晨礼与昏礼：十遍作证词配「lahul-mulku wa lahul-hamd…」。先知ﷺ言行此者获巨大回赐，至晚间得护免恶魔。`, yue: `(一)平安詞後：三遍「我向真主求恕」（Astaghfirullah），隨後「Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram」。(二)「La ilaha illallahu wahdahu la sharika lahu…」。(三)讚美詞、感讚詞、大讚詞各33-33-34遍（Subhanallah、Alhamdulillah、Allahu Akbar）。(四)每次主命拜後誦《寶座經》（2:255）、忠誠章、黎明章與世人章。(五)每次拜功末以自己嘅話祈禱  –  先知ﷺ言「宣禮與起立之間嘅祈禱不被拒絕」。(六)特別於晨禮與昏禮：十遍作證詞配「lahul-mulku wa lahul-hamd…」。先知ﷺ言行此者獲巨大回賜，至夜間得護免惡魔。`, ja: `(1) サラーム後に：三度「アスタグフィルッラー」、続いて「アッラーフマ・アンタッ＝サラーム・ワ・ミンカッ＝サラーム・タバーラクタ・ヤー・ザル＝ジャラーリ・ワル＝イクラーム」。(2)「ラー・イラーハ・イッラッラーフ・ワフダフー・ラー・シャリーカ・ラフー…」。(3) タスビーフ、タハミード、タクビールを33-33-34回（スブハーナッラー、アルハムドゥリッラー、アッラーフ・アクバル）。(4) 各ファルド礼拝後にアーヤトゥル＝クルスィー（2:255）、イフラース章、ファラク章、ナース章を朗誦。(5) 各礼拝の終わりに自分の言葉でドゥア  –  預言者ﷺは「アザーンとイカーマの間のドゥアは却下されない」と仰せられた。(6) 特にファジュルとマグリブの後に：信仰告白を十度、「ラフル＝ムルク・ワ・ラフル＝ハムド…」とともに。預言者ﷺは行う者に大いなる報奨と夕方までのシャイターンからの守護を約束された。`, ru: `1) После завершающего салама: трижды "Астагфируллах", затем "Аллахумма антас-салям ва минкас-салям табаракта йа заль-джаляли валь-икрам". 2) "Ля иляха илляллаху вахдаху ля шарика лаху...". 3) Тасбих, тахмид и такбир по 33-33-34 (Субханаллах, Альхамдулиллях, Аллаху Акбар). 4) Чтение Аят аль-Курси (2:255), сур аль-Ихляс, аль-Фаляк и ан-Нас после каждой обязательной молитвы. 5) Дуа своими словами в конце каждой молитвы  –  Пророк ﷺ сказал "между азаном и икамой дуа не отвергается". 6) В частности после Фаджра и Магриба: десять раз свидетельство веры с "ляхуль-мульку ва ляхуль-хамд...". Пророк ﷺ сказал, что совершающему это дарована огромная награда и защита от шайтана до вечера.`, es: `1) Tras el salam final: tres veces "Astaghfirullah", luego "Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram". 2) "La ilaha illallahu wahdahu la sharika lahu...". 3) Tasbih, tahmid y takbir 33-33-34 veces (Subhanallah, Alhamdulillah, Allahu Akbar). 4) Recitación de Ayat al-Kursi (2:255), Sura al-Ikhlas, al-Falaq y an-Nas tras cada oración obligatoria. 5) Du'a con palabras propias al final de cada oración  –  el Profeta ﷺ dijo "entre el adhan y la iqamah, el du'a no es rechazado". 6) Especialmente tras Fajr y Maghrib: diez veces el testimonio de fe con "lahul-mulku wa lahul-hamd...". El Profeta ﷺ dijo que a quien lo hace se le otorga enorme recompensa y protección de Shaytan hasta el atardecer.`, ko: `1) 마치는 살람 후: 세 번 "아스타그피룰라", 이어 "알라훔마 안타살람 와 민카살람 타바라크타 야 잘잘랄리 왈이크람". 2) "라 일라하 일랄라후 와흐다후 라 샤리카 라후…". 3) 타스비흐, 타흐미드, 타크비르 각 33-33-34회(수브하날라, 알함둘릴라, 알라후 아크바르). 4) 각 의무 예배 후 아야툴 쿠르시(2:255), 알이클라스, 알팔라크, 안나스 장 낭송. 5) 각 예배 끝에 자신의 말로 두아  –  예언자 ﷺ께서 "아잔과 이까마 사이의 두아는 거절되지 않는다"고 말씀하셨다. 6) 특히 파즈르와 마그립 후에: 열 번의 신앙 증언과 함께 "라훌물쿠 와 라훌함드…". 예언자 ﷺ께서는 이를 행하는 자에게 거대한 보상과 저녁까지 사탄으로부터의 보호가 있다고 하셨다.`, ta: `1) முடிவுச் ஸலாமுக்குப் பின்: மூன்று முறை "அஸ்தக்ஃபிருல்லாஹ்", பின் "அல்லாஹும்ம அன்தஸ்-ஸலாம் வ மின்கஸ்-ஸலாம் தபாரக்த யா தல்-ஜலாலி வல்-இக்ராம்". 2) "லா இலாஹ இல்லல்லாஹு வஹ்தஹு லா ஷரீக லஹு...". 3) தஸ்பீஹ், தஹ்மீத், தக்பீர் 33-33-34 முறை (ஸுப்ஹானல்லாஹ், அல்ஹம்துலில்லாஹ், அல்லாஹு அக்பர்). 4) ஒவ்வொரு ஃபர்ள் தொழுகைக்குப் பின் ஆயத்துல் குர்ஸி (2:255), சூரத்துல் இக்லாஸ், அல்-ஃபலக் மற்றும் அந்-நாஸ் ஓதுதல். 5) ஒவ்வொரு தொழுகையின் முடிவில் தம் சொற்களில் துஆ  –  நபி ﷺ "அதானுக்கும் இகாமத்துக்கும் இடையே துஆ நிராகரிக்கப்படாது" எனக் கூறினார். 6) குறிப்பாக ஃபஜ்ர் மற்றும் மக்ரிபுக்குப் பின்: பத்து முறை சாட்சியக் கலிமா "லஹுல்-முல்கு வ லஹுல்-ஹம்த்..." உடன். நபி ﷺ இதைச் செய்பவருக்குப் பெரும் கூலியும், மாலை வரை ஷைத்தானிடமிருந்து பாதுகாப்பும் உள்ளது எனக் கூறினார்.`, si: `1) අවසන් සලාම් පසු: තෙවරක් "අස්තග්ෆිරුල්ලාහ්", පසුව "අල්ලාහුම්ම අන්තස්-සලාම් ව මින්කස්-සලාම් තබාරක්ත යා දල්-ජලාලි වල්-ඉක්රාම්". 2) "ලා ඉලාහ ඉල්ලල්ලාහු වහ්දහු ලා ෂරීක ලහු...". 3) තස්බීහ්, තහ්මීද්, තක්බීර් 33-33-34 වරක් (සුබ්හානල්ලාහ්, අල්හම්දුලිල්ලාහ්, අල්ලාහු අක්බර්). 4) සෑම ෆර්ද් සලාතයකට පසු ආයතුල් කුර්සී (2:255), අල්-ඉක්ලාස් සූරාව, අල්-ෆලක් සහ අන්-නාස් කියවීම. 5) සෑම සලාතයක අවසානයේ තමන්ගේ වචනවලින් දුආ  –  නබි ﷺ "අදාන් සහ ඉකාමා අතර දුආ ප්‍රතික්ෂේප නොවේ" යැයි පැවසූහ. 6) විශේෂයෙන් ෆජ්ර් සහ මග්රිබ් පසු: දස වරක් ශහාදතය "ලහුල්-මුල්කු ව ලහුල්-හම්ද්..." සමඟ. නබි ﷺ එය කරන්නාට මහත් කුසල් සහ සවස් වන තෙක් ෂෛතාන්ගෙන් ආරක්ෂාව ලැබෙන බව පැවසූහ.` },
  /* ── Fajr ─────────────────────────────────────────────────── */
  fajr_name: { en: `Fajr  –  The Dawn Prayer`, ms: `Fajar (Subuh)  –  Solat Waktu Subuh`, tur: `Sabah Namazı  –  Fecr`, urd: `فجر  –  صبح کی نماز`, ben: `ফজর  –  ভোরের নামাজ`, fas: `فجر  –  نماز سپیده‌دم`, zh: `晨礼  –  破晓拜功`, yue: `晨禮  –  破曉拜功`, ja: `ファジュル  –  夜明けの礼拝`, ru: `Фаджр  –  предрассветная молитва`, es: `Fajr  –  la oración del alba`, ko: `파즈르  –  새벽 예배`, ta: `ஃபஜ்ர்  –  விடியல் தொழுகை`, si: `ෆජ්ර්  –  උදෑසන සලාතය` },
  fajr_when: { en: `Begins at true dawn (al-fajr al-sadiq), the moment the horizontal white light first spreads across the eastern horizon, and ends at sunrise. Performed before the sun's disc appears. It is the only daily prayer prayed while it is still dark, marking the transition from night to day.`, ms: `Bermula pada fajar sadiq (cahaya putih melintang di ufuk timur) dan berakhir ketika matahari terbit. Dilakukan sebelum cakra matahari muncul. Ini satu-satunya solat fardu yang ditunaikan ketika masih gelap, menandakan peralihan daripada malam kepada siang.`, tur: `Fecr-i sâdıkta (gerçek tan yerinde beyaz aydınlığın doğu ufkunda yatay olarak yayıldığı an) başlar ve güneşin doğuşuna kadar sürer. Güneş diski görünmeden kılınır. Hâlâ karanlıkken kılınan tek farz namazdır; geceden gündüze geçişi simgeler.`, urd: `صبحِ صادق (افق مشرق پر سفید روشنی کا افقی پھیلنا) سے شروع ہو کر طلوعِ آفتاب پر ختم۔ سورج کا قرص ظاہر ہونے سے پہلے ادا کی جاتی ہے۔ یہ واحد فرض نماز ہے جو اندھیرے میں ادا ہوتی ہے، رات سے دن کی منتقلی کی علامت۔`, ben: `সত্য ভোর (আল-ফাজর আস-সাদিক  –  পূর্ব আকাশে আনুভূমিক সাদা আলোর প্রথম বিস্তার) থেকে শুরু হয়ে সূর্যোদয়ে শেষ। সূর্যের চাকতি দেখা যাওয়ার আগেই আদায় করা হয়। এটিই একমাত্র ফরজ নামাজ যা অন্ধকারে আদায় করা হয়, রাত থেকে দিনের পরিবর্তনের প্রতীক।`, fas: `از فجر صادق (نخستین گستردگی روشنایی سفید افقی در افق شرقی) آغاز و تا طلوع خورشید ادامه دارد. پیش از پدیدار شدن قرص خورشید گزارده می‌شود. تنها نماز فرض روزانه است که در تاریکی خوانده می‌شود و نشانه گذار از شب به روز است.`, zh: `自真黎明（破晓白光于东方地平线横向铺开之时）开始，至日出结束。须在日轮出现之前完成。这是唯一在黑暗中完成的主命拜功，标志着夜与昼的交替。`, yue: `由真黎明（破曉白光於東方地平線橫向鋪開之時）開始，至日出結束。須喺日輪出現之前完成。呢個係唯一喺黑暗中完成嘅主命拜功，標誌住夜同晝嘅交替。`, ja: `真の夜明け（ファジュル・サーディク：白い光が東の地平線に横一文字に広がる瞬間）から始まり、日の出で終わる。太陽の円盤が現れる前に行う。まだ暗いうちに行う唯一の毎日のファルド礼拝で、夜から昼への移り変わりを印す。`, ru: `Начинается с истинного рассвета (аль-фаджр ас-садик) — мгновения, когда белый горизонтальный свет впервые расходится по восточному горизонту, и заканчивается восходом солнца. Совершается до появления диска солнца. Это единственная ежедневная молитва, совершаемая в темноте, отмечающая переход от ночи к дню.`, es: `Comienza con el verdadero amanecer (al-fajr al-sadiq), el instante en que la luz blanca horizontal se extiende por primera vez sobre el horizonte oriental, y termina al amanecer. Se realiza antes de que aparezca el disco solar. Es la única oración diaria que se reza aún de noche, marcando la transición de la noche al día.`, ko: `참 새벽(알파즈르 알사디크) — 흰 빛이 동쪽 지평선에 가로로 처음 펼쳐지는 순간 — 에 시작되어 일출에 끝납니다. 태양 원반이 나타나기 전에 행합니다. 어둠 속에서 행하는 유일한 의무 일일 예배로, 밤에서 낮으로의 전환을 표시합니다.`, ta: `உண்மை விடியல் (அல்-ஃபஜ்ர் அஸ்-ஸாதிக் — கீழ்த்திசை வானத்தில் வெள்ளை வெளிச்சம் கிடைமட்டமாக முதலில் பரவும் தருணம்) தொடங்கி சூரிய உதயத்தில் முடிகிறது. சூரிய வட்டு தோன்றுவதற்கு முன் தொழப்படுகிறது. இருளில் தொழப்படும் ஒரே தினசரி கடமைத் தொழுகை இது, இரவிலிருந்து பகலுக்கு மாறுவதைக் குறிக்கிறது.`, si: `සැබෑ අරුණෝදය (අල්-ෆජ්ර් අස්-සාදිඃක්  –  සුදු ආලෝකය නැගෙනහිර ක්ෂිතිජයේ තිරස් ලෙස පළමුවරට පැතිර යන මොහොත) සිට ආරම්භ වී හිරු උදාවේදී අවසන් වේ. හිරුගේ තැටිය පෙනීමට පෙර ඉටු කරයි. තවමත් අඳුර ඇති අතරතුර ඉටු කරන එකම අනිවාර්ය දෛනික සලාතය වන අතර, රාත්‍රියේ සිට දවලට මාරුවීම සලකුණු කරයි.` },
  fajr_structure: { en: `Two rak'ahs of fard. Preceded by two rak'ahs of confirmed Sunnah (Sunnah al-Fajr), which the Prophet ﷺ never abandoned at home or on journey, calling it "better than the world and all it contains." Recitation is aloud (jahri) for both rak'ahs.`, ms: `Dua rakaat fardu. Didahului oleh dua rakaat sunat muakkad (Sunnah al-Fajr), yang Nabi ﷺ tidak pernah meninggalkannya di rumah atau dalam musafir, dan baginda bersabda ia "lebih baik daripada dunia dan segala isinya". Bacaan dengan suara kuat (jahri) untuk kedua-dua rakaat.`, tur: `İki rekât farz. Öncesinde, Peygamber'in ﷺ ne evde ne seferde terk etmediği iki rekât müekked sünnet vardır; bunun için "dünyadan ve içindekilerden daha hayırlıdır" buyurmuştur. Her iki rekâtta da kıraat cehrî (sesli) yapılır.`, urd: `دو رکعت فرض۔ اس سے قبل دو رکعت سنّتِ مؤکدہ (سنّت الفجر) ہیں جنہیں نبی ﷺ نے گھر یا سفر میں کبھی نہیں چھوڑا اور فرمایا یہ "دنیا اور اس میں جو کچھ ہے، اس سے بہتر" ہیں۔ دونوں رکعات میں قراءت جہراً (بلند) ہوتی ہے۔`, ben: `দুই রাকাত ফরজ। এর আগে দুই রাকাত সুন্নাহ মুআক্কাদা (সুন্নাহ আল-ফজর), যা নবী ﷺ ঘরে বা সফরে কখনো ছাড়েননি, বলেছেন তা "দুনিয়া ও তার মধ্যে যা আছে সবকিছুর চেয়ে উত্তম"। উভয় রাকাতেই উচ্চস্বরে (জাহরি) কেরাত।`, fas: `دو رکعت فرض. پیش از آن دو رکعت سنت مؤکد (سنت فجر) که پیامبر ﷺ هرگز در حضر یا سفر آن را ترک نکرد و فرمود "از دنیا و آنچه در آن است بهتر" است. قرائت در هر دو رکعت با صدای بلند (جهری) است.`, zh: `主命两拜。前有两拜确证圣行（晨礼前圣行），先知ﷺ无论在家或旅行皆未曾舍弃，并称其"胜过世界与其中一切"。两拜均高声诵读（贾赫里）。`, yue: `主命兩拜。前有兩拜確證聖行（晨禮前聖行），先知ﷺ無論喺屋企或旅行都未曾捨棄過，並稱其「勝過世界與其中一切」。兩拜均高聲誦讀（賈赫里）。`, ja: `ファルドは二ラクア。その前に二ラクアの確認されたスンナ（スンナ・アル＝ファジュル）があり、預言者ﷺは在宅でも旅でもこれを欠かさず、「世界とその中にあるすべてより善い」と言われた。両ラクアとも声に出して（ジャフリー）朗誦する。`, ru: `Два раката фарда. Им предшествуют два раката подтверждённой сунны (Сунна аль-Фаджр), которые Пророк ﷺ не оставлял ни дома, ни в пути, называя их «лучше мира и всего, что в нём». Чтение вслух (джахрий) в обоих ракатах.`, es: `Dos rak'ahs de fard. Precedida por dos rak'ahs de Sunnah confirmada (Sunnah al-Fajr), que el Profeta ﷺ nunca abandonó ni en casa ni de viaje, llamándola "mejor que el mundo y cuanto contiene". La recitación es en voz alta (jahri) en ambos rak'ahs.`, ko: `파르드 두 라카. 앞서 두 라카의 확인된 순나(순나 알파즈르)가 있으며, 예언자 ﷺ께서는 집에서도 여행 중에도 결코 거르지 않으셨고 이를 "세상과 그 안의 모든 것보다 낫다"고 말씀하셨습니다. 두 라카 모두 소리 내어(자흐리) 낭송합니다.`, ta: `இரண்டு ரக்அத் ஃபர்ள். அதற்கு முன் இரண்டு ரக்அத் சுன்னத்துல் முஅக்கதா (சுன்னத் அல்-ஃபஜ்ர்), நபி ﷺ வீட்டிலும் பயணத்திலும் ஒருபோதும் கைவிடாமல் "உலகத்தையும் அதிலுள்ள அனைத்தையும் விட சிறந்தது" எனக் கூறியது. இரு ரக்அத்களிலும் உரக்க (ஜஹ்ரி) ஓதப்படுகிறது.`, si: `ෆර්ද් රකඅත් දෙකකි. ඊට පෙර තහවුරු කළ සුන්නා රකඅත් දෙකක් (සුන්නා අල්-ෆජ්ර්) ඇත; නබි ﷺ එය නිවසේදී හෝ ගමනකදී කිසිවිටෙක අත් නොහැරිය අතර, එය "ලෝකයටත් එහි ඇති සියල්ලටත් වඩා යහපත්" යැයි පැවසූහ. රකඅත් දෙකේදීම හඬ නඟා (ජහ්රී) කියවයි.` },
  fajr_story: { en: `Like all five prayers, Fajr was ordained on the Night Journey when the Prophet ﷺ ascended through the seven heavens and Allah originally prescribed fifty daily prayers, eventually reduced to five (with the reward of fifty). Specifically about Fajr, Jibril (as) led the Prophet ﷺ in this prayer at the Ka'bah twice on consecutive days to teach its time: once at the very beginning of dawn and once just before sunrise, then said: "The time is between these two."`, ms: `Seperti semua lima solat, Fajar diwajibkan pada malam Isra' dan Mi'raj ketika Nabi ﷺ naik ke tujuh langit dan Allah mulanya mewajibkan lima puluh solat sehari, akhirnya dikurangkan kepada lima (dengan ganjaran lima puluh). Khusus tentang Fajar, Jibril (as) mengimamkan Nabi ﷺ pada solat ini di Kaabah dua kali pada hari berturut-turut untuk mengajar waktunya: sekali pada permulaan fajar dan sekali sebelum matahari terbit, kemudian berkata: "Waktunya antara kedua-dua ini."`, tur: `Beş vakit gibi Sabah namazı da Mi'rac gecesinde, Peygamber ﷺ yedi göğe yükseldiğinde farz kılındı. Allah önce günde elli vakit emretti, sonunda beşe indirildi (ödülü elli). Sabah özelinde, Cibril (as) Peygamber'e ﷺ Kâbe yanında iki gün arka arkaya bu namazı kıldırarak vaktini öğretti: bir kez tan yerinin tam başında, bir kez güneş doğmadan az önce, sonra dedi: "Vakit bu ikisinin arasıdır."`, urd: `پانچوں نمازوں کی طرح فجر بھی شبِ معراج میں واجب ہوئی جب نبی ﷺ ساتوں آسمانوں پر تشریف لے گئے اور اللہ نے ابتدائی طور پر یومیہ پچاس نمازیں فرض کیں، آخرکار پانچ ہو گئیں (پچاس کے اجر کے ساتھ)۔ فجر کے بارے میں خاص بات: جبریل (ع) نے کعبہ کے پاس دو روز پے در پے نبی ﷺ کو یہ نماز پڑھائی تاکہ وقت سکھائیں: ایک بار طلوعِ فجر کے آغاز پر اور ایک بار طلوعِ آفتاب سے کچھ پہلے، پھر فرمایا: "وقت ان دونوں کے درمیان ہے۔"`, ben: `পাঁচ ওয়াক্ত নামাজের মতোই ফজরও মেরাজের রাতে ফরজ হয়, যখন নবী ﷺ সাত আসমানে উন্নীত হন; আল্লাহ প্রথমে দৈনিক পঞ্চাশ নামাজ ফরজ করেছিলেন, যা শেষ পর্যন্ত পাঁচে নামিয়ে আনা হয় (পঞ্চাশের সওয়াবসহ)। বিশেষত ফজর সম্পর্কে: জিবরিল (আ) নবী ﷺ-কে কাবার পাশে পরপর দুই দিনে এই নামাজে ইমামতি করেন সময় শেখাতে: একবার ভোরের একদম শুরুতে, একবার সূর্যোদয়ের ঠিক আগে, তারপর বললেন: "সময় এই দুইয়ের মাঝে।"`, fas: `همانند هر پنج نماز، فجر نیز در شب معراج هنگام صعود پیامبر ﷺ به هفت آسمان واجب شد و خداوند ابتدا پنجاه نماز روزانه را مقرر فرمود که سرانجام به پنج کاهش یافت (با پاداش پنجاه). درباره فجر به‌ویژه: جبرئیل (ع) دو روز پیاپی نزد کعبه پیشوای نماز پیامبر ﷺ شد تا وقت آن را تعلیم دهد: یک بار در آغاز فجر و یک بار اندکی پیش از طلوع، سپس فرمود: "وقت میان این دو است."`, zh: `与五时拜功一样，晨礼亦在登霄之夜被定为主命，时先知ﷺ升上七重天，真主最初降命每日五十次拜功，最终减为五次（仍获五十之回赐）。关于晨礼，吉卜利里（愿主赐他平安）连续两日在天房旁带领先知ﷺ礼此功修以教其时段：一次在破晓之始，一次在日出之前，然后说："时段在此二者之间。"`, yue: `同五時拜功一樣，晨禮亦喺登霄之夜被定為主命，當時先知ﷺ升上七重天，真主最初降命每日五十次拜功，最終減為五次（仍獲五十之回賜）。關於晨禮，吉卜利里（願主賜佢平安）連續兩日喺天房旁帶領先知ﷺ禮呢個功修以教其時段：一次喺破曉之始，一次喺日出之前，然後話：「時段喺此二者之間。」`, ja: `五時の礼拝と同様、ファジュルもミウラージュの夜、預言者ﷺが七天に昇られた折に義務付けられた。アッラーは当初日に五十回の礼拝を命じられ、最終的に五回に減じられた（報奨は五十のまま）。特にファジュルについて、ジブリール（に平安あれ）が連続二日カアバの傍で預言者ﷺのイマームとしてこの礼拝を導き、時刻を教えた。一度は夜明けのまさに初め、一度は日の出直前。そしてこう言った。「時はこの二つの間である」。`, ru: `Как и все пять молитв, Фаджр был предписан в Ночь Вознесения, когда Пророк ﷺ восшёл через семь небес, и Аллах первоначально установил пятьдесят ежедневных молитв, в итоге сведённых к пяти (с наградой пятидесяти). Что касается Фаджра в частности: Джибриль (мир ему) возглавил в этой молитве Пророка ﷺ у Каабы дважды в течение двух дней подряд, чтобы научить времени: один раз в самом начале рассвета и один раз непосредственно перед восходом, затем сказал: "Время — между этими двумя."`, es: `Como las cinco oraciones, el Fajr fue ordenado en la Noche del Viaje, cuando el Profeta ﷺ ascendió por los siete cielos y Allah prescribió en un principio cincuenta oraciones diarias, finalmente reducidas a cinco (con la recompensa de cincuenta). En particular sobre el Fajr, Yibril (as) dirigió al Profeta ﷺ en esta oración junto a la Ka'bah dos veces en días consecutivos para enseñarle su tiempo: una al comienzo mismo del alba y otra justo antes del amanecer, y luego dijo: "El tiempo está entre estos dos."`, ko: `다섯 예배와 마찬가지로 파즈르도 미으라즈의 밤, 예언자 ﷺ께서 일곱 하늘로 오르셨을 때에 의무로 정해졌으며, 알라께서는 처음 하루 쉰 번의 예배를 명하셨다가 결국 다섯 번으로 줄이셨습니다(쉰 번의 보상으로). 특별히 파즈르에 대해서는, 지브릴(평화가 그에게)께서 카바 옆에서 예언자 ﷺ와 함께 이 예배를 이틀 연속 인도하여 그 시간을 가르치셨습니다: 한 번은 새벽이 막 시작될 때, 한 번은 일출 직전. 그러고는 말씀하셨습니다: "시간은 이 둘 사이이다."`, ta: `ஐந்து தொழுகைகளைப் போலவே, ஃபஜ்ரும் இஸ்ரா-மிஃராஜ் இரவில் கடமையாக்கப்பட்டது, அப்போது நபி ﷺ ஏழு வானங்களுக்கு உயர்த்தப்பட்டார்; அல்லாஹ் ஆரம்பத்தில் தினமும் ஐம்பது தொழுகைகளை விதித்தான், இறுதியில் ஐந்தாகக் குறைக்கப்பட்டது (ஐம்பதின் கூலியுடன்). ஃபஜ்ர் குறித்து விசேஷமாக: கஅபாவின் அருகே ஜிப்ரீல் (அலை) நபி ﷺ அவர்களுக்கு இத்தொழுகையை இரு நாட்கள் தொடர்ந்து இமாமாக நிற்று வேளையைக் கற்பித்தார்: ஒருமுறை விடியலின் தொடக்கத்திலும், ஒருமுறை சூரிய உதயத்திற்குச் சற்றுமுன்பும், பின் கூறினார்: "வேளை இவ்விரண்டிற்கும் இடையே."`, si: `පංච සලාත මෙන්ම ෆජ්ර්ද මිඃරාජ් රාත්‍රියේදී අනිවාර්ය කෙරුණි; එවිට නබි ﷺ සත් ස්වර්ග හරහා ඉහළට ගමන් කළ අතර, අල්ලාහ් ආරම්භයේදී දිනකට සලාත පනහක් නියම කළ අතර, අවසානයේ පහකට අඩු කරන ලදී (පනහේ ප්‍රතිඵලය සමඟ). ෆජ්ර් ගැන විශේෂයෙන්: ජිබ්රීල් (ඔහුට සාමය) කඃබාව අසළ පිට පිට දින දෙකක් නබි ﷺ සමඟ මෙම සලාතයේ ඉමාම් වශයෙන් සිට කාලය ඉගැන්වූහ: එක් වරක් අරුණෝදයේ ආරම්භයේදී ද, එක් වරක් හිරු උදාවට මොහොතකට පෙර ද. පසුව පැවසූහ: "කාලය මේ දෙක අතරයි."` },
  fajr_significance: { en: `Fajr is described in the Quran as "witnessed"  –  the angels of the night and the angels of the day both attend it together, with no other prayer sharing this honour. It is the dividing line between the sincere believers and the hypocrites, who find it heaviest. It opens the day with the surrender of one's faculties to Allah before the worldly demands begin, and the Prophet ﷺ said the one who prays it is "in the protection of Allah" until evening.`, ms: `Fajar disifatkan dalam al-Quran sebagai "disaksikan"  –  para malaikat malam dan para malaikat siang menghadirinya bersama-sama, suatu kelebihan yang tidak dimiliki oleh solat lain. Ia adalah garis pemisah antara mukmin sejati dan munafik, yang merasakannya paling berat. Ia membuka hari dengan penyerahan diri kepada Allah sebelum tuntutan dunia bermula, dan Nabi ﷺ bersabda orang yang mendirikannya berada "dalam perlindungan Allah" sehingga petang.`, tur: `Fecr, Kur'an'da "şâhid kılınmış"  –  gece ve gündüz melekleri birlikte ona şahit olur, başka hiçbir namaz bu şerefi paylaşmaz. Samimi mü'minler ile münafıkları ayıran çizgidir; münafıklar onu en ağır bulurlar. Dünyanın talepleri başlamadan, kişinin tüm güçlerini Allah'a teslim ederek günü açar; Peygamber ﷺ "onu kılan, akşama kadar Allah'ın güvencesindedir" buyurmuştur.`, urd: `فجر کو قرآن میں "مشہود" (مشاہدہ کیا گیا) کہا گیا ہے  –  رات کے فرشتے اور دن کے فرشتے دونوں اس میں اکٹھے حاضر ہوتے ہیں، یہ شرف کسی اور نماز کو حاصل نہیں۔ یہ سچے مومنوں اور منافقوں کے درمیان حدِ فاصل ہے، اور منافق اسے سب سے بھاری پاتے ہیں۔ یہ دن کا آغاز اللہ کے سامنے اپنی صلاحیتوں کے سپرد ہونے سے کرتی ہے، اور نبی ﷺ نے فرمایا اسے پڑھنے والا شام تک "اللہ کی پناہ میں" ہے۔`, ben: `ফজরকে কুরআনে "সাক্ষীযুক্ত" বলা হয়েছে  –  রাতের ফেরেশতা ও দিনের ফেরেশতা উভয়েই একসঙ্গে এতে হাজির হন, অন্য কোনো নামাজে এই সম্মান নেই। এটি প্রকৃত মুমিন ও মুনাফিকদের মধ্যে বিভাজনরেখা; মুনাফিকরা এটিকে সবচেয়ে কঠিন মনে করে। দুনিয়ার চাহিদা শুরু হওয়ার আগেই আল্লাহর কাছে নিজেকে সমর্পণ করে দিনের সূচনা ঘটায়, এবং নবী ﷺ বলেছেন যে এটি আদায় করে সে সন্ধ্যা পর্যন্ত "আল্লাহর হেফাজতে" থাকে।`, fas: `فجر در قرآن "مشهود" (دارای شاهدان) خوانده شده  –  فرشتگان شب و فرشتگان روز هر دو با هم در آن حاضر می‌شوند، شرفی که هیچ نماز دیگری ندارد. مرز جداکننده مؤمنان راستین از منافقان است؛ منافقان آن را گران‌ترین می‌یابند. روز را با تسلیم همه قوای انسان به خداوند، پیش از آغاز خواست‌های دنیوی، می‌گشاید و پیامبر ﷺ فرمود گزارنده آن تا شب "در پناه خداست".`, zh: `《古兰经》称晨礼为「被见证」  –  夜间天使与白昼天使一同出席，无任何其他拜功享此殊荣。它是真信士与伪信者之间的分水岭，伪信者觉其最为沉重。它在世俗事务展开之前，以将一切官能交托真主而开启一日；先知ﷺ言行此者直至日暮"皆在真主的护佑中"。`, yue: `《古蘭經》稱晨禮為「被見證」  –  夜間天使與白晝天使一同出席，無任何其他拜功享此殊榮。佢係真信士與偽信者之間嘅分水嶺，偽信者覺其最為沉重。佢喺世俗事務展開之前，以將一切官能交託真主而開啟一日；先知ﷺ言行此者直至日暮「皆喺真主嘅護佑中」。`, ja: `ファジュルはクルアーンで「立ち会われた礼拝」と称される  –  夜の天使たちと昼の天使たちが共に出席し、他のいかなる礼拝もこの栄誉を共有しない。真の信者と偽善者を分かつ境界線であり、偽善者にとっては最も重い。世俗の要求が始まる前にあらゆる力をアッラーに委ねて一日を開く礼拝で、預言者ﷺは「これを礼拝する者は夕方までアッラーの庇護にある」と言われた。`, ru: `Фаджр в Коране назван «засвидетельствованной»  –  ангелы ночи и ангелы дня присутствуют на ней вместе, и ни одна другая молитва не разделяет этой чести. Она  –  рубеж между искренними верующими и лицемерами, которым она тяжелее всего. Она открывает день предании всех способностей Аллаху прежде, чем начнутся мирские требования, и Пророк ﷺ сказал, что совершивший её «находится под защитой Аллаха» до вечера.`, es: `El Fajr es descrito en el Corán como "atestiguado"  –  los ángeles de la noche y los ángeles del día asisten juntos, un honor del que no goza ninguna otra oración. Es la línea divisoria entre los creyentes sinceros y los hipócritas, que la encuentran la más pesada. Abre el día con la entrega de las facultades a Allah antes de que comiencen las exigencias mundanas, y el Profeta ﷺ dijo que quien la reza está "bajo la protección de Allah" hasta el anochecer.`, ko: `파즈르는 꾸란에서 "증언된" 예배로 묘사됩니다  –  밤의 천사들과 낮의 천사들이 함께 참석하며, 다른 어떤 예배도 이 영예를 공유하지 않습니다. 진실한 신자와 위선자를 가르는 경계선이며, 위선자에게는 가장 무겁게 느껴집니다. 세속의 요구가 시작되기 전에 모든 능력을 알라께 맡기며 하루를 여는 예배이고, 예언자 ﷺ께서는 이를 예배하는 자가 저녁까지 "알라의 보호 안에" 있다고 말씀하셨습니다.`, ta: `ஃபஜ்ர் குர்ஆனில் "சாட்சியளிக்கப்பட்டது" என வர்ணிக்கப்படுகிறது  –  இரவின் வானவர்களும் பகலின் வானவர்களும் ஒன்றாகக் கலந்துகொள்கின்றனர், இக்கௌரவத்தை வேறு எந்தத் தொழுகையும் பெறவில்லை. உண்மை விசுவாசிகளுக்கும் நயவஞ்சகர்களுக்கும் இடையேயான பிரிவுக் கோடு; நயவஞ்சகர்கள் இதையே மிகவும் சுமையாகக் காண்கிறார்கள். உலகியல் கோரிக்கைகள் தொடங்கும் முன், ஒருவரின் அனைத்துத் திறன்களையும் அல்லாஹ்விடம் ஒப்படைத்து நாளைத் திறக்கிறது; நபி ﷺ இதைத் தொழுபவர் மாலை வரை "அல்லாஹ்வின் பாதுகாப்பில்" இருப்பார் எனக் கூறினார்.`, si: `ෆජ්ර් කුර්ආනයේ "සාක්ෂි දරන ලද" ලෙස හඳුන්වයි  –  රාත්‍රියේ මලාඉකාවරුද දවසේ මලාඉකාවරුද එහි එක්ව සහභාගි වෙති; මෙම ගෞරවය වෙනත් කිසිදු සලාතයකට හිමි නැත. සැබෑ විශ්වාසවන්තයන් හා කපටියන් අතර බෙදීමේ රේඛාව වන අතර, කපටියන්ට එය බරම ලෙස දැනේ. ලෞකික ඉල්ලීම් ආරම්භ වීමට පෙර තමන්ගේ සියලු හැකියාවන් අල්ලාහ්ට පවරා දින ආරම්භ කරයි; නබි ﷺ එය ඉටු කරන්නා සවස වන තෙක් "අල්ලාහ්ගේ ආරක්ෂාවේ" සිටින බව පැවසූහ.` },
  fajr_proof_q: { en: `"Establish prayer at the decline of the sun [from its meridian] until the darkness of the night, and the recitation of dawn (qur'an al-fajr). Indeed, the recitation of dawn is ever witnessed." (Al-Isra' 17:78). The phrase "qur'an al-fajr" specifically denotes the Fajr prayer's lengthy recitation, and "ever witnessed" refers to the night and day angels both being present.`, ms: `"Dirikanlah solat sejak gelincirnya matahari [dari titik tegaknya] hingga kegelapan malam, dan bacaan fajar (qur'an al-fajr). Sesungguhnya bacaan fajar itu sentiasa disaksikan." (Al-Isra' 17:78). Ungkapan "qur'an al-fajr" khusus merujuk kepada bacaan panjang Subuh, dan "sentiasa disaksikan" merujuk kepada kehadiran bersama malaikat malam dan siang.`, tur: `"Güneşin batıya doğru kaymasından gecenin karanlığına dek namazı dosdoğru kıl ve sabah Kur'an'ını (kur'an al-fecr). Şüphesiz sabah Kur'an'ı şahit olunan bir okumadır." (İsrâ 17:78). "Kur'an al-fecr" tabiri özellikle Sabah namazının uzun kıraatini, "şahit olunan" ise gece ve gündüz meleklerinin birlikte hazır bulunmasını ifade eder.`, urd: `"نماز قائم کرو سورج کے ڈھلنے سے رات کے اندھیرے تک، اور فجر کی قراءت (قرآن الفجر)۔ بے شک فجر کی قراءت پر گواہی دی جاتی ہے۔" (الاسراء ۱۷:۷۸)۔ "قرآن الفجر" کی تعبیر خاص طور پر نمازِ فجر کی طویل قراءت کو ظاہر کرتی ہے، اور "گواہی دی جاتی ہے" سے مراد رات و دن کے فرشتوں کا اکٹھے حاضر ہونا ہے۔`, ben: `"সূর্য ঢলে পড়া থেকে রাতের অন্ধকার পর্যন্ত নামাজ কায়েম করো, এবং ফজরের কেরাত (কুরআনুল ফজর)। নিশ্চয়ই ফজরের কেরাত সাক্ষীযুক্ত।" (আল-ইসরা ১৭:৭৮)। "কুরআনুল ফজর" বিশেষভাবে ফজর নামাজের দীর্ঘ কেরাত নির্দেশ করে, এবং "সাক্ষীযুক্ত" রাত ও দিনের ফেরেশতাদের একসঙ্গে উপস্থিতিকে নির্দেশ করে।`, fas: `"نماز را از زوال خورشید تا تاریکی شب برپا دار، و قرآن فجر (قرائت سپیده‌دم) را. به‌راستی قرائت فجر مشهود است." (الإسراء ۱۷:۷۸). تعبیر "قرآن الفجر" به‌ویژه به قرائت طولانی نماز فجر اشاره دارد و "مشهود" به حضور همزمان فرشتگان شب و روز.`, zh: `「自日西斜直到夜暗，你当谨守拜功，并谨守晨礼之诵读（古尔安·法吉尔）。晨礼之诵读必被见证。」（夜行章17:78）「古尔安·法吉尔」一词专指晨礼的长段诵读，「必被见证」即指夜间与白昼天使一同出席。`, yue: `「自日西斜直到夜暗，你當謹守拜功，並謹守晨禮之誦讀（古爾安·法吉爾）。晨禮之誦讀必被見證。」（夜行章17:78）「古爾安·法吉爾」一詞專指晨禮嘅長段誦讀，「必被見證」即指夜間與白晝天使一同出席。`, ja: `「太陽が傾く時から夜の暗闇に至るまで礼拝を確立せよ。そして夜明けの朗誦（クルアーン・アル＝ファジュル）を。まことに、夜明けの朗誦は常に立ち会われている。」（夜の旅章 17:78）「クルアーン・アル＝ファジュル」の語は特にファジュル礼拝の長い朗誦を指し、「常に立ち会われる」とは夜と昼の天使がともに居合わせることを意味する。`, ru: `«Совершай молитву от склонения солнца [с зенита] до наступления ночной тьмы, и чтение на рассвете (кур'ан аль-фаджр). Поистине, чтение на рассвете всегда засвидетельствовано.» (Аль-Исра 17:78). Выражение «кур'ан аль-фаджр» относится именно к продолжительному чтению Фаджра, а «всегда засвидетельствовано»  –  к одновременному присутствию ангелов ночи и дня.`, es: `"Establece la oración desde la declinación del sol [desde su meridiano] hasta la oscuridad de la noche, y la recitación del alba (qur'an al-fajr). En verdad, la recitación del alba siempre es atestiguada." (Al-Isra' 17:78). La expresión "qur'an al-fajr" se refiere específicamente a la recitación extensa del Fajr, y "siempre atestiguada" alude a la presencia conjunta de los ángeles de la noche y del día.`, ko: `"태양이 [정점에서] 기울 때부터 밤의 어둠까지 예배를 세우고, 새벽의 낭송(꾸르안 알파즈르)을 [세우라]. 진실로 새벽의 낭송은 항상 증언되니라." (알이스라 17:78) "꾸르안 알파즈르"라는 구는 특별히 파즈르 예배의 긴 낭송을 가리키며, "항상 증언된다"는 것은 밤과 낮의 천사들이 함께 임함을 뜻한다.`, ta: `"சூரியன் [உச்சியிலிருந்து] சாயத் தொடங்கியதிலிருந்து இரவின் இருள் வரை தொழுகையை நிலைநிறுத்துவீராக, மற்றும் விடியலின் ஓதலை (குர்ஆனுல் ஃபஜ்ர்). நிச்சயமாக விடியலின் ஓதல் சாட்சியளிக்கப்படுவதாகும்." (அல்-இஸ்ரா 17:78). "குர்ஆனுல் ஃபஜ்ர்" என்னும் சொற்றொடர் ஃபஜ்ர் தொழுகையின் நீண்ட ஓதலையே குறிக்கிறது, மேலும் "சாட்சியளிக்கப்படுவது" என்பது இரவு பகல் வானவர்களின் ஒன்றுசேர் கலந்துகொள்ளலைக் குறிக்கிறது.`, si: `"සූර්යයාගේ බැසීමේ සිට රාත්‍රියේ අන්ධකාරය දක්වා සලාතය ස්ථාපිත කරන්න, සහ අරුණෝදයේ පාරායනය (කුර්ආන් අල්-ෆජ්ර්). සැබැවින්ම අරුණෝදයේ පාරායනය සැමවිටම සාක්ෂි දරනු ලැබේ." (අල්-ඉස්රා 17:78). "කුර්ආන් අල්-ෆජ්ර්" යන වදන විශේෂයෙන් ෆජ්ර් සලාතයේ දිගු පාරායනය හඟවන අතර, "සැමවිටම සාක්ෂි දරනු ලැබේ" යනු රාත්‍රී හා දිවා මලාඉකාවරුන් එක්ව සහභාගි වීම යි.` },
  fajr_proof_h: { en: `The Prophet ﷺ said: "Whoever prays the Fajr prayer is in the protection of Allah." (Muslim 657). He also said: "The two cool prayers  –  whoever prays them will enter Paradise." (Bukhari 574, Muslim 635). When asked about the "two cool prayers," the Companions explained: Fajr and Asr. Abu Hurayrah (ra) reported that the angels of the night and the angels of the day gather at Fajr, ascend together, and the angels of the day stay; this is the witnessing referred to in the verse.`, ms: `Nabi ﷺ bersabda: "Sesiapa yang mendirikan solat Subuh, dia berada dalam perlindungan Allah." (Muslim 657). Baginda juga bersabda: "Dua solat sejuk  –  sesiapa yang mendirikannya akan masuk syurga." (Bukhari 574, Muslim 635). Apabila ditanya tentang "dua solat sejuk", para sahabat menjelaskan: Subuh dan Asar. Abu Hurayrah (ra) meriwayatkan bahawa malaikat malam dan malaikat siang berhimpun pada waktu Subuh, naik bersama, dan malaikat siang tinggal; inilah penyaksian yang dimaksudkan dalam ayat.`, tur: `Peygamber ﷺ buyurdu: "Sabah namazını kılan kişi Allah'ın güvencesindedir." (Müslim 657). Yine: "İki serinlik namazını  –  kim onları kılarsa cennete girer." (Buhârî 574, Müslim 635). "İki serinlik namazı" sorulduğunda sahabe Sabah ve İkindi olduğunu açıkladı. Ebû Hureyre (ra) rivayet etti ki gece ve gündüz melekleri Sabah'ta toplanır, birlikte yükselirler ve gündüz melekleri kalır; âyetteki şahitlik budur.`, urd: `نبی ﷺ نے فرمایا: "جو فجر کی نماز پڑھتا ہے، وہ اللہ کی پناہ میں ہے۔" (مسلم ۶۵۷)۔ نیز: "دو ٹھنڈی نمازیں  –  جو انہیں پڑھے، جنت میں داخل ہو گا۔" (بخاری ۵۷۴، مسلم ۶۳۵)۔ "دو ٹھنڈی نمازوں" کے بارے میں پوچھے جانے پر صحابہ نے بیان فرمایا: فجر اور عصر۔ ابو ہریرہ (رض) نے روایت کیا کہ رات اور دن کے فرشتے فجر کے وقت اکٹھے ہوتے ہیں، اوپر چڑھتے ہیں، اور دن کے فرشتے باقی رہتے ہیں؛ یہی وہ گواہی ہے جس کا ذکر آیت میں ہے۔`, ben: `নবী ﷺ বলেছেন: "যে ফজরের নামাজ পড়ে, সে আল্লাহর হেফাজতে।" (মুসলিম ৬৫৭)। আরও বলেছেন: "দুই শীতল নামাজ  –  যে এগুলো পড়বে সে জান্নাতে প্রবেশ করবে।" (বুখারি ৫৭৪, মুসলিম ৬৩৫)। "দুই শীতল নামাজ" সম্পর্কে জিজ্ঞাসিত হলে সাহাবিগণ ব্যাখ্যা করেন: ফজর ও আসর। আবু হুরায়রা (রা) বর্ণনা করেন রাতের ও দিনের ফেরেশতা ফজরে একত্রিত হন, একসঙ্গে ঊর্ধ্বগামী হন, এবং দিনের ফেরেশতারা থেকে যান; এটিই আয়াতে উল্লেখিত সাক্ষ্য।`, fas: `پیامبر ﷺ فرمود: "هرکس نماز فجر را بگزارد، در پناه خداست." (مسلم ۶۵۷). همچنین فرمود: "دو نماز خنک  –  هرکس آن دو را بگزارد، به بهشت وارد می‌شود." (بخاری ۵۷۴، مسلم ۶۳۵). چون از "دو نماز خنک" پرسیدند، صحابه گفتند: فجر و عصر. ابوهریره (رض) روایت کرد که فرشتگان شب و فرشتگان روز هنگام فجر گرد می‌آیند، با هم بالا می‌روند و فرشتگان روز می‌مانند؛ این همان شهودی است که در آیه آمده.`, zh: `先知ﷺ言："凡礼晨礼者，皆在真主的护佑中。"（穆斯林657）又言："两次凉时拜  –  凡礼此二者必入乐园。"（布哈里574，穆斯林635）问及"两次凉时拜"时，圣门弟子解释为：晨礼与晡礼。艾布·胡赖赖（愿主喜悦之）传述：夜间天使与白昼天使在晨礼时聚集，同升而去，白昼天使留下；此即经文所言之"被见证"。`, yue: `先知ﷺ言：「凡禮晨禮者，皆喺真主嘅護佑中。」（穆斯林657）又言：「兩次涼時拜  –  凡禮此二者必入樂園。」（布哈里574，穆斯林635）問及「兩次涼時拜」時，聖門弟子解釋為：晨禮與晡禮。艾布·胡賴賴（願主喜悅之）傳述：夜間天使與白晝天使喺晨禮時聚集，同升而去，白晝天使留低；此即經文所言之「被見證」。`, ja: `預言者ﷺは言われた。「ファジュル礼拝を行う者はアッラーの庇護にある。」（ムスリム657）。また仰せられた。「二つの涼しい礼拝  –  これを礼拝する者は楽園に入る。」（ブハーリー574、ムスリム635）。「二つの涼しい礼拝」とは何かを問われ、教友たちはファジュルとアスルだと答えた。アブー・フライラ（ラ）は伝える：夜の天使と昼の天使はファジュル時に集まり、共に昇って行き、昼の天使が留まる。これが節で言われる「立ち会い」である。`, ru: `Пророк ﷺ сказал: «Тот, кто совершит молитву Фаджр, под защитой Аллаха.» (Муслим 657). Он также сказал: «Две прохладные молитвы  –  кто совершит их, войдёт в Рай.» (Бухари 574, Муслим 635). Когда сподвижников спросили о «двух прохладных молитвах», они пояснили: Фаджр и Аср. Абу Хурайра (ра) передал, что ангелы ночи и ангелы дня собираются на Фаджре, поднимаются вместе, а ангелы дня остаются; это и есть засвидетельствование, упомянутое в аяте.`, es: `El Profeta ﷺ dijo: "Quien reza la oración del Fajr está bajo la protección de Allah." (Muslim 657). También dijo: "Las dos oraciones frescas  –  quien las reza entrará al Paraíso." (Bujari 574, Muslim 635). Al preguntar por las "dos oraciones frescas," los Compañeros explicaron: Fajr y Asr. Abu Hurayrah (ra) relató que los ángeles de la noche y los ángeles del día se reúnen en el Fajr, ascienden juntos, y los ángeles del día permanecen; este es el atestiguamiento al que se refiere el versículo.`, ko: `예언자 ﷺ께서 말씀하셨다: "파즈르 예배를 행하는 자는 알라의 보호 안에 있다." (무슬림 657). 또한 말씀하셨다: "두 시원한 예배  –  이를 행하는 자는 천국에 들어갈 것이다." (부카리 574, 무슬림 635). 동료들이 "두 시원한 예배"가 무엇인지 묻자 그들은 답하였다: 파즈르와 아스르. 아부 후라이라(라)께서는 전한다: 밤의 천사와 낮의 천사가 파즈르 시에 모이고 함께 올라가며, 낮의 천사가 남는다; 이것이 구절에서 언급된 증언이다.`, ta: `நபி ﷺ கூறினார்: "ஃபஜ்ர் தொழுகையைத் தொழுபவர் அல்லாஹ்வின் பாதுகாப்பில் இருக்கிறார்." (முஸ்லிம் 657). மேலும்: "இரு குளிர்ந்த தொழுகைகள்  –  இவ்விரண்டையும் தொழுபவர் சொர்க்கம் நுழைவார்." (புகாரி 574, முஸ்லிம் 635). "இரு குளிர்ந்த தொழுகைகள்" எவை எனக் கேட்கப்பட்டபோது தோழர்கள் விளக்கினார்கள்: ஃபஜ்ர் மற்றும் அஸ்ர். அபூ ஹுரைரா (ரழி) அறிவித்தார்: இரவின் வானவர்களும் பகலின் வானவர்களும் ஃபஜ்ரின்போது கூடி, ஒன்றாக மேலேறிச் செல்கின்றனர், பகலின் வானவர்கள் தங்குகின்றனர்; இதுவே வசனத்தில் குறிப்பிடப்படும் சாட்சி.`, si: `නබි ﷺ පැවසූහ: "ෆජ්ර් සලාතය ඉටු කරන්නා අල්ලාහ්ගේ ආරක්ෂාවේ සිටී." (මුස්ලිම් 657). තවද පැවසූහ: "සිසිල් සලාත දෙක  –  ඒවා ඉටු කරන්නා ස්වර්ගයට පිවිසෙයි." (බුහාරි 574, මුස්ලිම් 635). "සිසිල් සලාත දෙක" කවරේදැයි විමසූ විට සහචරයන් පැහැදිලි කළහ: ෆජ්ර් සහ අස්ර්. අබූ හුරෛරා (රළි) වාර්තා කළේ රාත්‍රියේ මලාඉකාවරුද දවසේ මලාඉකාවරුද ෆජ්ර්හි එක්රැස් වී, එක්ව ඉහළට යන අතර, දවසේ මලාඉකාවරු රැඳී සිටින බවය; මෙය වැකියේ සඳහන් සාක්ෂි දැරීමයි.` },
  fajr_recitation: { en: `Recited aloud (jahri). The Sunnah is to lengthen the recitation here more than any other prayer  –  often 60 to 100 verses in total. The Prophet ﷺ frequently recited Surah Qaf (50), al-Waqi'ah (56), al-Mursalat (77), at-Takwir (81), or similar surahs of the latter half of the Quran. On Friday Fajr specifically, the Sunnah is to recite Surah as-Sajdah (32) in the first rak'ah and Surah al-Insan (76) in the second  –  the only two surahs reported to contain Sunnah sujud al-tilawah in this prayer.`, ms: `Dibaca dengan suara kuat (jahri). Sunnah memanjangkan bacaan di sini lebih daripada solat lain  –  selalunya 60 hingga 100 ayat secara keseluruhan. Nabi ﷺ kerap membaca Surah Qaf (50), al-Waqi'ah (56), al-Mursalat (77), at-Takwir (81), atau surah-surah seumpamanya dari separuh akhir al-Quran. Pada Subuh hari Jumaat khususnya, sunnah membaca Surah as-Sajdah (32) pada rakaat pertama dan Surah al-Insan (76) pada rakaat kedua  –  dua-duanya mengandungi sujud tilawah yang disyariatkan dalam solat ini.`, tur: `Cehrî (sesli) okunur. Sünnet, burada kıraati diğer namazlardan daha uzun tutmaktır  –  genellikle toplam 60-100 âyet. Peygamber ﷺ sıkça Kaf (50), Vâkıa (56), Mürselât (77), Tekvîr (81) gibi Kur'an'ın ikinci yarısının surelerini okurdu. Özellikle Cuma sabahında, ilk rekâtta Secde (32) ve ikinci rekâtta İnsân (76) okumak sünnettir  –  bu namazda tilavet secdesi rivayet edilen iki sureden ibarettir.`, urd: `جہراً (بلند آواز) سے۔ سنّت یہ ہے کہ یہاں قراءت دیگر نمازوں سے زیادہ طویل ہو  –  اکثر مجموعی طور پر ۶۰ سے ۱۰۰ آیات۔ نبی ﷺ اکثر سورۃ ق (۵۰)، الواقعہ (۵۶)، المرسلات (۷۷)، التکویر (۸۱)، یا قرآن کے دوسرے نصف کی ایسی ہی سورتیں پڑھتے۔ خاص جمعہ کی فجر میں سنّت ہے کہ پہلی رکعت میں سورۃ السجدہ (۳۲) اور دوسری میں سورۃ الإنسان (۷۶) پڑھی جائے  –  اس نماز میں سجدہ تلاوت کے ساتھ مرفوع روایات صرف انہی دو سورتوں میں ہیں۔`, ben: `উচ্চস্বরে (জাহরি)। সুন্নাহ এখানে অন্যান্য নামাজের তুলনায় কেরাত দীর্ঘতর করা  –  সাধারণত মোট ৬০ থেকে ১০০ আয়াত। নবী ﷺ প্রায়ই সূরা কাফ (৫০), আল-ওয়াকিয়াহ (৫৬), আল-মুরসালাত (৭৭), আত-তাকউইর (৮১), বা কুরআনের শেষ অর্ধাংশের অনুরূপ সূরা পড়তেন। বিশেষত শুক্রবারের ফজরে সুন্নাহ হলো প্রথম রাকাতে সূরা আস-সাজদাহ (৩২) এবং দ্বিতীয়টিতে সূরা আল-ইনসান (৭৬) পড়া  –  এই নামাজে সিজদা তিলাওয়াত সম্বলিত যে দুটি সূরা সুন্নাহ হিসাবে বর্ণিত।`, fas: `با صدای بلند (جهری). سنت آن است که قرائت در اینجا از سایر نمازها طولانی‌تر باشد  –  معمولاً در مجموع ۶۰ تا ۱۰۰ آیه. پیامبر ﷺ اغلب سوره ق (۵۰)، واقعه (۵۶)، مرسلات (۷۷)، تکویر (۸۱) یا سوره‌های مشابه از نیمه دوم قرآن را تلاوت می‌کرد. به‌ویژه در فجر روز جمعه، سنت است در رکعت اول سوره سجده (۳۲) و در رکعت دوم سوره انسان (۷۶) خوانده شود  –  تنها دو سوره‌ای که در این نماز سجده تلاوت سنت برای آنها روایت شده.`, zh: `高声诵读（贾赫里）。圣行是于此处诵读较其他拜功更长  –  通常合计60至100节。先知ﷺ常诵读《戛弗》（50）、《大事》（56）、《奉使者》（77）、《卷起》（81）或《古兰经》后半部之类经章。特别于主麻日晨礼，圣行为首拜诵《叩头章》（32）、次拜诵《人章》（76）  –  此乃此功修中带"诵读叩头"之圣行而见诸传报的两章。`, yue: `高聲誦讀（賈赫里）。聖行係於此處誦讀較其他拜功更長  –  通常合計60至100節。先知ﷺ常誦讀《戛弗》（50）、《大事》（56）、《奉使者》（77）、《捲起》（81）或《古蘭經》後半部之類經章。特別於主麻日晨禮，聖行為首拜誦《叩頭章》（32）、次拜誦《人章》（76）  –  此乃此功修中帶「誦讀叩頭」之聖行而見諸傳報嘅兩章。`, ja: `声に出して（ジャフリー）朗誦する。スンナはここで他のどの礼拝よりも長く朗誦すること  –  通常合計60～100節。預言者ﷺは頻繁にカーフ章（50）、ワーキア章（56）、ムルサラート章（77）、タクウィール章（81）など、クルアーン後半の章を朗誦された。特に金曜日のファジュルでは、第一ラクアでサジダ章（32）、第二ラクアでインサーン章（76）を朗誦するのがスンナ  –  この礼拝で朗誦の平伏（スジュード・アッ＝ティラーワ）がスンナとして伝えられる二章のみである。`, ru: `Читается вслух (джахрий). Сунна  –  здесь удлинять чтение больше, чем в любой другой молитве  –  часто всего 60–100 аятов. Пророк ﷺ часто читал суру Каф (50), аль-Вакиа (56), аль-Мурсалят (77), ат-Таквир (81) или подобные суры второй половины Корана. Конкретно в пятничный Фаджр сунной является чтение суры ас-Саджда (32) в первом ракате и суры аль-Инсан (76) во втором  –  это две суры, для которых в этой молитве передан сунновский саджда тилявы.`, es: `Se recita en voz alta (jahri). La Sunnah es alargar aquí la recitación más que en cualquier otra oración  –  a menudo de 60 a 100 versículos en total. El Profeta ﷺ recitaba con frecuencia la Sura Qaf (50), al-Waqi'ah (56), al-Mursalat (77), at-Takwir (81), o suras similares de la segunda mitad del Corán. Específicamente en el Fajr del viernes, la Sunnah es recitar la Sura as-Sajdah (32) en el primer rak'ah y la Sura al-Insan (76) en el segundo  –  las únicas dos suras de las que se reporta que en esta oración contengan la sujud al-tilawah sunnah.`, ko: `소리 내어(자흐리) 낭송. 순나는 여기서 다른 어떤 예배보다도 낭송을 길게 하는 것  –  보통 전체 60~100 구절. 예언자 ﷺ께서는 자주 카프 장(50), 알와끼아(56), 알무르살라트(77), 앗타크위르(81) 등 꾸란 후반부 장들을 낭송하셨습니다. 특별히 금요일 파즈르에는 첫 라카에서 앗사즈다 장(32), 둘째에서 알인산 장(76)을 낭송하는 것이 순나  –  이 예배에서 낭송 엎드림(수주드 알틸라와)이 순나로 보고된 두 장입니다.`, ta: `உரக்க (ஜஹ்ரி) ஓதப்படுகிறது. சுன்னா இங்கே மற்ற எந்தத் தொழுகையை விடவும் ஓதலை நீட்டுவது  –  பெரும்பாலும் மொத்தம் 60 முதல் 100 வசனங்கள் வரை. நபி ﷺ அடிக்கடி சூரத்து காஃப் (50), அல்-வாகிஆ (56), அல்-முர்ஸலாத் (77), அத்-தக்வீர் (81), அல்லது குர்ஆனின் பிற்பகுதியின் இதுபோன்ற சூராக்களை ஓதினார். குறிப்பாக வெள்ளிக்கிழமை ஃபஜ்ரில், முதல் ரக்அத்தில் சூரத்துஸ்-ஸஜ்தா (32) மற்றும் இரண்டாவதில் சூரத்துல்-இன்ஸான் (76) ஓதுவது சுன்னா  –  இத்தொழுகையில் ஓதல் சுஜூத் (சுஜூத் அத்-திலாவா) சுன்னாவாக அறிவிக்கப்பட்ட இரு சூராக்கள் இவையே.`, si: `හඬ නඟා (ජහ්රී) කියවයි. සුන්නාව වන්නේ වෙනත් කවර සලාතයකටත් වඩා මෙහි කියවීම දිගු කිරීමයි  –  සාමාන්‍යයෙන් මුළු වැකි 60 සිට 100 දක්වා. නබි ﷺ බොහෝ විට කාෆ් (50), අල්-වාකිඃඃඃ (56), අල්-මුර්සලාත් (77), අත්-තක්වීර් (81), හෝ කුර්ආනයේ දෙවන භාගයේ එවැනි සූරාවන් කියවූහ. විශේෂයෙන් සිකුරාදා ෆජ්ර්හිදී, පළමු රකඅතේ අස්-සජ්දා (32) සහ දෙවැන්නේ අල්-ඉන්සාන් (76) කියවීම සුන්නාව  –  මෙම සලාතයේ පාරායන සජ්දාව (සජ්දත් අත්-තිලාවා) සුන්නාවක් ලෙස වාර්තා වූ එකම සූරා දෙකකි.` },
  fajr_sunnah_say: { en: `In the two Sunnah rak'ahs of Fajr, the Prophet ﷺ recited very short surahs: in the first rak'ah Surah al-Kafirun (109) or "Qulu amanna billahi..." (2:136), and in the second Surah al-Ikhlas (112) or "Qul ya ahla al-kitab..." (3:64). Make the two Sunnah rak'ahs short and the two fard long. Between the two Sunnah and the fard, supplicate quietly; the dawn is one of the times du'a is most accepted. Before the prayer, on rising from sleep, say "Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur".`, ms: `Dalam dua rakaat sunat Subuh, Nabi ﷺ membaca surah-surah sangat pendek: rakaat pertama Surah al-Kafirun (109) atau "Qulu amanna billahi..." (2:136), rakaat kedua Surah al-Ikhlas (112) atau "Qul ya ahla al-kitab..." (3:64). Pendekkan dua rakaat sunat, panjangkan dua rakaat fardu. Antara sunat dan fardu, berdoalah secara senyap; fajar adalah antara waktu doa paling makbul. Sebelum solat, ketika bangun tidur, ucap "Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur".`, tur: `Sabahın iki sünnetinde Peygamber ﷺ çok kısa sureler okurdu: ilk rekâtta Kâfirûn (109) veya "Kûlû âmennâ billâhi..." (2:136), ikinci rekâtta İhlâs (112) veya "Kul yâ ehlel-kitâb..." (3:64). İki sünneti kısa, iki farzı uzun tut. Sünnetle farz arasında sessizce dua et; fecir, duanın en makbul vakitlerindendir. Namazdan önce, uykudan kalkınca "Elhamdü lillâhillezî ahyânâ ba'de mâ emâtenâ ve ileyhin-nüşûr" de.`, urd: `فجر کی دو سنّتوں میں نبی ﷺ بہت چھوٹی سورتیں پڑھتے: پہلی رکعت میں سورۃ الکافرون (۱۰۹) یا "قولوا آمنا باللہ..." (۲:۱۳۶)، دوسری میں سورۃ الإخلاص (۱۱۲) یا "قل یا أہل الکتاب..." (۳:۶۴)۔ دو سنّتیں مختصر رکھیں اور دو فرض طویل۔ سنّت اور فرض کے درمیان آہستہ سے دعا کریں؛ فجر دعا کی قبولیت کے بہترین اوقات میں سے ہے۔ نماز سے پہلے، نیند سے اٹھتے ہوئے کہیں: "الحمد للہ الذي أحیانا بعد ما أماتنا و إلیہ النشور"۔`, ben: `ফজরের দুই সুন্নাহ রাকাতে নবী ﷺ অত্যন্ত ছোট সূরা পড়তেন: প্রথম রাকাতে সূরা আল-কাফিরূন (১০৯) বা "কূলূ আমান্না বিল্লাহি..." (২:১৩৬), দ্বিতীয়টিতে সূরা আল-ইখলাস (১১২) বা "কুল ইয়া আহলাল কিতাব..." (৩:৬৪)। দুই সুন্নাহ সংক্ষিপ্ত, দুই ফরজ দীর্ঘ। সুন্নাহ ও ফরজের মাঝে নীরবে দোয়া করুন; ফজর হলো দোয়া কবুলের সর্বাধিক উত্তম সময়সমূহের একটি। নামাজের আগে, ঘুম থেকে উঠে বলুন: "আলহামদু লিল্লাহিল্লাযী আহইয়ানা বা'দা মা আমাতানা ওয়া ইলাইহিন-নুশূর"।`, fas: `در دو رکعت سنت فجر، پیامبر ﷺ سوره‌های بسیار کوتاه می‌خواند: در رکعت اول سوره کافرون (۱۰۹) یا "قولوا آمنا بالله..." (۲:۱۳۶) و در رکعت دوم سوره اخلاص (۱۱۲) یا "قل یا أهل الکتاب..." (۳:۶۴). دو سنت را کوتاه و دو فرض را بلند بگذار. میان سنت و فرض آرام دعا کن؛ فجر از زمان‌های پراجابت‌ترین دعاست. پیش از نماز، هنگام بیداری از خواب بگو: "الحمد لله الذي أحیانا بعد ما أماتنا و إلیه النشور".`, zh: `在晨礼前的两拜圣行中，先知ﷺ诵读极短的章：首拜诵《不信者章》（109）或「Qulu amanna billahi…」（2:136），次拜诵《忠诚章》（112）或「Qul ya ahla al-kitab…」（3:64）。两拜圣行从短，两拜主命则长。圣行与主命之间静默祈祷；破晓乃祈祷最易被应答的时段之一。礼前自睡眠中起身时诵：「Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur」。`, yue: `喺晨禮前嘅兩拜聖行中，先知ﷺ誦讀極短嘅章：首拜誦《不信者章》（109）或「Qulu amanna billahi…」（2:136），次拜誦《忠誠章》（112）或「Qul ya ahla al-kitab…」（3:64）。兩拜聖行宜短，兩拜主命則長。聖行與主命之間靜默祈禱；破曉乃祈禱最易被應答嘅時段之一。禮前自睡眠中起身時誦：「Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur」。`, ja: `ファジュル前の二ラクアのスンナで、預言者ﷺは非常に短い章を朗誦された：第一ラクアでカーフィルーン章（109）または「クールー・アーマンナー・ビッラーヒ…」（2:136）、第二ラクアでイフラース章（112）または「クル・ヤー・アフラル＝キターブ…」（3:64）。二ラクアのスンナは短く、二ラクアのファルドは長くする。スンナとファルドの間に静かにドゥアする  –  夜明けはドゥアが最も受け入れられる時の一つ。礼拝前、寝覚めの際には「アルハムドゥ・リッラーヒッラジー・アヒヤーナー・バアダ・マー・アマータナー・ワ・イライヒンヌシュール」と唱える。`, ru: `В двух ракатах сунны Фаджра Пророк ﷺ читал очень короткие суры: в первом — суру аль-Кафирун (109) или «Кулу амання биллахи…» (2:136), во втором — суру аль-Ихляс (112) или «Куль йа ахль аль-китаб…» (3:64). Сделай два раката сунны короткими, а два раката фарда длинными. Между сунной и фардом тихо взывай  –  рассвет одно из самых принимаемых времён дуа. Перед молитвой, при пробуждении ото сна, произнеси «Альхамду лилляхиль-лази ахьяна баада ма аматана ва иляйхин-нушур».`, es: `En los dos rak'ahs Sunnah del Fajr, el Profeta ﷺ recitaba suras muy breves: en el primer rak'ah la Sura al-Kafirun (109) o "Qulu amanna billahi..." (2:136), y en el segundo la Sura al-Ikhlas (112) o "Qul ya ahla al-kitab..." (3:64). Haz cortos los dos rak'ahs Sunnah y largos los dos del fard. Entre la Sunnah y el fard, suplica en silencio; el alba es uno de los tiempos en que el du'a es más aceptado. Antes de la oración, al levantarse del sueño, di "Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur".`, ko: `파즈르의 두 순나 라카에서 예언자 ﷺ께서는 아주 짧은 장을 낭송하셨다: 첫 라카에서 알카피룬 장(109) 또는 "꿀루 아만나 빌라히…"(2:136), 둘째에서 알이클라스 장(112) 또는 "꿀 야 아흘랄 키타브…"(3:64). 두 순나 라카는 짧게, 두 파르드 라카는 길게 하라. 순나와 파르드 사이에 조용히 기원하라  –  새벽은 두아가 가장 잘 받아들여지는 때 중 하나이다. 예배 전, 잠에서 깨면 "알함두 릴라힐 라디 아하야나 바으다 마 아마타나 와 일라이힌누슈르"를 말하라.`, ta: `ஃபஜ்ர் சுன்னா இரண்டு ரக்அத்களில் நபி ﷺ மிகக் குறுகிய சூராக்கள் ஓதினார்: முதல் ரக்அத்தில் சூரத்துல்-காஃபிரூன் (109) அல்லது "குலூ ஆமன்னா பில்லாஹி..." (2:136), இரண்டாவதில் சூரத்துல்-இக்லாஸ் (112) அல்லது "குல் யா அஹ்லல் கிதாப்..." (3:64). இரு சுன்னா ரக்அத்களைச் சுருக்கி, இரு ஃபர்ள் ரக்அத்களை நீட்டுங்கள். சுன்னாவுக்கும் ஃபர்ளுக்கும் இடையே அமைதியாக துஆ செய்யுங்கள்  –  துஆ அதிகம் ஏற்கப்படும் வேளைகளில் விடியல் ஒன்று. தொழுகைக்கு முன், உறக்கத்திலிருந்து எழும்போது சொல்லுங்கள்: "அல்ஹம்து லில்லாஹில்லதீ அஹ்யானா பஃத மா அமாதனா வ இலைஹின்-நுஷூர்".`, si: `ෆජ්ර්හි සුන්නා රකඅත් දෙකේදී නබි ﷺ ඉතා කෙටි සූරා කියවූහ: පළමු රකඅතේදී අල්-කාෆිරූන් සූරාව (109) හෝ "කූලූ ආමන්නා බිල්ලාහි..." (2:136), දෙවැන්නේදී අල්-ඉක්ලාස් සූරාව (112) හෝ "කුල් යා අහ්ලල් කිතාබ්..." (3:64). සුන්නා රකඅත් දෙක කෙටි කොට, ෆර්ද් රකඅත් දෙක දිගු කරන්න. සුන්නාව හා ෆර්ද් අතර නිහඬව ප්‍රාර්ථනා කරන්න  –  දුආ වැඩි පිළිගැනීමක් ලැබෙන මොහොත අතර අරුණෝදය එකකි. සලාතයට පෙර, නින්දෙන් අවදි වන විට කියන්න: "අල්හම්දු ලිල්ලාහිල්ලදී අහ්යානා බඃද මා අමාතනා ව ඉලෛහින්-නුෂූර්".` },
  fajr_extras_say: { en: `After the fard salam, in addition to the universal post-prayer adhkar: the morning adhkar (adhkar al-sabah) are due now and remain valid until sunrise. Among them: Ayat al-Kursi, the three Quls each three times with blowing into the palms, "Hasbiyallahu la ilaha illa huwa, 'alayhi tawakkaltu wa huwa Rabbul-'Arshil-'Azim" (seven times), and "Allahumma bika asbahna wa bika amsayna...". After completing the morning adhkar, remain seated in the place of prayer until sunrise, then pray two rak'ahs of "Ishraq"; the Prophet ﷺ said this carries the reward of a complete Hajj and Umrah.`, ms: `Selepas salam fardu, sebagai tambahan kepada zikir umum selepas solat: zikir pagi (adhkar al-sabah) jatuh tempo sekarang dan sah sehingga matahari terbit. Antaranya: Ayat al-Kursi, tiga Qul setiap satu tiga kali sambil meniup ke tapak tangan, "Hasbiyallahu la ilaha illa huwa, 'alayhi tawakkaltu wa huwa Rabbul-'Arshil-'Azim" (tujuh kali), dan "Allahumma bika asbahna wa bika amsayna...". Selepas selesai zikir pagi, duduk di tempat solat sehingga matahari terbit, kemudian dirikan dua rakaat "Isyraq"; Nabi ﷺ bersabda ini membawa pahala satu Haji dan Umrah yang sempurna.`, tur: `Farzın selamından sonra, namaz sonrası genel zikirlere ek olarak: sabah zikirleri (ezkâru's-sabâh) zamanı gelmiştir ve güneş doğana kadar geçerlidir. Bunlardan: Âyetü'l-Kürsî; üç "Kul" suresi her biri üç defa avuçlara üflenerek; "Hasbiyallâhu lâ ilâhe illâ Hû, aleyhi tevekkeltü ve Hüve Rabbül-Arşil-Azîm" (yedi defa); ve "Allâhümme bike asbahnâ ve bike emseynâ..." Sabah zikirleri bittikten sonra güneş doğana kadar namaz yerinde otur, sonra iki rekât "İşrak" namazı kıl; Peygamber ﷺ bunun tam bir hac ve umre sevabını taşıdığını buyurmuştur.`, urd: `فرض کے سلام کے بعد، عمومی بعد از نماز اذکار کے علاوہ: اذکارِ صبح کا وقت اب شروع ہوتا ہے اور طلوعِ آفتاب تک رہتا ہے۔ ان میں: آیت الکرسی؛ تین قل ہر ایک تین بار ہتھیلیوں میں پھونک کر؛ "حسبي اللہ لا إلہ إلا ہو علیہ توکلت وہو رب العرش العظیم" (سات بار)؛ "اللہم بک أصبحنا و بک أمسینا..."۔ اذکارِ صبح ختم کرنے کے بعد طلوعِ آفتاب تک نمازی جگہ پر بیٹھے رہیں، پھر دو رکعت "اشراق" پڑھیں؛ نبی ﷺ نے فرمایا یہ ایک مکمل حج اور عمرہ کا ثواب رکھتا ہے۔`, ben: `ফরজের সালামের পরে, সাধারণ নামাজোত্তর জিকিরের পাশাপাশি: সকালের জিকিরের (আযকার আস-সাবাহ) সময় এখন শুরু হয় এবং সূর্যোদয় পর্যন্ত বৈধ থাকে। এর মধ্যে: আয়াতুল কুরসী; তিনটি কুল প্রতিটি তিনবার, হাতের তালুতে ফুঁ দিয়ে; "হাসবিয়াল্লাহু লা ইলাহা ইল্লা হুয়া, আলাইহি তাওয়াক্কালতু ওয়া হুয়া রব্বুল-আরশিল-আজীম" (সাত বার); এবং "আল্লাহুম্মা বিকা আসবাহনা ওয়া বিকা আমসায়না..."। সকালের জিকির শেষ করার পর সূর্যোদয় পর্যন্ত নামাজের জায়গায় বসে থাকুন, তারপর দুই রাকাত "ইশরাক" পড়ুন; নবী ﷺ বলেছেন এটি একটি পূর্ণ হজ ও উমরাহর সওয়াব বহন করে।`, fas: `پس از سلام فرض، علاوه بر اذکار عمومی پس از نماز: زمان اذکار صبح (أذکار الصباح) فرارسیده و تا طلوع خورشید معتبر است. از جمله: آیة الکرسی؛ سه "قل" هر یک سه بار با دمیدن در کف دست‌ها؛ "حسبي الله لا إله إلا هو علیه توکلت و هو رب العرش العظیم" (هفت بار)؛ "اللهم بک أصبحنا و بک أمسینا...". پس از اتمام اذکار صبح، در محل نماز تا طلوع خورشید نشسته بمان، سپس دو رکعت "اشراق" بخوان؛ پیامبر ﷺ فرمود این پاداش یک حج و عمره کامل را دارد.`, zh: `主命之平安词后，除拜功后通用赞念外：晨间赞念（晨念，adhkar al-sabah）此时到时，至日出仍有效。其中包括：宝座经；三章"qul"各三遍，向掌心吹气；"Hasbiyallahu la ilaha illa huwa…"七遍；"Allahumma bika asbahna wa bika amsayna…"。完成晨念后，于礼拜处坐至日出，再礼两拜"伊什拉格"；先知ﷺ言此具完整朝觐与副朝之回赐。`, yue: `主命之平安詞後，除拜功後通用讚念外：晨間讚念（晨念，adhkar al-sabah）此時到時，至日出仍有效。其中包括：寶座經；三章「qul」各三遍，向掌心吹氣；「Hasbiyallahu la ilaha illa huwa…」七遍；「Allahumma bika asbahna wa bika amsayna…」。完成晨念後，於禮拜處坐至日出，再禮兩拜「伊什拉格」；先知ﷺ言此具完整朝覲與副朝之回賜。`, ja: `ファルドのサラーム後、礼拝後の一般的なズィクルに加えて：朝のズィクル（アズカール・アッ＝サバーハ）の時が今訪れ、日の出までは有効である。その中には：アーヤトゥル＝クルスィー、三つの「クル」各三回ずつ手のひらに息を吹きかけて、「ハスビヤッラーフ・ラー・イラーハ・イッラー・フワ、アライヒ・タワッカルトゥ・ワ・フワ・ラッブル＝アルシル＝アズィーム」（七回）、そして「アッラーフマ・ビカ・アスバフナー・ワ・ビカ・アムサイナー…」。朝のズィクルを終えた後、日の出まで礼拝の場に座り続け、それから二ラクアの「イシュラーク」礼拝を行う；預言者ﷺは、これが完全なハッジとウムラの報奨を持つと仰せられた。`, ru: `После завершающего салама фарда, помимо общих послемолитвенных азкаров: настало время утренних азкаров (азкар ас-сабах), действительных до восхода. Среди них: Аят аль-Курси; три суры «кул» каждая по три раза с дуновением в ладони; «Хасбийаллаху ля иляха илля Хува, 'аляйхи таваккальту ва Хува Рабб аль-'Аршиль-'Азым» (семь раз); «Аллахумма бика асбахна ва бика амсайна…». По окончании утренних азкаров оставайся сидеть на месте молитвы до восхода, затем соверши два раката «Ишрак»; Пророк ﷺ сказал, что это несёт награду полного Хаджа и Умры.`, es: `Tras el salam del fard, además de los adhkar post-oración universales: los adhkar de la mañana (adhkar al-sabah) son ahora debidos y siguen siendo válidos hasta la salida del sol. Entre ellos: Ayat al-Kursi; los tres "qul" cada uno tres veces, soplando en las palmas; "Hasbiyallahu la ilaha illa huwa, 'alayhi tawakkaltu wa huwa Rabbul-'Arshil-'Azim" (siete veces); y "Allahumma bika asbahna wa bika amsayna...". Tras completar los adhkar matinales, permanece sentado en el lugar de oración hasta el amanecer, luego reza dos rak'ahs de "Ishraq"; el Profeta ﷺ dijo que esto lleva la recompensa de un Hajj y Umrah completos.`, ko: `파르드 살람 후, 보편적인 예배 후 아드카르 외에: 아침 아드카르(아드카르 알사바흐)의 시간이 시작되며 일출까지 유효하다. 그중에는: 아야툴 쿠르시; 세 "꿀" 장 각각 세 번씩 손바닥에 입김을 불며; "하스비얄라후 라 일라하 일라 후와, 알라이히 타왁칼투 와 후와 랍불아르쉴아짐"(일곱 번); "알라훔마 비카 아스바흐나 와 비카 암사이나…". 아침 아드카르를 마친 뒤, 일출까지 예배 자리에 앉아 있다가 두 라카의 "이슈라끄"를 예배하라; 예언자 ﷺ께서는 이것이 완전한 핫즈와 우므라의 보상을 가진다고 말씀하셨다.`, ta: `ஃபர்ளின் ஸலாமுக்குப் பின், பொதுவான தொழுகைக்குப் பின்தைய திக்ருகள் தவிர: காலை திக்ருகளுக்கான (அத்காரு அஸ்-ஸபாஹ்) வேளை இப்போது வந்துவிட்டது, சூரிய உதயம் வரை செல்லும். அவற்றில்: ஆயத்துல் குர்ஸி; மூன்று "குல்" ஒவ்வொன்றும் மூன்று முறை, உள்ளங்கைகளில் ஊதி; "ஹஸ்பியல்லாஹு லா இலாஹ இல்லா ஹுவ, அலைஹி தவக்கல்து வ ஹுவ ரப்புல்-அர்ஷில்-அழீம்" (ஏழு முறை); மற்றும் "அல்லாஹும்ம பிக அஸ்பஹ்னா வ பிக அம்ஸைனா...". காலை திக்ருகளை முடித்த பிறகு, சூரிய உதயம் வரை தொழுகை இடத்தில் அமர்ந்திருங்கள், பின் இரண்டு ரக்அத் "இஷ்ராக்" தொழுங்கள்; நபி ﷺ இது ஒரு முழுமையான ஹஜ் மற்றும் உம்ராவின் கூலியைச் சுமக்கிறது எனக் கூறினார்.`, si: `ෆර්ද් සලාම් පසු, සලාතයෙන් පසු සාර්වත්‍රික දික්ර්වලට අමතරව: උදෑසන දික්ර්වල (අද්කාර් අස්-සබාහ්) කාලය දැන් පැමිණී ඇත, හිරු උදාව දක්වා වලංගුව පවතී. ඒවා අතර: ආයතුල් කුර්සී; "කුල්" තුන බැගින් තුන් වරක්, අල්ල තුළට පිඹ; "හස්බියල්ලාහු ලා ඉලාහ ඉල්ලා හුව, අලෛහි තවක්කල්තු ව හුව රබ්බුල්-අර්ෂිල්-අසීම්" (හත් වරක්); සහ "අල්ලාහුම්ම බික අස්බහ්නා ව බික අම්සෛනා...". උදෑසන දික්ර් අවසන් කළ පසු, හිරු උදාව දක්වා සලාත් කළ ස්ථානයේ වාඩි වී සිට, පසුව රකඅත් දෙකක "ඉෂ්රාක්" සලාත් කරන්න; නබි ﷺ එය සම්පූර්ණ හජ් සහ උම්රාවේ ප්‍රතිඵලය දරන බව පැවසූහ.` },
  fajr_virtues: { en: `Praying Fajr in congregation has the reward of standing the entire night in prayer (Muslim 656). Standing in prayer between Fajr and sunrise is described by the Prophet ﷺ as "more beloved to me than freeing four slaves." The morning hours after Fajr are blessed: the Prophet ﷺ supplicated, "O Allah, bless my nation in their early mornings." The hypocrites are identified by their inability to attend Fajr  –  "the heaviest prayers on the hypocrites are Isha and Fajr; if they knew what they contain, they would crawl to them." (Bukhari 657, Muslim 651).`, ms: `Mendirikan Subuh secara berjemaah membawa pahala berdiri solat sepanjang malam (Muslim 656). Berdiri solat antara Subuh dan matahari terbit disifatkan oleh Nabi ﷺ sebagai "lebih dicintai olehku daripada memerdekakan empat hamba." Waktu pagi selepas Subuh diberkati: Nabi ﷺ berdoa, "Ya Allah, berkatilah umatku pada awal pagi mereka." Munafik dikenali daripada ketidakmampuan mereka menghadiri Subuh  –  "solat yang paling berat ke atas munafik ialah Isyak dan Subuh; jika mereka tahu apa yang ada padanya, nescaya mereka akan datang merangkak." (Bukhari 657, Muslim 651).`, tur: `Sabah'ı cemaatle kılmak, bütün geceyi namazda geçirmenin sevabını taşır (Müslim 656). Sabah ile güneşin doğuşu arasında namazda durmak Peygamber'in ﷺ "dört köle azat etmekten daha sevimli" gördüğü ameldir. Sabahtan sonraki saatler bereketlidir: Peygamber ﷺ "Allah'ım, ümmetimi erken sabahlarında bereketlendir." diye dua etti. Münafıklar Sabah'a gelememeleriyle tanınır  –  "münafıklara en ağır gelen iki namaz Yatsı ve Sabah'tır; içinde olanı bilselerdi sürünerek bile gelirlerdi." (Buhârî 657, Müslim 651).`, urd: `فجر کو باجماعت پڑھنا پوری رات قیام کرنے کا ثواب رکھتا ہے (مسلم ۶۵۶)۔ نبی ﷺ نے فجر اور طلوعِ آفتاب کے درمیان نماز کھڑے ہو کر پڑھنے کو "چار غلام آزاد کرنے سے زیادہ محبوب" قرار دیا۔ فجر کے بعد کے صبح کے اوقات بابرکت ہیں: نبی ﷺ نے دعا فرمائی، "اے اللہ! میری امت کے لیے ان کی صبح کے اوقات میں برکت دے۔" منافقوں کی پہچان فجر میں حاضر نہ ہونا ہے  –  "منافقین پر سب سے بھاری دو نمازیں عشاء اور فجر ہیں؛ اگر وہ جان لیں کہ ان میں کیا ہے، تو گھٹنوں کے بل بھی آ جائیں۔" (بخاری ۶۵۷، مسلم ۶۵۱)۔`, ben: `ফজর জামাতে আদায় করা পুরো রাত নামাজে দাঁড়িয়ে থাকার সওয়াব বহন করে (মুসলিম ৬৫৬)। ফজর ও সূর্যোদয়ের মাঝে নামাজে দাঁড়ানোকে নবী ﷺ "চারজন দাসকে মুক্ত করার চেয়েও আমার কাছে প্রিয়" বলেছেন। ফজরের পরের সকালের সময়গুলো বরকতময়: নবী ﷺ দোয়া করেছেন, "হে আল্লাহ! আমার উম্মতকে তাদের সকালের শুরুতে বরকত দাও।" মুনাফিকদের চেনা যায় তাদের ফজরে উপস্থিত হতে না পারা দিয়ে  –  "মুনাফিকদের উপর সবচেয়ে ভারী দুটি নামাজ ইশা ও ফজর; যদি তারা জানত এতে কী আছে, তারা হামাগুড়ি দিয়েও আসত।" (বুখারি ৬৫৭, মুসলিম ৬৫১)।`, fas: `گزاردن نماز فجر به جماعت پاداش قیام تمام شب را دارد (مسلم ۶۵۶). ایستادن در نماز میان فجر و طلوع را پیامبر ﷺ "نزد من از آزاد کردن چهار بنده محبوب‌تر" خواند. ساعات صبح پس از فجر مبارک‌اند: پیامبر ﷺ دعا فرمود، "خدایا، در صبح زود امتم برکت قرار ده." منافقان به ناتوانی از حضور در فجر شناخته می‌شوند  –  "سنگین‌ترین دو نماز بر منافقان عشاء و فجر است؛ اگر می‌دانستند در آنها چیست، حتی به سینه‌خیز هم می‌آمدند." (بخاری ۶۵۷، مسلم ۶۵۱).`, zh: `集体礼晨礼具有彻夜立礼之回赐（穆斯林656）。先知ﷺ言介乎晨礼与日出之间的立礼"于我比释放四名奴隶更可爱"。晨礼后之晨时蒙福：先知ﷺ祈祷"主啊，求你在我民众清早之时降福"。伪信者以无能赴晨礼而显形  –  "对伪信者最沉重的两次拜功是宵礼与晨礼；他们若知其中内涵，必将匍匐而来。"（布哈里657，穆斯林651）`, yue: `集體禮晨禮具有徹夜立禮之回賜（穆斯林656）。先知ﷺ言介乎晨禮與日出之間嘅立禮「於我比釋放四名奴隸更可愛」。晨禮後嘅晨時蒙福：先知ﷺ祈禱「主啊，求祢喺我民眾清早之時降福」。偽信者以無能赴晨禮而顯形  –  「對偽信者最沉重嘅兩次拜功係宵禮與晨禮；佢哋若知其中內涵，必將匍匐而嚟。」（布哈里657，穆斯林651）`, ja: `ファジュルを集団で行うことには夜通し礼拝に立つ報奨がある（ムスリム656）。預言者ﷺはファジュルから日の出までの礼拝の立位を「私にとって四人の奴隷を解放するよりも愛しい」と仰せられた。ファジュル後の朝の時間は祝福される：預言者ﷺは祈った、「アッラーよ、わが民の朝早くに祝福を与え給え」。偽善者はファジュルに出席できないことで識別される  –  「偽善者にとって最も重い二つの礼拝はイシャーとファジュルである。その中身を知っていたなら、彼らは這ってでも来ただろう。」（ブハーリー657、ムスリム651）`, ru: `Совершение Фаджра в коллективе несёт награду стояния всю ночь в молитве (Муслим 656). Стояние в молитве между Фаджром и восходом Пророк ﷺ называл «более любимым для меня, чем освобождение четырёх рабов». Утренние часы после Фаджра благословенны: Пророк ﷺ молил, «О Аллах, благослови мою общину в их раннее утро». Лицемеры узнаются по неспособности явиться на Фаджр  –  «самые тяжкие для лицемеров две молитвы — Иша и Фаджр; если бы они знали, что в них, они приползли бы к ним.» (Бухари 657, Муслим 651).`, es: `Rezar el Fajr en congregación tiene la recompensa de permanecer toda la noche en oración (Muslim 656). El Profeta ﷺ describió el orar entre el Fajr y el amanecer como "más amado para mí que liberar a cuatro esclavos." Las horas matutinas tras el Fajr son benditas: el Profeta ﷺ suplicó, "Oh Allah, bendice a mi nación en sus madrugadas." Los hipócritas se identifican por su incapacidad para asistir al Fajr  –  "las oraciones más pesadas para los hipócritas son el Isha y el Fajr; si supieran lo que contienen, vendrían a gatas." (Bujari 657, Muslim 651).`, ko: `파즈르를 회중으로 예배하는 것은 밤새 예배에 서 있는 보상을 가집니다(무슬림 656). 파즈르와 일출 사이에 예배에 서는 것을 예언자 ﷺ께서는 "네 명의 노예를 해방하는 것보다 내게 더 사랑스럽다"고 묘사하셨다. 파즈르 이후의 아침 시간은 축복받았다: 예언자 ﷺ께서 기도하셨다, "오 알라, 제 공동체에게 그들의 이른 아침에 축복을 주소서." 위선자는 파즈르에 참석하지 못함으로 식별된다  –  "위선자들에게 가장 무거운 두 예배는 이샤와 파즈르이다; 그들이 그 안에 무엇이 있는지 알았더라면 기어서라도 왔을 것이다." (부카리 657, 무슬림 651).`, ta: `ஃபஜ்ரை கூட்டாகத் தொழுவது இரவு முழுவதும் தொழுகையில் நிற்கும் கூலியைச் சுமக்கிறது (முஸ்லிம் 656). ஃபஜ்ருக்கும் சூரிய உதயத்திற்கும் இடையே தொழுகையில் நிற்பதை நபி ﷺ "எனக்கு நான்கு அடிமைகளை விடுவிப்பதை விட விரும்பப்படுவது" எனக் கூறினார். ஃபஜ்ருக்குப் பின்னான காலை வேளைகள் பாக்கியமானவை: நபி ﷺ துஆ செய்தார், "அல்லாஹ்வே! என் சமுதாயத்தினருக்கு அவர்களின் அதிகாலையில் பாக்கியம் அளி." நயவஞ்சகர்கள் ஃபஜ்ரில் கலந்துகொள்ள இயலாமையால் அடையாளம் காணப்படுகிறார்கள்  –  "நயவஞ்சகர்கள் மீது மிக கடினமான இரு தொழுகைகள் இஷாவும் ஃபஜ்ரும்; அவற்றில் என்ன உள்ளது என அவர்கள் அறிந்திருந்தால், ஊர்ந்தாவது வந்திருப்பார்கள்." (புகாரி 657, முஸ்லிம் 651).`, si: `ෆජ්ර් සමූහ වශයෙන් ඉටු කිරීම මුළු රාත්‍රියම සලාතයේ සිටීමේ ප්‍රතිඵලය දරයි (මුස්ලිම් 656). නබි ﷺ ෆජ්ර් සහ හිරු උදාව අතර සලාතයේ සිටීම "මට වහල්ලු සිවුදෙනෙකු නිදහස් කිරීමට වඩා ප්‍රිය" යැයි විස්තර කළහ. ෆජ්ර්ට පසු උදෑසන වේලාවන් ආශීර්වාද ලත්ය: නබි ﷺ ප්‍රාර්ථනා කළහ, "අල්ලාහ්වනේ, මාගේ සමාජයේ අයට ඔවුන්ගේ අලුයමේදී ආශීර්වාද කරන්න." කපටියන් හඳුනා ගනු ලබන්නේ ඔවුන්ට ෆජ්ර්ට පැමිණීමට නොහැකි වීමෙනි  –  "කපටියන්ට බරම සලාත දෙක ඉෂා සහ ෆජ්ර්; ඒවායේ ඇති දේ ඔවුන් දන්නේ නම්, බඩගා හෝ ඔවුහු ඊට පැමිණෙනු ඇත." (බුහාරි 657, මුස්ලිම් 651).` },
  fajr_timing_notes: { en: `Avoid praying any voluntary prayer (other than greeting the mosque or the omitted Sunnah al-Fajr) from sunrise until the sun has fully risen and risen "the height of a spear" (approximately 15-20 minutes after sunrise). If a person misses Fajr by sleep or genuine forgetfulness, he prays it as soon as he wakes  –  the Prophet ﷺ did this once on a journey when the army overslept, and said: "There is no failure (lit. 'no negligence') in sleep; failure is in wakefulness." (Muslim 681). The two Sunnah rak'ahs can also be prayed immediately after the fard if missed beforehand, or after sunrise (Tirmidhi 423).`, ms: `Elakkan menunaikan sebarang solat sunat (selain tahiyyat masjid atau Sunnah Subuh yang tertinggal) dari matahari terbit hingga matahari naik sepenuhnya "setinggi tombak" (kira-kira 15-20 minit selepas terbit). Jika seseorang terlepas Subuh kerana tidur atau lupa, dia mendirikannya sebaik sahaja terjaga  –  Nabi ﷺ pernah berbuat demikian dalam satu perjalanan apabila tentera tertidur, dan bersabda: "Tiada kelalaian dalam tidur; kelalaian adalah ketika sedar." (Muslim 681). Dua rakaat sunat juga boleh dilakukan sebaik selepas fardu jika tertinggal sebelumnya, atau selepas matahari terbit (Tirmidhi 423).`, tur: `Güneşin doğuşundan, güneş tamamen yükselip "bir mızrak boyu" yükselene kadar (yaklaşık 15-20 dakika) hiçbir nafile namaz kılınmaz (mescide selâm ve kaçırılmış Sabah sünneti hariç). Bir kimse Sabah'ı uyku veya gerçek unutkanlıkla kaçırırsa, uyandığı anda kılar  –  Peygamber ﷺ bir seferde ordu uyuyakaldığında bunu yapmış ve "Uykuda kusur yoktur; kusur uyanıklıkta olur" buyurmuştur (Müslim 681). İki rekât sünnet de farzdan hemen sonra kılınabilir veya güneş doğduktan sonra kaza edilebilir (Tirmizî 423).`, urd: `طلوعِ آفتاب سے سورج کے مکمل بلند ہونے اور "نیزے کے قد" تک بلند ہونے (تقریباً ۱۵-۲۰ منٹ بعد) تک کوئی نفل نماز نہ پڑھیں (تحیة المسجد یا قضا شدہ سنّت الفجر کے علاوہ)۔ اگر کوئی نیند یا حقیقی بھول کے باعث فجر چھوڑ دے تو جاگتے ہی پڑھے  –  نبی ﷺ نے ایک سفر میں جب لشکر سو گیا تو ایسا کیا اور فرمایا: "نیند میں کوئی کوتاہی نہیں؛ کوتاہی بیداری میں ہے۔" (مسلم ۶۸۱)۔ دو سنّت رکعات بھی فرض کے فوراً بعد ادا کی جا سکتی ہیں اگر پہلے رہ گئی ہوں، یا طلوعِ آفتاب کے بعد (ترمذی ۴۲۳)۔`, ben: `সূর্যোদয় থেকে সূর্য পূর্ণরূপে উঠে "একটি বর্শার উচ্চতা" পর্যন্ত (সূর্যোদয়ের প্রায় ১৫-২০ মিনিট পর) কোনো নফল নামাজ পড়বেন না (মসজিদকে অভিবাদন বা ছুটে যাওয়া সুন্নাহ আল-ফজর ব্যতীত)। কেউ যদি ঘুম বা প্রকৃত ভুলে ফজর ছুটিয়ে ফেলে, সে জেগে উঠেই পড়বে  –  নবী ﷺ একবার সফরে যখন বাহিনী ঘুমিয়ে পড়ল তখন এমন করেছিলেন এবং বলেছিলেন: "ঘুমে কোনো অবহেলা নেই; অবহেলা জাগরণে।" (মুসলিম ৬৮১)। দুই সুন্নাহ রাকাত আগে ছুটে গেলে ফরজের পরপরই, বা সূর্যোদয়ের পরে আদায় করা যায় (তিরমিযি ৪২৩)।`, fas: `از طلوع خورشید تا کاملاً برآمدن و رسیدن آن به اندازه "قامت یک نیزه" (تقریباً ۱۵-۲۰ دقیقه پس از طلوع) هیچ نماز نافله نخوان (به جز تحیة المسجد یا سنت فوت‌شده فجر). اگر کسی فجر را با خواب یا فراموشی واقعی از دست داد، به محض بیداری بخواند  –  پیامبر ﷺ یک بار در سفری چنین کرد و فرمود: "در خواب کوتاهی نیست؛ کوتاهی در بیداری است." (مسلم ۶۸۱). دو رکعت سنت را نیز اگر پیش از فرض از دست رفت می‌توان بلافاصله پس از فرض یا پس از طلوع خواند (ترمذی ۴۲۳).`, zh: `自日出至太阳完全升起、升至"一矛之高"（约日出后15-20分钟）期间，勿礼任何副功拜（除问候清真寺或补晨礼前圣行外）。若有人因睡眠或真正的遗忘而错过晨礼，应一醒来即礼  –  先知ﷺ曾在一次旅途中军队过睡时如此行，并说："睡眠中无怠惰；怠惰在醒时。"（穆斯林681）。两拜圣行若于主命前漏礼，可于主命之后立即补礼，或日出之后补礼（提尔米兹423）。`, yue: `自日出至太陽完全升起、升至「一矛之高」（約日出後15-20分鐘）期間，勿禮任何副功拜（除問候清真寺或補晨禮前聖行外）。若有人因睡眠或真正嘅遺忘而錯過晨禮，應一醒嚟即禮  –  先知ﷺ曾喺一次旅途中軍隊過睡時如此行，並話：「睡眠中無怠惰；怠惰喺醒時。」（穆斯林681）。兩拜聖行若於主命前漏禮，可於主命之後立即補禮，或日出之後補禮（提爾米茲423）。`, ja: `日の出から、太陽が完全に昇り「槍一本の高さ」になるまで（日の出後約15～20分）、任意の礼拝（モスクへの挨拶か逃したスンナ・アル＝ファジュルを除く）を行わない。眠りや真の忘却によってファジュルを逃した場合は、目覚めたらすぐに行う  –  預言者ﷺは旅で軍が寝過ごした際にそうし、「眠りには怠慢はない。怠慢は目覚めにある」と仰せられた（ムスリム681）。二ラクアのスンナも、ファルド前に逃した場合はファルドの直後に、または日の出後に補える（ティルミズィー423）。`, ru: `Не совершай никакой добровольной молитвы (кроме приветствия мечети или пропущенной сунны Фаджра) с восхода солнца до полного его подъёма «на высоту копья» (примерно через 15–20 минут после восхода). Если человек пропустил Фаджр из-за сна или подлинной забывчивости, он совершает её, как только проснётся  –  Пророк ﷺ так сделал однажды в пути, когда войско проспало, и сказал: «В сне нет небрежности; небрежность  –  в бодрствовании.» (Муслим 681). Два раката сунны также можно совершить сразу после фарда, если пропущены ранее, или после восхода (Тирмизи 423).`, es: `Evita rezar cualquier oración voluntaria (salvo el saludo a la mezquita o la Sunnah al-Fajr omitida) desde el amanecer hasta que el sol haya salido por completo y se haya elevado "la altura de una lanza" (aproximadamente 15-20 minutos tras el amanecer). Si una persona pierde el Fajr por sueño o por un olvido genuino, lo reza tan pronto como despierte  –  el Profeta ﷺ lo hizo una vez en un viaje cuando el ejército se quedó dormido, y dijo: "No hay negligencia en el sueño; la negligencia está en la vigilia." (Muslim 681). Los dos rak'ahs Sunnah también pueden rezarse inmediatamente después del fard si se omitieron antes, o tras el amanecer (Tirmidhi 423).`, ko: `일출부터 태양이 완전히 떠올라 "창 하나의 높이"가 될 때까지(일출 후 약 15~20분) 자발 예배(모스크 인사 또는 놓친 순나 알파즈르 제외)는 행하지 말라. 누군가 잠이나 진정한 망각으로 파즈르를 놓쳤다면, 깨는 즉시 예배한다  –  예언자 ﷺ께서는 여행 중 군대가 늦잠 잤을 때 이를 행하시며 "잠에는 태만이 없다; 태만은 깨어 있을 때이다"고 말씀하셨다 (무슬림 681). 두 순나 라카도 미리 놓쳤다면 파르드 직후나 일출 후에 보충할 수 있다 (티르미디 423).`, ta: `சூரிய உதயத்திலிருந்து சூரியன் முழுமையாக ஏறி "ஒரு ஈட்டியின் உயரம்" (சூரிய உதயத்திற்குப் பின் சுமார் 15-20 நிமிடங்கள்) வரை எந்த நஃபில் தொழுகையையும் தொழ வேண்டாம் (பள்ளி வாழ்த்து அல்லது தவறிய ஃபஜ்ர் சுன்னா தவிர). ஒருவர் தூக்கம் அல்லது உண்மையான மறதியால் ஃபஜ்ரை இழந்தால், விழித்தவுடனேயே தொழுகிறார்  –  ஒரு பயணத்தில் படை அதிக நேரம் தூங்கியபோது நபி ﷺ இவ்வாறு செய்தார், கூறினார்: "தூக்கத்தில் அலட்சியம் இல்லை; அலட்சியம் விழிப்பில் உள்ளது." (முஸ்லிம் 681). இரு சுன்னா ரக்அத்களையும் முன்னர் தவறியிருந்தால் ஃபர்ளுக்குப் பிறகு உடனடியாகவோ, சூரிய உதயத்திற்குப் பிறகோ தொழலாம் (திர்மிதி 423).`, si: `හිරු උදාවේ සිට හිරු සම්පූර්ණයෙන් ඉහළ නැගී "ඇවැස්මක උස" දක්වා (හිරු උදාවට පසු මිනිත්තු 15-20ක් පමණ) කිසිදු ස්වේච්ඡා සලාතයක් (මස්ජිදයට ආචාර කිරීම හෝ අතපසු වූ සුන්නා අල්-ෆජ්ර් හැර) නොකරන්න. කෙනෙකු නින්දෙන් හෝ සැබෑ අමතකකමින් ෆජ්ර් මඟ හැරුණොත්, අවදි වූ විගසම එය ඉටු කරයි  –  නබි ﷺ එක් ගමනක දී හමුදාව අධික නින්දට ගිය විට මෙය කළ අතර පැවසූහ: "නින්දේදී නොසැලකිල්ලක් නැත; නොසැලකිල්ල ඇත්තේ අවදිවෙහි." (මුස්ලිම් 681). සුන්නා රකඅත් දෙකද කලින් මඟ හැරුණොත් ෆර්ද්ට පසු වහාම හෝ හිරු උදාවට පසු ඉටු කළ හැක (තිර්මිදී 423).` },
  /* ── Dhuhr ────────────────────────────────────────────────── */
  dhuhr_name: { en: `Dhuhr  –  The Noon Prayer`, ms: `Zuhur  –  Solat Tengah Hari`, tur: `Öğle Namazı  –  Zuhr`, urd: `ظہر  –  دوپہر کی نماز`, ben: `যোহর  –  মধ্যাহ্নের নামাজ`, fas: `ظهر  –  نماز نیمروز`, zh: `晌礼  –  正午拜功`, yue: `晌禮  –  正午拜功`, ja: `ズフル  –  正午の礼拝`, ru: `Зухр  –  полуденная молитва`, es: `Dhuhr  –  la oración del mediodía`, ko: `주흐르  –  정오 예배`, ta: `ளுஹர்  –  நண்பகல் தொழுகை`, si: `සුහ්ර්  –  මධ්‍යාහ්න සලාතය` },
  dhuhr_when: { en: `Begins the moment the sun passes its zenith (zawal), no longer perpendicular to the earth and beginning to decline westward, and lasts until the shadow of an upright object equals its own length (the Shafi'i, Maliki, and Hanbali view) or twice its length (the Hanafi view). On Friday it is replaced by the Jumu'ah prayer for those who attend. It is the prayer that wakes the world from the noonday heat to the remembrance of Allah.`, ms: `Bermula ketika matahari melepasi titik tegaknya (zawal), tidak lagi tegak lurus dengan bumi dan mula condong ke barat, dan berlangsung sehingga bayang sesuatu objek tegak sama dengan panjangnya (pendapat Shafi'i, Maliki, Hanbali) atau dua kali panjangnya (Hanafi). Pada hari Jumaat, ia digantikan dengan solat Jumaat bagi mereka yang hadir. Ia adalah solat yang membangunkan dunia daripada bahang tengah hari kepada zikrullah.`, tur: `Güneşin zevalden geçtiği (yere dik olmaktan çıkıp batıya meyletmeye başladığı) anda başlar; dik bir cismin gölgesi kendi boyuna eşit olana (Şâfiî, Mâlikî, Hanbelî) ya da iki katına ulaşana (Hanefî) dek sürer. Cuma günü, katılanlar için yerini Cuma namazına bırakır. Dünyayı öğle sıcağından Allah'ı zikre uyandıran namazdır.`, urd: `سورج کے زوال (نصف النہار سے گزر کر مغرب کی طرف جھکنے) کے لمحے سے شروع، اور کسی کھڑی چیز کا سایہ اس کی اپنی لمبائی کے برابر ہونے تک (شافعی، مالکی، حنبلی) یا اس کی دو گنا (حنفی) تک رہتا ہے۔ جمعہ کے دن حاضرین کے لیے نمازِ جمعہ اس کا قائم مقام ہوتی ہے۔ یہ وہ نماز ہے جو دنیا کو دوپہر کی گرمی سے اللہ کی یاد کی طرف بیدار کرتی ہے۔`, ben: `সূর্য মধ্যাকাশ অতিক্রম করার (যাওয়াল) মুহূর্ত থেকে শুরু  –  যখন তা আর পৃথিবীর সাথে লম্ব নয়, পশ্চিমে হেলতে শুরু করে  –  এবং একটি দণ্ডায়মান বস্তুর ছায়া তার নিজের দৈর্ঘ্যের সমান হওয়া (শাফিয়ি, মালিকি, হাম্বলি মত) বা দ্বিগুণ হওয়া (হানাফি মত) পর্যন্ত। শুক্রবার যারা উপস্থিত হন তাদের জন্য জুমার নামাজ এর স্থলে আসে। এটি সেই নামাজ যা দুনিয়াকে মধ্যাহ্নের তাপ থেকে আল্লাহর স্মরণে জাগায়।`, fas: `از لحظه گذر خورشید از نصف النهار (زوال) آغاز و تا برابر شدن سایه چیز ایستاده با خود آن (نظر شافعی، مالکی، حنبلی) یا دو برابر آن (حنفی) ادامه دارد. در روز جمعه برای حاضران جای آن را نماز جمعه می‌گیرد. نمازی است که جهان را از گرمای نیمروز به یاد خدا بیدار می‌سازد.`, zh: `自太阳过中天（zawal，不再与地面垂直，开始向西偏斜）开始，至直立物之影与其本身等长（沙斐仪、马立基、罕百里之见）或两倍长（哈乃斐之见）为止。主麻日为出席者由主麻拜功取代之。它是把世界从正午之炎热唤醒至记念真主的拜功。`, yue: `自太陽過中天（zawal，唔再與地面垂直，開始向西偏斜）開始，至直立物之影與其本身等長（沙斐儀、馬立基、罕百里之見）或兩倍長（哈乃斐之見）為止。主麻日為出席者由主麻拜功取代之。佢係將世界由正午之炎熱喚醒至記念真主嘅拜功。`, ja: `太陽が南中を過ぎる（ザワール：地面に垂直でなくなり西へ傾き始める）瞬間に始まり、直立した物の影がその物自身の長さと等しくなる（シャーフィイー、マーリキー、ハンバリー説）か、二倍に達する（ハナフィー説）まで続く。金曜日、出席する者にとってはジュムア礼拝がこれに代わる。世界を正午の暑さからアッラーの想起へと目覚めさせる礼拝である。`, ru: `Начинается с момента, когда солнце проходит зенит (заваль)  –  больше не перпендикулярно земле и начинает склоняться к западу  –  и длится до момента, когда тень от вертикального предмета сравняется с его длиной (мнение шафиитов, маликитов и ханбалитов) или достигнет двойной длины (мнение ханафитов). В пятницу её заменяет молитва Джумуа для тех, кто присутствует. Это молитва, пробуждающая мир от полуденного зноя к поминанию Аллаха.`, es: `Comienza en el momento en que el sol pasa su cenit (zawal), dejando de ser perpendicular a la tierra y comenzando a declinar hacia el oeste, y dura hasta que la sombra de un objeto vertical iguala su propia longitud (parecer shafi'i, maliki, hanbali) o el doble (parecer hanafi). El viernes la sustituye la oración del yumu'ah para quienes asisten. Es la oración que despierta al mundo del calor del mediodía al recuerdo de Allah.`, ko: `태양이 정점을 지나는(자왈  –  더 이상 지면에 수직이 아니며 서쪽으로 기울기 시작) 순간에 시작되어, 똑바로 선 물체의 그림자가 그 자체 길이와 같아질 때(샤피이·말리키·한발리의 견해) 또는 두 배가 될 때(하나피의 견해)까지 지속됩니다. 금요일에는 참석하는 자에게 주무아 예배가 이를 대신합니다. 한낮의 열기로부터 세상을 알라의 기억으로 깨우는 예배입니다.`, ta: `சூரியன் தன் உச்சத்தைக் கடக்கும் (ஸவால்  –  பூமிக்கு செங்குத்தாக இல்லாமல் மேற்கு நோக்கி சாயத் தொடங்கும்) தருணத்தில் தொடங்கி, ஒரு செங்குத்தான பொருளின் நிழல் அதன் சொந்த நீளத்திற்குச் சமமாகும் வரை (ஷாஃபிஈ, மாலிக்கி, ஹன்பலி கருத்து) அல்லது அதன் இரு மடங்காகும் வரை (ஹனஃபி கருத்து) நீடிக்கும். வெள்ளியன்று கலந்துகொள்வோருக்கு இதற்குப் பதிலாக ஜும்ஆத் தொழுகை வருகிறது. நண்பகல் வெப்பத்திலிருந்து உலகை அல்லாஹ்வின் நினைவுக்கு எழுப்பும் தொழுகை இது.`, si: `සූර්යයා මුදුන ඉක්මවා යන (සවාල්  –  තවදුරටත් භූමියට සෘජු නොව බටහිර දෙසට බැස ගැනීමට පටන් ගන්නා) මොහොතේ ආරම්භ වී, සෘජුව සිටුවන වස්තුවක සෙවණැල්ල එහි දිගට සමාන වන තෙක් (ෂාෆිඊ, මාලිකී, හන්බලී මතය) හෝ දෙගුණයක් වන තෙක් (හනෆී මතය) පවතී. සිකුරාදා දින සහභාගි වන අයට ඊට වෙනුවට ජුමුආ සලාතය එයි. මධ්‍යාහ්නයේ උෂ්ණයේ සිට අල්ලාහ්ව සිහිපත් කිරීමට ලෝකය අවදි කරවන සලාතය මෙයයි.` },
  dhuhr_structure: { en: `Four rak'ahs of fard. The standard Sunnah Mu'akkadah is four rak'ahs before (in two sets of two with one tasleem) and two rak'ahs after. The Prophet ﷺ said about the four before Dhuhr: "There is no Muslim who prays four rak'ahs before Dhuhr after the sun has passed its zenith except that the gates of heaven are opened for him." (Ibn Majah 1157, graded hasan). Recitation is silent (sirri) in all four rak'ahs.`, ms: `Empat rakaat fardu. Sunnah muakkad piawainya empat rakaat sebelum (dalam dua set dua dengan satu salam) dan dua rakaat selepas. Nabi ﷺ bersabda tentang empat sebelum Zuhur: "Tidak seorang Muslim mendirikan empat rakaat sebelum Zuhur setelah matahari melepasi titik tegaknya melainkan dibukakan baginya pintu-pintu langit." (Ibn Majah 1157, hasan). Bacaan secara sirri (perlahan) dalam keempat-empat rakaat.`, tur: `Dört rekât farz. Müekked sünneti, dört rekât önce (iki ikişer şeklinde, bir selam ile) ve iki rekât sonra şeklindedir. Peygamber ﷺ Öğle'den önceki dörtlü hakkında: "Güneş zevalden geçtikten sonra Öğle'den önce dört rekât kılan hiçbir Müslüman yoktur ki ona göklerin kapıları açılmasın." (İbn Mâce 1157, hasen). Dört rekâtta da kıraat sessizdir (sirrî).`, urd: `چار رکعت فرض۔ معیاری سنّتِ مؤکدہ چار رکعت قبل (دو دو کے دو سیٹ، ایک سلام کے ساتھ) اور دو رکعت بعد۔ نبی ﷺ نے ظہر سے پہلے کی چار کے بارے میں فرمایا: "کوئی مسلمان زوال کے بعد ظہر سے پہلے چار رکعت پڑھتا ہے تو اس کے لیے آسمان کے دروازے کھول دیے جاتے ہیں۔" (ابن ماجہ ۱۱۵۷، حسن)۔ چاروں رکعتوں میں قراءت سرّاً (آہستہ) ہوتی ہے۔`, ben: `চার রাকাত ফরজ। মানসম্মত সুন্নাহ মুআক্কাদা হলো চার রাকাত আগে (এক সালামে দুই-দুই করে দুই সেট) এবং দুই রাকাত পরে। নবী ﷺ যোহরের আগের চার সম্পর্কে বলেছেন: "কোনো মুসলিম সূর্য মধ্যাকাশ অতিক্রম করার পর যোহরের আগে চার রাকাত পড়লে তার জন্য আসমানের দরজাসমূহ খুলে দেওয়া হয়।" (ইবনে মাজাহ ১১৫৭, হাসান)। চার রাকাতেই কেরাত নীরবে (সিররি)।`, fas: `چهار رکعت فرض. سنت مؤکد متعارف چهار رکعت پیش از آن (دو دو رکعت با یک سلام) و دو رکعت پس از آن است. پیامبر ﷺ درباره چهار رکعت پیش از ظهر فرمود: "هیچ مسلمانی پس از زوال خورشید چهار رکعت پیش از ظهر نمی‌خواند مگر آنکه درهای آسمان برایش گشوده می‌شود." (ابن‌ماجه ۱۱۵۷، حسن). در هر چهار رکعت قرائت آرام (سرّی) است.`, zh: `主命四拜。标准的强调圣行为前四拜（两两为一组，各以一次平安词结束）与后两拜。先知ﷺ论晌礼前四拜：「凡穆斯林于日过中天后晌礼前礼此四拜，天门必为之而开。」（伊本·马哲1157，良好）。四拜中诵读皆为低声（西里）。`, yue: `主命四拜。標準嘅強調聖行為前四拜（兩兩為一組，各以一次平安詞結束）與後兩拜。先知ﷺ論晌禮前四拜：「凡穆斯林於日過中天後晌禮前禮此四拜，天門必為之而開。」（伊本·馬哲1157，良好）。四拜中誦讀皆為低聲（西里）。`, ja: `ファルドは四ラクア。標準的なスンナ・ムアッカダは前に四ラクア（二ラクアずつ二組、各々一回のサラームで）と、後に二ラクア。預言者ﷺはズフル前の四ラクアについて仰せられた：「太陽が南中を過ぎた後、ズフル前に四ラクアを行うムスリムには天の門が開かれぬ者はいない。」（イブン・マージャ 1157、ハサン）。四ラクアともに朗誦は無声（シッリー）。`, ru: `Четыре раката фарда. Стандартная сунна муаккада  –  четыре раката до (двумя группами по два с одним саламом) и два раката после. Пророк ﷺ сказал о четырёх до Зухра: «Нет мусульманина, который совершит четыре раката перед Зухром после прохождения солнцем зенита, без того, чтобы для него не были открыты врата небес.» (Ибн Маджа 1157, хасан). Чтение во всех четырёх ракатах тихое (сирри).`, es: `Cuatro rak'ahs de fard. La Sunnah Mu'akkadah estándar son cuatro rak'ahs antes (en dos series de dos con un solo salam) y dos rak'ahs después. El Profeta ﷺ dijo de los cuatro antes del Dhuhr: "No hay musulmán que rece cuatro rak'ahs antes del Dhuhr tras pasar el sol su cenit sin que se le abran las puertas del cielo." (Ibn Mayah 1157, hasan). La recitación es en silencio (sirri) en los cuatro rak'ahs.`, ko: `파르드 네 라카. 표준 순나 무앗카다는 앞에 네 라카(두 라카씩 두 묶음, 각 묶음 끝에 살람) + 뒤에 두 라카. 예언자 ﷺ께서는 주흐르 전 네 라카에 대해 말씀하셨다: "태양이 정점을 지난 뒤 주흐르 전에 네 라카를 예배하는 어떤 무슬림에게든 하늘의 문이 열리지 않는 자가 없다." (이븐 마자 1157, 하산). 네 라카 모두 낭송은 소리 없이(시르리).`, ta: `நான்கு ரக்அத் ஃபர்ள். நிலையான ஸுன்னத்துல் முஅக்கதா முன் நான்கு ரக்அத்கள் (இரண்டிரண்டாக ஒவ்வொன்றும் ஒரு ஸலாமுடன்) மற்றும் பின் இரண்டு ரக்அத்கள். ளுஹருக்கு முன் நான்கு பற்றி நபி ﷺ கூறினார்: "சூரியன் உச்சத்தைக் கடந்த பிறகு ளுஹருக்கு முன் நான்கு ரக்அத் தொழும் எந்த முஸ்லிமுக்கும் வானத்தின் கதவுகள் திறக்கப்படாமலிருக்காது." (இப்னு மாஜா 1157, ஹஸன்). நான்கு ரக்அத்களிலும் ஓதல் அமைதியாக (ஸிர்ரி).`, si: `ෆර්ද් රකඅත් හතරක්. සම්මත සුන්නා මුඅක්කදා වන්නේ පෙර රකඅත් හතරක් (දෙක දෙක බැගින් එක් සලාම්කින්) සහ පසු රකඅත් දෙකකි. නබි ﷺ සුහ්ර්ට පෙර හතර ගැන පැවසූහ: "හිරු මුදුන ඉක්මවා ගිය පසු සුහ්ර්ට පෙර රකඅත් හතරක් ඉටු කරන කවර මුස්ලිම්වරයෙකුට වුවද අහසේ දොරටු විවර නොකරනු නොලැබේ." (ඉබ්නු මාජා 1157, හසන්). රකඅත් හතරේදීම කියවීම නිහඬව (සිර්රී).` },
  dhuhr_story: { en: `Like the other four, Dhuhr was ordained on the Night of Ascension. Significantly, Dhuhr was the first prayer Jibril (as) taught the Prophet ﷺ practically  –  the day after the Mi'raj. Jibril descended at noon, immediately after the sun had passed its zenith, led the Prophet ﷺ in this prayer at the Ka'bah in front of Makkah's onlookers, and then taught him every prayer's time over the next two days. This was the moment the abstract command of "fifty became five" took its visible, lived form. The first congregational prayer in Islamic history was a Dhuhr prayer, prayed by the Prophet ﷺ with Khadijah (ra) and the young Ali (ra) behind him at the Ka'bah.`, ms: `Seperti empat yang lain, Zuhur diwajibkan pada malam Mi'raj. Yang signifikan, Zuhur adalah solat pertama yang Jibril (as) ajarkan kepada Nabi ﷺ secara praktikal  –  pada hari selepas Mi'raj. Jibril turun pada tengah hari, sebaik sahaja matahari melepasi titik tegaknya, mengimamkan Nabi ﷺ pada solat ini di Kaabah di hadapan saksi-saksi Makkah, kemudian mengajarkannya waktu setiap solat selama dua hari berikutnya. Inilah saat perintah abstrak "lima puluh menjadi lima" mengambil bentuk yang terlihat dan dihidupi. Solat berjemaah pertama dalam sejarah Islam adalah solat Zuhur, didirikan oleh Nabi ﷺ dengan Khadijah (ra) dan 'Ali muda (ra) di belakangnya di Kaabah.`, tur: `Diğer dördü gibi Öğle de Mi'rac gecesinde farz kılındı. Önemli olanı: Öğle, Cibril'in (as) Peygamber'e ﷺ amelî olarak öğrettiği ilk namazdır  –  Mi'rac'ın ertesi günü. Cibril, güneş zevalden hemen sonra inip Peygamber'i ﷺ Kâbe'de Mekkelilerin önünde bu namazda imamlık etti; sonra iki gün boyunca her namazın vaktini öğretti. "Elliden beşe" indirilen mücerret emrin, görünür ve yaşanan biçim aldığı an buydu. İslam tarihinin ilk cemaat namazı, Peygamber'in ﷺ Kâbe'de arkasında Hatice (ra) ve genç Ali (ra) ile kıldığı bir Öğle namazıdır.`, urd: `دیگر چار کی طرح ظہر بھی شبِ معراج میں واجب ہوئی۔ اہم بات: ظہر وہ پہلی نماز ہے جو جبریل (ع) نے نبی ﷺ کو عملاً سکھائی  –  معراج کے اگلے دن۔ جبریل دوپہر کو نازل ہوئے، سورج کے زوال کے فوراً بعد، نبی ﷺ کو کعبہ کے پاس مکہ کے نظارہ کرنے والوں کے سامنے اس نماز میں امامت کروائی، پھر اگلے دو دن میں ہر نماز کا وقت سکھایا۔ یہ وہ لمحہ تھا جب "پچاس سے پانچ" کا حکم مجسم اور قابلِ مشاہدہ شکل میں سامنے آیا۔ اسلامی تاریخ کی پہلی باجماعت نماز ظہر تھی جو نبی ﷺ نے کعبہ کے پاس خدیجہ (رض) اور کم سن علی (رض) کو اپنے پیچھے لے کر پڑھی۔`, ben: `অন্য চারটির মতো যোহরও মেরাজের রাতে ফরজ হয়েছে। গুরুত্বপূর্ণ বিষয়: যোহর সেই প্রথম নামাজ যা জিবরিল (আ) নবী ﷺ-কে কার্যত শিক্ষা দেন  –  মেরাজের পরের দিন। জিবরিল মধ্যাহ্নে অবতীর্ণ হলেন, সূর্য মধ্যাকাশ অতিক্রম করার ঠিক পর, নবী ﷺ-কে কাবার পাশে মক্কার দর্শকদের সামনে এই নামাজে ইমামতি করালেন, এরপর পরবর্তী দুই দিনে প্রতিটি নামাজের সময় শেখালেন। এটিই সেই মুহূর্ত যখন "পঞ্চাশ থেকে পাঁচ" এর বিমূর্ত আদেশ দৃশ্যমান, জীবন্ত রূপ ধারণ করল। ইসলামি ইতিহাসে প্রথম জামাতের নামাজ ছিল যোহরের নামাজ, যা নবী ﷺ কাবার পাশে পেছনে খাদিজা (রা) ও কিশোর আলী (রা)-কে নিয়ে আদায় করেন।`, fas: `همانند چهار نماز دیگر، ظهر نیز در شب معراج واجب شد. نکته مهم: ظهر نخستین نمازی است که جبرئیل (ع) به‌طور عملی به پیامبر ﷺ آموخت  –  روز پس از معراج. جبرئیل در نیمروز فرود آمد، بلافاصله پس از گذر خورشید از زوال، پیامبر ﷺ را در این نماز کنار کعبه در برابر شاهدان مکه پیشوایی کرد و سپس در دو روز بعد وقت هر نماز را آموزش داد. این لحظه‌ای بود که فرمان مجرد "پنجاه به پنج" شکل دیدنی و زنده‌ای یافت. نخستین نماز جماعت در تاریخ اسلام نمازی ظهر بود که پیامبر ﷺ کنار کعبه با خدیجه (رض) و علی نوجوان (رض) پشت سر خود گزارد.`, zh: `与其他四时一样，晌礼亦于登霄之夜被定为主命。重要的是：晌礼乃吉卜利里（愿主赐他平安）首次实地教授先知ﷺ的拜功  –  在登霄之翌日。吉卜利里于正午、日刚过中天时下降，在天房旁、麦加观者面前为先知ﷺ领此功修，随后于其后两日教授每次拜功之时段。这便是"五十归五"的抽象命令化为可见、可活之形貌的时刻。伊斯兰史上首次集体拜功即是晌礼，由先知ﷺ于天房旁带领赫蒂彻（愿主喜悦之）与年少的阿里（愿主喜悦之）于其身后所行。`, yue: `同其他四時一樣，晌禮亦於登霄之夜被定為主命。重要嘅係：晌禮乃吉卜利里（願主賜佢平安）首次實地教授先知ﷺ嘅拜功  –  喺登霄之翌日。吉卜利里於正午、日剛過中天時下降，喺天房旁、麥加觀者面前為先知ﷺ領呢個功修，隨後於其後兩日教授每次拜功之時段。呢個就係「五十歸五」嘅抽象命令化為可見、可活之形貌嘅時刻。伊斯蘭史上首次集體拜功就係晌禮，由先知ﷺ於天房旁帶領赫蒂徹（願主喜悅之）與年少嘅阿里（願主喜悅之）於其身後所行。`, ja: `他の四つと同様、ズフルもミウラージュの夜に義務付けられた。重要なのは、ズフルがジブリール（に平安あれ）が預言者ﷺに実践的に教えた最初の礼拝だということ  –  ミウラージュの翌日。ジブリールは太陽が南中を過ぎた直後の正午に下り、カアバの傍でマッカの見物人の前で預言者ﷺのイマームとしてこの礼拝を導き、その後二日間ですべての礼拝の時刻を教えた。これは「五十が五へ」という抽象的な命令が目に見える、生きた形を取った瞬間であった。イスラム史上初の集団礼拝はズフル礼拝であり、預言者ﷺがカアバの傍でハディージャ（ラ）と少年アリー（ラ）を後ろに従えて行われた。`, ru: `Как и остальные четыре, Зухр был предписан в Ночь Вознесения. Важно: Зухр  –  первая молитва, которой Джибриль (мир ему) практически обучил Пророка ﷺ  –  на следующий день после Мираджа. Джибриль сошёл в полдень, сразу после прохождения солнцем зенита, возглавил Пророка ﷺ в этой молитве у Каабы перед взорами мекканцев, а затем в течение двух следующих дней научил его времени каждой молитвы. Это был момент, когда абстрактное повеление «пятьдесят свелось к пяти» приняло видимую, прожитую форму. Первая коллективная молитва в исламской истории  –  это молитва Зухр, которую Пророк ﷺ совершил у Каабы с Хадиджей (ра) и юным Али (ра) позади себя.`, es: `Como las otras cuatro, el Dhuhr fue ordenado en la Noche de la Ascensión. Significativamente, el Dhuhr fue la primera oración que Yibril (as) enseñó al Profeta ﷺ de manera práctica  –  el día siguiente a la Mi'raj. Yibril descendió al mediodía, justo después de que el sol pasara su cenit, dirigió al Profeta ﷺ en esta oración junto a la Ka'bah ante los testigos de La Meca, y luego le enseñó el tiempo de cada oración a lo largo de los dos días siguientes. Este fue el momento en que el mandato abstracto de "cincuenta convertidas en cinco" tomó su forma visible y vivida. La primera oración congregacional de la historia islámica fue una oración de Dhuhr, rezada por el Profeta ﷺ junto a la Ka'bah con Jadiya (ra) y el joven Ali (ra) tras él.`, ko: `다른 네 예배처럼 주흐르도 미으라즈의 밤에 의무로 정해졌습니다. 의미심장하게도, 주흐르는 지브릴(평화가 그에게)께서 예언자 ﷺ께 실천적으로 가르치신 첫 예배입니다  –  미으라즈 다음 날에. 지브릴은 정오에, 태양이 정점을 지난 직후 내려와 카바 옆에서 마카의 관망자들 앞에서 예언자 ﷺ와 함께 이 예배의 이맘이 되셨고, 그 다음 이틀에 걸쳐 모든 예배의 시간을 가르치셨습니다. "쉰이 다섯이 된" 추상적인 명령이 보이고 살아있는 형태를 띠게 된 순간이었습니다. 이슬람 역사상 최초의 회중 예배는 주흐르 예배였으며, 예언자 ﷺ께서 카바 옆에서 카디자(라)와 어린 알리(라)를 뒤에 두고 예배하셨습니다.`, ta: `மற்ற நான்கைப் போலவே, ளுஹரும் இஸ்ரா-மிஃராஜ் இரவில் கடமையாக்கப்பட்டது. முக்கியமாக: ஜிப்ரீல் (அலை) நபி ﷺ அவர்களுக்கு நடைமுறையாக கற்பித்த முதல் தொழுகை ளுஹரே  –  மிஃராஜின் மறுநாள். ஜிப்ரீல் நண்பகலில், சூரியன் உச்சத்தைக் கடந்த உடனேயே இறங்கி, மக்காவின் பார்வையாளர்களுக்கு முன்னால் கஅபாவின் அருகே நபி ﷺ அவர்களுக்கு இத்தொழுகையில் இமாமாக நின்று, பின் தொடர்ந்த இரு நாட்களில் ஒவ்வொரு தொழுகையின் வேளையையும் கற்பித்தார். "ஐம்பது ஐந்தாக ஆனது" என்னும் சுருக்கமான கட்டளை காணக்கூடிய, வாழ்நிலை வடிவம் பெற்ற தருணம் இதுவே. இஸ்லாமிய வரலாற்றில் முதல் கூட்டுத் தொழுகை ளுஹர் தொழுகையாகவே இருந்தது  –  நபி ﷺ கஅபாவின் அருகே தம் பின்னால் கதீஜா (ரழி) மற்றும் சிறுவன் அலி (ரழி) ஆகியோருடன் தொழுதார்.`, si: `අනෙක් හතර මෙන්ම සුහ්ර්ද මිඃරාජ් රාත්‍රියේදී අනිවාර්ය කෙරුණි. වැදගත් වශයෙන්: ජිබ්රීල් (ඔහුට සාමය) නබි ﷺ වෙත ප්‍රායෝගිකව ඉගැන්වූ පළමු සලාතය වූයේ සුහ්ර්ය  –  මිඃරාජ්ට පසු දින. ජිබ්රීල් මධ්‍යාහ්නයේ, හිරු මුදුන ඉක්මවා ගිය වහාම බැස, මක්කා නැරඹන්නන් ඉදිරියේ කඃබාව අසළ නබි ﷺ සමඟ මෙම සලාතයේ ඉමාම් ලෙස සිට, පසුව දින දෙකක් පුරා සෑම සලාතයකම කාලය ඉගැන්වූහ. "පනහ පහට හරවන ලද" යන වියුක්ත අණ දෘශ්‍ය, ජීවමාන ස්වරූපයක් ගත් මොහොත මෙයයි. ඉස්ලාම් ඉතිහාසයේ පළමු සමූහ සලාතය වූයේ සුහ්ර් සලාතයකි; නබි ﷺ කඃබාව අසළ පිටුපසින් කදීජා (රළි) සහ බාල අලී (රළි) සමඟ එය ඉටු කළහ.` },
  dhuhr_significance: { en: `Dhuhr is the central pivot of the believer's day  –  it interrupts the height of worldly activity (markets, work, trade) with submission to Allah. The Prophet ﷺ identified the moment of zawal (when the sun has just passed its zenith) as the time when the gates of heaven are opened, which is why he loved to pray voluntary prayers then. The prayer's silent recitation reflects the inward focus required to turn the heart away from the heat and noise of the day. Historically, it was the first prayer prayed openly in congregation after the command to do so came down  –  marking it as the public, visible declaration of Islam.`, ms: `Zuhur adalah paksi tengah hari seorang mukmin  –  ia memutuskan kemuncak aktiviti duniawi (pasar, kerja, perniagaan) dengan ketundukan kepada Allah. Nabi ﷺ mengenal pasti detik zawal (ketika matahari baru sahaja melepasi titik tegaknya) sebagai waktu pintu langit dibuka, sebab itu baginda suka mendirikan solat sunat ketika itu. Bacaan sirri solat ini mencerminkan tumpuan dalaman yang diperlukan untuk memalingkan hati daripada bahang dan bising siang. Dari segi sejarah, ia adalah solat pertama yang didirikan secara terbuka berjemaah selepas perintah untuk berbuat demikian diturunkan  –  menandakannya sebagai pengisytiharan Islam yang terbuka dan terlihat.`, tur: `Öğle, mü'minin gününün merkezî eksenidir  –  dünyevî faaliyetin (çarşı, iş, ticaret) zirvesini Allah'a teslimiyetle keser. Peygamber ﷺ zeval anını (güneşin az önce zevalden geçtiği vakti) gök kapılarının açıldığı vakit olarak tarif etmiş ve o vakitte nafile namaz kılmayı sevmiştir. Sessiz kıraat, gündüzün sıcağından ve gürültüsünden kalbi çevirmek için gereken iç odağı yansıtır. Tarihsel olarak, açıkça cemaatle kılınması emredildikten sonra ilk açıkça cemaatle kılınan namazdır  –  İslam'ın aleni ve görünür ilanı.`, urd: `ظہر مومن کے دن کا مرکزی محور ہے  –  یہ دنیاوی سرگرمیوں کی بلندی (بازار، کام، تجارت) کو اللہ کے سامنے سرنگوں ہو کر روک دیتی ہے۔ نبی ﷺ نے زوال کے لمحے کو (جب سورج ابھی زوال سے گزرا ہو) آسمان کے دروازے کھلنے کا وقت قرار دیا، اور اسی لیے اس وقت نفل پڑھنا پسند فرماتے۔ اس نماز کی سری قراءت دن کی گرمی اور شور سے دل کو ہٹانے کے لیے درکار اندرونی انہماک کی عکاسی کرتی ہے۔ تاریخی طور پر، یہ پہلی نماز ہے جو علانیہ باجماعت ادا کی گئی جب ایسا کرنے کا حکم نازل ہوا  –  یہ اسلام کا کھلا، دکھائی دینے والا اعلان تھا۔`, ben: `যোহর মুমিনের দিনের কেন্দ্রীয় ভিত্তি  –  এটি দুনিয়াবি কাজের শীর্ষ মুহূর্তকে (বাজার, কাজ, ব্যবসা) আল্লাহর প্রতি আত্মসমর্পণ দ্বারা বিরতি দেয়। নবী ﷺ যাওয়ালের মুহূর্তকে (সূর্য সবেমাত্র মধ্যাকাশ অতিক্রম করার সময়) আসমানের দরজা খোলার সময় হিসেবে চিহ্নিত করেছেন, এ কারণেই তিনি তখন নফল নামাজ পড়তে ভালোবাসতেন। এই নামাজের সিররি (নীরব) কেরাত দিনের তাপ ও কোলাহল থেকে হৃদয়কে সরিয়ে আনার অভ্যন্তরীণ মনোযোগকে প্রতিফলিত করে। ঐতিহাসিকভাবে, প্রকাশ্যে জামাতে আদায়ের আদেশ আসার পর এটিই প্রথম নামাজ যা প্রকাশ্যে জামাতে আদায় করা হয়েছিল  –  এটি ছিল ইসলামের প্রকাশ্য, দৃশ্যমান ঘোষণা।`, fas: `ظهر محور مرکزی روز مؤمن است  –  اوج فعالیت دنیوی (بازار، کار، تجارت) را با تسلیم در برابر خدا قطع می‌کند. پیامبر ﷺ لحظه زوال را (هنگامی که خورشید تازه از نصف النهار گذشته) زمان گشایش درهای آسمان دانست و از این رو خواندن نوافل را در آن وقت دوست می‌داشت. قرائت آرام این نماز بازتاب تمرکز درونی لازم برای منصرف کردن دل از گرما و سروصدای روز است. از نظر تاریخی، نخستین نمازی است که پس از فرمان به جماعت آشکار، آشکارا به جماعت گزارده شد  –  اعلام علنی و دیدنی اسلام.`, zh: `晌礼乃信士一日之中枢  –  以归服真主中止世俗活动（市场、工作、贸易）之巅峰。先知ﷺ将日过中天之刹那（zawal，太阳刚过中天）识为天门开启之时，故喜在此时礼副功。此功修之低声诵读，反映出从昼之炎热与喧嚣中收摄心神所需的内在专注。历史上，自降命公开举行集体拜功以来，它是首次公开集体礼拜的功修  –  标志着伊斯兰之公开、可见之宣告。`, yue: `晌禮乃信士一日之中樞  –  以歸服真主中止世俗活動（市場、工作、貿易）之巔峰。先知ﷺ將日過中天之剎那（zawal，太陽剛過中天）識為天門開啟之時，故喜喺此時禮副功。呢個功修之低聲誦讀，反映出從晝之炎熱與喧囂中收攝心神所需嘅內在專注。歷史上，自降命公開舉行集體拜功以嚟，佢係首次公開集體禮拜嘅功修  –  標誌住伊斯蘭之公開、可見之宣告。`, ja: `ズフルは信者の一日の中心軸である  –  世俗の活動（市場、仕事、商売）の最盛時を、アッラーへの服従によって中断する。預言者ﷺは太陽が南中を過ぎたばかりのザワールの瞬間を、天の門が開かれる時と定め、その時に任意の礼拝を行うことを愛された。この礼拝の無声の朗誦は、昼の熱と喧噪から心を引き離すために必要な内なる集中を反映する。歴史的には、公然と集団で行うよう命じられて以来、初めて公然と集団礼拝として行われた礼拝であり  –  イスラムの公の、目に見える宣言を印した。`, ru: `Зухр  –  центральная ось дня верующего  –  он прерывает пик мирской деятельности (рынки, работу, торговлю) покорностью Аллаху. Пророк ﷺ определил момент заваля (когда солнце только что прошло зенит) как время, когда открываются врата небес, и потому любил совершать добровольные молитвы в это время. Тихое чтение этой молитвы отражает внутреннюю сосредоточенность, нужную, чтобы отвернуть сердце от жары и шума дня. Исторически это первая молитва, открыто совершённая в коллективе после повеления делать так открыто  –  что сделало её публичным, видимым провозглашением ислама.`, es: `El Dhuhr es el eje central del día del creyente  –  interrumpe el punto álgido de la actividad mundana (mercados, trabajo, comercio) con sumisión a Allah. El Profeta ﷺ identificó el momento de zawal (cuando el sol acaba de pasar su cenit) como el tiempo en que se abren las puertas del cielo, por lo que amaba rezar oraciones voluntarias entonces. La recitación silenciosa de esta oración refleja el enfoque interior requerido para apartar el corazón del calor y el bullicio del día. Históricamente, fue la primera oración rezada abiertamente en congregación tras la orden de hacerlo  –  marcándola como la declaración pública y visible del islam.`, ko: `주흐르는 신자 하루의 중심 축입니다  –  세속 활동(시장, 일, 무역)의 정점을 알라께 대한 복종으로 중단시킵니다. 예언자 ﷺ께서는 자왈의 순간(태양이 막 정점을 지난 때)을 하늘의 문이 열리는 때로 지목하셨고, 그 때에 자발 예배를 사랑하셨습니다. 이 예배의 무성 낭송은 한낮의 열기와 소음으로부터 마음을 돌리는 데 필요한 내면의 집중을 반영합니다. 역사적으로 공개적 회중 예배 명령이 내린 후 공개적으로 회중 예배로 행해진 첫 예배였습니다  –  이슬람의 공개적이고 가시적인 선언이었습니다.`, ta: `விசுவாசியின் நாளின் மைய அச்சாக ளுஹர் இருக்கிறது  –  உலகியல் செயல்பாட்டின் (சந்தைகள், வேலை, வாணிபம்) உச்சத்தை அல்லாஹ்விற்கான கீழ்ப்படிதலால் இடைநிறுத்துகிறது. நபி ﷺ ஸவாலின் தருணத்தை (சூரியன் உச்சத்தைக் கடந்த உடனேயே) வானத்தின் கதவுகள் திறக்கப்படும் நேரம் எனக் கூறி, அப்போது நஃபில் தொழ விரும்பினார். இத்தொழுகையின் அமைதியான ஓதல், நாளின் வெப்பத்திலிருந்தும் இரைச்சலிலிருந்தும் இதயத்தைத் திருப்ப தேவையான உள் கவனத்தைப் பிரதிபலிக்கிறது. வரலாற்று ரீதியாக, கூட்டுத் தொழுகையை வெளிப்படையாகச் செய்ய கட்டளை வந்த பிறகு வெளிப்படையாக கூட்டுத் தொழுகையாக நிறைவேற்றப்பட்ட முதல் தொழுகை  –  இஸ்லாத்தின் வெளிப்படையான, காணக்கூடிய பிரகடனம்.`, si: `සුහ්ර් යනු විශ්වාසවන්තයාගේ දිනයේ කේන්ද්‍රීය අක්ෂයයි  –  ලෞකික ක්‍රියාකාරකම්වල (වෙළඳපොළ, වැඩ, වෙළඳාම) උපරිමය අල්ලාහ්ට යටත් වීමෙන් බිඳ දමයි. නබි ﷺ සවාල් මොහොත (හිරු දැන්මත් මුදුන ඉක්මවා ඇති විට) අහසේ දොරටු විවර වන කාලය ලෙස හඳුනා ගත් අතර, එම නිසා එවිට ස්වේච්ඡා සලාත කිරීමට ආදරය කළහ. මෙම සලාතයේ නිහඬ කියවීම, දවසේ උෂ්ණයෙන් හා ඝෝෂාවෙන් හදවත වෙනතකට හැරවීමට අවශ්‍ය අභ්‍යන්තර අවධානය පිළිබිඹු කරයි. ඓතිහාසිකව, එය ප්‍රසිද්ධ සමූහ සලාත ලෙස කරන ලෙස අණ පැමිණි පසු ප්‍රසිද්ධියේ සමූහ වශයෙන් ඉටු කරන ලද පළමු සලාතය  –  ඉස්ලාමයේ ප්‍රසිද්ධ, දෘශ්‍යමාන ප්‍රකාශය.` },
  dhuhr_proof_q: { en: `"Establish prayer at the decline of the sun (li-duluki ash-shams) until the darkness of the night, and the recitation of dawn..." (Al-Isra' 17:78). Classical commentators (Ibn 'Abbas, Mujahid, Qatadah) explain "duluk ash-shams" as the sun's declination from its zenith, identifying this verse as the textual establishment of Dhuhr, Asr, Maghrib and Isha. Also: "Indeed, prayer has been decreed upon the believers a decree of specified times." (An-Nisa' 4:103).`, ms: `"Dirikanlah solat sejak gelincirnya matahari (li-duluki ash-shams) hingga kegelapan malam, dan bacaan fajar..." (Al-Isra' 17:78). Mufassir klasik (Ibn 'Abbas, Mujahid, Qatadah) menjelaskan "duluk ash-shams" sebagai gelincir matahari dari titik tegaknya, mengenal pasti ayat ini sebagai dalil nas bagi Zuhur, Asar, Maghrib dan Isyak. Juga: "Sesungguhnya solat itu adalah fardu yang ditentukan waktunya ke atas orang-orang beriman." (An-Nisa' 4:103).`, tur: `"Güneşin batıya kaymasından (li-dülûki'ş-şems) gecenin karanlığına dek namazı kıl ve sabah Kur'an'ını..." (İsrâ 17:78). Klasik müfessirler (İbn Abbas, Mücâhid, Katâde) "dülûku'ş-şems"i güneşin zevalden meyletmesi olarak açıklar ve bu âyeti Öğle, İkindi, Akşam ve Yatsı'nın naslî dayanağı olarak görür. Ayrıca: "Şüphesiz namaz, mü'minlere belirli vakitlerde farz kılınmıştır." (Nisâ 4:103).`, urd: `"نماز قائم کرو سورج کے ڈھلنے سے (لدلوک الشمس) رات کے اندھیرے تک، اور فجر کی قراءت..." (الإسراء ۱۷:۷۸)۔ کلاسیکی مفسرین (ابن عباس، مجاہد، قتادہ) "دلوک الشمس" کی تفسیر سورج کے زوال سے ڈھلنا کرتے ہیں اور اس آیت کو ظہر، عصر، مغرب اور عشاء کی نصی دلیل قرار دیتے ہیں۔ نیز: "بے شک نماز مومنوں پر مقررہ اوقات میں فرض کی گئی ہے۔" (النساء ۴:۱۰۳)۔`, ben: `"সূর্য ঢলে পড়া থেকে (লি-দুলূকিশ শামস) রাতের অন্ধকার পর্যন্ত নামাজ কায়েম করো, এবং ফজরের কেরাত..." (আল-ইসরা ১৭:৭৮)। ধ্রুপদী তাফসিরকারগণ (ইবন আব্বাস, মুজাহিদ, কাতাদাহ) "দুলূকুশ শামস"-কে সূর্যের মধ্যাকাশ থেকে ঢলে পড়া হিসেবে ব্যাখ্যা করেন এবং এই আয়াতকে যোহর, আসর, মাগরিব ও ইশার নসী প্রমাণ হিসেবে চিহ্নিত করেন। আরও: "নিশ্চয়ই নামাজ মুমিনদের উপর নির্ধারিত সময়ে ফরজ করা হয়েছে।" (আন-নিসা ৪:১০৩)।`, fas: `"نماز را از زوال خورشید (لِدُلُوک الشمس) تا تاریکی شب برپا دار، و قرائت فجر..." (الإسراء ۱۷:۷۸). مفسران کلاسیک (ابن‌عباس، مجاهد، قتاده) "دلوک الشمس" را میل خورشید از زوال می‌دانند و این آیه را دلیل نصی برای ظهر، عصر، مغرب و عشاء برمی‌شمارند. همچنین: "همانا نماز بر مؤمنان در اوقاتی معین واجب شده است." (النساء ۴:۱۰۳).`, zh: `「自日西斜（li-duluki ash-shams）至夜暗，你当谨守拜功，并谨守晨礼之诵读……」（夜行章17:78）。古典经注家（伊本·阿巴斯、穆贾希德、卡塔达）将「dulūk ash-shams」释为日过中天后之偏斜，并以此节作为晌、晡、昏、宵四时之经文依据。又：「拜功对于信士确是在特定时段被规定的功修。」（妇女章4:103）`, yue: `「自日西斜（li-duluki ash-shams）至夜暗，你當謹守拜功，並謹守晨禮之誦讀……」（夜行章17:78）。古典經注家（伊本·阿巴斯、穆賈希德、卡塔達）將「dulūk ash-shams」釋為日過中天後之偏斜，並以此節作為晌、晡、昏、宵四時之經文依據。又：「拜功對於信士確係喺特定時段被規定嘅功修。」（婦女章4:103）`, ja: `「太陽が傾く時（リ＝ドゥルーキ・アッ＝シャムス）から夜の暗闇まで礼拝を確立せよ、そして夜明けの朗誦を……」（夜の旅章 17:78）。古典の注釈家たち（イブン・アッバース、ムジャーヒド、カターダ）は「ドゥルーク・アッ＝シャムス」を太陽の南中からの傾きと解し、この節をズフル、アスル、マグリブ、イシャーの聖典的根拠と認める。また：「まことに礼拝は信者たちに、定められた時刻における義務として定められている。」（婦人章 4:103）`, ru: `«Совершай молитву от склонения солнца (ли-дулюки ш-шамс) до ночной тьмы, и чтение на рассвете…» (Аль-Исра 17:78). Классические комментаторы (Ибн Аббас, Муджахид, Катада) объясняют «дулюк аш-шамс» как склонение солнца с зенита, видя в этом аяте текстуальное установление Зухра, Асра, Магриба и Иша. Также: «Поистине, молитва предписана верующим как обязанность в определённое время.» (Ан-Ниса 4:103).`, es: `"Establece la oración desde la declinación del sol (li-duluki ash-shams) hasta la oscuridad de la noche, y la recitación del alba…" (Al-Isra' 17:78). Los exegetas clásicos (Ibn 'Abbas, Muyahid, Qatadah) explican "duluk ash-shams" como la declinación del sol desde su cenit, identificando este versículo como el sustento textual de Dhuhr, Asr, Maghrib e Isha. También: "En verdad, la oración ha sido decretada para los creyentes en tiempos específicos." (An-Nisa' 4:103).`, ko: `"태양이 기울 때부터(리-둘루키 앗샴스) 밤의 어둠까지 예배를 세우라, 그리고 새벽의 낭송…" (알이스라 17:78). 고전 주석가들(이븐 압바스, 무자히드, 카타다)은 "둘루크 앗샴스"를 태양의 정점에서의 기울어짐으로 설명하며, 이 구절을 주흐르·아스르·마그립·이샤의 성전적 근거로 본다. 또한: "진실로 예배는 신자들에게 정해진 시간들에 의무로 정해졌느니라." (안니사 4:103).`, ta: `"சூரியன் சாயத் தொடங்குவதிலிருந்து (லி-துலூகி அஷ்-ஷம்ஸ்) இரவின் இருள் வரை தொழுகையை நிலைநிறுத்துவீராக, மற்றும் விடியலின் ஓதலையும்..." (அல்-இஸ்ரா 17:78). கிளாசிக்கல் தஃப்ஸீர் அறிஞர்கள் (இப்னு அப்பாஸ், முஜாஹித், கதாதா) "துலூக் அஷ்-ஷம்ஸ்" என்பதை சூரியன் உச்சத்திலிருந்து சாய்வதாக விளக்கி, இவ்வசனத்தை ளுஹர், அஸ்ர், மக்ரிப், இஷாவின் வேதவாக்கு ஆதாரமாகக் காண்கின்றனர். மேலும்: "நிச்சயமாக தொழுகை விசுவாசிகள் மீது குறிப்பிட்ட நேரங்களில் கடமையாக விதிக்கப்பட்டுள்ளது." (அன்-நிஸா 4:103).`, si: `"සූර්යයාගේ බැසීමේ සිට (ලි-දුලූකි අෂ්-ෂම්ස්) රාත්‍රියේ අන්ධකාරය දක්වා සලාතය ස්ථාපිත කරන්න, සහ අරුණෝදයේ පාරායනය..." (අල්-ඉස්රා 17:78). සම්භාව්‍ය විවරණකරුවන් (ඉබ්නු අබ්බාස්, මුජාහිද්, කතාදා) "දුලූක් අෂ්-ෂම්ස්" යනු හිරුගේ මුදුනේ සිට බැසීම ලෙස පැහැදිලි කරති, මෙම වැකිය සුහ්ර්, අස්ර්, මග්රිබ් සහ ඉෂාගේ පාඨ පදනම ලෙස හඳුනා ගනිති. තවද: "සැබැවින්ම සලාතය විශ්වාසවන්තයන් කෙරෙහි නියමිත වේලාවන්හි අනිවාර්ය යුතුකමක් ලෙස නියම කර ඇත." (අන්-නිසා 4:103).` },
  dhuhr_proof_h: { en: `Jibril (as) led the Prophet ﷺ in Dhuhr immediately after zawal (the sun's first decline) at the Ka'bah, then again the next day when the shadow of every object was equal to its length, and said: "The time of Dhuhr is between these two." (Tirmidhi 149, Abu Dawud 393). The Prophet ﷺ also said: "The five daily prayers and Friday to Friday and Ramadan to Ramadan are expiations for what is between them as long as major sins are avoided." (Muslim 233). And: "The likeness of the five prayers is that of a river flowing at the door of one of you, in which he bathes five times a day. Would any filth remain on him?" (Bukhari 528, Muslim 667).`, ms: `Jibril (as) mengimamkan Nabi ﷺ pada solat Zuhur sebaik sahaja selepas zawal (gelincir matahari yang pertama) di Kaabah, kemudian pada hari berikutnya ketika bayang setiap objek sama dengan panjangnya, dan bersabda: "Waktu Zuhur adalah antara kedua-dua ini." (Tirmidhi 149, Abu Dawud 393). Nabi ﷺ juga bersabda: "Lima solat sehari semalam, Jumaat ke Jumaat, dan Ramadan ke Ramadan menghapuskan dosa antaranya selagi dosa besar dijauhi." (Muslim 233). Dan: "Perumpamaan lima solat itu seperti sungai yang mengalir di pintu salah seorang daripada kamu, di mana dia mandi lima kali sehari. Adakah masih ada kekotoran padanya?" (Bukhari 528, Muslim 667).`, tur: `Cibril (as), Kâbe'de zevalin hemen ardından (güneşin ilk meyli) Peygamber'e ﷺ Öğle namazını kıldırdı, ertesi gün de her şeyin gölgesi kendi boyuna eşit olduğunda kıldırdı ve "Öğle vakti bu ikisinin arasıdır." dedi (Tirmizî 149, Ebû Dâvûd 393). Peygamber ﷺ ayrıca buyurdu: "Beş vakit namaz, Cumadan Cumaya, Ramazandan Ramazana, büyük günahlardan kaçınıldığı sürece aralarındaki günahlara keffarettir." (Müslim 233). Ve: "Beş vakit namazın misali, birinizin kapısının önünden akan ve günde beş kez yıkandığı bir nehir gibidir. Üzerinde kir kalır mı?" (Buhârî 528, Müslim 667).`, urd: `جبریل (ع) نے کعبہ کے پاس زوال کے فوراً بعد (سورج کی پہلی ڈھلائی پر) نبی ﷺ کو ظہر کی نماز پڑھائی، پھر اگلے دن جب ہر چیز کا سایہ اس کی اپنی لمبائی کے برابر تھا، اور فرمایا: "ظہر کا وقت ان دونوں کے درمیان ہے۔" (ترمذی ۱۴۹، ابو داؤد ۳۹۳)۔ نبی ﷺ نے یہ بھی فرمایا: "پانچ وقت کی نمازیں، ایک جمعہ سے دوسرے جمعہ تک، اور ایک رمضان سے دوسرے رمضان تک ان کے درمیان کے گناہوں کا کفارہ ہیں جب تک کبیرہ گناہوں سے بچا جائے۔" (مسلم ۲۳۳)۔ اور: "پانچ نمازوں کی مثال ایسی ہے جیسے تم میں سے کسی کے دروازے پر بہنے والی نہر جس میں وہ دن میں پانچ بار غسل کرے۔ کیا کوئی میل اس پر باقی رہے گی؟" (بخاری ۵۲۸، مسلم ۶۶۷)۔`, ben: `জিবরিল (আ) কাবার পাশে যাওয়ালের পরপরই (সূর্যের প্রথম ঢলে পড়া) নবী ﷺ-কে যোহরের নামাজে ইমামতি করালেন, এরপর পরের দিন যখন প্রতিটি বস্তুর ছায়া তার নিজের দৈর্ঘ্যের সমান হলো, এবং বললেন: "যোহরের সময় এই দুইয়ের মাঝে।" (তিরমিযি ১৪৯, আবু দাউদ ৩৯৩)। নবী ﷺ আরও বলেছেন: "পাঁচ ওয়াক্ত নামাজ, এক জুমা থেকে আরেক জুমা, এবং এক রমজান থেকে আরেক রমজান  –  বড় গুনাহ থেকে বাঁচা পর্যন্ত এসবের মধ্যবর্তী গুনাহের কাফফারা।" (মুসলিম ২৩৩)। আরও: "পাঁচ ওয়াক্ত নামাজের উপমা যেন তোমাদের কারো দরজায় বহমান নদী, যাতে সে দিনে পাঁচবার গোসল করে। তাতে কি কোনো ময়লা অবশিষ্ট থাকবে?" (বুখারি ৫২৮, মুসলিম ৬৬৭)।`, fas: `جبرئیل (ع) در کنار کعبه بلافاصله پس از زوال (نخستین میل خورشید) امام نماز ظهر پیامبر ﷺ شد، سپس روز بعد آنگاه که سایه هر چیز برابر خودش شد، و فرمود: "وقت ظهر میان این دو است." (ترمذی ۱۴۹، ابوداود ۳۹۳). پیامبر ﷺ نیز فرمود: "نمازهای پنجگانه و جمعه تا جمعه و رمضان تا رمضان، تا زمانی که از کبائر اجتناب شود، کفاره گناهان میان آن‌هاست." (مسلم ۲۳۳). و: "مثل نمازهای پنجگانه چون نهری است جاری بر در یکی از شما که روزی پنج بار در آن شست‌وشو کند. آیا چیزی از چرک بر او باقی می‌ماند؟" (بخاری ۵۲۸، مسلم ۶۶۷).`, zh: `吉卜利里（愿主赐他平安）于天房旁，在日刚过中天（zawal）后立即带领先知ﷺ礼晌礼，翌日于每物之影与其本身等长时再带领一次，并言：「晌礼之时段在此二者之间。」（提尔米兹149，艾布·达伍德393）。先知ﷺ又言：「五时拜功、自此主麻至下一主麻、自此拉马丹至下一拉马丹，凡远离大罪者，皆为其间罪过之赎。」（穆斯林233）。又：「五时拜功好比流经你们家门的河流，每日于其中沐浴五次，身上还会留有污垢吗？」（布哈里528，穆斯林667）`, yue: `吉卜利里（願主賜佢平安）喺天房旁，喺日剛過中天（zawal）後立即帶領先知ﷺ禮晌禮，翌日於每物之影與其本身等長時再帶領一次，並話：「晌禮之時段喺此二者之間。」（提爾米茲149，艾布·達伍德393）。先知ﷺ又話：「五時拜功、自此主麻至下一主麻、自此拉馬丹至下一拉馬丹，凡遠離大罪者，皆為其間罪過之贖。」（穆斯林233）。又：「五時拜功好比流經你哋家門嘅河流，每日於其中沐浴五次，身上仲會留有污垢嗎？」（布哈里528，穆斯林667）`, ja: `ジブリール（に平安あれ）はカアバの傍で、ザワール（太陽の最初の傾き）の直後に預言者ﷺのズフル礼拝のイマームとなり、翌日にはあらゆるものの影がそれ自身の長さに等しくなる時に再びイマームとなり、「ズフルの時はこの二つの間である」と仰せられた（ティルミズィー149、アブー・ダーウード393）。預言者ﷺはまた仰せられた：「五時の礼拝、金曜から金曜、ラマダーンからラマダーンは、大罪が避けられている限り、その間の罪を贖うものである。」（ムスリム233）。また：「五時の礼拝の譬えは、あなたがたの一人の戸の前を流れる川のごとし。日に五度浴びるなら、彼に汚れが残るだろうか。」（ブハーリー528、ムスリム667）`, ru: `Джибриль (мир ему) возглавил Пророка ﷺ в Зухре сразу после заваля (первого склонения солнца) у Каабы, затем на следующий день, когда тень каждого предмета сравнялась с его длиной, и сказал: «Время Зухра между этими двумя.» (Тирмизи 149, Абу Дауд 393). Пророк ﷺ также сказал: «Пять ежедневных молитв, пятница до пятницы и Рамадан до Рамадана  –  искупление за то, что между ними, пока избегаются великие грехи.» (Муслим 233). И: «Подобие пяти молитв  –  как река, текущая у двери одного из вас, в которой он купается пять раз в день. Останется ли на нём грязь?» (Бухари 528, Муслим 667).`, es: `Yibril (as) dirigió al Profeta ﷺ en el Dhuhr inmediatamente después del zawal (la primera declinación del sol) junto a la Ka'bah, y al día siguiente cuando la sombra de cada objeto era igual a su longitud, y dijo: "El tiempo del Dhuhr está entre estos dos." (Tirmidhi 149, Abu Dawud 393). El Profeta ﷺ también dijo: "Las cinco oraciones diarias, de viernes a viernes y de Ramadán a Ramadán son expiación de lo que hay entre ellos mientras se eviten los pecados mayores." (Muslim 233). Y: "El símil de las cinco oraciones es el de un río que fluye en la puerta de uno de vosotros, en el que se baña cinco veces al día. ¿Quedaría suciedad en él?" (Bujari 528, Muslim 667).`, ko: `지브릴(평화가 그에게)께서는 카바 옆에서 자왈(태양의 첫 기울어짐) 직후 예언자 ﷺ와 함께 주흐르 예배의 이맘이 되셨고, 다음 날 모든 물체의 그림자가 자체 길이와 같아질 때 다시 이맘이 되셨으며, 말씀하셨다: "주흐르의 시간은 이 둘 사이이다." (티르미디 149, 아부 다우드 393). 예언자 ﷺ께서는 또한 말씀하셨다: "다섯 일일 예배, 금요일에서 금요일, 라마단에서 라마단은, 큰 죄들이 피해지는 한, 그 사이의 죄들에 대한 속죄이다." (무슬림 233). 또한: "다섯 예배의 비유는 너희 중 한 사람의 문 앞에 흐르는 강과 같으니, 하루 다섯 번 그 속에서 목욕한다. 그에게 더러움이 남아 있겠는가?" (부카리 528, 무슬림 667).`, ta: `ஜிப்ரீல் (அலை) கஅபாவின் அருகே ஸவாலுக்கு (சூரியனின் முதல் சாய்வு) உடனேயே நபி ﷺ அவர்களுக்கு ளுஹர் தொழுகையில் இமாமாக நின்றார், பின் மறுநாள் ஒவ்வொரு பொருளின் நிழலும் அதன் சொந்த நீளத்திற்குச் சமமாகும்போது மீண்டும், கூறினார்: "ளுஹரின் வேளை இவ்விரண்டிற்கும் இடையே." (திர்மிதி 149, அபூ தாவூத் 393). நபி ﷺ மேலும் கூறினார்: "ஐந்து வேளைத் தொழுகைகள், ஒரு ஜும்ஆவிலிருந்து இன்னொரு ஜும்ஆ வரை, ஒரு ரமழானிலிருந்து இன்னொரு ரமழான் வரை  –  பெருங்குற்றங்கள் தவிர்க்கப்படும் வரை அவற்றுக்கு இடையேயான பாவங்களுக்குப் பரிகாரம்." (முஸ்லிம் 233). மேலும்: "ஐந்து தொழுகைகளின் உவமை, உங்களில் ஒருவரின் வாசலில் ஓடும் ஆற்றைப் போன்றது  –  அதில் நாளில் ஐந்து முறை அவர் குளிக்கிறார். அவர் மீது அழுக்கு ஏதேனும் மீதியிருக்குமா?" (புகாரி 528, முஸ்லிம் 667).`, si: `ජිබ්රීල් (ඔහුට සාමය) කඃබාව අසළ සවාල්ට (හිරුගේ පළමු බැසීම) පසු වහාම නබි ﷺ සමඟ සුහ්ර් සලාතයේ ඉමාම් වශයෙන් සිට, පසුදින සෑම වස්තුවකගේම සෙවණැල්ල එහි දිගට සමාන වූ විට නැවතත් ඉමාම් වශයෙන් සිට පැවසූහ: "සුහ්ර්ගේ කාලය මේ දෙක අතරයි." (තිර්මිදී 149, අබූ දාවූද් 393). නබි ﷺ තවද පැවසූහ: "පංච දෛනික සලාත, සිකුරාදාවේ සිට සිකුරාදාවට, රමදානයේ සිට රමදානයට, මහා පාප වළක්වා ගන්නා තාක්, ඒවා අතර ඇති දෑට ප්‍රතිකර්ම වේ." (මුස්ලිම් 233). තවද: "පංච සලාතයේ උපමාව, ඔබ අතුරින් කෙනෙකුගේ දොරටුව ඉදිරිපිට ගලා බසින ගඟකට සමානය; දිනකට පස් වරක් එහි ස්නානය කරයි. ඔහුට කිලුටක් ඉතිරිවේද?" (බුහාරි 528, මුස්ලිම් 667).` },
  dhuhr_recitation: { en: `Silent (sirri) in all four rak'ahs. The Sunnah length is medium-to-long: the Prophet ﷺ would recite around the length of Surah as-Sajdah (32  –  about 30 verses) in the first two rak'ahs, and roughly half of that in the third and fourth. He varied the surahs but often selected from the middle section of the Mufassal (chapters from al-Buruj 85 onward), though longer surahs are equally Sunnah. In the third and fourth rak'ahs only Surah al-Fatihah is recited, with no additional surah, in the standard view.`, ms: `Sirri (perlahan) dalam keempat-empat rakaat. Panjang sunnah adalah pertengahan hingga panjang: Nabi ﷺ membaca kira-kira panjang Surah as-Sajdah (32  –  sekitar 30 ayat) dalam dua rakaat pertama, dan kira-kira separuh dalam rakaat ketiga dan keempat. Baginda mempelbagaikan surah tetapi sering memilih daripada bahagian tengah Mufassal (surah dari al-Buruj 85 dan seterusnya), walaupun surah yang lebih panjang juga sunnah. Dalam rakaat ketiga dan keempat, hanya Surah al-Fatihah dibaca, tanpa surah tambahan, mengikut pendapat piawai.`, tur: `Dört rekâtın hepsinde sirrî (sessiz). Sünnet uzunluk orta-uzundur: Peygamber ﷺ ilk iki rekâtta Secde suresi (32  –  yaklaşık 30 âyet) uzunluğunda okurdu, üçüncü ve dördüncüde bunun yarısı kadar. Sureleri çeşitlendirir, fakat genellikle Mufassal'ın orta kısmından (Bürûc 85'ten itibaren) seçerdi; daha uzun sureler de sünnettir. Standart görüşe göre üçüncü ve dördüncü rekâtlarda yalnızca Fâtiha okunur, ek sure yoktur.`, urd: `چاروں رکعتوں میں سرّاً (آہستہ)۔ سنّت طوالت درمیانہ سے طویل: نبی ﷺ پہلی دو رکعتوں میں تقریباً سورۃ السجدہ (۳۲  –  تقریباً ۳۰ آیات) جتنا پڑھتے، اور تیسری چوتھی میں اس کا قریباً نصف۔ آپ سورتیں متبدّل فرماتے مگر اکثر مفصل کے درمیانی حصے سے (سورۃ البروج ۸۵ سے آگے) چنتے، اگرچہ طویل تر سورتیں بھی سنّت ہیں۔ معیاری رائے میں تیسری اور چوتھی رکعت میں صرف سورۃ الفاتحہ پڑھی جاتی ہے، کوئی اضافی سورت نہیں۔`, ben: `চার রাকাতেই সিররি (নীরবে)। সুন্নাহ দৈর্ঘ্য মধ্যম থেকে দীর্ঘ: নবী ﷺ প্রথম দুই রাকাতে সূরা আস-সাজদাহর (৩২  –  প্রায় ৩০ আয়াত) সমান কেরাত পড়তেন, এবং তৃতীয় ও চতুর্থ রাকাতে এর প্রায় অর্ধেক। তিনি সূরা পরিবর্তন করতেন কিন্তু প্রায়ই মুফাসসালের মধ্যাংশ থেকে (সূরা আল-বুরূজ ৮৫ এবং পরবর্তী) বেছে নিতেন, যদিও দীর্ঘতর সূরাও সমভাবে সুন্নাহ। মানসম্মত মতে তৃতীয় ও চতুর্থ রাকাতে শুধু সূরা আল-ফাতিহা পড়া হয়, অতিরিক্ত কোনো সূরা নয়।`, fas: `در هر چهار رکعت سرّی (آرام). درازای سنت میانه تا بلند است: پیامبر ﷺ در دو رکعت اول حدوداً به اندازه سوره سجده (۳۲  –  حدود ۳۰ آیه) و در سوم و چهارم تقریباً نصف آن می‌خواند. سوره‌ها را متغیر می‌کرد اما اغلب از بخش میانی مفصل (از بروج ۸۵ به بعد) برمی‌گزید، هرچند سوره‌های بلندتر نیز سنت‌اند. در نظر مرسوم در رکعت سوم و چهارم تنها فاتحه خوانده می‌شود، بدون سوره اضافه.`, zh: `四拜均为低声（西里）。圣行长度为中至长：先知ﷺ于前两拜诵读约《叩头章》（32  –  约30节）之长，于第三、第四拜约其半。所诵之章不一，常自《细分章》之中段（自《星宿章》85起）选取，长章亦同为圣行。依标准之见，第三、第四拜仅诵《开端章》，不加他章。`, yue: `四拜均為低聲（西里）。聖行長度為中至長：先知ﷺ於前兩拜誦讀約《叩頭章》（32  –  約30節）之長，於第三、第四拜約其半。所誦之章不一，常自《細分章》之中段（自《星宿章》85起）選取，長章亦同為聖行。依標準之見，第三、第四拜僅誦《開端章》，不加他章。`, ja: `四ラクアすべてで無声（シッリー）。スンナの長さは中～長：預言者ﷺは最初の二ラクアでサジダ章（32  –  約30節）程度を朗誦され、第三・第四ラクアではその約半分であった。章を変えられたが、しばしばムファッサルの中間部（ブルージュ章 85 以降）から選ばれた。より長い章も同等にスンナである。標準的見解では、第三・第四ラクアではファーティハ章のみ朗誦し、追加の章は無い。`, ru: `Тихо (сирри) во всех четырёх ракатах. Сунновская длина  –  средне-длинная: Пророк ﷺ читал примерно длиной с суру ас-Саджда (32  –  около 30 аятов) в первых двух ракатах, и примерно вдвое короче в третьем и четвёртом. Он варьировал суры, но часто выбирал из средней части Муфассал (с суры аль-Бурудж 85 и далее), хотя более длинные суры также являются сунной. В стандартном мнении в третьем и четвёртом ракатах читается только сура аль-Фатиха, без дополнительной суры.`, es: `Silenciosa (sirri) en los cuatro rak'ahs. La longitud Sunnah es media a larga: el Profeta ﷺ recitaba alrededor de la extensión de la Sura as-Sajdah (32  –  unos 30 versículos) en los dos primeros rak'ahs, y aproximadamente la mitad en el tercero y cuarto. Variaba las suras pero solía elegir de la sección media del Mufassal (capítulos a partir de al-Buruy 85), aunque suras más largas son igualmente Sunnah. En el parecer estándar, en el tercer y cuarto rak'ahs solo se recita la Sura al-Fatiha, sin sura adicional.`, ko: `네 라카 모두 무성(시르리). 순나 길이는 중간에서 긴 편: 예언자 ﷺ께서는 처음 두 라카에서 앗사즈다 장(32  –  약 30구절) 정도 길이로 낭송하셨고, 셋째·넷째 라카에서는 그 약 절반. 장들을 다양하게 하셨으나 자주 무팟살의 중간 부분(알부루즈 85 이후)에서 고르셨다. 더 긴 장도 똑같이 순나. 표준 견해에서 셋째·넷째 라카에서는 알파티하만 낭송하고 추가 장은 없다.`, ta: `நான்கு ரக்அத்களிலும் ஸிர்ரி (அமைதியாக). சுன்னா நீளம் நடுத்தர முதல் நீண்டது வரை: முதல் இரு ரக்அத்களில் நபி ﷺ சூரத்துஸ்-ஸஜ்தா (32  –  சுமார் 30 வசனங்கள்) நீளம் வரை ஓதினார், மூன்றாவது நான்காவதில் அதன் சுமார் பாதி. சூராக்களை மாற்றி வந்தார், ஆனால் அடிக்கடி முஃபஸ்ஸலின் நடுப் பகுதியிலிருந்து (சூரத்துல்-புரூஜ் 85 முதலானவை) தேர்ந்தெடுத்தார்; நீண்ட சூராக்களும் அதே போல் சுன்னாவே. நிலையான கருத்தின்படி மூன்றாவது நான்காவது ரக்அத்களில் ஃபாதிஹா மட்டுமே ஓதப்படுகிறது, கூடுதல் சூரா இல்லை.`, si: `රකඅත් හතරේදීම නිහඬව (සිර්රී). සුන්නා දිගට මධ්‍යම සිට දිගු: නබි ﷺ පළමු රකඅත් දෙකේ අස්-සජ්දා සූරාවට (32  –  වැකි 30 පමණ) ආසන්න දිගකින් කියවූහ, තෙවැන්න සහ සිවුවැන්නේ එහි අඩක් පමණ. සූරා වෙනස් කළත්, බොහෝ විට මුෆස්සල්හි මැද කොටසින් (අල්-බුරූජ් 85 සිට) තෝරාගත් අතර, දිගු සූරාද ඒ හා සමානව සුන්නාවය. සම්මත මතය අනුව තෙවැන්න සහ සිවුවැන්න රකඅත්හිදී අල්-ෆාතිහා පමණක් කියවයි, අතිරේක සූරාවක් නැත.` },
  dhuhr_sunnah_say: { en: `The 4 Sunnah before Dhuhr are prayed as two sets of two with one tasleem each (per the authentic Sunnah). In them recite any moderate-length surah. The 2 Sunnah after Dhuhr the Prophet ﷺ used to pray at home; if you must pray in the masjid, that is permitted. Some narrations also mention two further rak'ahs (totalling four after); both are reported. The Sunnahs before Dhuhr are particularly emphasised  –  on a long Friday "before" they can be substituted by reading Surah al-Kahf, but on weekdays they are kept. Make du'a between the Sunnah and the fard, as zawal is a time of acceptance.`, ms: `Empat rakaat sunat sebelum Zuhur didirikan sebagai dua set dua rakaat dengan satu salam setiap satu (mengikut sunnah yang sahih). Padanya bacalah mana-mana surah sederhana. Dua rakaat sunat selepas Zuhur Nabi ﷺ tunaikan di rumah; jika anda terpaksa di masjid, itu dibenarkan. Beberapa riwayat juga menyebut dua lagi rakaat (jumlah empat selepas); kedua-duanya diriwayatkan. Sunat sebelum Zuhur sangat ditekankan  –  pada Jumaat yang panjang "sebelum" boleh diganti dengan membaca Surah al-Kahf, tetapi pada hari biasa ia dikekalkan. Berdoalah antara sunat dan fardu, kerana zawal adalah waktu pengabulan.`, tur: `Öğleden önceki 4 sünnet, her ikisi bir selamla olmak üzere iki ikili olarak kılınır (sahih sünnete göre). İçinde orta uzunlukta bir sure okunur. Öğleden sonraki 2 sünneti Peygamber ﷺ evde kılardı; mecbur kalırsanız camide kılmak da caizdir. Bazı rivayetler ek iki rekât daha (sonra toplam dört) zikreder; her ikisi de nakledilmiştir. Öğleden önceki sünnetler özellikle önemlidir  –  uzun bir Cuma'da "önce" yerine Kehf okunabilir, fakat hafta içinde kılınır. Zeval bir kabul vakti olduğundan, sünnetle farz arasında dua edin.`, urd: `ظہر سے قبل ۴ رکعت سنّتیں دو دو کے دو سیٹ کے طور پر، ہر سیٹ ایک سلام کے ساتھ ادا کی جاتی ہیں (صحیح سنّت کے مطابق)۔ ان میں کوئی متوسط طوالت کی سورت پڑھیں۔ ظہر کے بعد ۲ سنّت رکعتیں نبی ﷺ گھر میں پڑھتے؛ مسجد میں مجبور ہوں تو جائز ہے۔ بعض روایات میں مزید دو رکعتیں (بعد کل چار) بھی آئی ہیں؛ دونوں ثابت ہیں۔ ظہر سے پہلے کی سنّتیں خصوصاً مؤکد ہیں  –  لمبے جمعے میں "پہلے" کے بدلے سورۃ الکہف پڑھی جا سکتی ہے، مگر دوسرے دنوں میں قائم رکھیں۔ سنّت اور فرض کے درمیان دعا کریں، کیونکہ زوال قبولیت کا وقت ہے۔`, ben: `যোহরের আগের ৪ সুন্নাহ দুই দুই করে দুই সেটে এক সালামে আদায় করা হয় (সহিহ সুন্নাহ অনুসারে)। এতে যেকোনো মাঝারি দৈর্ঘ্যের সূরা পড়ুন। যোহরের পরের ২ সুন্নাহ নবী ﷺ ঘরে আদায় করতেন; মসজিদে আদায় করতে বাধ্য হলে তা অনুমোদিত। কিছু বর্ণনায় আরও দুই রাকাত (পরে মোট চার) উল্লেখ আছে; উভয়ই বর্ণিত। যোহরের আগের সুন্নাহ বিশেষভাবে গুরুত্বপূর্ণ  –  দীর্ঘ জুমার দিনে "আগে" এর পরিবর্তে সূরা আল-কাহফ পড়া যেতে পারে, কিন্তু সপ্তাহান্তের অন্য দিনে তা বহাল রাখুন। সুন্নাহ ও ফরজের মাঝে দোয়া করুন, কারণ যাওয়াল গ্রহণের সময়।`, fas: `چهار رکعت سنت پیش از ظهر به‌صورت دو دو رکعت با یک سلام برای هر دو خوانده می‌شود (طبق سنت صحیح). در آنها سوره‌ای متوسط بخوان. دو رکعت سنت پس از ظهر را پیامبر ﷺ در خانه می‌خواند؛ اگر ناگزیر در مسجد بخوانی، رواست. در برخی روایات دو رکعت دیگر (در مجموع چهار پس از ظهر) نیز آمده؛ هر دو روایت شده‌اند. سنت‌های پیش از ظهر تأکید ویژه دارند  –  در جمعه طولانی به جای "قبل" می‌توان سوره کهف خواند، اما در روزهای دیگر باقی می‌مانند. میان سنت و فرض دعا کن، چرا که زوال زمان اجابت است.`, zh: `晌礼前的4拜圣行依确证圣行以"两两一拜、各一平安词"行之。其中诵读任何中等长度之章。晌礼后的2拜圣行先知ﷺ常于家中礼之；若不得已须在清真寺礼，亦允许。亦有传报言其后另两拜（共四拜于后）；二者皆有传报。晌礼前的圣行尤为受重  –  逢长主麻日，"前"可代以诵《山洞章》，但平日则保留之。圣行与主命之间作祈祷，因zawal为应答之时。`, yue: `晌禮前嘅4拜聖行依確證聖行以「兩兩一拜、各一平安詞」行之。其中誦讀任何中等長度之章。晌禮後嘅2拜聖行先知ﷺ常於家中禮之；若不得已須喺清真寺禮，亦容許。亦有傳報言其後另兩拜（共四拜於後）；二者皆有傳報。晌禮前嘅聖行尤為受重  –  逢長主麻日，「前」可代以誦《山洞章》，但平日則保留之。聖行與主命之間作祈禱，因zawal為應答之時。`, ja: `ズフル前の4スンナは、確証されたスンナに従い二ラクアずつ二組（各々一回のサラーム）で行う。中庸の長さの章を朗誦する。ズフル後の2スンナを預言者ﷺは家で行われた。モスクで行わざるを得ない場合も許される。一部の伝承では更に二ラクア（後に合計四）が言及されており、双方とも伝えられている。ズフル前のスンナは特に重視される  –  長い金曜日には「前」をスーラ・カフ朗誦で代えられるが、平日は保たれる。ザワールは受け入れの時なので、スンナとファルドの間にドゥアを行うこと。`, ru: `4 раката сунны до Зухра совершаются двумя группами по два с одним саламом каждая (по достоверной сунне). В них читай суру средней длины. Два раката сунны после Зухра Пророк ﷺ совершал дома; если приходится в мечети  –  это допустимо. В некоторых преданиях упомянуты ещё два раката (всего четыре после); обе версии переданы. Сунны до Зухра особенно подчёркнуты  –  в длинную пятницу "до" можно заменить чтением суры аль-Кахф, но в будни их сохраняют. Делай дуа между сунной и фардом, ибо заваль  –  время принятия.`, es: `Los 4 rak'ahs Sunnah antes del Dhuhr se rezan como dos series de dos con un solo salam cada una (según la Sunnah auténtica). En ellos recita cualquier sura de extensión moderada. Los 2 rak'ahs Sunnah tras el Dhuhr el Profeta ﷺ los rezaba en casa; si has de rezar en la mezquita, está permitido. Algunas narraciones mencionan también dos rak'ahs adicionales (cuatro en total después); ambos están reportados. Las Sunnahs antes del Dhuhr son particularmente enfatizadas  –  en un viernes largo "antes" puede sustituirse por la lectura de Sura al-Kahf, pero en días entre semana se conservan. Haz du'a entre la Sunnah y el fard, ya que el zawal es tiempo de aceptación.`, ko: `주흐르 전 4 순나는 진실된 순나에 따라 두 라카씩 두 묶음으로 각 묶음 끝에 한 살람으로 예배한다. 그 안에서 중간 길이의 어떤 장을 낭송하라. 주흐르 후 2 순나를 예언자 ﷺ께서는 집에서 예배하셨다; 모스크에서 예배해야만 한다면 허용된다. 일부 전승에는 두 라카가 더(총 네 라카 후) 언급된다; 둘 다 보고되었다. 주흐르 전 순나는 특히 강조된다  –  긴 금요일에 "전" 대신 알카흐프 장 낭송으로 대체할 수 있으나, 평일에는 유지한다. 자왈은 받아들임의 시간이므로 순나와 파르드 사이에 두아하라.`, ta: `ளுஹருக்கு முந்தைய 4 சுன்னாக்கள் சரியான சுன்னாவின்படி இரண்டு இரண்டாக ஒவ்வொன்றும் ஒரு ஸலாமுடன் தொழப்படுகிறது. அவற்றில் எந்த நடுத்தர நீளமான சூராவையும் ஓதவும். ளுஹருக்குப் பின் 2 சுன்னாக்களை நபி ﷺ வீட்டில் தொழுதார்; பள்ளியில் தொழ வேண்டியதாயின் அனுமதிக்கப்பட்டது. சில அறிவிப்புகளில் கூடுதலாக இரு ரக்அத்களும் (பின் மொத்தம் நான்கு) குறிப்பிடப்படுகின்றன; இரண்டும் அறிவிக்கப்பட்டுள்ளன. ளுஹருக்கு முந்தைய சுன்னாக்கள் குறிப்பாக வலியுறுத்தப்பட்டவை  –  நீண்ட வெள்ளியில் "முன்" சூரத்துல்-கஹ்ஃப் ஓதுவதால் மாற்றலாம், ஆனால் மற்ற நாட்களில் அவை வைக்கப்படுகின்றன. ஸவால் ஏற்கப்படும் வேளை என்பதால் சுன்னாவுக்கும் ஃபர்ளுக்கும் இடையே துஆ செய்யுங்கள்.`, si: `සුහ්ර්ට පෙර සුන්නා 4 ක්, සත්‍ය සුන්නාව අනුව රකඅත් දෙක දෙක බැගින් එක් සලාම්කින් ඉටු කරයි. ඒවායේ මධ්‍යම දිගකින් යුතු ඕනෑම සූරාවක් කියවන්න. සුහ්ර්ට පසු සුන්නා රකඅත් 2 නබි ﷺ නිවසේ ඉටු කළහ; මස්ජිදයේ ඉටු කිරීමට බල කරන්නේ නම් එයද අනුමතය. සමහර වාර්තා තවත් රකඅත් දෙකක් (පසුව මුළු හතරක්) සඳහන් කරයි; දෙකම වාර්තා වී ඇත. සුහ්ර්ට පෙර සුන්නා විශේෂයෙන් අවධාරණය කරයි  –  දිගු සිකුරාදාවක "පෙර" වෙනුවට අල්-කහ්ෆ් සූරාව කියවීමෙන් ආදේශ කළ හැක, නමුත් වෙනත් දිනවල පවත්වා ගනී. සවාල් පිළිගැනීමේ වේලාව බැවින් සුන්නාව හා ෆර්ද් අතර දුආ කරන්න.` },
  dhuhr_extras_say: { en: `In addition to the universal post-prayer adhkar, the time after Dhuhr until Asr is a recommended time for reading Quran, voluntary du'a, and reviewing one's day. The Prophet ﷺ would often take a brief midday rest (qaylulah) before or shortly after Dhuhr  –  this is itself a Sunnah, and the morning's productive work is enhanced by it. The 2 Sunnah after Dhuhr should ideally be prayed at home; the Prophet ﷺ taught that the best prayers (after the fard) are those a person performs in his house. Avoid praying nafl in the few minutes immediately before Dhuhr's start (during the heat of zawal itself, before the sun has clearly passed its zenith).`, ms: `Selain zikir umum selepas solat, waktu antara Zuhur dan Asar adalah waktu yang digalakkan untuk membaca al-Quran, doa sunat, dan menilai semula hari anda. Nabi ﷺ sering mengambil rehat ringkas tengah hari (qaylulah) sebelum atau sebaik selepas Zuhur  –  ini sendiri adalah sunnah, dan kerja pagi yang produktif diperkukuh olehnya. Dua sunat selepas Zuhur sebaiknya dilakukan di rumah; Nabi ﷺ mengajar bahawa sebaik-baik solat (selepas fardu) ialah yang dilakukan di rumah. Elakkan solat sunat dalam beberapa minit sebelum Zuhur bermula (semasa kemuncak zawal itu sendiri, sebelum matahari jelas melepasi titik tegaknya).`, tur: `Namaz sonrası umumî zikirlere ek olarak, Öğle ile İkindi arası vakit Kur'an okumak, nafile dua ve günün muhasebesi için tavsiye edilir. Peygamber ﷺ çoğu zaman Öğle'den önce veya hemen sonra kısa bir öğle uykusu (kaylûle) alırdı  –  bu da bir sünnettir ve sabahın verimli işini güçlendirir. Öğle sonrası iki sünnetin tercihen evde kılınması iyidir; Peygamber ﷺ farzdan sonra en hayırlı namazların kişinin evinde kıldıkları olduğunu öğretmiştir. Öğle'nin başlamasından hemen önceki birkaç dakikada (zevalın tam zirvesinde, güneş belirgin biçimde zevalden geçmeden) nafile kılmaktan kaçının.`, urd: `بعد از نماز عمومی اذکار کے علاوہ، ظہر سے عصر تک کا وقت قرآن کی تلاوت، نفل دعا، اور اپنے دن کے جائزے کے لیے مستحب ہے۔ نبی ﷺ اکثر ظہر سے قبل یا اس کے فوراً بعد ایک مختصر دوپہر کا آرام (قیلولہ) فرماتے  –  یہ بھی سنّت ہے، اور صبح کے نتیجہ خیز کام کو تقویت دیتا ہے۔ ظہر کے بعد دو سنّت رکعات بہتر ہے کہ گھر میں ادا کی جائیں؛ نبی ﷺ نے سکھایا کہ فرض کے بعد سب سے بہترین نمازیں وہ ہیں جو انسان اپنے گھر میں پڑھتا ہے۔ ظہر کے آغاز سے بالکل پہلے کے چند منٹوں میں (زوال کی عین چوٹی پر، جب سورج واضح طور پر زوال سے گزر نہ چکا ہو) نفل پڑھنے سے بچیں۔`, ben: `সাধারণ নামাজোত্তর জিকিরের পাশাপাশি, যোহর থেকে আসর পর্যন্ত সময় কুরআন পাঠ, নফল দোয়া এবং নিজের দিনের পর্যালোচনার জন্য উৎসাহিত। নবী ﷺ প্রায়ই যোহরের আগে বা ঠিক পরে একটি সংক্ষিপ্ত মধ্যাহ্ন বিশ্রাম (কাইলূলাহ) নিতেন  –  এটি নিজেই একটি সুন্নাহ, এবং সকালের উৎপাদনশীল কাজ এর দ্বারা শক্তিশালী হয়। যোহরের পর দুই সুন্নাহ আদর্শভাবে ঘরে আদায় করা উচিত; নবী ﷺ শিখিয়েছেন যে ফরজের পরে সর্বোত্তম নামাজগুলো সেগুলো যা একজন তার ঘরে আদায় করে। যোহর শুরুর ঠিক আগের কয়েক মিনিটে (যাওয়ালের শীর্ষে, সূর্য স্পষ্টভাবে মধ্যাকাশ অতিক্রম করার আগে) নফল পড়া এড়িয়ে চলুন।`, fas: `علاوه بر اذکار عمومی پس از نماز، وقت میان ظهر و عصر برای تلاوت قرآن، دعای مستحب و مرور روز توصیه شده. پیامبر ﷺ غالباً پیش از ظهر یا اندکی پس از آن استراحتی کوتاه نیمروزی (قیلوله) داشت  –  این خود سنت است و کار پربازده صبح را تقویت می‌کند. دو سنت پس از ظهر بهتر است در خانه خوانده شود؛ پیامبر ﷺ آموخت بهترین نمازها (پس از فرض) آنهایی است که در خانه گزارده می‌شود. در چند دقیقه پیش از آغاز ظهر (در اوج زوال، پیش از آنکه خورشید آشکارا از نصف النهار بگذرد) از نوافل بپرهیز.`, zh: `除拜功后通用赞念外，晌礼至晡礼之间是诵读《古兰经》、副功祈祷与省思一日之佳时。先知ﷺ常于晌礼前或其后不久略作午时小憩（盖卢拉），此本身即为圣行，并使清晨之高效工作得益。晌礼后两拜圣行宜在家中礼之；先知ﷺ教导，主命之外最佳之礼拜为人于家中所行者。当避免于晌礼开始前数分钟内（zawal之巅、太阳尚未明显过中天之时）礼副功。`, yue: `除拜功後通用讚念外，晌禮至晡禮之間係誦讀《古蘭經》、副功祈禱與省思一日之佳時。先知ﷺ常於晌禮前或其後不久略作午時小憩（蓋盧拉），此本身即為聖行，並令清晨之高效工作得益。晌禮後兩拜聖行宜喺家中禮之；先知ﷺ教導，主命之外最佳之禮拜為人於家中所行者。當避免於晌禮開始前數分鐘內（zawal之巔、太陽尚未明顯過中天之時）禮副功。`, ja: `礼拝後の一般的なズィクルに加えて、ズフルからアスルまでの時間はクルアーン読誦、任意のドゥア、その日の省察に推奨される。預言者ﷺはしばしばズフルの前か直後に短い昼休み（カイルーラ）を取られた  –  これ自体スンナであり、午前中の生産的な働きを支える。ズフル後の二スンナは可能ならば家で行うのが望ましい；預言者ﷺはファルド以外で最も良い礼拝は人が自宅で行うものだと教えられた。ズフル開始直前の数分間（ザワール真っ盛り、太陽がまだ明確に南中を過ぎていない時）には任意の礼拝を避けること。`, ru: `Помимо общих послемолитвенных азкаров, время между Зухром и Асром рекомендовано для чтения Корана, добровольных дуа и осмысления дня. Пророк ﷺ часто брал короткий полуденный отдых (кайлюля) перед Зухром или вскоре после него  –  это сама по себе сунна, и она усиливает продуктивную утреннюю работу. Два раката сунны после Зухра в идеале совершать дома; Пророк ﷺ учил, что лучшие молитвы (после фарда) — те, которые человек совершает в своём доме. Избегай совершения нафл за несколько минут до начала Зухра (в самый пик заваля, до того как солнце явно прошло зенит).`, es: `Además de los adhkar post-oración universales, el tiempo entre el Dhuhr y el Asr es un tiempo recomendado para leer el Corán, du'a voluntario y revisar el día. El Profeta ﷺ solía tomar un breve descanso de mediodía (qaylulah) antes o poco después del Dhuhr  –  esto es en sí una Sunnah, y refuerza el trabajo productivo de la mañana. Los 2 Sunnah tras el Dhuhr idealmente se rezan en casa; el Profeta ﷺ enseñó que las mejores oraciones (tras el fard) son las que uno realiza en su casa. Evita rezar nafl en los pocos minutos previos al inicio del Dhuhr (durante el pico mismo del zawal, antes de que el sol haya pasado claramente su cenit).`, ko: `보편적 예배 후 아드카르 외에, 주흐르에서 아스르 사이는 꾸란 낭송, 자발 두아, 그날의 점검을 위한 권장 시간이다. 예언자 ﷺ께서는 종종 주흐르 전 또는 직후에 짧은 정오 휴식(까일룰라)을 취하셨다  –  이는 그 자체로 순나이며, 아침의 생산적인 일을 강화한다. 주흐르 후 두 순나는 이상적으로 집에서 예배하라; 예언자 ﷺ께서는 파르드를 제외한 최고의 예배는 사람이 자기 집에서 행하는 것이라고 가르치셨다. 주흐르 시작 직전 몇 분 동안(자왈의 정점, 태양이 분명히 정점을 지나기 전)에는 나플 예배를 피하라.`, ta: `பொதுவான தொழுகைக்குப் பின்தைய திக்ருகள் தவிர, ளுஹருக்கும் அஸ்ருக்கும் இடைப்பட்ட நேரம் குர்ஆன் ஓதவும், நஃபில் துஆவும், நாளை மீளாய்வு செய்யவும் பரிந்துரைக்கப்பட்ட நேரம். நபி ﷺ அடிக்கடி ளுஹருக்கு முன் அல்லது சற்று பின்னர் ஒரு குறுகிய நண்பகல் ஓய்வு (கைலூலா) எடுத்துக்கொள்வார்  –  இது தானே ஒரு சுன்னா, காலையின் உற்பத்திகர வேலையை வலுப்படுத்துகிறது. ளுஹருக்குப் பின் 2 சுன்னாக்கள் வீட்டில் தொழுவது சிறந்தது; ஃபர்ளுக்கு வெளியே சிறந்த தொழுகைகள் ஒருவர் தம் வீட்டில் செய்வவை என நபி ﷺ கற்பித்தார். ளுஹர் தொடங்குவதற்கு சில நிமிடங்கள் முன் (ஸவாலின் உச்சத்தில், சூரியன் தெளிவாக உச்சத்தைக் கடப்பதற்கு முன்) நஃபில் தொழுவதைத் தவிர்க்கவும்.`, si: `සලාතයෙන් පසු සාර්වත්‍රික දික්ර්වලට අමතරව, සුහ්ර් සහ අස්ර් අතර කාලය කුර්ආනය කියවීමට, ස්වේච්ඡා දුආ සහ දින සමාලෝචනය සඳහා නිර්දේශිතය. නබි ﷺ බොහෝ විට සුහ්ර්ට පෙර හෝ ඉන් වහාම පසු කෙටි මධ්‍යාහ්න විවේකයක් (කය්ලූලා) ලබා ගත්හ  –  මෙයද සුන්නාවක් වන අතර, උදෑසන ඵලදායී කාර්යය ශක්තිමත් කරයි. සුහ්ර්ට පසු සුන්නා 2 වඩාත් සුදුසු වන්නේ නිවසේ ඉටු කිරීමයි; ෆර්ද් හැර හොඳම සලාත වන්නේ පුද්ගලයෙකු තම නිවසේ ඉටු කරන සලාත බව නබි ﷺ ඉගැන්වූහ. සුහ්ර් ආරම්භවීමට මොහොතකට පෙර මිනිත්තු කිහිපය තුළ (සවාල්හි උපරිමයේදී, හිරු පැහැදිලිව මුදුන ඉක්මවා ඇති පෙර) නෆ්ල් ඉටු කිරීමෙන් වළකින්න.` },
  dhuhr_virtues: { en: `Dhuhr stands at the doorway of "the better half" of the day after zawal  –  the half in which sustenance is sought, with prayer at its threshold to keep the heart anchored. The Prophet ﷺ said the angels of heaven open the gates of the sky at zawal, and praying four rak'ahs of voluntary worship at that moment is a beloved act. Praying Dhuhr in congregation in the Prophet's mosque carries the reward of one thousand prayers, in al-Masjid al-Haram one hundred thousand. In general, every fard prayer in any congregation is twenty-seven times the reward of praying alone (Bukhari 645, Muslim 650).`, ms: `Zuhur berdiri di ambang pintu "separuh hari yang lebih baik" selepas zawal  –  separuh di mana rezeki dicari, dengan solat di ambangnya untuk mengikat hati. Nabi ﷺ bersabda bahawa malaikat langit membuka pintu-pintu langit pada waktu zawal, dan mendirikan empat rakaat solat sunat pada saat itu adalah amalan yang dicintai. Mendirikan Zuhur secara berjemaah di Masjid Nabi membawa pahala seribu solat, di Masjidil Haram seratus ribu. Umumnya, setiap solat fardu secara berjemaah adalah dua puluh tujuh kali pahala bersendirian (Bukhari 645, Muslim 650).`, tur: `Öğle, zevalden sonra "günün daha hayırlı yarısının" eşiğinde durur  –  rızkın arandığı yarı, eşiğinde namaz kalbin sabit kalmasını sağlar. Peygamber ﷺ zeval anında semâ meleklerinin gök kapılarını açtığını ve o anda dört rekât nafile kılmanın sevilen bir amel olduğunu buyurdu. Peygamber'in mescidinde Öğle'yi cemaatle kılmak bin namaz sevabı taşır; Mescid-i Harâm'da yüz bin. Genel olarak, herhangi bir cemaatle her farz namaz, tek başına kılınanın yirmi yedi katı sevap taşır (Buhârî 645, Müslim 650).`, urd: `ظہر زوال کے بعد "دن کے بہتر نصف" کے دروازے پر کھڑی ہوتی ہے  –  وہ نصف جس میں رزق تلاش کیا جاتا ہے، اور اس کی دہلیز پر نماز دل کو لنگرانداز رکھتی ہے۔ نبی ﷺ نے فرمایا کہ زوال کے وقت آسمان کے فرشتے آسمان کے دروازے کھولتے ہیں، اور اس لمحے چار رکعت نفل ادا کرنا ایک محبوب عمل ہے۔ مسجد نبوی میں ظہر باجماعت پڑھنا ایک ہزار نمازوں کا ثواب رکھتا ہے، مسجد الحرام میں ایک لاکھ۔ عمومی طور پر، کسی بھی جماعت میں ہر فرض نماز تنہا پڑھنے کے ستائیس گنا ثواب کی حامل ہے (بخاری ۶۴۵، مسلم ۶۵۰)۔`, ben: `যাওয়ালের পর "দিনের উত্তম অর্ধাংশের" দরজায় যোহর দাঁড়িয়ে থাকে  –  যে অর্ধাংশে রিযিক সন্ধান করা হয়, যার দ্বারপ্রান্তে নামাজ হৃদয়কে নোঙর করে রাখে। নবী ﷺ বলেছেন যাওয়ালের সময় আকাশের ফেরেশতারা আসমানের দরজাসমূহ খুলে দেন, এবং সেই মুহূর্তে চার রাকাত নফল আদায় করা একটি প্রিয় আমল। মসজিদে নববীতে যোহর জামাতে আদায় একহাজার নামাজের সওয়াব বহন করে, মসজিদুল হারামে একলাখ। সাধারণভাবে যেকোনো জামাতে প্রতিটি ফরজ নামাজ একা পড়ার সাতাশ গুণ সওয়াব বহন করে (বুখারি ৬৪৫, মুসলিম ৬৫০)।`, fas: `ظهر در آستانه "نیمه بهتر روز" پس از زوال می‌ایستد  –  نیمه‌ای که در آن روزی جسته می‌شود و نماز در آستان آن دل را پاینده می‌دارد. پیامبر ﷺ فرمود فرشتگان آسمان در زمان زوال درهای آسمان را می‌گشایند و گزاردن چهار رکعت نافله در آن لحظه عملی است محبوب. گزاردن ظهر به جماعت در مسجد نبوی پاداش هزار نماز و در مسجدالحرام صدهزار را دارد. به‌طور کلی، هر نماز فرض در هر جماعتی بیست‌و‌هفت برابر پاداش گزاردن به تنهایی است (بخاری ۶۴۵، مسلم ۶۵۰).`, zh: `晌礼立于zawal后"一日较佳之半"的门槛上  –  此半为求生计之时，门槛处的拜功使心扎根。先知ﷺ言zawal之时天使开启诸天之门，于此刻礼四拜副功乃蒙喜悦之行。于先知圣寺集体礼晌礼具一千拜之回赐，于禁寺为十万。一般而言，任何集体之每一主命拜，回赐为独礼之二十七倍（布哈里645，穆斯林650）。`, yue: `晌禮立於zawal後「一日較佳之半」嘅門檻上  –  此半為求生計之時，門檻處嘅拜功使心扎根。先知ﷺ言zawal之時天使開啟諸天之門，於此刻禮四拜副功乃蒙喜悅之行。於先知聖寺集體禮晌禮具一千拜之回賜，於禁寺為十萬。一般而言，任何集體之每一主命拜，回賜為獨禮之二十七倍（布哈里645，穆斯林650）。`, ja: `ズフルはザワール後の「一日のより善き半分」の入口に立つ  –  生計が求められる半分であり、その入口に礼拝があって心が錨を下ろす。預言者ﷺは、ザワール時に天の天使たちが天の門を開かれ、その瞬間に四ラクアの任意礼拝を行うことは愛される行いだと仰せられた。預言者のモスクで集団でズフルを行うと千礼拝の報奨、神聖な聖殿では十万の報奨。一般に、いかなる集団でも各ファルド礼拝は一人で行うことの二十七倍の報奨を持つ（ブハーリー645、ムスリム650）。`, ru: `Зухр стоит у порога «лучшей половины» дня после заваля  –  половины, в которой ищут пропитание, с молитвой на её пороге, чтобы удержать сердце якорем. Пророк ﷺ сказал, что ангелы небес открывают врата неба в момент заваля, и совершение четырёх ракатов добровольной молитвы в это мгновение  –  любимое деяние. Молитва Зухр в коллективе в Мечети Пророка несёт награду тысячи молитв, в аль-Масджид аль-Харам  –  ста тысяч. В общем, каждая обязательная молитва в любом коллективе несёт двадцать семь раз больше награды, чем молитва в одиночку (Бухари 645, Муслим 650).`, es: `El Dhuhr se sitúa en el umbral de "la mejor mitad" del día tras el zawal  –  la mitad en la que se busca el sustento, con la oración en su umbral para anclar el corazón. El Profeta ﷺ dijo que los ángeles del cielo abren las puertas del firmamento en el zawal, y rezar cuatro rak'ahs de adoración voluntaria en ese momento es un acto amado. Rezar el Dhuhr en congregación en la Mezquita del Profeta lleva la recompensa de mil oraciones; en al-Masjid al-Haram, cien mil. En general, cada oración obligatoria en cualquier congregación equivale a veintisiete veces la recompensa de rezar solo (Bujari 645, Muslim 650).`, ko: `주흐르는 자왈 이후 "하루의 더 나은 절반"의 입구에 서 있다  –  생계를 구하는 절반이며, 그 입구에 예배가 있어 마음을 닻처럼 붙잡아 둔다. 예언자 ﷺ께서 자왈 시에 하늘의 천사들이 하늘의 문을 여신다고 말씀하셨고, 그 순간에 네 라카의 자발 예배를 행함은 사랑받는 행위이다. 예언자 모스크에서 회중으로 주흐르를 예배하는 것은 천 예배의 보상을, 알마스지드 알하람에서는 십만의 보상을 가진다. 일반적으로 어떤 회중에서든 각 의무 예배는 혼자 예배하는 것의 스물일곱 배의 보상을 가진다 (부카리 645, 무슬림 650).`, ta: `ஸவாலுக்குப் பின் "நாளின் சிறந்த அரைப் பகுதியின்" வாயிலில் ளுஹர் நிற்கிறது  –  அந்த அரைப்பகுதியில் உணவு தேடப்படுகிறது, அதன் வாயிலில் தொழுகை இதயத்தை நங்கூரம் போட்டு வைக்கிறது. ஸவால் வேளையில் வானத்தின் வானவர்கள் வானத்தின் கதவுகளைத் திறக்கிறார்கள் என நபி ﷺ கூறினார், அந்தத் தருணத்தில் நான்கு ரக்அத் நஃபில் தொழுவது விரும்பப்படும் செயல். நபியின் பள்ளியில் ளுஹரை கூட்டாகத் தொழுவது ஆயிரம் தொழுகைகளின் கூலியைச் சுமக்கிறது, மஸ்ஜிதுல் ஹராமில் ஒரு லட்சம். பொதுவாக எந்த கூட்டத்திலும் ஒவ்வொரு ஃபர்ள் தொழுகையும் தனியாகத் தொழுவதின் இருபத்தேழு மடங்கு கூலியைச் சுமக்கிறது (புகாரி 645, முஸ்லிம் 650).`, si: `සවාල්ට පසු "දවසේ වඩා යහපත් භාගයේ" දොරටුව මත සුහ්ර් සිටී  –  ජීවනෝපාය සොයන භාගය, එහි දොරටුවේ සලාතය හදවත නැංගුරම් ලා තබයි. නබි ﷺ පැවසූහ සවාල් වේලාවේ අහසේ මලාඉකාවරු අහසේ දොරටු විවර කරන බවත්, එම මොහොතේ ස්වේච්ඡා නෆ්ල් රකඅත් හතරක් ඉටු කිරීම ආදරණීය ක්‍රියාවක් බවත්. නබි ﷺ ගේ මස්ජිදයේදී සමූහ වශයෙන් සුහ්ර් ඉටු කිරීම සලාත දහසක ප්‍රතිඵලය දරයි, අල්-මස්ජිදුල් හරාම් හි ලක්ෂයක්. සාමාන්‍යයෙන්, ඕනෑම සමූහයකදී සෑම ෆර්ද් සලාතයක්ම තනිව ඉටු කිරීමට වඩා හත් විසි ගුණයක ප්‍රතිඵලයක් දරයි (බුහාරි 645, මුස්ලිම් 650).` },
  dhuhr_timing_notes: { en: `Avoid voluntary prayer at the absolute peak of zawal (the moment the sun is at the exact zenith, before it has clearly begun to decline)  –  this is one of the three times the Prophet ﷺ forbade prayer. The window is small (a few minutes) and once the sun has clearly passed zenith, Dhuhr begins. In extreme heat the Prophet ﷺ allowed delaying Dhuhr (ibrad) until the heat softens; this is for the well-being of the worshippers, not a separate ruling for cool climates. If Dhuhr is missed, pray it as a qada' (makeup) before Asr begins  –  the Prophet ﷺ said the missed prayer must be prayed as soon as one remembers, with no other valid expiation.`, ms: `Elakkan solat sunat pada kemuncak mutlak zawal (saat matahari berada di titik tegak yang tepat, sebelum jelas mula condong)  –  ini adalah satu daripada tiga waktu yang Nabi ﷺ larang solat. Tetingkapnya kecil (beberapa minit) dan sebaik matahari jelas melepasi titik tegak, Zuhur bermula. Pada cuaca panas yang melampau, Nabi ﷺ membenarkan menangguhkan Zuhur (ibrad) sehingga panas melembut; ini untuk kebajikan jemaah, bukan hukum berasingan untuk iklim sejuk. Jika Zuhur tertinggal, dirikanlah sebagai qadha sebelum Asar bermula  –  Nabi ﷺ bersabda solat yang tertinggal mesti didirikan sebaik sahaja diingati, tanpa kafarat lain yang sah.`, tur: `Zevalın tam zirvesinde (güneşin tam tepe noktasında olduğu, açıkça meyletmeden önceki an) nafile namaz kılmaktan kaçının  –  bu, Peygamber'in ﷺ namazı yasakladığı üç vakitten biridir. Pencere küçüktür (birkaç dakika); güneş zevalden açıkça geçer geçmez Öğle başlar. Aşırı sıcakta Peygamber ﷺ sıcaklık yumuşayana kadar Öğle'yi geciktirmeye (ibrâd) izin vermiştir; bu cemaatin selameti içindir, serin iklimler için ayrı bir hüküm değildir. Öğle kaçırılırsa İkindi başlamadan kazasını kılın  –  Peygamber ﷺ kaçırılan namazın hatırlanır hatırlanmaz kılınması gerektiğini, başka geçerli bir kefaret bulunmadığını buyurdu.`, urd: `زوال کے بالکل عروج پر (وہ لمحہ جب سورج بالکل نصف النہار پر ہو، اس کے واضح طور پر ڈھلنے سے پہلے) نفل پڑھنے سے بچیں  –  یہ ان تین اوقات میں سے ایک ہے جن میں نبی ﷺ نے نماز سے منع فرمایا۔ یہ وقفہ مختصر ہے (چند منٹ)، اور جیسے ہی سورج واضح طور پر نصف النہار سے گزرے، ظہر شروع ہو جاتی ہے۔ شدید گرمی میں نبی ﷺ نے ظہر کو موخر کرنے (ابراد) کی اجازت دی جب تک گرمی ٹھنڈی ہو؛ یہ نمازیوں کی بہتری کے لیے ہے، ٹھنڈے موسموں کے لیے کوئی الگ حکم نہیں۔ اگر ظہر چھوٹ جائے، تو عصر کے شروع ہونے سے پہلے قضا کے طور پر پڑھیں  –  نبی ﷺ نے فرمایا چھوٹی ہوئی نماز یاد آتے ہی پڑھی جانی چاہیے، کوئی اور صحیح کفارہ نہیں۔`, ben: `যাওয়ালের একদম শীর্ষে (যখন সূর্য ঠিক মধ্যাকাশে থাকে, স্পষ্টভাবে ঢলে পড়ার আগে) নফল নামাজ এড়িয়ে চলুন  –  এটি সেই তিনটি সময়ের একটি যেগুলোতে নবী ﷺ নামাজ নিষেধ করেছেন। সময়সীমা ছোট (কয়েক মিনিট), এবং সূর্য স্পষ্টভাবে মধ্যাকাশ অতিক্রম করার সাথে সাথেই যোহর শুরু হয়। চরম তাপে নবী ﷺ যোহরকে বিলম্বিত (ইবরাদ) করার অনুমতি দিয়েছেন যতক্ষণ না তাপ কমে; এটি মুসল্লিদের কল্যাণের জন্য, ঠাণ্ডা জলবায়ুর জন্য আলাদা বিধান নয়। যোহর ছুটে গেলে আসর শুরুর আগে কাযা হিসেবে আদায় করুন  –  নবী ﷺ বলেছেন ছুটে যাওয়া নামাজ মনে পড়া মাত্রই আদায় করতে হবে, অন্য কোনো বৈধ কাফফারা নেই।`, fas: `از خواندن نوافل در اوج مطلق زوال (لحظه‌ای که خورشید درست در نصف النهار است، پیش از آنکه آشکارا میل کند) بپرهیز  –  این یکی از سه وقتی است که پیامبر ﷺ از نماز خواندن نهی فرمود. این بازه کوتاه است (چند دقیقه)؛ به محض آنکه خورشید آشکارا از نصف النهار بگذرد، ظهر آغاز می‌شود. در گرمای شدید پیامبر ﷺ تأخیر ظهر (ابراد) را تا فروکش گرما اجازه داد؛ این برای رفاه نمازگزاران است، نه حکمی جدا برای آب‌و‌هواهای خنک. اگر ظهر فوت شد، پیش از آغاز عصر آن را قضا کن  –  پیامبر ﷺ فرمود نماز فوت‌شده باید به محض یادآوری گزارده شود و کفاره معتبر دیگری ندارد.`, zh: `应避免于zawal之绝顶（太阳正处中天、尚未明显偏斜之刻）礼副功  –  此乃先知ﷺ禁止礼拜之三时段之一。窗口短暂（数分钟）；太阳一旦明显过中天，晌礼即开始。酷暑中先知ﷺ准许延后晌礼（伊布拉德）至炎热稍缓；此为礼拜者之福祉，非凉爽气候之另判。若错过晌礼，应于晡礼开始前补礼  –  先知ﷺ言所漏之拜应一忆起即礼，别无他法之有效赎补。`, yue: `應避免於zawal之絕頂（太陽正處中天、尚未明顯偏斜之刻）禮副功  –  此乃先知ﷺ禁止禮拜之三時段之一。窗口短暫（數分鐘）；太陽一旦明顯過中天，晌禮即開始。酷暑中先知ﷺ准許延後晌禮（伊布拉德）至炎熱稍緩；此為禮拜者之福祉，非涼爽氣候之另判。若錯過晌禮，應於晡禮開始前補禮  –  先知ﷺ言所漏之拜應一憶起即禮，別無他法之有效贖補。`, ja: `ザワールの絶対的な頂点（太陽がまさに南中にあり、まだ明確に傾き始めていない瞬間）には任意の礼拝を避けること  –  これは預言者ﷺが礼拝を禁じた三つの時刻の一つである。窓は短く（数分）、太陽が明確に南中を過ぎた瞬間、ズフルが始まる。極度の暑さの中で預言者ﷺは暑さが和らぐまでズフルを遅らせる（イブラード）ことを許された；これは礼拝者の安寧のためであり、涼しい気候のための別個の規定ではない。ズフルを逃した場合は、アスル開始前にカダー（補い）として行う  –  預言者ﷺは、逃した礼拝は思い出した瞬間に行わねばならず、他に有効な贖いはないと仰せられた。`, ru: `Избегай добровольной молитвы в самый пик заваля (момент, когда солнце находится точно в зените, до того, как оно явно начало склоняться)  –  это одно из трёх времён, в которые Пророк ﷺ запретил молитву. Окно коротко (несколько минут); как только солнце явно прошло зенит, начинается Зухр. В сильную жару Пророк ﷺ позволил откладывать Зухр (ибрад) до спада зноя; это ради благополучия молящихся, а не отдельное правило для прохладного климата. Если Зухр пропущен, соверши его как кады (восполнение) до начала Асра  –  Пророк ﷺ сказал, что пропущенную молитву нужно совершить, как только вспомнишь, и нет иного действительного искупления.`, es: `Evita la oración voluntaria en el pico absoluto del zawal (el instante en que el sol está exactamente en el cenit, antes de comenzar claramente a declinar)  –  este es uno de los tres tiempos en que el Profeta ﷺ prohibió la oración. La ventana es breve (unos minutos); en cuanto el sol haya pasado claramente el cenit, comienza el Dhuhr. En calor extremo el Profeta ﷺ permitió retrasar el Dhuhr (ibrad) hasta que el calor amaine; esto es por el bienestar de los orantes, no una norma aparte para climas frescos. Si se pierde el Dhuhr, rézalo como qada' (recuperación) antes del comienzo del Asr  –  el Profeta ﷺ dijo que la oración perdida debe rezarse en cuanto se la recuerde, sin otra expiación válida.`, ko: `자왈의 절대 정점(태양이 정확히 정점에 있고, 명확히 기울기 시작하기 전 순간)에는 자발 예배를 피하라  –  이는 예언자 ﷺ께서 예배를 금하신 세 시간 중 하나이다. 창은 짧으며(몇 분), 태양이 분명히 정점을 지나는 순간 주흐르가 시작된다. 극심한 더위에서 예언자 ﷺ께서는 더위가 누그러질 때까지 주흐르를 연기(이브라드)하는 것을 허용하셨다; 이는 예배자의 안녕을 위한 것이며 시원한 기후를 위한 별도 규정이 아니다. 주흐르를 놓쳤다면 아스르 시작 전에 까다(만회)로 예배하라  –  예언자 ﷺ께서는 놓친 예배는 기억나는 즉시 예배해야 하며 다른 유효한 속죄가 없다고 말씀하셨다.`, ta: `ஸவாலின் முற்றிலும் உச்சத்தில் (சூரியன் சரியான உச்சியில் இருக்கும், தெளிவாக சாயத் தொடங்கும் முன்னான தருணம்) நஃபில் தொழுவதைத் தவிர்க்கவும்  –  நபி ﷺ தொழுகையைத் தடைசெய்த மூன்று நேரங்களில் இது ஒன்று. சாளரம் சிறியது (சில நிமிடங்கள்), சூரியன் தெளிவாக உச்சியைக் கடந்தவுடன் ளுஹர் தொடங்குகிறது. கடும் வெப்பத்தில் நபி ﷺ வெப்பம் குறையும் வரை ளுஹரைத் தாமதப்படுத்த (இப்ராத்) அனுமதித்தார்; இது தொழுபவர்களின் நலனுக்காக, குளிர் காலநிலைகளுக்கான தனி சட்டம் அல்ல. ளுஹர் தவறினால் அஸ்ர் தொடங்குவதற்கு முன் கழா (ஈடாக) தொழுங்கள்  –  தவறிய தொழுகை நினைவுக்கு வரும் உடனேயே தொழப்பட வேண்டும், வேறு செல்லத்தக்க பரிகாரம் இல்லை என நபி ﷺ கூறினார்.`, si: `සවාල්හි පරම උපරිමයේ (හිරු හරියටම මුදුනේ ඇති විට, පැහැදිලිව බැසීමට පෙර) ස්වේච්ඡා සලාත වළකින්න  –  මෙය නබි ﷺ සලාත තහනම් කළ වේලාවන් තුනෙන් එකකි. කවුළුව කෙටිය (මිනිත්තු කිහිපයක්); හිරු පැහැදිලිව මුදුන ඉක්මවූ වහාම සුහ්ර් ආරම්භ වේ. දරුණු උෂ්ණයේදී නබි ﷺ උෂ්ණය මෘදු වන තෙක් සුහ්ර් ප්‍රමාද කිරීමට (ඉබ්රාද්) අවසර දුන්හ; මෙය නැමදුම් කරන්නන්ගේ සුවය සඳහා වන අතර, සිසිල් දේශගුණයන් සඳහා වෙනම තීන්දුවක් නොවේ. සුහ්ර් මඟ හැරුණොත් අස්ර් ආරම්භවීමට පෙර එය කදා (ආවරණය) ලෙස ඉටු කරන්න  –  මඟ හැරුණු සලාතය මතක් වූ වහාම ඉටු කළ යුතු බවත් වෙනත් වලංගු කාහනයක් නැති බවත් නබි ﷺ පැවසූහ.` },
  /* ── Asr ──────────────────────────────────────────────────── */
  asr_name: { en: `Asr  –  The Afternoon Prayer`, ms: `Asar  –  Solat Petang`, tur: `İkindi Namazı  –  Asr`, urd: `عصر  –  سہ پہر کی نماز`, ben: `আসর  –  বিকেলের নামাজ`, fas: `عصر  –  نماز عصر`, zh: `晡礼  –  下午拜功`, yue: `晡禮  –  下午拜功`, ja: `アスル  –  午後の礼拝`, ru: `Аср  –  предвечерняя молитва`, es: `Asr  –  la oración de la tarde`, ko: `아스르  –  오후 예배`, ta: `அஸ்ர்  –  பிற்பகல் தொழுகை`, si: `අස්ර්  –  සවස් සලාතය` },
  asr_when: { en: `Begins when the shadow of an upright object equals its own length (or twice its length per the Hanafi view), continuing until sunset. The preferred (chosen) time ends when the sun begins to turn yellow; from then until sunset is permissible but disliked without excuse. The Prophet ﷺ said: "Whoever delays Asr until the sun has turned yellow, that is the prayer of the hypocrite." (Muslim 622). Pray it early in its window unless a valid reason prevents.`, ms: `Bermula apabila bayang sesuatu objek tegak sama dengan panjangnya (atau dua kali panjangnya menurut Hanafi), berterusan sehingga matahari terbenam. Waktu yang dipilih berakhir ketika matahari mulai menguning; dari itu hingga terbenam dibenarkan tetapi makruh tanpa uzur. Nabi ﷺ bersabda: "Sesiapa melengahkan Asar sehingga matahari menguning, itulah solat orang munafik." (Muslim 622). Dirikanlah pada awal waktunya kecuali ada keuzuran yang sah.`, tur: `Bir cismin gölgesi kendi boyuna (Hanefî'ye göre iki katına) eşit olduğunda başlar ve gün batımına kadar sürer. Tercih edilen vakit, güneşin sararmaya başlamasına kadardır; ondan batıma kadar caiz fakat mazeretsiz mekruhtur. Peygamber ﷺ buyurdu: "Güneş sararıncaya kadar İkindi'yi geciktiren münafık namazıdır." (Müslim 622). Geçerli mazeret yoksa vaktin başında kılın.`, urd: `جب کسی کھڑی چیز کا سایہ اس کی اپنی لمبائی کے برابر ہو جائے (یا حنفی کے نزدیک دو گنا)، شروع ہوتی ہے اور غروبِ آفتاب تک رہتی ہے۔ مختار (پسندیدہ) وقت تب ختم ہوتا ہے جب سورج زرد پڑنے لگے؛ اس سے غروب تک جائز مگر بلا عذر مکروہ ہے۔ نبی ﷺ نے فرمایا: "جو عصر کو سورج کے زرد ہونے تک موخر کرے، یہ منافق کی نماز ہے۔" (مسلم ۶۲۲)۔ بلا عذر اول وقت میں پڑھیں۔`, ben: `কোনো দণ্ডায়মান বস্তুর ছায়া তার নিজের দৈর্ঘ্যের সমান হলে (অথবা হানাফি মতে দ্বিগুণ) শুরু হয়, সূর্যাস্ত পর্যন্ত স্থায়ী। পছন্দনীয় (উত্তম) সময় শেষ হয় যখন সূর্য হলুদ হতে শুরু করে; তখন থেকে সূর্যাস্ত পর্যন্ত জায়েয কিন্তু ওজর ছাড়া মাকরূহ। নবী ﷺ বলেছেন: "যে আসরকে সূর্য হলুদ হওয়া পর্যন্ত বিলম্বিত করে, এটি মুনাফিকের নামাজ।" (মুসলিম ৬২২)। বৈধ ওজর না থাকলে সময়ের শুরুতে পড়ুন।`, fas: `هنگامی آغاز می‌شود که سایه چیز ایستاده برابر خود آن گردد (یا بنا بر حنفی دو برابر آن) و تا غروب ادامه دارد. وقت اختیاری تا زرد شدن خورشید است؛ از آن پس تا غروب جایز اما بدون عذر مکروه است. پیامبر ﷺ فرمود: "هرکس عصر را تا زرد شدن خورشید به تأخیر اندازد، آن نماز منافق است." (مسلم ۶۲۲). بدون عذر در اول وقت بخوان.`, zh: `自直立物之影与其本身等长（哈乃斐之见为两倍长）开始，至日落止。首选（择优）时段于日色转黄前结束；自此至日落虽属可行，但无故则属可憎。先知ﷺ言：「凡延晡礼至日色转黄者，乃伪信士之拜。」（穆斯林622）。无正当理由当于初时段礼之。`, yue: `自直立物之影與其本身等長（哈乃斐之見為兩倍長）開始，至日落止。首選（擇優）時段於日色轉黃前結束；自此至日落雖屬可行，但無故則屬可憎。先知ﷺ言：「凡延晡禮至日色轉黃者，乃偽信士之拜。」（穆斯林622）。無正當理由當於初時段禮之。`, ja: `直立した物の影がその物自身の長さに等しくなる（ハナフィー説では二倍）瞬間に始まり、日没まで続く。望ましい時間帯は太陽が黄ばみ始めるまで；それから日没までは可能だが正当な理由なしには嫌われる。預言者ﷺは仰せられた：「アスルを太陽が黄ばむまで遅らせる者、それは偽善者の礼拝である。」（ムスリム622）。正当な理由がない限り、時間帯の最初に行うこと。`, ru: `Начинается, когда тень от вертикального предмета сравняется с его длиной (или удвоится по мнению ханафитов), и продолжается до заката. Предпочтительное время заканчивается, когда солнце начинает желтеть; от него до заката  –  допустимо, но нежелательно без уважительной причины. Пророк ﷺ сказал: "Кто откладывает Аср до пожелтения солнца  –  это молитва лицемера." (Муслим 622). Совершайте в начале её окна, если нет уважительной причины.`, es: `Comienza cuando la sombra de un objeto vertical iguala su propia longitud (o el doble según el parecer hanafi), y se extiende hasta el ocaso. El tiempo preferido termina cuando el sol comienza a amarillear; de ahí hasta el ocaso es permitido pero detestable sin excusa válida. El Profeta ﷺ dijo: "Quien retrasa el Asr hasta que el sol amarillea, esa es la oración del hipócrita." (Muslim 622). Réza al principio de su ventana salvo que haya razón válida.`, ko: `똑바로 선 물체의 그림자가 자체 길이와 같아지면(또는 하나피 견해로 두 배) 시작되어 일몰까지 지속됩니다. 선호되는(우선) 시간은 태양이 노랗게 변하기 시작할 때 끝나며, 그 이후 일몰까지는 허용되지만 정당한 사유 없이는 혐오됩니다. 예언자 ﷺ께서 말씀하셨다: "아스르를 태양이 노랗게 될 때까지 지연시키는 자, 그것은 위선자의 예배이다." (무슬림 622). 정당한 사유가 없으면 그 시간대의 초기에 예배하라.`, ta: `செங்குத்தான ஒரு பொருளின் நிழல் அதன் சொந்த நீளத்திற்குச் சமமாகும்போது தொடங்கி (அல்லது ஹனஃபி கருத்தின்படி இரு மடங்கு), சூரிய அஸ்தமனம் வரை நீடிக்கும். விரும்பப்படும் (சிறப்பான) வேளை சூரியன் மஞ்சளாக மாறத் தொடங்கும் போது முடிகிறது; அதிலிருந்து அஸ்தமனம் வரை அனுமதிக்கப்படுகிறது ஆனால் காரணமின்றி மக்ரூஹ். நபி ﷺ கூறினார்: "சூரியன் மஞ்சளாகும் வரை அஸ்ரைத் தாமதப்படுத்துபவர்  –  அது நயவஞ்சகனின் தொழுகை." (முஸ்லிம் 622). செல்லத்தக்க காரணம் இல்லையெனில் வேளையின் தொடக்கத்தில் தொழுங்கள்.`, si: `සෘජුව සිටුවන වස්තුවක සෙවණැල්ල එහි දිගට සමාන වන විට ආරම්භ වී (හනෆී මතය අනුව දෙගුණයක්), හිරු බැසීම දක්වා පවතී. රුචි කරන (පූජ්‍ය) කාලය හිරු කහ වීමට පටන් ගන්නා විට අවසන් වේ; එතැන් සිට හිරු බැසීම දක්වා අනුමත වුවද වලංගු හේතුවක් නොමැතිව මක්රූහ්ය. නබි ﷺ පැවසූහ: "හිරු කහ වන තෙක් අස්ර් ප්‍රමාද කරන කවරෙක්ද එය කපටියාගේ සලාතයයි." (මුස්ලිම් 622). වලංගු හේතුවක් නැත්නම් කාල සීමාවේ ආරම්භයේදී ඉටු කරන්න.` },
  asr_structure: { en: `Four rak'ahs of fard. The Sunnah ghayr mu'akkadah (recommended but not strongly confirmed) is four rak'ahs before Asr  –  the Prophet ﷺ said: "May Allah have mercy on one who prays four rak'ahs before Asr." (Tirmidhi 430). There is no confirmed Sunnah after Asr. Recitation in all four rak'ahs is silent (sirri), as in Dhuhr.`, ms: `Empat rakaat fardu. Sunnah ghayr muakkad (digalakkan tetapi tidak diteguhkan dengan kuat) adalah empat rakaat sebelum Asar  –  Nabi ﷺ bersabda: "Semoga Allah merahmati orang yang mendirikan empat rakaat sebelum Asar." (Tirmidhi 430). Tiada sunnah muakkad selepas Asar. Bacaan dalam keempat-empat rakaat secara sirri (perlahan), seperti Zuhur.`, tur: `Dört rekât farz. Gayri müekked sünnet, İkindi'den önce dört rekâttır  –  Peygamber ﷺ buyurdu: "İkindi'den önce dört rekât kılana Allah rahmet etsin." (Tirmizî 430). İkindi'den sonra müekked sünnet yoktur. Dört rekâtın hepsinde kıraat Öğle'deki gibi sessizdir (sirrî).`, urd: `چار رکعت فرض۔ سنّت غیر مؤکدہ (مستحب لیکن مؤکد نہیں) عصر سے قبل چار رکعت ہے  –  نبی ﷺ نے فرمایا: "اللہ اس پر رحم کرے جو عصر سے پہلے چار رکعت پڑھے۔" (ترمذی ۴۳۰)۔ عصر کے بعد کوئی سنّت مؤکدہ نہیں۔ چاروں رکعتوں میں قراءت ظہر کی طرح سرّاً ہوتی ہے۔`, ben: `চার রাকাত ফরজ। সুন্নাহ গায়র মুআক্কাদা (পরামর্শকৃত কিন্তু দৃঢ়ভাবে নিশ্চিত নয়) হলো আসরের আগে চার রাকাত  –  নবী ﷺ বলেছেন: "আল্লাহ সেই ব্যক্তির প্রতি রহম করুন যিনি আসরের আগে চার রাকাত পড়েন।" (তিরমিযি ৪৩০)। আসরের পর কোনো নিশ্চিত সুন্নাহ নেই। যোহরের মতোই চার রাকাতেই কেরাত নীরবে (সিররি)।`, fas: `چهار رکعت فرض. سنت غیر مؤکد (مستحب اما تأکیدنشده) چهار رکعت پیش از عصر است  –  پیامبر ﷺ فرمود: "خدا رحمت کند کسی را که پیش از عصر چهار رکعت بگزارد." (ترمذی ۴۳۰). پس از عصر سنت مؤکد نیست. در هر چهار رکعت قرائت مانند ظهر آرام (سرّی) است.`, zh: `主命四拜。非强调圣行（虽属可嘉但未强化确证者）为晡礼前四拜  –  先知ﷺ言：「愿真主慈悯于晡礼前礼四拜者。」（提尔米兹430）。晡礼后无强调圣行。四拜中诵读如晌礼般低声（西里）。`, yue: `主命四拜。非強調聖行（雖屬可嘉但未強化確證者）為晡禮前四拜  –  先知ﷺ言：「願真主慈憫於晡禮前禮四拜者。」（提爾米茲430）。晡禮後無強調聖行。四拜中誦讀如晌禮般低聲（西里）。`, ja: `ファルドは四ラクア。スンナ・ガイル・ムアッカダ（推奨されるが強く確認はされていない）はアスル前の四ラクア  –  預言者ﷺは仰せられた：「アスルの前に四ラクアを行う者にアッラーの慈悲があらんことを。」（ティルミズィー430）。アスル後に確認されたスンナはない。四ラクアともに朗誦はズフルと同様に無声（シッリー）。`, ru: `Четыре раката фарда. Сунна гайр муаккада (рекомендованное, но не сильно подтверждённое)  –  четыре раката перед Асром  –  Пророк ﷺ сказал: "Да помилует Аллах того, кто совершит четыре раката перед Асром." (Тирмизи 430). После Асра подтверждённой сунны нет. Чтение во всех четырёх ракатах тихое (сирри), как в Зухре.`, es: `Cuatro rak'ahs de fard. La Sunnah ghayr mu'akkadah (recomendada pero no fuertemente confirmada) son cuatro rak'ahs antes del Asr  –  el Profeta ﷺ dijo: "Que Allah tenga misericordia de quien reza cuatro rak'ahs antes del Asr." (Tirmidhi 430). No hay Sunnah confirmada tras el Asr. La recitación en los cuatro rak'ahs es silenciosa (sirri), como en el Dhuhr.`, ko: `파르드 네 라카. 순나 가이르 무앗카다(권장되지만 강하게 확정되지는 않은 것)는 아스르 전 네 라카  –  예언자 ﷺ께서 말씀하셨다: "아스르 전에 네 라카를 예배하는 자에게 알라께서 자비를 베푸시기를." (티르미디 430). 아스르 후에는 확정된 순나가 없다. 네 라카 모두 낭송은 주흐르와 같이 무성(시르리).`, ta: `நான்கு ரக்அத் ஃபர்ள். அஸ்ருக்கு முன் நான்கு ரக்அத் சுன்னத்துல் ஃகைர் முஅக்கதா (பரிந்துரைக்கப்பட்டது ஆனால் வலியுறுத்தப்படாதது)  –  நபி ﷺ கூறினார்: "அஸ்ருக்கு முன் நான்கு ரக்அத் தொழுபவர் மீது அல்லாஹ் கருணை காட்டட்டும்." (திர்மிதி 430). அஸ்ருக்குப் பின் வலியுறுத்தப்பட்ட சுன்னா இல்லை. ளுஹரைப் போல நான்கு ரக்அத்களிலும் ஓதல் அமைதியாக (ஸிர்ரி).`, si: `ෆර්ද් රකඅත් හතරකි. සුන්නා ඝයිර් මුඅක්කදා (නිර්දේශ වුවද ශක්තිමත් ලෙස තහවුරු නොකළ) අස්ර්ට පෙර රකඅත් හතරකි  –  නබි ﷺ පැවසූහ: "අස්ර්ට පෙර රකඅත් හතරක් ඉටු කරන කෙනෙකුට අල්ලාහ්ගේ ආශීර්වාද ලැබේවා." (තිර්මිදී 430). අස්ර්ට පසු තහවුරු කළ සුන්නා නැත. රකඅත් හතරේදීම කියවීම සුහ්ර් මෙන් නිහඬව (සිර්රී).` },
  asr_story: { en: `Like the others, Asr was ordained on the Mi'raj. Jibril (as) led the Prophet ﷺ in Asr at the Ka'bah on the first day when the shadow of each thing equalled its own length, then on the second day when the shadow was twice its length, and said: "The time of Asr is between these two." (Abu Dawud 393). It is Asr that the Quran specifically singles out for emphasis: "Guard your prayers, especially the middle prayer (al-salat al-wusta)" (2:238) — the strongest opinion among the Companions and classical scholars is that "the middle prayer" is Asr, because it falls between the two day prayers (Fajr and Dhuhr) and the two night prayers (Maghrib and Isha), and because it comes at the busiest, most distracted moment of the day.`, ms: `Seperti yang lain, Asar diwajibkan pada Mi'raj. Jibril (as) mengimamkan Nabi ﷺ pada Asar di Kaabah pada hari pertama ketika bayang setiap sesuatu sama dengan panjangnya, kemudian pada hari kedua ketika bayang dua kali panjangnya, dan bersabda: "Waktu Asar antara kedua-dua ini." (Abu Dawud 393). Asarlah yang khusus diketengahkan oleh al-Quran: "Peliharalah segala solat kamu, terutama solat pertengahan (al-salat al-wusta)" (2:238) — pendapat yang paling kuat di kalangan sahabat dan ulama klasik ialah "solat pertengahan" itu Asar, kerana ia jatuh antara dua solat siang (Subuh dan Zuhur) dan dua solat malam (Maghrib dan Isyak), dan kerana ia datang pada saat tersibuk dan paling banyak mengganggu fokus dalam sehari.`, tur: `Diğerleri gibi İkindi de Mi'rac'ta farz kılındı. Cibril (as) ilk gün her şeyin gölgesi kendi boyuna eşit olduğunda Kâbe'de Peygamber'e ﷺ İkindi'yi kıldırdı, ikinci gün gölge iki katına çıktığında yine kıldırdı ve "İkindi'nin vakti bu ikisinin arasıdır." dedi (Ebû Dâvûd 393). Kur'an'ın özellikle vurguladığı namaz İkindi'dir: "Namazları, özellikle orta namazı (es-salâtü'l-vustâ) muhafaza edin" (2:238) — Sahabe ve klasik âlimler arasındaki en güçlü görüş, "orta namaz"ın İkindi olduğudur; çünkü iki gündüz namazı (Sabah ve Öğle) ile iki gece namazı (Akşam ve Yatsı) arasında yer alır ve günün en yoğun, en dağıtıcı saatine denk gelir.`, urd: `دیگر کی طرح عصر بھی معراج میں فرض ہوئی۔ جبریل (ع) نے کعبہ کے پاس پہلے دن، جب ہر چیز کا سایہ اس کی اپنی لمبائی کے برابر تھا، نبی ﷺ کو عصر کی نماز پڑھائی، پھر دوسرے دن جب سایہ دو گنا تھا، اور فرمایا: "عصر کا وقت ان دونوں کے درمیان ہے۔" (ابو داؤد ۳۹۳)۔ یہ عصر ہے جس کا قرآن خصوصاً ذکر کرتا ہے: "اپنی نمازوں کی حفاظت کرو خصوصاً درمیانی نماز (الصلوٰۃ الوسطیٰ) کی" (۲:۲۳۸) — صحابہ اور کلاسیکی علماء کا سب سے قوی قول ہے کہ "درمیانی نماز" عصر ہے، کیونکہ یہ دو دن کی نمازوں (فجر و ظہر) اور دو رات کی نمازوں (مغرب و عشاء) کے درمیان ہے، اور کیونکہ یہ دن کے سب سے مصروف اور سب سے زیادہ بٹے ہوئے لمحے پر آتی ہے۔`, ben: `অন্যান্যের মতো আসরও মেরাজে ফরজ হয়। জিবরিল (আ) প্রথম দিনে যখন প্রতিটি বস্তুর ছায়া তার নিজের দৈর্ঘ্যের সমান ছিল তখন কাবার পাশে নবী ﷺ-কে আসরে ইমামতি করালেন, পরের দিন যখন ছায়া দ্বিগুণ ছিল তখনও, এবং বললেন: "আসরের সময় এই দুইয়ের মাঝে।" (আবু দাউদ ৩৯৩)। কুরআন বিশেষভাবে যাকে গুরুত্ব দিয়ে উল্লেখ করেছে তা আসর: "তোমাদের নামাজগুলোর হেফাজত করো, বিশেষভাবে মধ্য নামাজের (আস-সালাতুল উসতা)" (২:২৩৮) — সাহাবি ও ধ্রুপদী আলেমদের মধ্যে সবচেয়ে শক্তিশালী মত হলো "মধ্য নামাজ" আসর, কারণ এটি দুই দিনের নামাজ (ফজর ও যোহর) এবং দুই রাতের নামাজ (মাগরিব ও ইশা)-এর মাঝে পড়ে, এবং কারণ এটি দিনের সবচেয়ে ব্যস্ত ও মনঃসংযোগ-বিভ্রান্তকর মুহূর্তে আসে।`, fas: `همانند دیگران، عصر نیز در معراج فرض شد. جبرئیل (ع) در روز نخست هنگامی که سایه هر چیز برابر خودش بود، نزد کعبه امام نماز عصر پیامبر ﷺ شد، و در روز دوم هنگامی که سایه دو برابر بود، و فرمود: "وقت عصر میان این دو است." (ابوداود ۳۹۳). همین عصر است که قرآن آن را به‌ویژه برجسته کرده: "بر نمازهای خود محافظت کنید، به‌ویژه بر نماز میانه (الصلاة الوسطی)" (۲:۲۳۸) — قوی‌ترین نظر در میان صحابه و علمای کلاسیک آن است که "نماز میانه" عصر است، زیرا میان دو نماز روز (فجر و ظهر) و دو نماز شب (مغرب و عشاء) قرار می‌گیرد و در پر مشغله‌ترین و پراکنده‌ترین لحظه روز فرامی‌رسد.`, zh: `与其他四时一样，晡礼亦于登霄被定为主命。吉卜利里（愿主赐他平安）于天房旁，第一日万物之影与其本身等长时带先知ﷺ礼晡礼，次日影长二倍时再带一次，并言：「晡礼之时段在此二者之间。」（艾布·达伍德393）。《古兰经》特别强调的正是晡礼：「你们当谨守拜功，尤其当谨守中正的拜功」（2:238）  –  圣门弟子与古典学者间最有力之见，「中正的拜功」即晡礼，因其介乎二日拜（晨与晌）与二夜拜（昏与宵）之间，且降临于一日最忙、最分心之刻。`, yue: `同其他四時一樣，晡禮亦於登霄被定為主命。吉卜利里（願主賜佢平安）於天房旁，第一日萬物之影與其本身等長時帶先知ﷺ禮晡禮，次日影長二倍時再帶一次，並話：「晡禮之時段喺此二者之間。」（艾布·達伍德393）。《古蘭經》特別強調嘅正係晡禮：「你哋當謹守拜功，尤其當謹守中正嘅拜功」（2:238）  –  聖門弟子與古典學者間最有力之見，「中正嘅拜功」就係晡禮，因其介乎二日拜（晨與晌）與二夜拜（昏與宵）之間，且降臨於一日最忙、最分心之刻。`, ja: `他の礼拝と同様、アスルもミウラージュで義務付けられた。ジブリール（に平安あれ）はカアバの傍で、第一日にあらゆる物の影がそれ自身の長さに等しくなった時に預言者ﷺのアスル礼拝のイマームとなり、第二日に影が二倍になった時に再びイマームとなって「アスルの時はこの二つの間である」と仰せられた（アブー・ダーウード393）。クルアーンが特に強調するのはアスルである：「礼拝、特に中間の礼拝（アッ＝サラート・アル＝ウスター）を守りなさい」（2:238）  –  教友たちと古典学者の間で最も有力な意見は「中間の礼拝」がアスルだということ。これは二つの昼の礼拝（ファジュルとズフル）と二つの夜の礼拝（マグリブとイシャー）の間に位置し、一日のうち最も忙しく、最も気を散らされる時刻に来るからである。`, ru: `Как и остальные, Аср был предписан в Мирадж. Джибриль (мир ему) у Каабы возглавил Пророка ﷺ в Асре в первый день, когда тень каждой вещи равнялась её длине, а на второй день  –  когда тень была двойной, и сказал: "Время Асра между этими двумя." (Абу Дауд 393). Именно Аср особо выделен Кораном: «Сохраняйте свои молитвы, особенно срединную молитву (ас-салят аль-вуста)» (2:238)  –  сильнейшее мнение среди сподвижников и классических учёных в том, что «срединная молитва»  –  Аср, ибо она стоит между двумя дневными (Фаджр и Зухр) и двумя ночными (Магриб и Иша) молитвами и приходит в самый занятой и наиболее отвлекающий момент дня.`, es: `Como las demás, el Asr fue ordenado en la Mi'raj. Yibril (as) dirigió al Profeta ﷺ en el Asr junto a la Ka'bah el primer día cuando la sombra de cada cosa igualaba su propia longitud, y el segundo día cuando la sombra era el doble, y dijo: "El tiempo del Asr está entre estos dos." (Abu Dawud 393). Es el Asr el que el Corán singulariza especialmente: "Guardad vuestras oraciones, especialmente la oración del medio (al-salat al-wusta)" (2:238)  –  el parecer más fuerte entre los Compañeros y los sabios clásicos es que "la oración del medio" es el Asr, porque cae entre las dos oraciones diurnas (Fajr y Dhuhr) y las dos nocturnas (Maghrib e Isha), y porque llega en el momento más ocupado y distraído del día.`, ko: `다른 예배와 마찬가지로 아스르도 미으라즈에서 의무로 정해졌다. 지브릴(평화가 그에게)께서 첫 날 모든 물체의 그림자가 자체 길이와 같아질 때 카바 옆에서 예언자 ﷺ의 아스르 예배 이맘이 되셨고, 둘째 날 그림자가 두 배가 되었을 때 다시 이맘이 되시며 말씀하셨다: "아스르의 시간은 이 둘 사이이다." (아부 다우드 393). 꾸란이 특별히 강조하는 것이 바로 아스르이다: "너희 예배를 지키라, 특히 중간 예배(앗살라투 알우스타)를" (2:238)  –  동료들과 고전 학자들 사이에서 가장 강한 견해는 "중간 예배"가 아스르라는 것이다. 그것이 두 낮 예배(파즈르와 주흐르)와 두 밤 예배(마그립과 이샤) 사이에 위치하며, 하루 중 가장 바쁘고 산만한 순간에 오기 때문이다.`, ta: `பிற தொழுகைகளைப் போல, அஸ்ரும் மிஃராஜில் கடமையாக்கப்பட்டது. ஜிப்ரீல் (அலை) கஅபாவின் அருகே முதல் நாள் ஒவ்வொரு பொருளின் நிழலும் அதன் சொந்த நீளத்திற்குச் சமமாக இருந்தபோது நபி ﷺ அவர்களுக்கு அஸ்ரில் இமாமாக நின்றார், இரண்டாம் நாள் நிழல் இரு மடங்கானபோதும், கூறினார்: "அஸ்ரின் வேளை இவ்விரண்டிற்கும் இடையே." (அபூ தாவூத் 393). குர்ஆன் சிறப்பாக வலியுறுத்துவது அஸ்ரையே: "உங்கள் தொழுகைகளை, குறிப்பாக நடுத்தர தொழுகையை (அஸ்-ஸலாத்துல் வுஸ்தா), பாதுகாத்துக் கொள்ளுங்கள்" (2:238)  –  தோழர்கள் மற்றும் கிளாசிக்கல் அறிஞர்களிடையே வலிமையான கருத்து என்னவென்றால் "நடுத்தர தொழுகை" அஸ்ர், ஏனெனில் அது இரு பகல் தொழுகைகளுக்கும் (ஃபஜ்ர், ளுஹர்) இரு இரவுத் தொழுகைகளுக்கும் (மக்ரிப், இஷா) இடையே வருகிறது, மேலும் நாளின் மிகவும் பரபரப்பான, மிகவும் கவனச் சிதறல் கொண்ட தருணத்தில் வருகிறது.`, si: `අනෙක් ඒවා මෙන්ම අස්ර්ද මිඃරාජ්හිදී අනිවාර්ය කෙරුණි. ජිබ්රීල් (ඔහුට සාමය) පළමු දින සෑම දෙයකම සෙවණැල්ල එහි දිගට සමාන වූ විට කඃබාව අසළ නබි ﷺ සමඟ අස්ර් සලාතයේ ඉමාම් වශයෙන් සිට, දෙවන දින සෙවණැල්ල දෙගුණයක් වූ විට නැවතත් ඉමාම් වශයෙන් සිට පැවසූහ: "අස්ර්ගේ කාලය මේ දෙක අතරයි." (අබූ දාවූද් 393). කුර්ආනය විශේෂයෙන් ඉස්මතු කරන්නේ අස්ර්යි: "ඔබේ සලාත සුරකින්න, විශේෂයෙන් මැද සලාතය (අල්-සලාත් අල්-වුස්තා)" (2:238)  –  සහචරයන් හා සම්භාව්‍ය විද්වතුන් අතර ශක්තිමත්ම මතය වන්නේ "මැද සලාතය" අස්ර් බවයි; මන්ද එය දිවා සලාත දෙක (ෆජ්ර් සහ සුහ්ර්) සහ රාත්‍රී සලාත දෙක (මග්රිබ් සහ ඉෂා) අතර වැටෙන අතර, දවසේ වඩාත් කාර්යබහුල, වඩාත් අවධානය විසිරෙන මොහොතේ පැමිණේ.` },
  asr_significance: { en: `Asr is "the middle prayer" of the five (al-salat al-wusta) and the test of the believer's day  –  it falls at the very moment when work, fatigue, and inattention peak together. The Prophet ﷺ said: "Whoever misses Asr, his deeds are nullified." (Bukhari 553) — meaning his deeds for that day. It is the prayer the previous communities lost first, becoming the marker that the Muslims must guard most carefully so that they do not follow the same path. It is also the second of "the two cool prayers" whose preservation guarantees Paradise.`, ms: `Asar ialah "solat pertengahan" daripada lima (al-salat al-wusta) dan ujian hari mukmin  –  ia jatuh tepat ketika kerja, keletihan, dan kelalaian memuncak bersama-sama. Nabi ﷺ bersabda: "Sesiapa yang terlepas Asar, amalannya dibatalkan." (Bukhari 553) — bermaksud amalannya untuk hari itu. Ia adalah solat yang umat-umat terdahulu hilangkan terlebih dahulu, menjadi tanda yang umat Islam mesti jaga dengan lebih berhati-hati supaya mereka tidak mengikuti jalan yang sama. Ia juga yang kedua daripada "dua solat sejuk" yang pemeliharaannya menjamin syurga.`, tur: `İkindi, beş vakitten "orta namaz"dır (es-salâtü'l-vustâ) ve mü'minin gününün sınavıdır  –  iş, yorgunluk ve dikkatsizliğin aynı anda zirveye ulaştığı vakte denk gelir. Peygamber ﷺ buyurdu: "Kim İkindi'yi kaçırırsa amelleri boşa gider." (Buhârî 553)  –  o günkü amelleri kastedilir. Önceki ümmetlerin ilk yitirdiği namazdır; bu yüzden Müslümanların aynı yola düşmemek için en dikkatli koruması gereken bir nişanedir. Aynı zamanda "iki serinlik namazı"nın ikincisidir; her ikisinin korunması cenneti garanti eder.`, urd: `عصر پانچوں کی "درمیانی نماز" (الصلوٰۃ الوسطیٰ) اور مومن کے دن کا امتحان ہے  –  یہ بالکل اس لمحے آتی ہے جب کام، تھکن، اور بے توجہی ایک ساتھ عروج پر ہوتے ہیں۔ نبی ﷺ نے فرمایا: "جو عصر چھوڑ دے، اس کے اعمال ضائع ہو جاتے ہیں۔" (بخاری ۵۵۳)  –  یعنی اس دن کے اعمال۔ یہ وہ نماز ہے جسے گزشتہ امتیں سب سے پہلے کھو بیٹھیں، اس لیے یہ ایک علامت ہے کہ مسلمانوں کو اسے سب سے زیادہ احتیاط سے محفوظ رکھنا چاہیے تاکہ وہ اسی راہ پر نہ چلیں۔ یہ "دو ٹھنڈی نمازوں" میں سے دوسری بھی ہے، جن کی حفاظت جنت کی ضامن ہے۔`, ben: `আসর হলো পাঁচের মধ্যে "মধ্য নামাজ" (আস-সালাতুল উসতা) এবং মুমিনের দিনের পরীক্ষা  –  এটি ঠিক সেই মুহূর্তে আসে যখন কাজ, ক্লান্তি ও অমনোযোগ একসাথে চূড়ায় পৌঁছায়। নবী ﷺ বলেছেন: "যে আসর হারিয়ে ফেলে, তার আমল বিনষ্ট হয়।" (বুখারি ৫৫৩)  –  অর্থাৎ সেই দিনের আমল। এটি সেই নামাজ যা পূর্ববর্তী উম্মতরা প্রথম হারিয়েছিল, ফলে এটি এমন একটি চিহ্ন হয়ে উঠেছে যা মুসলিমদের সবচেয়ে যত্ন সহকারে রক্ষা করতে হবে যাতে তারা একই পথে না চলে। এটি "দুই শীতল নামাজ"-এর দ্বিতীয়টিও, যাদের সংরক্ষণ জান্নাতের নিশ্চয়তা দেয়।`, fas: `عصر "نماز میانه" پنج نماز (الصلاة الوسطی) و آزمون روز مؤمن است  –  درست در لحظه‌ای فرامی‌رسد که کار، خستگی و بی‌توجهی هم‌زمان به اوج می‌رسند. پیامبر ﷺ فرمود: "هرکس عصر را از دست بدهد، اعمالش تباه می‌شود." (بخاری ۵۵۳)  –  یعنی اعمال آن روز. این نمازی است که امت‌های گذشته نخستین بار آن را گم کردند، و از این رو نشانه‌ای است که مسلمانان باید با بیشترین مراقبت آن را حفظ کنند تا در همان مسیر نیفتند. همچنین دومین "نماز خنک" است که حفظ هر دو، بهشت را تضمین می‌کند.`, zh: `晡礼乃五时之「中正拜功」（al-salat al-wusta），亦为信士一日之试炼  –  其降临之刻，正值工作、疲惫与失神同登顶峰。先知ﷺ言：「凡错过晡礼者，其功绩归于无效。」（布哈里553）  –  指其当日之功绩。前代诸民族最先丢失之拜功即此，故为穆斯林必须最谨慎守护之标记，免蹈其覆辙。亦为「两次凉时拜」之第二者，二者皆守得保乐园。`, yue: `晡禮乃五時之「中正拜功」（al-salat al-wusta），亦為信士一日之試煉  –  其降臨之刻，正值工作、疲憊與失神同登頂峰。先知ﷺ言：「凡錯過晡禮者，其功績歸於無效。」（布哈里553）  –  指其當日之功績。前代諸民族最先丟失之拜功即此，故為穆斯林必須最謹慎守護之標記，免蹈其覆轍。亦為「兩次涼時拜」之第二者，二者皆守得保樂園。`, ja: `アスルは五時の「中間の礼拝」（アッ＝サラート・アル＝ウスター）であり、信者の一日の試金石である  –  仕事、疲労、不注意がともに頂点に達する瞬間に降りてくる。預言者ﷺは仰せられた：「アスルを逃した者は、その行いが無効となる。」（ブハーリー553）  –  その日の行いを指す。先行の諸ウンマが最初に失った礼拝であり、そのためムスリムが同じ道をたどらぬよう最も注意深く守らねばならない印である。また「二つの涼しい礼拝」の二番目でもあり、両者の保持が楽園を保証する。`, ru: `Аср  –  «срединная молитва» из пяти (ас-салят аль-вуста) и испытание дня верующего  –  она приходит ровно в тот момент, когда работа, усталость и невнимание достигают пика одновременно. Пророк ﷺ сказал: «Кто пропустил Аср, тот свёл на нет свои деяния.» (Бухари 553)  –  то есть деяния того дня. Это молитва, которую первые общины утратили первой, и потому она стала знаком, который мусульмане должны хранить с особой бдительностью, чтобы не пойти по тому же пути. Она также вторая из «двух прохладных молитв», сохранение которых гарантирует Рай.`, es: `El Asr es "la oración del medio" de las cinco (al-salat al-wusta) y la prueba del día del creyente  –  cae precisamente en el momento en que el trabajo, la fatiga y la inatención alcanzan a la vez su punto culminante. El Profeta ﷺ dijo: "Quien pierde el Asr, sus obras quedan anuladas." (Bujari 553)  –  refiriéndose a sus obras de ese día. Es la oración que las comunidades anteriores perdieron primero, convirtiéndose en el marcador que los musulmanes deben guardar con más cuidado para no seguir el mismo camino. Es también la segunda de "las dos oraciones frescas" cuya preservación garantiza el Paraíso.`, ko: `아스르는 다섯 중 "중간 예배"(앗살라투 알우스타)이며 신자 하루의 시험이다  –  일, 피로, 부주의가 동시에 정점에 이르는 바로 그 순간에 다가온다. 예언자 ﷺ께서 말씀하셨다: "아스르를 놓치는 자는 그의 행위가 무효가 된다." (부카리 553)  –  그날의 행위를 의미한다. 이전 공동체들이 가장 먼저 잃은 예배이며, 그래서 무슬림들이 같은 길을 따르지 않도록 가장 신중하게 지켜야 할 표시이다. 또한 "두 시원한 예배"의 두 번째이며, 두 예배의 보존이 천국을 보장한다.`, ta: `அஸ்ர் ஐந்தில் "நடுத்தர தொழுகை" (அல்-ஸலாத்துல் வுஸ்தா) மற்றும் விசுவாசியின் நாளின் சோதனை  –  வேலை, களைப்பு மற்றும் கவனமின்மை ஒன்றாக உச்சத்தை அடையும் சரியான தருணத்தில் வருகிறது. நபி ﷺ கூறினார்: "அஸ்ரை விட்டுவிட்டவரின் செயல்கள் வீணாகும்." (புகாரி 553)  –  அந்த நாளின் செயல்களைக் குறிக்கிறது. முந்தைய சமுதாயங்கள் முதலில் இழந்த தொழுகை இதுவே, எனவே முஸ்லிம்கள் அதே பாதையில் செல்லாதிருக்க மிக கவனத்துடன் இதைப் பாதுகாக்க வேண்டிய அடையாளமாகியுள்ளது. "இரு குளிர்ந்த தொழுகைகளில்" இரண்டாவதும் இதுவே, இரண்டையும் பாதுகாப்பது சொர்க்கத்திற்கு உத்தரவாதம்.`, si: `අස්ර් යනු පහෙන් "මැද සලාතය" (අල්-සලාත් අල්-වුස්තා) සහ විශ්වාසවන්තයාගේ දිනයේ පරීක්ෂණයයි  –  වැඩ, වෙහෙස, හා නොසලකා හැරීම එක්ව උපරිමයට පැමිණෙන මොහොතේම පැමිණේ. නබි ﷺ පැවසූහ: "අස්ර් මඟ හරින්නාගේ ක්‍රියා නිෂ්ඵල වේ." (බුහාරි 553)  –  එම දිනයේ ක්‍රියා අදහස් කරයි. පෙර සමාජයන් මුලින්ම අහිමි කරගත් සලාතය මෙයයි, එම නිසා මුස්ලිම්වරුන් එම මාර්ගය අනුගමනය නොකරන පරිදි වඩාත් සැලකිලිමත්ව රකින්නට අවශ්‍ය ලකුණයි. එය "සිසිල් සලාත දෙකේ" දෙවැන්නද වන අතර, ඒ දෙකම සුරැකීම ස්වර්ගය සහතික කරයි.` },
  asr_proof_q: { en: `"Guard your prayers, especially the middle prayer, and stand before Allah in devotion." (Al-Baqarah 2:238). The Companions including Ali, Abu Hurayrah, Ibn Mas'ud and Ibn 'Abbas (may Allah be pleased with them all) confirmed "the middle prayer" as Asr. The Battle of the Trench delayed the Companions' Asr; the Prophet ﷺ said upon learning of it: "May Allah fill their hearts and houses with fire as they kept us from the middle prayer until the sun set!" (Bukhari 2931, Muslim 627)  –  a curse he ﷺ rarely uttered, showing the gravity of missing Asr.`, ms: `"Peliharalah segala solat kamu, terutama solat pertengahan, dan berdirilah dengan khusyuk kerana Allah." (Al-Baqarah 2:238). Para sahabat termasuk 'Ali, Abu Hurayrah, Ibn Mas'ud dan Ibn 'Abbas (semoga Allah meredhai mereka semua) mengesahkan "solat pertengahan" sebagai Asar. Peperangan Khandaq menyebabkan para sahabat tertangguh Asar; Nabi ﷺ bersabda apabila mengetahuinya: "Semoga Allah memenuhkan hati dan rumah mereka dengan api kerana mereka menghalang kami daripada solat pertengahan sehingga matahari terbenam!" (Bukhari 2931, Muslim 627)  –  laknat yang jarang baginda ucapkan, menunjukkan beratnya meninggalkan Asar.`, tur: `"Namazları, özellikle orta namazı muhafaza edin ve Allah'ın huzurunda saygıyla durun." (Bakara 2:238). Ali, Ebû Hureyre, İbn Mes'ûd ve İbn Abbas (ra) gibi sahabe "orta namaz"ın İkindi olduğunu doğrulamıştır. Hendek Savaşı sahabenin İkindi'yi geciktirmesine yol açtı; Peygamber ﷺ bunu öğrenince şöyle buyurdu: "Allah, güneş batıncaya kadar bizi orta namazdan alıkoydukları için onların kalplerini ve evlerini ateşle doldursun!" (Buhârî 2931, Müslim 627)  –  nadiren ettiği bir bedduadır; İkindi'yi kaçırmanın ağırlığını gösterir.`, urd: `"اپنی نمازوں کی حفاظت کرو خصوصاً درمیانی نماز کی، اور اللہ کے سامنے خشوع سے کھڑے ہو۔" (البقرہ ۲:۲۳۸)۔ علی، ابو ہریرہ، ابن مسعود اور ابن عباس (رضی اللہ عنہم) سمیت صحابہ نے "درمیانی نماز" کو عصر کے طور پر تصدیق فرمائی۔ غزوۂ خندق نے صحابہ کی عصر مؤخر کر دی؛ نبی ﷺ نے یہ جان کر فرمایا: "اللہ ان کے دلوں اور گھروں کو آگ سے بھر دے کیونکہ انہوں نے ہمیں درمیانی نماز سے سورج غروب ہونے تک روکا!" (بخاری ۲۹۳۱، مسلم ۶۲۷)  –  ایسی بد دعا جو آپ ﷺ نے کم ہی فرمائی، عصر چھوڑنے کی شدت کو ظاہر کرتی ہے۔`, ben: `"তোমাদের নামাজগুলোর হেফাজত করো, বিশেষভাবে মধ্য নামাজের, এবং বিনয়ের সাথে আল্লাহর সামনে দাঁড়াও।" (আল-বাকারাহ ২:২৩৮)। আলী, আবু হুরায়রা, ইবন মাসঊদ ও ইবন আব্বাস (রা)-সহ সাহাবিগণ "মধ্য নামাজ"-কে আসর হিসেবে নিশ্চিত করেছেন। খন্দকের যুদ্ধ সাহাবিদের আসর বিলম্বিত করেছিল; নবী ﷺ এটি জানতে পেরে বললেন: "আল্লাহ যেন তাদের অন্তর ও ঘর আগুনে ভরে দেন কারণ তারা সূর্যাস্ত পর্যন্ত আমাদের মধ্য নামাজ থেকে বিরত রেখেছে!" (বুখারি ২৯৩১, মুসলিম ৬২৭)  –  একটি অভিশাপ যা তিনি ﷺ কদাচিৎ উচ্চারণ করেছেন, আসর ছেড়ে দেওয়ার গুরুত্ব প্রকাশ করে।`, fas: `"بر نمازهای خود محافظت کنید، به‌ویژه نماز میانه، و در پیشگاه خدا با خضوع بایستید." (البقره ۲:۲۳۸). صحابه از جمله علی، ابوهریره، ابن مسعود و ابن عباس (رض) "نماز میانه" را عصر تأیید کرده‌اند. جنگ خندق سبب تأخیر عصر صحابه شد؛ پیامبر ﷺ چون شنید فرمود: "خدا قلب‌ها و خانه‌هایشان را پر از آتش کند که ما را تا غروب از نماز میانه بازداشتند!" (بخاری ۲۹۳۱، مسلم ۶۲۷)  –  نفرینی که آن حضرت کمتر می‌فرمود و سنگینی ترک عصر را نشان می‌دهد.`, zh: `「你们当谨守拜功，尤其当谨守中正的拜功，并当虔诚地为真主而立。」（巴格拉章2:238）。圣门弟子如阿里、艾布·胡赖赖、伊本·麦斯欧德、伊本·阿巴斯（愿主喜悦之）皆确证「中正的拜功」即晡礼。壕沟之战使圣门弟子延误晡礼；先知ﷺ闻而言：「愿真主以火填满他们的心与房舍，因他们使我们错过中正的拜功直至日落！」（布哈里2931，穆斯林627）  –  此为先知ﷺ罕有之诅咒，足见错过晡礼之严重。`, yue: `「你哋當謹守拜功，尤其當謹守中正嘅拜功，並當虔誠咁為真主而立。」（巴格拉章2:238）。聖門弟子如阿里、艾布·胡賴賴、伊本·麥斯歐德、伊本·阿巴斯（願主喜悅之）皆確證「中正嘅拜功」就係晡禮。壕溝之戰使聖門弟子延誤晡禮；先知ﷺ聞而言：「願真主以火填滿佢哋嘅心與房舍，因佢哋使我哋錯過中正嘅拜功直至日落！」（布哈里2931，穆斯林627）  –  此為先知ﷺ罕有之詛咒，足見錯過晡禮之嚴重。`, ja: `「礼拝、特に中間の礼拝を守り、敬虔にアッラーの御前に立ちなさい。」（バカラ章 2:238）。アリー、アブー・フライラ、イブン・マスウード、イブン・アッバース（彼ら一同にアッラーがお喜びになりますように）を含む教友たちは「中間の礼拝」がアスルであることを確認した。塹壕の戦いは教友たちのアスルを遅らせた。預言者ﷺはそれを知って仰せられた：「アッラーが彼らの心と家を火で満たされますように。彼らは日没まで我々を中間の礼拝から妨げたのだから！」（ブハーリー2931、ムスリム627）  –  預言者ﷺが滅多に口にされなかった呪詛であり、アスルを逃すことの重大さを示す。`, ru: `«Сохраняйте свои молитвы, особенно срединную молитву, и стойте перед Аллахом смиренно.» (Аль-Бакара 2:238). Сподвижники, в том числе Али, Абу Хурайра, Ибн Мас'уд и Ибн 'Аббас (да будет доволен ими Аллах), подтвердили, что «срединная молитва»  –  Аср. Битва у Рва задержала сподвижников от Асра; узнав об этом, Пророк ﷺ сказал: «Да наполнит Аллах их сердца и дома огнём, ибо они удержали нас от срединной молитвы до заката!» (Бухари 2931, Муслим 627)  –  проклятие, которое он ﷺ редко произносил, что показывает тяжесть упущения Асра.`, es: `"Guardad vuestras oraciones, especialmente la oración del medio, y poneos en pie ante Allah con devoción." (Al-Baqarah 2:238). Los Compañeros, incluidos 'Ali, Abu Hurayrah, Ibn Mas'ud e Ibn 'Abbas (que Allah esté complacido con todos ellos), confirmaron "la oración del medio" como el Asr. La Batalla del Foso retrasó el Asr de los Compañeros; el Profeta ﷺ dijo al saberlo: "¡Que Allah llene de fuego sus corazones y sus casas, pues nos retuvieron de la oración del medio hasta que el sol se puso!" (Bujari 2931, Muslim 627)  –  una maldición que él ﷺ rara vez profirió, mostrando la gravedad de perder el Asr.`, ko: `"너희 예배를 지키라, 특히 중간 예배를. 그리고 알라 앞에 경건히 서라." (알바카라 2:238). 알리, 아부 후라이라, 이븐 마스우드, 이븐 압바스(라) 등을 포함한 동료들은 "중간 예배"가 아스르임을 확인했다. 참호 전투는 동료들의 아스르를 지연시켰다. 그 사실을 안 예언자 ﷺ께서 말씀하셨다: "그들이 일몰까지 우리를 중간 예배로부터 막았으니, 알라께서 그들의 마음과 집을 불로 채우시기를!" (부카리 2931, 무슬림 627)  –  그분 ﷺ께서 좀처럼 입에 담지 않으신 저주이며, 아스르를 놓치는 일의 무거움을 보여준다.`, ta: `"உங்கள் தொழுகைகளை, குறிப்பாக நடுத்தர தொழுகையை, பாதுகாத்துக் கொள்ளுங்கள், அல்லாஹ்வின் முன் பணிவுடன் நில்லுங்கள்." (அல்-பகரா 2:238). அலி, அபூ ஹுரைரா, இப்னு மஸ்ஊத், இப்னு அப்பாஸ் (ரளி) உள்ளிட்ட தோழர்கள் "நடுத்தர தொழுகை" அஸ்ர் என உறுதிப்படுத்தினர். அகழ்ப் போர் தோழர்களின் அஸ்ரைத் தாமதப்படுத்தியது; அதை அறிந்த நபி ﷺ கூறினார்: "சூரியன் அஸ்தமிக்கும் வரை எங்களை நடுத்தர தொழுகையிலிருந்து தடுத்ததால் அவர்களின் இதயங்களையும் வீடுகளையும் அல்லாஹ் நெருப்பால் நிரப்புவானாக!" (புகாரி 2931, முஸ்லிம் 627)  –  நபி ﷺ அரிதாகவே உச்சரித்த சாபம், அஸ்ரை விட்டுவிடுவதின் கடினத்தைக் காட்டுகிறது.`, si: `"ඔබේ සලාත සුරකින්න, විශේෂයෙන් මැද සලාතය, සහ අල්ලාහ් ඉදිරියේ භක්තියෙන් සිටගන්න." (අල්-බකරා 2:238). අලී, අබූ හුරෛරා, ඉබ්නු මස්උද් සහ ඉබ්නු අබ්බාස් (රළි) ඇතුළු සහචරයන් "මැද සලාතය" අස්ර් බව තහවුරු කළහ. අගල් සටන සහචරයන්ගේ අස්ර් ප්‍රමාද කළ අතර, එය දැනගත් නබි ﷺ පැවසූහ: "හිරු බැසීම දක්වා අපව මැද සලාතයෙන් වළක්වා දැමූ බැවින් අල්ලාහ් ඔවුන්ගේ හදවත් හා නිවාස ගින්නෙන් පුරවාලාවා!" (බුහාරි 2931, මුස්ලිම් 627)  –  උන්වහන්සේ ﷺ දුර්ලභව පැවසූ ශාපයක්; අස්ර් මඟ හැරීමේ බැරෑරුම්කම පෙන්වයි.` },
  asr_proof_h: { en: `The Prophet ﷺ said: "Whoever misses Asr, his deeds are nullified." (Bukhari 553). And: "The angels of the night and the angels of the day take turns over you, gathering at Fajr and at Asr. Then those who had been with you ascend and the Lord asks them — though He knows best — 'How did you leave My servants?' They say: 'We left them while they were praying, and we came to them while they were praying.'" (Bukhari 555, Muslim 632). Asr and Fajr are the two prayers angels witness as the believer's day opens and closes.`, ms: `Nabi ﷺ bersabda: "Sesiapa yang terlepas Asar, amalannya dibatalkan." (Bukhari 553). Dan: "Malaikat malam dan malaikat siang bergilir-gilir menjaga kamu, dan berkumpul pada Subuh dan Asar. Kemudian yang bersama kamu naik dan Tuhan bertanya kepada mereka  –  walaupun Dia lebih mengetahui  –  'Bagaimana kamu tinggalkan hamba-hamba-Ku?' Mereka menjawab: 'Kami tinggalkan mereka sedang bersolat, dan kami datang kepada mereka sedang bersolat.'" (Bukhari 555, Muslim 632). Asar dan Subuh adalah dua solat yang malaikat saksikan ketika hari mukmin terbuka dan tertutup.`, tur: `Peygamber ﷺ buyurdu: "Kim İkindi'yi kaçırırsa amelleri boşa gider." (Buhârî 553). Ve: "Gece ile gündüz melekleri sırayla yanınızda bulunur; Sabah'ta ve İkindi'de toplanırlar. Sonra yanınızda kalanlar yükselir ve Rab onlara  –  daha iyi bildiği halde  –  sorar: 'Kullarımı nasıl bıraktınız?' Derler ki: 'Onları namaz kılarken bıraktık ve namaz kılarken bulduk.'" (Buhârî 555, Müslim 632). İkindi ve Sabah, mü'minin günü açılırken ve kapanırken meleklerin şahit olduğu iki namazdır.`, urd: `نبی ﷺ نے فرمایا: "جو عصر چھوڑ دے، اس کے اعمال ضائع ہو جاتے ہیں۔" (بخاری ۵۵۳)۔ اور: "رات اور دن کے فرشتے باری باری تمہارے پاس آتے ہیں، اور فجر اور عصر میں اکٹھے ہوتے ہیں۔ پھر جو تمہارے ساتھ تھے وہ اوپر جاتے ہیں اور رب ان سے پوچھتا ہے  –  حالانکہ وہ بہتر جانتا ہے  –  'تم نے میرے بندوں کو کس حال میں چھوڑا؟' وہ کہتے ہیں: 'ہم نے انہیں نماز پڑھتے ہوئے چھوڑا اور انہیں نماز پڑھتے ہوئے پایا۔'" (بخاری ۵۵۵، مسلم ۶۳۲)۔ عصر اور فجر وہ دو نمازیں ہیں جن پر فرشتے گواہی دیتے ہیں جب مومن کا دن کھلتا اور بند ہوتا ہے۔`, ben: `নবী ﷺ বলেছেন: "যে আসর হারিয়ে ফেলে, তার আমল বিনষ্ট হয়।" (বুখারি ৫৫৩)। আরও: "রাতের ও দিনের ফেরেশতাগণ পালা করে তোমাদের কাছে আসেন, এবং ফজর ও আসরে একত্রিত হন। এরপর যারা তোমাদের সাথে ছিলেন তারা ঊর্ধ্বে যান এবং প্রভু তাদের জিজ্ঞাসা করেন  –  যদিও তিনি সবচেয়ে ভালো জানেন  –  'তোমরা আমার বান্দাদের কোন অবস্থায় ছেড়েছ?' তারা বলেন: 'আমরা তাদের নামাজরত অবস্থায় ছেড়েছি, এবং নামাজরত অবস্থায় তাদের কাছে এসেছিলাম।'" (বুখারি ৫৫৫, মুসলিম ৬৩২)। আসর ও ফজর সেই দুই নামাজ যেগুলোতে ফেরেশতাগণ সাক্ষ্য দেন যখন মুমিনের দিন খোলে ও বন্ধ হয়।`, fas: `پیامبر ﷺ فرمود: "هرکس عصر را از دست بدهد، اعمالش تباه می‌شود." (بخاری ۵۵۳). و: "فرشتگان شب و فرشتگان روز به نوبت نزد شما می‌آیند و در فجر و عصر گرد می‌آیند. سپس کسانی که با شما بودند بالا می‌روند و خداوند از آنان می‌پرسد  –  هرچند او بهتر می‌داند  –  'بندگانم را در چه حال ترک کردید؟' می‌گویند: 'آنان را در حال نماز ترک کردیم و در حال نماز نزد آنان آمده بودیم.'" (بخاری ۵۵۵، مسلم ۶۳۲). عصر و فجر دو نمازی هستند که فرشتگان هنگام آغاز و پایان روز مؤمن بر آن گواهی می‌دهند.`, zh: `先知ﷺ言：「凡错过晡礼者，其功绩归于无效。」（布哈里553）。又：「夜间天使与白昼天使轮流值守于你们之上，集会于晨礼与晡礼。随后与你们同在者升上，主问他们  –  尽管祂最知  –  '你们留下我的仆人在何种状态？' 他们说：'我们留下他们在礼拜之中，并在礼拜之中到达他们。'」（布哈里555，穆斯林632）。晡礼与晨礼乃信士一日开启与闭合时天使所见证之二拜。`, yue: `先知ﷺ言：「凡錯過晡禮者，其功績歸於無效。」（布哈里553）。又：「夜間天使與白晝天使輪流值守於你哋之上，集會於晨禮與晡禮。隨後與你哋同在者升上，主問佢哋  –  雖然祂最知  –  '你哋留下我嘅僕人喺乜嘢狀態？' 佢哋話：'我哋留下佢哋喺禮拜之中，並喺禮拜之中到達佢哋。'」（布哈里555，穆斯林632）。晡禮與晨禮乃信士一日開啟與閉合時天使所見證之二拜。`, ja: `預言者ﷺは仰せられた：「アスルを逃した者は、その行いが無効となる。」（ブハーリー553）。また：「夜の天使と昼の天使は交代であなたがたの上に来て、ファジュルとアスルで集まる。その後、あなたがたと共にいた者たちが昇り、主は彼らに問われる  –  最もよく知り給うにもかかわらず  –  『わが僕たちをどのような状態で残してきたか』。彼らは言う：『私たちは彼らが礼拝中の時に残し、礼拝中の時に彼らのところに着きました。』」（ブハーリー555、ムスリム632）。アスルとファジュルは、信者の一日が開き閉じる時に天使が立ち会う二つの礼拝である。`, ru: `Пророк ﷺ сказал: "Кто пропустил Аср, тот свёл на нет свои деяния." (Бухари 553). И: "Ангелы ночи и ангелы дня сменяют друг друга над вами, собираясь на Фаджре и Асре. Затем те, что были с вами, восходят, и Господь спрашивает их  –  хотя Он лучше знает  –  'В каком состоянии вы оставили Моих рабов?' Они говорят: 'Мы оставили их молящимися, и мы пришли к ним молящимися.'" (Бухари 555, Муслим 632). Аср и Фаджр  –  две молитвы, при которых ангелы свидетельствуют, когда день верующего открывается и закрывается.`, es: `El Profeta ﷺ dijo: "Quien pierde el Asr, sus obras quedan anuladas." (Bujari 553). Y: "Los ángeles de la noche y los ángeles del día se turnan sobre vosotros, reuniéndose en el Fajr y en el Asr. Luego los que estaban con vosotros ascienden, y el Señor les pregunta  –  aunque Él mejor sabe  –  '¿En qué estado dejasteis a Mis siervos?' Dicen: 'Los dejamos rezando, y los encontramos rezando.'" (Bujari 555, Muslim 632). El Asr y el Fajr son las dos oraciones en las que los ángeles atestiguan al abrirse y cerrarse el día del creyente.`, ko: `예언자 ﷺ께서 말씀하셨다: "아스르를 놓치는 자는 그의 행위가 무효가 된다." (부카리 553). 또한: "밤의 천사와 낮의 천사가 너희에게 번갈아 와서, 파즈르와 아스르에서 모인다. 그 후 너희와 함께 있던 자들이 올라가고, 주님께서 그들에게 물으신다  –  그분이 가장 잘 아시지만  –  '너희는 내 종들을 어떤 상태로 두고 왔느냐?' 그들이 말한다: '우리는 그들이 예배 중에 있을 때 두고 왔고, 예배 중에 있을 때 그들에게 도착했습니다.'" (부카리 555, 무슬림 632). 아스르와 파즈르는 신자의 하루가 열리고 닫힐 때 천사들이 증언하는 두 예배이다.`, ta: `நபி ﷺ கூறினார்: "அஸ்ரை விட்டுவிட்டவரின் செயல்கள் வீணாகும்." (புகாரி 553). மேலும்: "இரவின் வானவர்களும் பகலின் வானவர்களும் மாறி மாறி உங்கள் மீது வருகின்றனர், ஃபஜ்ர் மற்றும் அஸ்ரில் கூடுகின்றனர். பின் உங்களுடன் இருந்தவர்கள் மேலே செல்கின்றனர், இறைவன் அவர்களைக் கேட்கிறான்  –  அவன் மிக நன்கு அறிந்திருந்தாலும்  –  'என் அடியார்களை எந்த நிலையில் விட்டுவந்தீர்கள்?' அவர்கள் கூறுவர்: 'அவர்கள் தொழுகையில் இருக்கையில் விட்டுவந்தோம், தொழுகையில் இருக்கையிலேயே சென்றடைந்தோம்.'" (புகாரி 555, முஸ்லிம் 632). அஸ்ரும் ஃபஜ்ரும் விசுவாசியின் நாள் திறக்கும்போதும் மூடும்போதும் வானவர்கள் சாட்சியளிக்கும் இரு தொழுகைகள்.`, si: `නබි ﷺ පැවසූහ: "අස්ර් මඟ හරින්නාගේ ක්‍රියා නිෂ්ඵල වේ." (බුහාරි 553). තවද: "රාත්‍රී මලාඉකාවරුද දිවා මලාඉකාවරුද වරින් වර ඔබ වෙත පැමිණෙති; ෆජ්ර්හි සහ අස්ර්හි එක්ව රැස්වෙති. පසුව ඔබ සමඟ සිටි අය ඉහළට යති, පරමාධිපති ඔවුන්ගෙන් අසයි  –  උන්වහන්සේ වඩාත් දන්නේ වුවද  –  'මාගේ දාසයන් කවර තත්ත්වයක දමා ආවෙහි ද?' ඔවුහු කියති: 'අපි ඔවුන් සලාත් කරමින් සිටිය දී ඔවුන් දමා ආවෙමු, සලාත් කරමින් සිටිය දී ඔවුන් වෙත පැමිණියෙමු.'" (බුහාරි 555, මුස්ලිම් 632). අස්ර් සහ ෆජ්ර් යනු විශ්වාසවන්තයාගේ දිනය විවර වන හා වැසෙන විට මලාඉකාවරු සාක්ෂි දරන සලාත දෙකයි.` },
  asr_recitation: { en: `Silent (sirri) in all four rak'ahs. Shorter than Dhuhr  –  the Sunnah length is to recite around half of what is recited in Dhuhr in the first two rak'ahs. The Prophet ﷺ often selected from the Mufassal section (chapters from al-Buruj 85 onward) but kept it medium-short. In the third and fourth rak'ahs only Surah al-Fatihah is recited, with no additional surah, in the standard view. The relatively shorter recitation reflects that Asr falls when the worshipper's energy is at its lowest point in the day; Allah eased the burden while still requiring its complete preservation.`, ms: `Sirri (perlahan) dalam keempat-empat rakaat. Lebih pendek daripada Zuhur  –  panjang sunnahnya adalah membaca lebih kurang separuh daripada apa yang dibaca dalam Zuhur pada dua rakaat pertama. Nabi ﷺ sering memilih daripada bahagian Mufassal (surah dari al-Buruj 85 dan seterusnya) tetapi mengekalkannya sederhana pendek. Pada rakaat ketiga dan keempat hanya Surah al-Fatihah dibaca, tanpa surah tambahan, mengikut pendapat piawai. Bacaan yang relatif lebih pendek ini mencerminkan bahawa Asar jatuh ketika tenaga mukmin berada pada titik terendah dalam sehari; Allah meringankan beban sambil tetap menuntut pemeliharaannya sepenuhnya.`, tur: `Dört rekâtın hepsinde sirrî (sessiz). Öğle'den daha kısadır  –  sünnet uzunluk, ilk iki rekâtta Öğle'de okunanın yaklaşık yarısı kadardır. Peygamber ﷺ genellikle Mufassal bölümünden (Bürûc 85'ten itibaren) seçer, fakat orta-kısa tutardı. Standart görüşe göre üçüncü ve dördüncü rekâtlarda yalnızca Fâtiha okunur. Görece daha kısa kıraat, İkindi'nin mü'minin enerjisinin günün en düşük noktasında olduğu vakte denk geldiğini yansıtır; Allah yükü hafifletmiş, ancak namazın tam olarak korunmasını istemiştir.`, urd: `چاروں رکعتوں میں سرّاً (آہستہ)۔ ظہر سے چھوٹی  –  سنّت طوالت یہ ہے کہ پہلی دو رکعتوں میں ظہر کی قراءت کا تقریباً نصف پڑھا جائے۔ نبی ﷺ اکثر مفصل کے حصے سے (سورۃ البروج ۸۵ سے آگے) چنتے مگر اسے درمیانہ سے چھوٹا رکھتے۔ معیاری رائے میں تیسری اور چوتھی رکعت میں صرف فاتحہ پڑھی جاتی ہے۔ یہ نسبتاً مختصر قراءت ظاہر کرتی ہے کہ عصر اس وقت آتی ہے جب مومن کی توانائی دن کے سب سے کم نقطے پر ہوتی ہے؛ اللہ نے بوجھ ہلکا کیا مگر اس کی مکمل حفاظت کا تقاضا برقرار رکھا۔`, ben: `চার রাকাতেই সিররি (নীরবে)। যোহরের চেয়ে সংক্ষিপ্ত  –  সুন্নাহ দৈর্ঘ্য হলো প্রথম দুই রাকাতে যোহরে যা পড়া হয় তার প্রায় অর্ধেক পড়া। নবী ﷺ প্রায়ই মুফাসসাল অংশ থেকে (সূরা আল-বুরূজ ৮৫ এবং পরবর্তী) বেছে নিতেন কিন্তু মধ্যম-সংক্ষিপ্ত রাখতেন। মানসম্মত মতে তৃতীয় ও চতুর্থ রাকাতে শুধু ফাতিহা পড়া হয়। তুলনামূলকভাবে সংক্ষিপ্ত কেরাত প্রতিফলিত করে যে আসর তখন আসে যখন মুমিনের শক্তি দিনের সর্বনিম্ন বিন্দুতে; আল্লাহ বোঝা হালকা করেছেন কিন্তু এর পূর্ণ সংরক্ষণ এখনও দাবি করেন।`, fas: `در هر چهار رکعت سرّی (آرام). از ظهر کوتاه‌تر  –  درازای سنت آن است که در دو رکعت اول حدوداً نصف آنچه در ظهر می‌خوانند خوانده شود. پیامبر ﷺ اغلب از مفصل (از بروج ۸۵ به بعد) برمی‌گزید اما متوسط-کوتاه نگه می‌داشت. در نظر مرسوم در رکعت سوم و چهارم تنها فاتحه خوانده می‌شود. این قرائت نسبتاً کوتاه‌تر بازتاب آن است که عصر در پایین‌ترین نقطه انرژی روزانه مؤمن فرامی‌رسد؛ خدا بار را سبک کرده اما حفظ کامل آن را همچنان لازم می‌داند.`, zh: `四拜均为低声（西里）。较晌礼为短  –  圣行长度为前两拜诵读约晌礼之半。先知ﷺ常自《细分章》之段（自《星宿章》85起）选取，但保持中至短。依标准之见，第三、第四拜仅诵《开端章》。此相对较短之诵读反映：晡礼降临之刻，信士一日精力处于最低点；真主减其负担，仍要求完整守护此功。`, yue: `四拜均為低聲（西里）。較晌禮為短  –  聖行長度為前兩拜誦讀約晌禮之半。先知ﷺ常自《細分章》之段（自《星宿章》85起）選取，但保持中至短。依標準之見，第三、第四拜僅誦《開端章》。此相對較短之誦讀反映：晡禮降臨之刻，信士一日精力處於最低點；真主減其負擔，仍要求完整守護此功。`, ja: `四ラクアともに無声（シッリー）。ズフルより短い  –  スンナの長さは、最初の二ラクアでズフルで読まれる量の約半分。預言者ﷺはしばしばムファッサル部（ブルージュ章 85 以降）から選ばれたが、中～短に保たれた。標準的見解では、第三・第四ラクアではファーティハ章のみ朗誦する。比較的短い朗誦は、アスルが信者の一日のエネルギーが最低点にある時刻に降りてくることを反映する。アッラーは負担を軽くされたが、完全な保持はなお求められる。`, ru: `Тихо (сирри) во всех четырёх ракатах. Короче, чем Зухр  –  сунновская длина  –  читать в первых двух ракатах примерно вдвое короче, чем в Зухре. Пророк ﷺ часто выбирал из раздела Муфассал (с суры аль-Бурудж 85 и далее), но держал чтение средне-коротким. По стандартному мнению, в третьем и четвёртом ракатах читается только сура аль-Фатиха. Это относительно более короткое чтение отражает, что Аср приходит, когда силы верующего на их самой низкой точке за день; Аллах облегчил бремя, при этом требуя полного сохранения молитвы.`, es: `Silenciosa (sirri) en los cuatro rak'ahs. Más corta que el Dhuhr  –  la longitud Sunnah es recitar en los dos primeros rak'ahs aproximadamente la mitad de lo que se recita en el Dhuhr. El Profeta ﷺ solía seleccionar de la sección del Mufassal (capítulos desde al-Buruy 85), pero mantenerla en media-corta. Según el parecer estándar, en el tercer y cuarto rak'ah solo se recita la Sura al-Fatiha. La recitación relativamente más corta refleja que el Asr cae cuando la energía del creyente está en su punto más bajo del día; Allah aligeró la carga mientras seguía requiriendo su completa preservación.`, ko: `네 라카 모두 무성(시르리). 주흐르보다 짧다  –  순나 길이는 처음 두 라카에서 주흐르에서 낭송하는 양의 약 절반. 예언자 ﷺ께서는 종종 무팟살 부분(알부루즈 85 이후)에서 고르셨지만 중간에서 짧게 유지하셨다. 표준 견해에서 셋째·넷째 라카에서는 알파티하만 낭송한다. 비교적 짧은 낭송은 아스르가 신자의 에너지가 하루 중 가장 낮은 지점에 있을 때 다가옴을 반영한다; 알라께서 부담은 가볍게 하시되 여전히 그것의 완전한 보존을 요구하신다.`, ta: `நான்கு ரக்அத்களிலும் ஸிர்ரி (அமைதியாக). ளுஹரை விட குறுகியது  –  சுன்னா நீளம் என்பது முதல் இரு ரக்அத்களில் ளுஹரில் ஓதப்படுவதின் சுமார் பாதி ஓதுவது. நபி ﷺ அடிக்கடி முஃபஸ்ஸல் பகுதியிலிருந்து (சூரத்துல்-புரூஜ் 85 முதலானவை) தேர்ந்தெடுத்தார் ஆனால் நடுத்தர முதல் குறுகியதாக வைத்தார். நிலையான கருத்தின்படி மூன்றாவது நான்காவது ரக்அத்களில் ஃபாதிஹா மட்டுமே ஓதப்படுகிறது. ஒப்பீட்டளவில் குறுகிய ஓதல், விசுவாசியின் ஆற்றல் நாளில் மிகக் குறைந்த இடத்தில் இருக்கும்போது அஸ்ர் வருகிறது என்பதை பிரதிபலிக்கிறது; அல்லாஹ் சுமையை இலகுவாக்கினான், ஆனால் இன்னும் அதன் முழுமையான பாதுகாப்பையும் கோருகிறான்.`, si: `රකඅත් හතරේදීම නිහඬව (සිර්රී). සුහ්ර්ට වඩා කෙටිය  –  සුන්නා දිග වන්නේ පළමු රකඅත් දෙකේ සුහ්ර්හි කියවන දෙයින් ආසන්න වශයෙන් අඩක් කියවීමයි. නබි ﷺ බොහෝ විට මුෆස්සල් කොටසින් (අල්-බුරූජ් 85 සිට) තෝරා ගත් අතර, මධ්‍යම සිට කෙටි ලෙස තබා ගත්හ. සම්මත මතය අනුව තෙවැන්න සහ සිවුවැන්න රකඅත්හිදී අල්-ෆාතිහා පමණක් කියවයි. සාපේක්ෂව කෙටි කියවීම පෙන්වන්නේ අස්ර් යනු විශ්වාසවන්තයාගේ ශක්තිය දවසේ අවම ස්ථානයේ ඇති විට පැමිණෙන බවයි; අල්ලාහ් භාරය සැහැල්ලු කළ අතර, එහි පූර්ණ සුරැකීම තවමත් අවශ්‍ය කරයි.` },
  asr_sunnah_say: { en: `In the recommended four rak'ahs before Asr, the Prophet ﷺ would separate them with a tasleem after every two rak'ahs ("the prayer of the night and the day is two and two"  –  Tirmidhi 597). Recite a moderate-length surah in each. There is no confirmed Sunnah after Asr; in fact, voluntary prayer between Asr and Maghrib (specifically once the sun starts turning yellow) is among the times forbidden by the Prophet ﷺ. The "missed Sunnahs" exception is for the two rak'ahs of Sunnah Dhuhr that one missed; those may be made up after the Asr fard.`, ms: `Pada empat rakaat sunat yang digalakkan sebelum Asar, Nabi ﷺ akan memisahkannya dengan satu salam setiap dua rakaat ("solat malam dan siang itu dua-dua"  –  Tirmidhi 597). Bacalah satu surah sederhana panjang pada setiap satu. Tiada sunnah muakkad selepas Asar; bahkan solat sunat antara Asar dan Maghrib (khususnya setelah matahari mula menguning) adalah antara waktu yang Nabi ﷺ larang. Pengecualian "sunat yang tertinggal" adalah untuk dua rakaat sunat Zuhur yang terlepas; itu boleh diqadhakan selepas fardu Asar.`, tur: `İkindi öncesi tavsiye edilen dört rekâtta Peygamber ﷺ her iki rekâttan sonra selam vererek ayırırdı ("gece ve gündüz namazı ikişer ikişerdir"  –  Tirmizî 597). Her birinde orta uzunlukta bir sure okuyun. İkindi'den sonra müekked sünnet yoktur; aksine, İkindi ile Akşam arasında (özellikle güneş sararmaya başladıktan sonra) nafile namaz, Peygamber'in ﷺ yasakladığı vakitlerdendir. "Kaçırılan sünnetler" istisnası, kişinin kaçırdığı Öğle sünnetinin iki rekâtı içindir; bunlar İkindi farzından sonra kaza edilebilir.`, urd: `عصر سے قبل مستحب چار رکعات میں نبی ﷺ ہر دو رکعت کے بعد سلام پھیر کر انہیں الگ کرتے ("رات اور دن کی نماز دو دو ہے"  –  ترمذی ۵۹۷)۔ ہر ایک میں متوسط طوالت کی سورت پڑھیں۔ عصر کے بعد کوئی سنّت مؤکدہ نہیں؛ بلکہ عصر اور مغرب کے درمیان (خاص طور پر سورج کے زرد ہونے کے بعد) نفل نماز اُن اوقات میں سے ہے جن میں نبی ﷺ نے منع فرمایا۔ "چھوٹی ہوئی سنّتوں" کا استثنا ظہر کی دو رکعت سنّت کا ہے جو رہ گئی ہوں؛ انہیں عصر کے فرض کے بعد قضا کیا جا سکتا ہے۔`, ben: `আসরের আগে সুপারিশকৃত চার রাকাতে নবী ﷺ প্রতি দুই রাকাতের পর সালাম দিয়ে এগুলো আলাদা করতেন ("রাত ও দিনের নামাজ দুই দুই করে"  –  তিরমিযি ৫৯৭)। প্রতিটিতে মধ্যম দৈর্ঘ্যের একটি সূরা পড়ুন। আসরের পর কোনো নিশ্চিত সুন্নাহ নেই; বরং আসর ও মাগরিবের মাঝে (বিশেষত সূর্য হলুদ হতে শুরু করার পর) নফল নামাজ নবী ﷺ-এর নিষেধ করা সময়সমূহের অন্তর্ভুক্ত। "ছুটে যাওয়া সুন্নাহ"-এর ব্যতিক্রম হলো যোহরের দুই রাকাত সুন্নাহ যা ছুটে গেছে; সেগুলো আসরের ফরজের পরে কাযা করা যেতে পারে।`, fas: `در چهار رکعت مستحب پیش از عصر، پیامبر ﷺ هر دو رکعت را با یک سلام جدا می‌فرمود ("نماز شب و روز دو دو رکعت است"  –  ترمذی ۵۹۷). در هر دو رکعت سوره‌ای متوسط بخوان. پس از عصر سنت مؤکد نیست؛ بلکه نماز نافله میان عصر و مغرب (به‌ویژه پس از زرد شدن خورشید) از وقت‌هایی است که پیامبر ﷺ از آن نهی فرموده. استثنای "سنت‌های فوت‌شده" دو رکعت سنت ظهر است که فوت شده باشد؛ آنها را می‌توان پس از فرض عصر قضا کرد.`, zh: `于晡礼前所嘉之四拜中，先知ﷺ每两拜以一次平安词分隔之（「夜与昼之拜功，两两为一组」  –  提尔米兹597）。每两拜中诵一中等长度之章。晡礼后无确证之圣行；反之，晡礼与昏礼之间（尤其日色转黄之后）礼副功，乃先知ﷺ所禁之时段。「补漏圣行」之例外是错过的晌礼后两拜圣行；可于晡礼主命之后补礼。`, yue: `於晡禮前所嘉之四拜中，先知ﷺ每兩拜以一次平安詞分隔之（「夜與晝之拜功，兩兩為一組」  –  提爾米茲597）。每兩拜中誦一中等長度之章。晡禮後無確證之聖行；反之，晡禮與昏禮之間（尤其日色轉黃之後）禮副功，乃先知ﷺ所禁之時段。「補漏聖行」之例外係錯過嘅晌禮後兩拜聖行；可於晡禮主命之後補禮。`, ja: `アスル前の推奨四ラクアにおいて、預言者ﷺは二ラクアごとにサラームで区切られた（「夜と昼の礼拝は二と二である」  –  ティルミズィー597）。それぞれに中庸の長さの章を朗誦する。アスル後に確認されたスンナはない。実際、アスルとマグリブの間（特に太陽が黄ばみ始めて以降）の任意礼拝は預言者ﷺが禁じた時の一つ。「逃したスンナ」例外は、逃したズフル後の二ラクアのスンナで、これはアスルのファルド後に補える。`, ru: `В рекомендованных четырёх ракатах перед Асром Пророк ﷺ разделял их саламом после каждой двойки ("молитва ночи и дня  –  по два"  –  Тирмизи 597). Читай суру средней длины в каждой паре. После Асра подтверждённой сунны нет; более того, добровольная молитва между Асром и Магрибом (особенно после того, как солнце начнёт желтеть)  –  одно из времён, запрещённых Пророком ﷺ. Исключение "пропущенных сунн"  –  два раката сунны Зухра, которые человек пропустил: их можно восполнить после фарда Асра.`, es: `En los cuatro rak'ahs recomendados antes del Asr, el Profeta ﷺ los separaba con un salam tras cada dos rak'ahs ("la oración de la noche y del día es de dos en dos"  –  Tirmidhi 597). Recita una sura de longitud moderada en cada par. No hay Sunnah confirmada tras el Asr; de hecho, la oración voluntaria entre el Asr y el Maghrib (especialmente una vez que el sol comienza a amarillear) figura entre los tiempos prohibidos por el Profeta ﷺ. La excepción de las "Sunnahs perdidas" es para los dos rak'ahs Sunnah del Dhuhr que se hayan perdido; pueden recuperarse tras el fard del Asr.`, ko: `아스르 전 권장되는 네 라카에서 예언자 ﷺ께서는 두 라카마다 살람으로 나누셨다("밤과 낮의 예배는 둘과 둘이다"  –  티르미디 597). 각 쌍에서 중간 길이의 장을 낭송하라. 아스르 후에는 확정된 순나가 없다; 사실 아스르와 마그립 사이(특히 태양이 노랗게 변하기 시작한 후)의 자발 예배는 예언자 ﷺ께서 금하신 시간 중 하나이다. "놓친 순나" 예외는 놓친 주흐르 두 라카 순나에 한하며, 아스르 파르드 후에 보충할 수 있다.`, ta: `அஸ்ருக்கு முன் பரிந்துரைக்கப்பட்ட நான்கு ரக்அத்களில் நபி ﷺ ஒவ்வொரு இரு ரக்அத்களுக்குப் பின் ஸலாமுடன் பிரித்தார் ("இரவின் மற்றும் பகலின் தொழுகை இரண்டிரண்டாக"  –  திர்மிதி 597). ஒவ்வொரு ஜோடியிலும் நடுத்தர நீளமான ஒரு சூரா ஓதவும். அஸ்ருக்குப் பின் வலியுறுத்தப்பட்ட சுன்னா இல்லை; உண்மையில் அஸ்ருக்கும் மக்ரிபுக்கும் இடையேயான (குறிப்பாக சூரியன் மஞ்சளாகத் தொடங்கிய பிறகு) நஃபில் தொழுகை, நபி ﷺ தடைசெய்த நேரங்களில் ஒன்று. "தவறிய சுன்னாக்கள்" விதிவிலக்கு என்பது தவறிய ளுஹரின் இரு ரக்அத் சுன்னாக்களுக்காகவே; அவற்றை அஸ்ர் ஃபர்ளுக்குப் பிறகு கழா செய்யலாம்.`, si: `අස්ර්ට පෙර නිර්දේශිත රකඅත් හතරෙහි, නබි ﷺ සෑම රකඅත් දෙකකට පසුවම සලාම් ලබා දී වෙන් කළහ ("රාත්‍රී හා දිවා සලාත රකඅත් දෙක දෙක බැගිනි"  –  තිර්මිදී 597). සෑම යුගලයකම මධ්‍යම දිගකින් යුතු සූරාවක් කියවන්න. අස්ර්ට පසු තහවුරු කළ සුන්නා නැත; ඇත්ත වශයෙන්ම, අස්ර් සහ මග්රිබ් අතර (විශේෂයෙන් හිරු කහ වීමට පටන් ගත් පසු) ස්වේච්ඡා සලාත නබි ﷺ විසින් තහනම් කරන ලද වේලාවන් අතර වේ. "මඟ හැරුණු සුන්නාවන්" හි ව්‍යතිරේකය වන්නේ මඟ හැරුණු සුහ්ර්හි පසු සුන්නා රකඅත් දෙකයි; ඒවා අස්ර් ෆර්ද්ට පසු කදා කළ හැක.` },
  asr_extras_say: { en: `In addition to the universal post-prayer adhkar, the time after Asr until Maghrib is the second of the two prime times for "evening adhkar" (adhkar al-masa'). They have the same content as the morning adhkar and are due now; recite them while the sun is still visible. The Prophet ﷺ said: "Whoever says the morning adhkar in the morning and the evening adhkar in the evening will not be harmed by anything in between." (Abu Dawud 5074). Sitting in remembrance of Allah after Asr until sunset carries the reward of freeing four slaves from the children of Isma'il, according to the hadith. Avoid sleep, distracting conversation, and meaningless work in this window if possible.`, ms: `Selain zikir umum selepas solat, waktu antara Asar dan Maghrib adalah waktu kedua daripada dua waktu utama untuk "zikir petang" (adhkar al-masa'). Kandungannya sama seperti zikir pagi dan jatuh tempo sekarang; bacalah ketika matahari masih kelihatan. Nabi ﷺ bersabda: "Sesiapa yang membaca zikir pagi pada waktu pagi dan zikir petang pada waktu petang, tiada sesuatu pun yang akan memudaratkannya antara keduanya." (Abu Dawud 5074). Duduk dalam zikrullah selepas Asar sehingga matahari terbenam membawa pahala memerdekakan empat hamba daripada anak-anak Isma'il, menurut hadis. Elakkan tidur, perbualan yang mengganggu, dan kerja tidak bermakna dalam tetingkap ini jika boleh.`, tur: `Namaz sonrası genel zikirlere ek olarak, İkindi ile Akşam arası "akşam zikirleri" (ezkâru'l-mesâ) için iki başlıca vaktin ikincisidir. İçerik sabah zikirleriyle aynıdır ve şimdi zamanı gelmiştir; güneş hâlâ görünür iken okuyun. Peygamber ﷺ buyurdu: "Sabah sabah zikirlerini, akşam akşam zikirlerini söyleyen kişiye bunların arasında hiçbir şey zarar veremez." (Ebû Dâvûd 5074). İkindi'den gün batımına dek Allah'ı zikirde oturmak, hadise göre, İsmail evlatlarından dört köleyi azat etmenin sevabını taşır. Mümkünse bu pencerede uyumaktan, dağıtıcı sohbetten ve anlamsız işten kaçının.`, urd: `بعد از نماز عمومی اذکار کے علاوہ، عصر سے مغرب کا وقت "شام کے اذکار" (اذکار المساء) کے دو اہم اوقات میں سے دوسرا ہے۔ ان کا متن صبح کے اذکار جیسا ہی ہے اور اب وقت ہے؛ سورج کے ابھی نظر آتے ہوئے انہیں پڑھیں۔ نبی ﷺ نے فرمایا: "جو صبح صبح کے اذکار پڑھے اور شام شام کے اذکار پڑھے، ان دونوں کے درمیان اسے کوئی چیز نقصان نہیں پہنچا سکتی۔" (ابو داؤد ۵۰۷۴)۔ عصر سے غروبِ آفتاب تک ذکرِ الٰہی میں بیٹھنا حدیث کے مطابق اسماعیل کی اولاد سے چار غلام آزاد کرنے کا ثواب رکھتا ہے۔ اگر ممکن ہو تو اس وقفے میں سونے، خلل ڈالنے والی گفتگو، اور بے معنی کام سے بچیں۔`, ben: `সাধারণ নামাজোত্তর জিকিরের পাশাপাশি, আসর থেকে মাগরিব পর্যন্ত সময় "সন্ধ্যার জিকির" (আযকার আল-মাসা)-এর দুই প্রধান সময়ের দ্বিতীয়। এর বিষয়বস্তু সকালের জিকিরের মতোই এবং এখন সময়; সূর্য দৃশ্যমান থাকা অবস্থায় পড়ুন। নবী ﷺ বলেছেন: "যে সকালে সকালের জিকির ও সন্ধ্যায় সন্ধ্যার জিকির পাঠ করবে, এই দুইয়ের মাঝে তাকে কোনো কিছু ক্ষতি করতে পারবে না।" (আবু দাউদ ৫০৭৪)। আসর থেকে সূর্যাস্ত পর্যন্ত আল্লাহর স্মরণে বসা হাদিস অনুসারে ইসমাইলের সন্তানদের থেকে চার দাসকে মুক্ত করার সওয়াব বহন করে। সম্ভব হলে এই সময়ে ঘুম, মনোযোগ বিচ্ছিন্নকারী কথোপকথন, ও অর্থহীন কাজ এড়িয়ে চলুন।`, fas: `علاوه بر اذکار عمومی پس از نماز، وقت میان عصر و مغرب دومین وقت اصلی "اذکار شام" (أذکار المساء) است. متن آن همانند اذکار صبح است و اکنون موعد آن است؛ تا زمانی که خورشید پیداست بخوان. پیامبر ﷺ فرمود: "هرکس بامداد اذکار بامداد و شامگاه اذکار شامگاه را بگوید، در میان آنها چیزی به او زیان نمی‌رساند." (ابوداود ۵۰۷۴). نشستن در ذکر خدا از عصر تا غروب، طبق حدیث، پاداش آزادی چهار بنده از فرزندان اسماعیل را دارد. در صورت امکان از خواب، گفت‌و‌گوی پراکنده‌کننده و کار بی‌معنا در این بازه پرهیز کن.`, zh: `除拜功后通用赞念外，晡礼至昏礼之间为「晚念」（adhkar al-masa'）两大主要时段之第二者。其内容与晨念相同，此刻乃其当行之时；趁日仍在天空之时诵之。先知ﷺ言：「凡于清晨诵清晨之念，于黄昏诵黄昏之念者，其间无物可伤之。」（艾布·达伍德5074）。据圣训，自晡礼至日落坐于真主之记念中，具释放四名易斯马仪后裔奴隶之回赐。若可能，于此时段避免睡眠、扰人之闲谈与无意义之劳作。`, yue: `除拜功後通用讚念外，晡禮至昏禮之間為「晚念」（adhkar al-masa'）兩大主要時段之第二者。其內容與晨念相同，此刻乃其當行之時；趁日仍在天空之時誦之。先知ﷺ言：「凡於清晨誦清晨之念，於黃昏誦黃昏之念者，其間無物可傷之。」（艾布·達伍德5074）。據聖訓，自晡禮至日落坐於真主之記念中，具釋放四名易斯馬儀後裔奴隸之回賜。若可能，於此時段避免睡眠、擾人之閒談與無意義之勞作。`, ja: `礼拝後の一般的なズィクルに加えて、アスルからマグリブまでの時間は「夕方のズィクル」（アズカール・アル＝マサーゥ）の二大時間帯の第二である。内容は朝のズィクルと同じで、いまその時にあたる。太陽がまだ見えている間に唱える。預言者ﷺは仰せられた：「朝に朝のズィクル、夕に夕のズィクルを唱える者には、その間に何ものも害を与えない。」（アブー・ダーウード5074）。アスルから日没までアッラーの想起に座することは、ハディースによれば、イスマーイールの子らから四人の奴隷を解放する報奨を持つ。可能ならば、この時間帯に睡眠、気を散らす会話、無意味な仕事を避けること。`, ru: `Помимо общих послемолитвенных азкаров, время между Асром и Магрибом  –  вторая из двух главных пор для «вечерних азкаров» (азкар аль-маса'). Содержание то же, что у утренних азкаров, и сейчас их время; читай, пока солнце ещё видно. Пророк ﷺ сказал: "Тому, кто утром скажет утренние азкары и вечером  –  вечерние, между ними ничто не повредит." (Абу Дауд 5074). Сидение в поминании Аллаха от Асра до заката, по хадису, несёт награду освобождения четырёх рабов из потомков Исмаила. По возможности избегай в это окно сна, отвлекающих разговоров и бессмысленной работы.`, es: `Además de los adhkar post-oración universales, el tiempo entre el Asr y el Maghrib es el segundo de los dos tiempos principales para los "adhkar de la tarde" (adhkar al-masa'). Su contenido es el mismo que los adhkar de la mañana y son debidos ahora; recítalos mientras el sol aún sea visible. El Profeta ﷺ dijo: "Quien dice los adhkar de la mañana por la mañana y los adhkar de la tarde por la tarde, nada le perjudicará entre ambos." (Abu Dawud 5074). Sentarse en el recuerdo de Allah desde el Asr hasta la puesta del sol, según el hadiz, lleva la recompensa de liberar a cuatro esclavos de los descendientes de Isma'il. Evita en lo posible dormir, conversación distractora y trabajo insustancial en esta ventana.`, ko: `보편적 예배 후 아드카르 외에, 아스르에서 마그립 사이는 "저녁 아드카르"(아드카르 알마사으)의 두 주요 시간 중 두 번째이다. 그 내용은 아침 아드카르와 같고 지금이 그 시간이다; 태양이 아직 보일 때 낭송하라. 예언자 ﷺ께서 말씀하셨다: "아침에 아침 아드카르를, 저녁에 저녁 아드카르를 말하는 자에게 그 사이에 어떤 것도 해를 입히지 않을 것이다." (아부 다우드 5074). 하디스에 따르면 아스르부터 일몰까지 알라를 기억하며 앉아 있는 것은 이스마일의 후손 중 네 명의 노예를 해방하는 보상을 가진다. 가능하면 이 시간대에 잠, 산만한 대화, 무의미한 일을 피하라.`, ta: `பொதுவான தொழுகைக்குப் பின்தைய திக்ருகள் தவிர, அஸ்ருக்கும் மக்ரிபுக்கும் இடைப்பட்ட நேரம் "மாலை திக்ருகள்" (அத்காரு அல்-மஸா)-வின் இரு முதன்மை வேளைகளில் இரண்டாவது. அதன் உள்ளடக்கம் காலை திக்ருகளைப் போன்றதே மற்றும் இப்போது அதன் வேளை; சூரியன் இன்னும் தெரிகையில் ஓதவும். நபி ﷺ கூறினார்: "காலையில் காலை திக்ருகளையும் மாலையில் மாலை திக்ருகளையும் சொல்பவருக்கு அவற்றுக்கு இடையே எதுவும் தீங்கு செய்யாது." (அபூ தாவூத் 5074). ஹதீஸின்படி அஸ்ரிலிருந்து சூரிய அஸ்தமனம் வரை அல்லாஹ்வை நினைவுகூரும் நிலையில் அமர்வது இஸ்மாயீலின் சந்ததியிலிருந்து நான்கு அடிமைகளை விடுவிக்கும் கூலியைச் சுமக்கிறது. முடிந்தால் இந்த இடைவெளியில் தூக்கம், கவனச்சிதறல் உரையாடல், அர்த்தமற்ற வேலை ஆகியவற்றைத் தவிர்க்கவும்.`, si: `සලාතයෙන් පසු සාර්වත්‍රික දික්ර්වලට අමතරව, අස්ර් සහ මග්රිබ් අතර කාලය "සවස් දික්ර්" (අද්කාර් අල්-මසා) සඳහා වූ ප්‍රධාන කාල දෙකේ දෙවැන්නයි. එහි අන්තර්ගතය උදෑසන දික්ර්වලට සමානය, දැන් එහි කාලයයි; හිරු තවමත් පෙනෙන අතරතුර කියවන්න. නබි ﷺ පැවසූහ: "උදෑසනේදී උදෑසන දික්ර්, සවසේදී සවස් දික්ර් කියන කවරෙකුට වුවද ඒවා අතර කිසිවක් අනතුරක් නොකරයි." (අබූ දාවූද් 5074). හදීසයට අනුව අස්ර්හි සිට හිරු බැසීම දක්වා අල්ලාහ්ව සිහිපත් කරමින් වාඩි වී සිටීම ඉස්මාඊල්ගේ පරපුරෙන් වහල්ලු හතරදෙනෙකු මුදවා ගැනීමේ ප්‍රතිඵලය දරයි. හැකි නම් මෙම කාලය තුළ නින්ද, අවධානය වෙනතකට ගෙන යන කතාබහ, සහ අර්ථ විරහිත වැඩ වළකින්න.` },
  asr_virtues: { en: `Asr is half of "the two cool prayers" whose guard guarantees Paradise (Bukhari 574). Praying it in congregation has its own immense reward; the Prophet ﷺ said: "Whoever prays Asr in congregation, then sits down remembering Allah until sunrise the next morning  –  no, until Maghrib  –  has done a great act." Mu'adh ibn Jabal (ra) was taught by the Prophet ﷺ to say after every prayer: "Allahumma a'inni 'ala dhikrika wa shukrika wa husni 'ibadatik" (O Allah, help me remember You, thank You, and worship You well)  –  and this prayer was given to him specifically after an Asr. Faithful preservation of Asr is a sign of true Iman; its loss is the first crack in a believer's day.`, ms: `Asar ialah separuh daripada "dua solat sejuk" yang pemeliharaannya menjamin syurga (Bukhari 574). Mendirikannya berjemaah mempunyai pahala yang besar; Nabi ﷺ bersabda: "Sesiapa yang mendirikan Asar berjemaah, kemudian duduk berzikir kepada Allah sehingga matahari terbit pada esok hari  –  bukan, hingga Maghrib  –  telah melakukan amalan yang besar." Mu'adh ibn Jabal (ra) diajar oleh Nabi ﷺ untuk membaca selepas setiap solat: "Allahumma a'inni 'ala dhikrika wa shukrika wa husni 'ibadatik" (Ya Allah, tolonglah aku untuk mengingati-Mu, mensyukuri-Mu, dan beribadat dengan baik kepada-Mu)  –  doa ini diberikan kepadanya khususnya selepas satu solat Asar. Pemeliharaan Asar yang setia adalah tanda iman sejati; kehilangannya adalah retakan pertama dalam hari seorang mukmin.`, tur: `İkindi, korunması cenneti garanti eden "iki serinlik namazı"nın yarısıdır (Buhârî 574). Cemaatle kılmanın muazzam sevabı vardır; Peygamber ﷺ buyurdu: "Kim İkindi'yi cemaatle kılar, sonra ertesi sabah güneş doğana kadar  –  hayır, Akşam'a kadar  –  Allah'ı zikrederek oturursa büyük bir iş yapmıştır." Muâz ibn Cebel (ra), Peygamber'in ﷺ her namazdan sonra söylemesini öğrettiği: "Allâhumme einnî alâ zikrike ve şükrike ve husni ibâdetik" (Allah'ım, Seni zikretmeme, Sana şükretmeme ve Sana güzel ibadet etmeme yardım et)  –  bu dua özellikle bir İkindi sonrası ona verilmiştir. İkindi'nin sadakatle korunması gerçek imanın bir alametidir; onun kaybı, mü'minin gününün ilk çatlağıdır.`, urd: `عصر "دو ٹھنڈی نمازوں" کا نصف ہے جن کی حفاظت جنت کی ضامن ہے (بخاری ۵۷۴)۔ باجماعت پڑھنا اس کا اپنا عظیم اجر ہے؛ نبی ﷺ نے فرمایا: "جو عصر باجماعت پڑھے، پھر اللہ کو یاد کرتا ہوا اگلے دن طلوعِ آفتاب تک  –  نہیں، مغرب تک  –  بیٹھا رہے، اس نے بڑا کام کیا۔" معاذ بن جبل (رض) کو نبی ﷺ نے ہر نماز کے بعد یہ پڑھنے کی تعلیم دی: "اللهم أعنّي على ذكرك وشكرك وحسن عبادتك" (اے اللہ! اپنے ذکر، شکر، اور بہترین عبادت پر میری مدد فرما)  –  یہ دعا خاص طور پر ایک عصر کے بعد انہیں عطا کی گئی۔ عصر کی وفاداری سے حفاظت سچے ایمان کی علامت ہے؛ اس کا کھو دینا مومن کے دن کی پہلی دراڑ ہے۔`, ben: `আসর হলো "দুই শীতল নামাজ"-এর অর্ধেক, যাদের সংরক্ষণ জান্নাতের নিশ্চয়তা দেয় (বুখারি ৫৭৪)। জামাতে আদায়ের নিজস্ব বিশাল সওয়াব আছে; নবী ﷺ বলেছেন: "যে আসর জামাতে পড়ে, তারপর আল্লাহর জিকিরে বসে থাকে পরের দিন সূর্যোদয় পর্যন্ত  –  না, মাগরিব পর্যন্ত  –  সে এক বিরাট আমল করেছে।" মুআয ইবন জাবাল (রা)-কে নবী ﷺ প্রতি নামাজের পরে পড়তে শিখিয়েছেন: "আল্লাহুম্মা আ'ইন্নী 'আলা যিকরিকা ওয়া শুকরিকা ওয়া হুসনি 'ইবাদাতিক" (হে আল্লাহ! আপনার স্মরণ, শোকর, এবং উত্তম ইবাদতে আমাকে সাহায্য করুন)  –  এই দোয়া তাঁকে বিশেষত একটি আসরের পর প্রদান করা হয়েছিল। আসরের নিষ্ঠাপূর্ণ সংরক্ষণ সত্যিকারের ঈমানের চিহ্ন; এর হারানো মুমিনের দিনের প্রথম ফাটল।`, fas: `عصر نیمی از "دو نماز خنک" است که حفظش بهشت را تضمین می‌کند (بخاری ۵۷۴). گزاردن آن به جماعت پاداش بزرگ خود را دارد؛ پیامبر ﷺ فرمود: "هرکس عصر را به جماعت بگزارد، سپس در ذکر خدا تا طلوع روز بعد  –  نه، تا مغرب  –  بنشیند، کاری بزرگ کرده است." معاذ بن جبل (رض) را پیامبر ﷺ آموخت تا پس از هر نماز بگوید: "اللهم أعني على ذكرك وشكرك وحسن عبادتك" (خدایا، مرا بر ذکر، شکر و عبادت نیکوی خود یاری ده)  –  این دعا به‌ویژه پس از یک نماز عصر به او داده شد. حفظ وفادارانه عصر نشانه ایمان راستین است؛ از دست دادن آن نخستین ترک در روز یک مؤمن است.`, zh: `晡礼乃「两次凉时拜」之一半，其守保乐园（布哈里574）。集体礼之具自身之巨大回赐；先知ﷺ言：「凡集体礼晡礼，复坐于真主之记念中至翌晨日出  –  不，至昏礼  –  者，已行大事。」穆阿兹·本·杰拜勒（愿主喜悦之）由先知ﷺ教于每拜后诵：「主啊，求佑我于记念你、感谢你与善事奉于你」  –  此祷词特赐于一次晡礼之后。忠实守晡礼乃真信之标志；失之即信士一日之首裂。`, yue: `晡禮乃「兩次涼時拜」之一半，其守保樂園（布哈里574）。集體禮之具自身之巨大回賜；先知ﷺ言：「凡集體禮晡禮，復坐於真主之記念中至翌晨日出  –  不，至昏禮  –  者，已行大事。」穆阿茲·本·傑拜勒（願主喜悅之）由先知ﷺ教於每拜後誦：「主啊，求佑我於記念你、感謝你與善事奉於你」  –  此禱詞特賜於一次晡禮之後。忠實守晡禮乃真信之標誌；失之即信士一日之首裂。`, ja: `アスルは「二つの涼しい礼拝」の半分であり、その守りが楽園を保証する（ブハーリー574）。集団で行うことそれ自体に莫大な報奨がある。預言者ﷺは仰せられた：「アスルを集団で行い、その後翌朝の日の出まで  –  いや、マグリブまで  –  アッラーを想起しつつ座した者は、大いなる行いをなしたのだ。」ムアーズ・イブン・ジャバル（ラ）は預言者ﷺから毎礼拝後に唱えるようこう教えられた：「アッラーフマ・アインニー・アラー・ズィクリカ・ワ・シュクリカ・ワ・フスニ・イバーダティク」（アッラーよ、御身を想起し、御身に感謝し、御身を善く崇めるよう私を助け給え）  –  この祈りは特にあるアスル礼拝の後に彼に授けられた。アスルを忠実に守ることは真の信仰の徴であり、その喪失は信者の一日の最初の亀裂である。`, ru: `Аср  –  половина «двух прохладных молитв», сохранение которых гарантирует Рай (Бухари 574). Совершение её в коллективе несёт собственную колоссальную награду; Пророк ﷺ сказал: «Кто совершит Аср в коллективе, затем сядет в поминании Аллаха до восхода следующего утра  –  нет, до Магриба  –  совершил великое дело.» Муаз ибн Джабаль (ра) был обучен Пророком ﷺ говорить после каждой молитвы: «Аллахумма а'инни 'аля зикрика ва шукрика ва хусни 'ибадатик» (О Аллах, помоги мне поминать Тебя, благодарить Тебя и должным образом поклоняться Тебе)  –  эта мольба была передана ему именно после одной из Асров. Верное сохранение Асра  –  знак истинной веры; его утрата  –  первая трещина в дне верующего.`, es: `El Asr es la mitad de "las dos oraciones frescas" cuya guardia garantiza el Paraíso (Bujari 574). Rezarla en congregación tiene su propia recompensa inmensa; el Profeta ﷺ dijo: "Quien reza el Asr en congregación, luego se sienta recordando a Allah hasta el amanecer del día siguiente  –  no, hasta el Maghrib  –  ha realizado un acto grande." Mu'adh ibn Yabal (ra) fue enseñado por el Profeta ﷺ a decir tras cada oración: "Allahumma a'inni 'ala dhikrika wa shukrika wa husni 'ibadatik" (Oh Allah, ayúdame a recordarte, agradecerte y a adorarte de la mejor manera)  –  esta súplica le fue dada específicamente tras una oración de Asr. La preservación fiel del Asr es signo de verdadera Iman; su pérdida es la primera grieta en el día de un creyente.`, ko: `아스르는 그 보존이 천국을 보장하는 "두 시원한 예배"의 절반이다(부카리 574). 회중으로 예배하는 것은 그 자체로 막대한 보상이 있다; 예언자 ﷺ께서 말씀하셨다: "아스르를 회중으로 예배하고 다음 날 일출까지  –  아니, 마그립까지  –  알라를 기억하며 앉아 있는 자는 큰 행위를 한 것이다." 무아드 이븐 자발(라)께서는 예언자 ﷺ로부터 매 예배 후 다음을 말하라고 배우셨다: "알라훔마 아인니 알라 디크리카 와 슈크리카 와 후스니 이바다티크"(오 알라, 당신을 기억하고, 당신께 감사하며, 당신을 잘 경배할 수 있도록 저를 도우소서)  –  이 기원은 특별히 어느 아스르 예배 후에 그에게 주어졌다. 아스르를 충실히 지키는 것은 참된 이만의 표시이며, 그것을 잃는 것은 신자의 하루의 첫 균열이다.`, ta: `அஸ்ர் என்பது சொர்க்கத்திற்கு உத்தரவாதம் தரும் "இரு குளிர்ந்த தொழுகைகளில்" பாதி (புகாரி 574). கூட்டாகத் தொழுவதற்கு அதன் சொந்த பெரும் கூலி உள்ளது; நபி ﷺ கூறினார்: "அஸ்ரை கூட்டாகத் தொழுது, பின் மறுநாள் சூரிய உதயம் வரை  –  இல்லை, மக்ரிப் வரை  –  அல்லாஹ்வை நினைவுகூர்ந்தபடி அமர்ந்திருப்பவர் ஒரு பெரிய செயலைச் செய்தார்." முஆத் இப்னு ஜபல் (ரழி) அவர்களுக்கு நபி ﷺ ஒவ்வொரு தொழுகைக்குப் பிறகும் சொல்லக் கற்பித்தார்: "அல்லாஹும்ம அஇன்னீ அலா திக்ரிக வ ஷுக்ரிக வ ஹுஸ்னி இபாதத்திக" (அல்லாஹ்வே! உன்னை நினைவுகூரவும், உனக்கு நன்றி செலுத்தவும், உன்னை சிறப்பாக வழிபடவும் எனக்கு உதவுவாயாக)  –  இந்த துஆ அவருக்கு குறிப்பாக ஒரு அஸ்ர் தொழுகைக்குப் பிறகு வழங்கப்பட்டது. அஸ்ரின் விசுவாசமான பாதுகாப்பு உண்மையான ஈமானின் அறிகுறி; அதை இழப்பது ஒரு விசுவாசியின் நாளில் முதல் வெடிப்பு.`, si: `අස්ර් යනු එහි ආරක්ෂාව ස්වර්ගය සහතික කරන "සිසිල් සලාත දෙකේ" භාගයකි (බුහාරි 574). සමූහ වශයෙන් ඉටු කිරීමට එහි ම මහත් ප්‍රතිඵලයක් ඇත; නබි ﷺ පැවසූහ: "අස්ර් සමූහයක් වශයෙන් ඉටු කරන කවරෙකු, ඉන් පසු පසුදා හිරු උදාව තෙක්  –  නැත, මග්රිබ් තෙක්  –  අල්ලාහ්ව සිහිපත් කරමින් වාඩි වී සිටී ද, ඔහු මහත් ක්‍රියාවක් කර ඇත." මුආද් ඉබ්නු ජබල් (රළි) ට නබි ﷺ විසින් සෑම සලාතයකට පසුවම මෙය කීමට උගන්වන ලදී: "අල්ලාහුම්ම අඉන්නී අලා දික්රික ව ෂුක්රික ව හුස්නි ඉබාදතික" (අල්ලාහ්වනේ, ඔබව සිහි කිරීමටත්, ඔබට කෘතඥ වීමටත්, ඔබට යහපත් ලෙස නැමදීමටත් මට උපකාර කරන්න)  –  මෙම ප්‍රාර්ථනය විශේෂයෙන් එක් අස්ර් සලාතයකට පසු ඔහුට ලබා දෙන ලදී. අස්ර් විශ්වාසනීයව සුරැකීම සැබෑ ඊමාන්හි ලකුණයි; එය අහිමි වීම විශ්වාසවන්තයාගේ දිනයේ පළමු ඉරිතැලීමයි.` },
  asr_timing_notes: { en: `Two forbidden times bracket Asr: the first is the few minutes immediately before sunset (once the sun has clearly begun to set, the disc reddening), the second is shortly after sunrise. Voluntary prayer between Asr and Maghrib is generally disallowed; the exceptions are (a) a missed obligatory prayer, (b) a prayer with a clear cause such as tahiyyat al-masjid or the prayer of wudu, in the view of the majority. If Asr is delayed past sunset for a valid reason (sleep, true forgetfulness, urgent excuse), pray it as soon as one is able  –  it still counts as that day's Asr if performed before sleeping again. Combining Asr with Dhuhr during travel, illness or fear is allowed by the agreement of the four schools, with their respective conditions.`, ms: `Dua waktu yang dilarang mengapit Asar: yang pertama adalah beberapa minit sebaik sebelum matahari terbenam (sebaik sahaja matahari jelas mulai terbenam, cakranya kemerahan), yang kedua adalah sebentar selepas matahari terbit. Solat sunat antara Asar dan Maghrib umumnya tidak dibenarkan; pengecualian adalah (a) solat fardu yang tertinggal, (b) solat yang mempunyai sebab yang jelas seperti tahiyyat masjid atau solat wudu, mengikut pendapat majoriti. Jika Asar ditangguhkan melepasi matahari terbenam atas sebab yang sah (tidur, lupa yang sebenar, uzur mendesak), dirikan sebaik sahaja boleh  –  ia tetap dikira sebagai Asar hari itu jika dilakukan sebelum tidur semula. Menjamak Asar dengan Zuhur ketika dalam perjalanan, sakit atau ketakutan dibenarkan dengan persetujuan empat mazhab, dengan syarat masing-masing.`, tur: `İkindi'yi iki yasak vakit kuşatır: ilki, gün batımından hemen önceki birkaç dakika (güneş açıkça batmaya başladığı, diskin kızardığı an); ikincisi, gün doğumundan az sonra. İkindi ile Akşam arasındaki nafile namaz genel olarak yasaklanmıştır; istisnalar (a) kaçırılmış farz, (b) tahiyyetü'l-mescid veya abdest namazı gibi açık sebebi olan namaz, çoğunluğun görüşüne göre. İkindi geçerli bir mazeretle (uyku, gerçek unutkanlık, acil özür) güneş batımını geçerse, mümkün olur olmaz kılın  –  tekrar uyumadan kılındığında o günkü İkindi sayılır. Yolculuk, hastalık veya korku durumunda İkindi'yi Öğle ile cem etmek, kendi şartlarıyla dört mezhebin ittifakıyla caizdir.`, urd: `دو ممنوع اوقات عصر کو گھیرے میں رکھتے ہیں: پہلا، غروبِ آفتاب سے بالکل پہلے کے چند منٹ (جب سورج واضح طور پر غروب ہونے لگے، اس کا قرص سرخ ہو)؛ دوسرا، طلوعِ آفتاب کے کچھ دیر بعد۔ عصر اور مغرب کے درمیان نفل نماز عموماً جائز نہیں؛ استثناءات ہیں (الف) چھوٹی ہوئی فرض نماز، (ب) واضح سبب والی نماز جیسے تحیة المسجد یا وضو کی نماز  –  جمہور کی رائے۔ اگر عصر کسی صحیح عذر (نیند، حقیقی بھول، فوری مجبوری) کی وجہ سے غروب کے بعد تک موخر ہو، تو جیسے ہی ممکن ہو ادا کریں  –  دوبارہ سونے سے پہلے ادا کرنے پر یہ پھر بھی اسی دن کی عصر شمار ہوگی۔ سفر، بیماری یا خوف کی حالت میں ظہر کے ساتھ عصر جمع کرنا چاروں مذاہب کے اتفاق سے، اپنی اپنی شرائط کے ساتھ، جائز ہے۔`, ben: `দুটি নিষিদ্ধ সময় আসরকে ঘিরে রাখে: প্রথমটি সূর্যাস্তের ঠিক আগের কয়েক মিনিট (যখন সূর্য স্পষ্টভাবে অস্ত যেতে শুরু করেছে, চাকতি লালচে হয়ে); দ্বিতীয়টি সূর্যোদয়ের সামান্য পরে। আসর ও মাগরিবের মাঝে নফল নামাজ সাধারণত নিষিদ্ধ; ব্যতিক্রম হলো (ক) ছুটে যাওয়া ফরজ নামাজ, (খ) সুস্পষ্ট কারণসহ নামাজ যেমন তাহিয়্যাতুল মসজিদ বা ওযুর নামাজ, সংখ্যাগরিষ্ঠের মতে। যদি বৈধ কারণে (ঘুম, প্রকৃত ভুল, জরুরি ওজর) আসর সূর্যাস্ত পার করিয়ে বিলম্বিত হয়, যত শীঘ্রি সম্ভব আদায় করুন  –  পুনরায় ঘুমানোর আগে আদায় করলে তা এখনও সেই দিনের আসর হিসেবে গণ্য হবে। সফর, অসুস্থতা বা ভয়ে আসরকে যোহরের সাথে জমা করা চার মাযহাবের ঐকমত্যে, তাদের নিজস্ব শর্তসহ, অনুমোদিত।`, fas: `دو وقت ممنوع، عصر را در میان می‌گیرند: نخستین، چند دقیقه پیش از غروب (وقتی خورشید آشکارا به غروب رو می‌نهد، قرصش سرخ می‌شود)؛ دومی، اندکی پس از طلوع. نماز نافله میان عصر و مغرب عموماً جایز نیست؛ استثناها (الف) نماز فرض فوت‌شده، (ب) نمازی با سبب آشکار مانند تحیة المسجد یا نماز وضو، طبق نظر اکثریت. اگر عصر با عذر معتبر (خواب، فراموشی واقعی، عذر فوری) تا پس از غروب به تأخیر افتد، به محض امکان بخوان  –  پیش از خواب دوباره، همچنان به‌عنوان عصر همان روز محسوب می‌شود. جمع عصر با ظهر در سفر، بیماری یا ترس به اتفاق چهار مذهب، با شرایط هر یک، جایز است.`, zh: `两禁时段夹晡礼于其间：第一为日落前最后数分钟（日已明显下沉、日轮转红之时）；第二为日出后不久。晡礼与昏礼之间副功拜一般不许；其例外为（甲）所漏之主命拜、（乙）有明确因由之拜（如问候清真寺之拜或小净之拜），依多数派之见。若因正当之由（睡眠、真实忘记、急切之苦）晡礼延至日落之后，应一能即礼  –  若于再次入睡前完成，仍计入当日之晡礼。旅途、疾病或恐惧之际并礼晡礼与晌礼，四大学派以各自之条件一致认可。`, yue: `兩禁時段夾晡禮於其間：第一為日落前最後數分鐘（日已明顯下沉、日輪轉紅之時）；第二為日出後不久。晡禮與昏禮之間副功拜一般不許；其例外為（甲）所漏之主命拜、（乙）有明確因由之拜（如問候清真寺之拜或小淨之拜），依多數派之見。若因正當之由（睡眠、真實忘記、急切之苦）晡禮延至日落之後，應一能即禮  –  若於再次入睡前完成，仍計入當日之晡禮。旅途、疾病或恐懼之際並禮晡禮與晌禮，四大學派以各自之條件一致認可。`, ja: `アスルは二つの禁じられた時刻に挟まれる：第一は日没直前の数分間（太陽が明らかに沈み始め、その円盤が赤らむとき）、第二は日の出のしばらく後。アスルとマグリブの間の任意礼拝は一般に禁じられる。例外は多数派の見解で（イ）逃したファルド礼拝、（ロ）モスクへの挨拶や沐浴後の礼拝のように明確な理由がある礼拝。アスルが正当な理由（睡眠、真の忘却、緊急の事情）で日没を過ぎて遅れた場合、できるだけ早く行うこと  –  再び眠る前に行われればなお当日のアスルとみなされる。旅行、病、恐怖時にアスルをズフルと合わせて行うことは、それぞれの条件のもとで四大学派の合意により許される。`, ru: `Аср заключён между двумя запретными временами: первое  –  несколько минут непосредственно перед закатом (когда солнце явно начало садиться, диск багровеет); второе  –  вскоре после восхода. Добровольная молитва между Асром и Магрибом, как правило, не дозволена; исключения по мнению большинства: (а) пропущенная обязательная молитва, (б) молитва с явной причиной, такая как тахийят аль-масджид или молитва после вуду. Если Аср отложен за закат по уважительной причине (сон, подлинная забывчивость, неотложный узр), совершай, как только сможешь  –  он по-прежнему считается Асром того дня, если выполнен до повторного сна. Соединение Асра с Зухром во время путешествия, болезни или страха  –  допустимо по согласию четырёх мазхабов, каждый со своими условиями.`, es: `Dos tiempos prohibidos enmarcan al Asr: el primero son los pocos minutos inmediatamente anteriores a la puesta del sol (cuando el sol ha comenzado claramente a ponerse y el disco se enrojece); el segundo es poco después del amanecer. La oración voluntaria entre Asr y Maghrib generalmente no se permite; las excepciones según el parecer mayoritario son (a) una oración obligatoria perdida, (b) una oración con causa clara como tahiyyat al-masjid o la oración del wudu. Si el Asr se retrasa hasta después de la puesta del sol por motivo válido (sueño, olvido verdadero, urgencia), rézalo en cuanto puedas  –  sigue contando como el Asr de ese día si se realiza antes de volver a dormir. Combinar Asr con Dhuhr durante el viaje, la enfermedad o el temor está permitido por acuerdo de las cuatro escuelas, con sus respectivas condiciones.`, ko: `두 금지 시간이 아스르를 둘러싼다: 첫 번째는 일몰 직전의 몇 분(태양이 분명히 지기 시작하여 원반이 붉어질 때), 두 번째는 일출 후 잠시 뒤. 아스르와 마그립 사이의 자발 예배는 일반적으로 허용되지 않는다; 다수설에 따른 예외는 (가) 놓친 의무 예배, (나) 모스크 인사 예배나 우두 후 예배처럼 명확한 사유가 있는 예배이다. 정당한 사유(잠, 진정한 망각, 긴급한 우드르)로 아스르가 일몰 이후로 지연된 경우, 가능한 한 빨리 예배하라  –  다시 잠들기 전에 행해지면 여전히 그날의 아스르로 인정된다. 여행, 질병, 두려움 중에 아스르를 주흐르와 합쳐 행하는 것은 네 학파의 합의로, 각각의 조건에 따라 허용된다.`, ta: `இரு தடைசெய்யப்பட்ட நேரங்கள் அஸ்ரை சூழ்ந்துள்ளன: முதலாவது சூரிய அஸ்தமனத்திற்கு சற்று முன்னான சில நிமிடங்கள் (சூரியன் தெளிவாக அஸ்தமிக்கத் தொடங்கி, வட்டு சிவந்து வரும்போது); இரண்டாவது சூரிய உதயத்திற்குச் சற்று பிறகு. அஸ்ருக்கும் மக்ரிபுக்கும் இடையே நஃபில் தொழுகை பொதுவாக அனுமதிக்கப்படவில்லை; பெரும்பான்மை கருத்தின்படி விதிவிலக்குகள் (அ) தவறிய கடமைத் தொழுகை, (ஆ) தஹிய்யதுல் மஸ்ஜித் அல்லது வுளூ தொழுகை போன்ற தெளிவான காரணமுள்ள தொழுகை. செல்லத்தக்க காரணத்தால் (தூக்கம், உண்மையான மறதி, அவசர உத்ர்) அஸ்ர் சூரிய அஸ்தமனத்தை கடந்து தாமதமானால், முடியும் வரை விரைவில் தொழுங்கள்  –  மீண்டும் உறங்கும் முன் தொழப்பட்டால் இது இன்னும் அந்த நாளின் அஸ்ராகவே கணக்கிடப்படுகிறது. பயணம், நோய் அல்லது அச்சத்தின்போது ளுஹருடன் அஸ்ரை ஜமா செய்வது நான்கு மத்ஹபுகளின் ஒப்புதலுடன், அவற்றின் சொந்த நிபந்தனைகளுடன், அனுமதிக்கப்பட்டுள்ளது.`, si: `තහනම් වේලාවන් දෙකක් අස්ර් වටකරගෙන සිටී: පළමුව හිරු බැසීමට මොහොතකට පෙර වූ මිනිත්තු කිහිපය (හිරු පැහැදිලිව බැසීමට පටන් ගත් විට, තැටිය රතු වෙමින්); දෙවැන්න හිරු උදාවට ටික වේලාවකට පසු. අස්ර් සහ මග්රිබ් අතර ස්වේච්ඡා සලාත සාමාන්‍යයෙන් අවසර නැත; බහුතරයේ මතය අනුව ව්‍යතිරේක (අ) මඟ හැරුණු අනිවාර්ය සලාතය, (ආ) මස්ජිදයට ආචාර කිරීමේ සලාතය හෝ වුදූවේ සලාතය වැනි පැහැදිලි හේතුවක් ඇති සලාතය. වලංගු හේතුවක් (නින්ද, සැබෑ අමතකකම, හදිසි උද්ර්) නිසා අස්ර් හිරු බැසීම පසු කොට ප්‍රමාද වුවහොත්, හැකි ඉක්මනින් ඉටු කරන්න  –  නැවත නිදීමට පෙර ඉටු කළහොත් එය තවමත් එම දිනයේ අස්ර් ලෙස ගණන් ගැනේ. ගමන, රෝගය හෝ බියෙහි දී අස්ර් සුහ්ර් සමඟ ඒකාබද්ධ කිරීම මදහබ් හතරේ එකඟතාවෙන්, ඔවුන්ගේ අදාළ කොන්දේසි සමඟ, අනුමතය.` },
  /* ── Maghrib ──────────────────────────────────────────────── */
  maghrib_name: { en: `Maghrib  –  The Sunset Prayer`, ms: `Maghrib  –  Solat Terbenam Matahari`, tur: `Akşam Namazı  –  Mağrib`, urd: `مغرب  –  غروب آفتاب کی نماز`, ben: `মাগরিব  –  সূর্যাস্তের নামাজ`, fas: `مغرب  –  نماز غروب`, zh: `昏礼  –  日落拜功`, yue: `昏禮  –  日落拜功`, ja: `マグリブ  –  日没の礼拝`, ru: `Магриб  –  закатная молитва`, es: `Maghrib  –  la oración del ocaso`, ko: `마그립  –  일몰 예배`, ta: `மக்ரிப்  –  அஸ்தமன தொழுகை`, si: `මග්රිබ්  –  හිරු බැසීමේ සලාතය` },
  maghrib_when: { en: `Begins the instant the entire disc of the sun has disappeared below the horizon and continues until the red afterglow (shafaq al-ahmar) fades from the western sky  –  the Maliki/Shafi'i/Hanbali view  –  or until the white afterglow fades, per the Hanafi view. Pray it early. The Prophet ﷺ said: "My nation will remain in goodness as long as they do not delay Maghrib until the stars appear." (Abu Dawud 418). It is the shortest window of all five prayers, so guard it from delay.`, ms: `Bermula seketika seluruh cakra matahari hilang di bawah ufuk dan berterusan hingga mega merah (shafaq al-ahmar) lenyap dari langit barat  –  pandangan Maliki/Shafi'i/Hanbali  –  atau hingga mega putih lenyap menurut pandangan Hanafi. Dirikanlah pada awal waktunya. Nabi ﷺ bersabda: "Umatku akan kekal dalam kebaikan selagi mereka tidak melengahkan Maghrib hingga bintang-bintang muncul." (Abu Dawud 418). Ia adalah tetingkap paling pendek antara lima solat, jadi peliharalah ia daripada penangguhan.`, tur: `Güneşin disk olarak tamamen ufkun altına gizlendiği an başlar ve batı semasındaki kızıl şafak (şafakul-ahmer) sönene kadar sürer  –  Mâlikî/Şâfiî/Hanbelî görüşü  –  veya Hanefî'ye göre beyaz şafak sönene kadar. Erken kılın. Peygamber ﷺ buyurdu: "Ümmetim, Akşam'ı yıldızlar görünene kadar geciktirmedikleri sürece hayır üzere kalır." (Ebû Dâvûd 418). Beş namazın en kısa penceresidir; geciktirmeden koruyun.`, urd: `جس لمحے سورج کا پورا قرص افق کے نیچے غائب ہو جائے، شروع ہوتی ہے، اور سرخ شفق (شفقِ احمر) کے مغربی آسمان سے زائل ہونے تک رہتی ہے  –  مالکی/شافعی/حنبلی کی رائے  –  یا حنفی کی رائے کے مطابق سفید شفق کے زائل ہونے تک۔ اول وقت میں پڑھیں۔ نبی ﷺ نے فرمایا: "میری امت خیر پر باقی رہے گی جب تک وہ مغرب کو ستاروں کے نمودار ہونے تک موخر نہ کریں۔" (ابو داؤد ۴۱۸)۔ یہ پانچوں نمازوں میں سب سے مختصر وقفہ ہے، لہٰذا اسے تاخیر سے بچائیں۔`, ben: `যে মুহূর্তে সূর্যের সম্পূর্ণ চাকতি দিগন্তের নিচে অদৃশ্য হয় তখন শুরু হয় এবং পশ্চিম আকাশে লাল গোধূলি (শাফাক আল-আহমার) মিলিয়ে যাওয়া পর্যন্ত চলে  –  মালিকি/শাফিয়ি/হাম্বলি মত  –  অথবা হানাফি মতে সাদা গোধূলি মিলিয়ে যাওয়া পর্যন্ত। সময়ের শুরুতে পড়ুন। নবী ﷺ বলেছেন: "আমার উম্মত কল্যাণে অটল থাকবে যতক্ষণ না তারা মাগরিবকে নক্ষত্র দেখা যাওয়া পর্যন্ত বিলম্বিত করে।" (আবু দাউদ ৪১৮)। এটি পাঁচ ওয়াক্ত নামাজের সবচেয়ে সংক্ষিপ্ত সময়সীমা, তাই বিলম্ব থেকে রক্ষা করুন।`, fas: `از لحظه‌ای آغاز می‌شود که سراسر قرص خورشید زیر افق پنهان شود و تا فروکش شدن شفق سرخ (شفق احمر) از آسمان غربی ادامه دارد  –  نظر مالکی/شافعی/حنبلی  –  یا تا فروکش شدن شفق سفید بنا بر نظر حنفی. در اول وقت بخوان. پیامبر ﷺ فرمود: "امت من تا زمانی که مغرب را تا ظهور ستارگان به تأخیر نیندازند، در خیر باقی می‌مانند." (ابوداود ۴۱۸). کوتاه‌ترین بازه میان پنج نماز است؛ از تأخیر آن را پاس بدار.`, zh: `自太阳整个圆盘没入地平线之刻起，至西方红霞（红色昏霞）消散为止  –  马立基／沙斐仪／罕百里之见  –  或至白色昏霞消散，依哈乃斐之见。当于初时段礼之。先知ﷺ言：「我的民众将常处于善中，只要他们不将昏礼延至星辰显现。」（艾布·达伍德418）。五时拜功中时段最短，故须谨防延误。`, yue: `自太陽整個圓盤沒入地平線之刻起，至西方紅霞（紅色昏霞）消散為止  –  馬立基／沙斐儀／罕百里之見  –  或至白色昏霞消散，依哈乃斐之見。當於初時段禮之。先知ﷺ言：「我嘅民眾將常處於善中，只要佢哋唔將昏禮延至星辰顯現。」（艾布·達伍德418）。五時拜功中時段最短，故須謹防延誤。`, ja: `太陽の円盤全体が地平線の下に消えた瞬間に始まり、西の空の赤い残光（シャファク・アル＝アフマル）が消えるまで続く  –  マーリキー／シャーフィイー／ハンバリー説  –  またはハナフィー説では白い残光が消えるまで。早く行うこと。預言者ﷺは仰せられた：「わが民は、マグリブを星が現れるまで遅らせない限り、善にとどまる。」（アブー・ダーウード418）。五つの礼拝の中で最も短い時間帯であるから、遅延から守りなさい。`, ru: `Начинается с момента, когда весь диск солнца скрылся за горизонтом, и продолжается до угасания красной зари (шафак аль-ахмар) на западном небе  –  мнение маликитов, шафиитов и ханбалитов  –  или до угасания белой зари по мнению ханафитов. Совершайте раньше. Пророк ﷺ сказал: "Моя умма пребудет в добре, пока не задержит Магриб до появления звёзд." (Абу Дауд 418). Это самое короткое окно из пяти молитв  –  оберегайте её от задержки.`, es: `Comienza en el instante en que todo el disco del sol ha desaparecido bajo el horizonte y se prolonga hasta que el resplandor rojo (shafaq al-ahmar) se desvanece del cielo occidental  –  parecer maliki/shafi'i/hanbali  –  o hasta que se desvanece el resplandor blanco, según el parecer hanafi. Réza pronto. El Profeta ﷺ dijo: "Mi nación permanecerá en el bien mientras no retrase el Maghrib hasta que aparezcan las estrellas." (Abu Dawud 418). Es la ventana más breve de las cinco oraciones, así que guárdala del retraso.`, ko: `태양의 원반 전체가 지평선 아래로 사라지는 순간 시작되어, 서쪽 하늘의 붉은 잔광(샤파끄 알아흐마르)이 사라질 때까지 지속됩니다  –  말리키·샤피이·한발리 견해  –  또는 하나피 견해로는 흰 잔광이 사라질 때까지. 일찍 예배하라. 예언자 ﷺ께서 말씀하셨다: "내 움마는 별이 나타날 때까지 마그립을 지연시키지 않는 한 선함에 머무를 것이다." (아부 다우드 418). 다섯 예배 중 가장 짧은 시간대이므로 지연으로부터 지키라.`, ta: `சூரியனின் முழு வட்டும் தொடுவானத்திற்குக் கீழே மறையும் தருணத்தில் தொடங்கி, மேற்கு வானத்தில் சிவப்பு செவ்வானம் (ஷஃபக் அல்-அஹ்மர்) மறையும் வரை நீடிக்கும்  –  மாலிக்கி/ஷாஃபிஈ/ஹன்பலி கருத்து  –  அல்லது ஹனஃபி கருத்தின்படி வெள்ளை செவ்வானம் மறையும் வரை. ஆரம்பத்தில் தொழுங்கள். நபி ﷺ கூறினார்: "என் சமுதாயம் மக்ரிபை நட்சத்திரங்கள் தோன்றும் வரை தாமதப்படுத்தாதவரை நன்மையில் நிலைத்திருக்கும்." (அபூ தாவூத் 418). ஐந்து தொழுகைகளில் மிகக் குறுகிய சாளரம் இது, எனவே தாமதத்திலிருந்து பாதுகாக்கவும்.`, si: `හිරුගේ සම්පූර්ණ තැටිය ක්ෂිතිජයට පහළින් අතුරුදහන් වන මොහොතේ ආරම්භ වී, බටහිර අහසේ රතු බැබළුම (ෂෆක් අල්-අහ්මර්) අතුරුදහන් වන තෙක් පවතී  –  මාලිකී/ෂාෆිඊ/හන්බලී මතය  –  හෝ හනෆී මතය අනුව සුදු බැබළුම අතුරුදහන් වන තෙක්. ඉක්මනින් ඉටු කරන්න. නබි ﷺ පැවසූහ: "තාරකා පෙනෙන තෙක් මග්රිබ් ප්‍රමාද නොකරන තාක්, මාගේ සමාජය යහපතේ පවතිනු ඇත." (අබූ දාවූද් 418). පංච සලාතවල කෙටිම කාල සීමාව මෙයයි, එබැවින් ප්‍රමාදයෙන් එය රකින්න.` },
  maghrib_structure: { en: `Three rak'ahs of fard  –  the only fard prayer with an odd number of rak'ahs. It is called "the witr of the day" (the odd-numbered prayer of daylight). Followed by two rak'ahs of confirmed Sunnah (Sunnah Mu'akkadah) prayed at home. Recitation is aloud (jahri) in the first two rak'ahs and silent in the third. The first sitting (after the second rak'ah) holds the first tashahhud; the second sitting (after the third rak'ah) holds the final tashahhud and salam.`, ms: `Tiga rakaat fardu  –  satu-satunya solat fardu dengan bilangan rakaat ganjil. Ia dipanggil "witir siang" (solat ganjil pada siang hari). Diikuti dua rakaat sunat muakkad yang didirikan di rumah. Bacaan kuat (jahri) pada dua rakaat pertama dan perlahan pada rakaat ketiga. Duduk pertama (selepas rakaat kedua) untuk tasyahhud awal; duduk kedua (selepas rakaat ketiga) untuk tasyahhud akhir dan salam.`, tur: `Üç rekât farz  –  rekât sayısı tek olan tek farz namazdır. "Gündüzün vitri" (gündüzün tek rekâtlı namazı) olarak adlandırılır. Ardından evde kılınan iki rekât müekked sünnet vardır. Kıraat ilk iki rekâtta cehrî, üçüncüde sirrîdir. İlk oturuş (ikinci rekâttan sonra) ilk tahiyyât içindir; ikinci oturuş (üçüncü rekâttan sonra) son tahiyyât ve selam içindir.`, urd: `تین رکعت فرض  –  واحد فرض نماز جس کی رکعتیں طاق ہیں۔ اسے "دن کا وتر" کہا جاتا ہے۔ اس کے بعد دو رکعت سنّتِ مؤکدہ ہیں جو گھر میں پڑھی جائیں۔ پہلی دو رکعتوں میں قراءت جہراً (بلند) اور تیسری میں سرّاً۔ پہلا قعدہ (دوسری رکعت کے بعد) تشہّدِ اول کے لیے؛ دوسرا قعدہ (تیسری رکعت کے بعد) تشہّدِ اخیر اور سلام کے لیے۔`, ben: `তিন রাকাত ফরজ  –  একমাত্র ফরজ নামাজ যার রাকাত সংখ্যা বিজোড়। একে "দিনের বিতর" বলা হয়। পরে দুই রাকাত সুন্নাহ মুআক্কাদা ঘরে আদায় করা হয়। প্রথম দুই রাকাতে উচ্চস্বরে (জাহরি) এবং তৃতীয়টিতে নীরবে কেরাত। প্রথম বৈঠক (দ্বিতীয় রাকাতের পর) প্রথম তাশাহহুদের জন্য; দ্বিতীয় বৈঠক (তৃতীয় রাকাতের পর) শেষ তাশাহহুদ ও সালামের জন্য।`, fas: `سه رکعت فرض  –  تنها نماز فرض با تعداد رکعت فرد. آن را "وتر روز" می‌نامند. سپس دو رکعت سنت مؤکد است که در خانه خوانده می‌شود. قرائت در دو رکعت اول جهری و در رکعت سوم سرّی است. نشست اول (پس از رکعت دوم) برای تشهد اول؛ نشست دوم (پس از رکعت سوم) برای تشهد آخر و سلام.`, zh: `主命三拜  –  唯一拜数为奇之主命拜。称为「白昼之单」（白昼之奇拜）。其后有两拜确证圣行，宜在家中礼之。前两拜诵读高声（贾赫里），第三拜低声。第一坐（第二拜后）为初次作证；第二坐（第三拜后）为末次作证与平安词。`, yue: `主命三拜  –  唯一拜數為奇之主命拜。稱為「白晝之單」（白晝之奇拜）。其後有兩拜確證聖行，宜喺家中禮之。前兩拜誦讀高聲（賈赫里），第三拜低聲。第一坐（第二拜後）為初次作證；第二坐（第三拜後）為末次作證與平安詞。`, ja: `ファルドは三ラクア  –  ラクア数が奇数の唯一のファルド礼拝。「昼のウィトル」（昼の奇数礼拝）と呼ばれる。続いて家で行う二ラクアの確認されたスンナ（スンナ・ムアッカダ）がある。朗誦は最初の二ラクアで音読（ジャフリー）、第三ラクアで無声。第一の座（第二ラクア後）で第一タシャフード；第二の座（第三ラクア後）で最終タシャフードとサラーム。`, ru: `Три раката фарда  –  единственная обязательная молитва с нечётным числом ракатов. Её называют «витр дня» (нечётная дневная молитва). За ней следуют два раката подтверждённой сунны (Сунна Муаккада), совершаемые дома. Чтение вслух (джахрий) в первых двух ракатах и тихое в третьем. Первое сидение (после второго раката) для первого ташаххуда; второе (после третьего раката) для последнего ташаххуда и салама.`, es: `Tres rak'ahs de fard  –  la única oración obligatoria con un número impar de rak'ahs. Se la llama "el witr del día" (la oración impar de la luz del día). Le siguen dos rak'ahs de Sunnah confirmada (Sunnah Mu'akkadah) rezados en casa. La recitación es en voz alta (jahri) en los dos primeros rak'ahs y en silencio en el tercero. La primera sentada (tras el segundo rak'ah) para el primer tashahhud; la segunda (tras el tercer rak'ah) para el tashahhud final y el salam.`, ko: `파르드 세 라카  –  라카 수가 홀수인 유일한 의무 예배. "낮의 위트르"(낮의 홀수 예배)라고 불립니다. 그 뒤에 집에서 예배하는 두 라카의 확인된 순나(순나 무앗카다)가 있다. 낭송은 처음 두 라카에서 소리 내어(자흐리), 셋째 라카에서는 무성. 첫 앉음(둘째 라카 후)은 첫 타샤후드; 둘째 앉음(셋째 라카 후)은 마지막 타샤후드와 살람.`, ta: `மூன்று ரக்அத் ஃபர்ள்  –  ஒற்றை எண்ணிக்கையிலான ரக்அத்கள் கொண்ட ஒரே ஃபர்ள் தொழுகை. இது "பகலின் வித்ர்" (பகலின் ஒற்றை எண் தொழுகை) என அழைக்கப்படுகிறது. பின் வீட்டில் தொழப்படும் இரண்டு ரக்அத் ஸுன்னத்துல் முஅக்கதா. முதல் இரு ரக்அத்களில் உரக்க (ஜஹ்ரி) ஓதல், மூன்றாவதில் அமைதியாக. முதல் இருப்பு (இரண்டாம் ரக்அத்துக்குப் பின்) முதல் தஷஹ்ஹுதுக்கு; இரண்டாவது இருப்பு (மூன்றாம் ரக்அத்துக்குப் பின்) இறுதி தஷஹ்ஹுத் மற்றும் ஸலாமுக்கு.`, si: `ෆර්ද් රකඅත් තුනකි  –  රකඅත් සංඛ්‍යාව ඔත්තේ වන එකම අනිවාර්ය සලාතය. එය "දිවාකාලයේ විත්ර්" (දිවාකාලයේ ඔත්තේ සංඛ්‍යා සලාතය) ලෙස හැඳින්වේ. ඉන් පසු නිවසේ ඉටු කරන තහවුරු කළ සුන්නා රකඅත් දෙකක් (සුන්නා මුඅක්කදා) ඇත. පළමු රකඅත් දෙකේදී කියවීම හඬ නඟා (ජහ්රී) සහ තෙවැන්නේදී නිහඬව. පළමු ඉඳීම (දෙවන රකඅතට පසු) පළමු තශහ්හුද් සඳහා; දෙවන ඉඳීම (තෙවන රකඅතට පසු) අවසන් තශහ්හුද් සහ සලාම් සඳහා.` },
  maghrib_story: { en: `Like the other four, Maghrib was ordained on the Mi'raj. On the day after Mi'raj, Jibril (as) led the Prophet ﷺ at the Ka'bah in Maghrib the instant the sun's disc disappeared, then on the second day at the same instant, and said: "The time of Maghrib is one"  –  meaning a single, narrow window. The three-rak'ah count is itself significant: Allah preserved an "odd" prayer in the daylight  –  one that mirrors the witr of the night  –  so that the believer ends his day on a single, definitive declaration of Allah's oneness. It is also the prayer at which the day's deeds are "tied up": the angels of the day depart and the night-watch arrives during this very prayer.`, ms: `Seperti empat yang lain, Maghrib diwajibkan pada Mi'raj. Pada hari selepas Mi'raj, Jibril (as) mengimamkan Nabi ﷺ di Kaabah pada Maghrib sebaik sahaja cakra matahari hilang, kemudian pada hari kedua pada saat yang sama, dan bersabda: "Waktu Maghrib hanya satu"  –  bermaksud satu tetingkap yang sempit. Bilangan tiga rakaat itu sendiri bermakna: Allah memelihara satu solat "ganjil" pada siang  –  yang mencerminkan witir malam  –  supaya mukmin mengakhiri harinya dengan satu pengakuan keesaan Allah yang tunggal dan muktamad. Ia juga solat di mana amalan hari itu "diikat": malaikat siang berlepas dan pengawal malam tiba semasa solat ini sendiri.`, tur: `Diğer dördü gibi Akşam da Mi'rac'ta farz kılındı. Mi'rac'tan sonraki gün Cibril (as), Peygamber'i ﷺ Kâbe'de güneşin diski kaybolur kaybolmaz Akşam'a kıldırdı, ertesi gün de aynı anda; ve "Akşam'ın vakti birdir" buyurdu  –  yani tek ve dar bir pencere. Üç rekât oluşu da anlamlıdır: Allah, gündüzde bir "tek" namaz korumuştur  –  gecenin vitrini yansıtan bir namaz  –  böylece mü'min gününü Allah'ın birliğinin tek, kesin bir beyanıyla bitirir. Aynı zamanda günün amellerinin "kapatıldığı" namazdır: gündüz melekleri ayrılır ve gece nöbeti tam bu namaz sırasında gelir.`, urd: `دیگر چار کی طرح، مغرب بھی معراج میں فرض ہوئی۔ معراج کے اگلے دن، جبریل (ع) نے کعبہ کے پاس نبی ﷺ کو مغرب کی نماز سورج کے قرص کے غائب ہوتے ہی پڑھائی، پھر دوسرے دن اسی لمحے، اور فرمایا: "مغرب کا وقت ایک ہے"  –  یعنی واحد، تنگ وقفہ۔ تین رکعت کی تعداد بھی معنی خیز ہے: اللہ نے دن میں ایک "طاق" نماز محفوظ رکھی  –  جو رات کے وتر کا عکس ہے  –  تاکہ مومن اپنے دن کا اختتام اللہ کی توحید کے ایک واحد، قطعی اعلان پر کرے۔ یہ وہ نماز بھی ہے جس میں دن کے اعمال "بند" ہوتے ہیں: دن کے فرشتے روانہ ہوتے ہیں اور رات کا پہرہ اسی نماز کے دوران آتا ہے۔`, ben: `অন্য চারটির মতো মাগরিবও মেরাজে ফরজ হয়। মেরাজের পরের দিন জিবরিল (আ) কাবার পাশে নবী ﷺ-কে সূর্যের চাকতি অদৃশ্য হওয়ামাত্র মাগরিবে ইমামতি করালেন, এরপর পরের দিন একই মুহূর্তে, এবং বললেন: "মাগরিবের সময় একটি"  –  অর্থাৎ একটিই সংকীর্ণ সময়সীমা। তিন রাকাতের সংখ্যা নিজেই অর্থবহ: আল্লাহ দিনের মধ্যে একটি "বিজোড়" নামাজ সংরক্ষণ করেছেন  –  যা রাতের বিতরের প্রতিফলন  –  যাতে মুমিন তার দিনের সমাপ্তি ঘটায় আল্লাহর একত্বের এক একক, সিদ্ধান্তমূলক ঘোষণায়। এটি সেই নামাজও যেখানে দিনের আমলগুলো "বাঁধা" হয়: দিনের ফেরেশতারা চলে যান এবং রাতের পাহারা এই নামাজের সময়ই এসে পৌঁছায়।`, fas: `همانند چهار نماز دیگر، مغرب نیز در معراج فرض شد. روز پس از معراج، جبرئیل (ع) در کنار کعبه پیامبر ﷺ را به محض پنهان شدن قرص خورشید بر نماز مغرب پیشوایی کرد، سپس روز دوم در همان لحظه، و فرمود: "وقت مغرب یکی است"  –  یعنی پنجره‌ای واحد و باریک. خود شمار سه رکعت معنادار است: خداوند یک نماز "فرد" را در روز نگه داشت  –  که آینه وتر شب است  –  تا مؤمن روزش را با اعلامی واحد و قاطع از یگانگی خدا به پایان رساند. این نمازی است که اعمال روز در آن "بسته" می‌شود: فرشتگان روز می‌روند و نگهبانان شب در همین نماز فرامی‌رسند.`, zh: `与其他四时一样，昏礼亦于登霄被定为主命。登霄翌日，吉卜利里（愿主赐他平安）于天房旁，于日轮一没即带先知ﷺ礼昏礼，次日于同一刻再带一次，并言：「昏礼之时段只一」  –  即单一且窄之窗。三拜之数本身具义：真主于白昼保留一「单」拜  –  与夜之单数拜（witr）相映  –  使信士以对真主独一之单一、决定性宣告结其一日。此亦为一日之功被「封缄」之拜：白昼天使于此拜中辞去，夜班天使于此到来。`, yue: `同其他四時一樣，昏禮亦於登霄被定為主命。登霄翌日，吉卜利里（願主賜佢平安）於天房旁，於日輪一沒即帶先知ﷺ禮昏禮，次日於同一刻再帶一次，並話：「昏禮之時段只一」  –  即單一且窄之窗。三拜之數本身具義：真主於白晝保留一「單」拜  –  與夜之單數拜（witr）相映  –  使信士以對真主獨一之單一、決定性宣告結其一日。此亦為一日之功被「封緘」之拜：白晝天使於此拜中辭去，夜班天使於此到來。`, ja: `他の四つと同様、マグリブもミウラージュで義務付けられた。ミウラージュの翌日、ジブリール（に平安あれ）はカアバの傍で太陽の円盤が消えた瞬間に預言者ﷺのマグリブ礼拝のイマームとなり、二日目も同じ瞬間に再び行い、「マグリブの時は一つである」と仰せられた  –  すなわち単一の狭い時間帯。三ラクアという数自体に意味がある：アッラーは昼に「奇数」の礼拝を残された  –  夜のウィトルを映し返すように  –  これにより信者はその日を、アッラーの唯一性を単一かつ決定的に宣言して終える。一日の行いが「封じられる」礼拝でもある：昼の天使たちはこの礼拝の最中に去り、夜の当番が到着する。`, ru: `Как и остальные четыре, Магриб был предписан в Мирадж. На следующий день после Мираджа Джибриль (мир ему) у Каабы возглавил Пророка ﷺ в Магрибе в тот самый миг, когда исчез диск солнца, а на второй день в тот же миг, и сказал: «Время Магриба одно»  –  то есть единственное и узкое окно. Само число три раката значимо: Аллах сохранил «нечётную» молитву днём  –  отражающую витр ночи  –  чтобы верующий заканчивал свой день единственным, окончательным провозглашением единобожия. Это также молитва, на которой «запечатываются» дела дня: ангелы дня уходят и ночная стража прибывает именно во время этой молитвы.`, es: `Como las otras cuatro, el Maghrib fue ordenado en la Mi'raj. Al día siguiente de la Mi'raj, Yibril (as) dirigió al Profeta ﷺ junto a la Ka'bah en el Maghrib en el instante en que el disco del sol desapareció, y al segundo día en el mismo instante, diciendo: "El tiempo del Maghrib es uno"  –  es decir, una única ventana estrecha. El número tres de rak'ahs es en sí significativo: Allah preservó una oración "impar" durante el día  –  que refleja el witr de la noche  –  para que el creyente termine su día con una declaración única y definitiva de la unicidad de Allah. Es también la oración en la que las obras del día se "sellan": los ángeles del día parten y la guardia de la noche llega durante esta misma oración.`, ko: `다른 네 예배와 마찬가지로 마그립도 미으라즈에서 의무로 정해졌다. 미으라즈 다음 날, 지브릴(평화가 그에게)께서 카바 옆에서 태양의 원반이 사라지는 순간 예언자 ﷺ의 마그립 예배 이맘이 되셨고, 둘째 날 같은 순간 다시, 말씀하셨다: "마그립의 시간은 하나이다"  –  즉 단일하고 좁은 시간대. 세 라카의 수 자체가 의미 있다: 알라께서는 낮에 "홀수"의 예배를 보존하셨다  –  밤의 위트르를 거울처럼 비추는  –  그리하여 신자가 자신의 하루를 알라의 유일성에 대한 단일하고 결정적인 선언으로 끝맺도록 하셨다. 또한 이 예배는 하루의 행위가 "봉인되는" 예배이다: 낮의 천사들이 떠나고 밤의 당직이 바로 이 예배 중에 도착한다.`, ta: `பிற நான்கைப் போலவே மக்ரிபும் மிஃராஜில் கடமையாக்கப்பட்டது. மிஃராஜின் மறுநாள், ஜிப்ரீல் (அலை) கஅபாவின் அருகே நபி ﷺ அவர்களுக்கு சூரியனின் வட்டு மறையும் தருணத்திலேயே மக்ரிபில் இமாமாக நின்றார், பின் இரண்டாம் நாளும் அதே தருணத்தில், மற்றும் கூறினார்: "மக்ரிபின் வேளை ஒன்றே"  –  அதாவது ஒற்றை, குறுகலான சாளரம். மூன்று ரக்அத்களின் எண்ணிக்கையே முக்கியமானது: அல்லாஹ் பகலில் ஒரு "ஒற்றை" தொழுகையைப் பாதுகாத்தான்  –  இரவின் வித்ரை எதிரொலிக்கிறது  –  இதனால் விசுவாசி தம் நாளை அல்லாஹ்வின் ஏகத்துவத்தின் ஒற்றை, தீர்க்கமான பிரகடனத்துடன் முடிக்கிறார். நாளின் செயல்கள் "முடிக்கப்படும்" தொழுகையும் இதுவே: பகலின் வானவர்கள் புறப்படுகின்றனர், இரவின் காவல் இத்தொழுகையின் போதே வந்தடைகிறது.`, si: `අනෙක් සතර මෙන්ම මග්රිබ්ද මිඃරාජ්හිදී අනිවාර්ය කෙරුණි. මිඃරාජ්ට පසු දින, ජිබ්රීල් (ඔහුට සාමය) කඃබාව අසළ හිරුගේ තැටිය අතුරුදහන් වූ මොහොතේම නබි ﷺ සමඟ මග්රිබ් සලාතයේ ඉමාම් වශයෙන් සිට, දෙවන දින ද එම මොහොතේම, "මග්රිබ්හි කාලය එකකි" යැයි පැවසූහ  –  එනම් තනි, පටු කවුළුවක්. රකඅත් තුනේ ගණනයම අර්ථවත්ය: අල්ලාහ් දිවාකාලයේ "ඔත්තේ" සලාතයක් රැක ගත්හ  –  රාත්‍රියේ විත්ර්ට කැඩපතක් වැනි  –  එවිට විශ්වාසවන්තයා තම දිනය අල්ලාහ්ගේ ඒකීයත්වයේ තනි, තීරණාත්මක ප්‍රකාශයකින් අවසන් කරයි. දිනයේ ක්‍රියා "මුද්‍රා කරන" සලාතයද මෙයයි: දිවා මලාඉකාවරු සමු ගන්නා අතර, රාත්‍රී මුර කරුවන් මෙම සලාතය අතරතුරම පැමිණෙති.` },
  maghrib_significance: { en: `Maghrib is "the prayer of the breaker of the fast" (salat al-saim)  –  the prayer at which the fasting person breaks his fast, the prayer at which the worker returns home, the prayer at which evening begins. It is the seal of the day's deeds: whatever a person has earned of good or ill that day is enclosed by this prayer. Its three rak'ahs make it the "witr of daylight"  –  Allah preserved an odd-numbered prayer in the day so that the day, like the night, ends on a single, indivisible affirmation of His oneness. The Prophet ﷺ used to hurry to it and forbade delaying it without a valid reason.`, ms: `Maghrib ialah "solat orang yang berbuka puasa" (salat al-sa'im)  –  solat di mana orang berpuasa berbuka, solat di mana pekerja pulang ke rumah, solat di mana petang bermula. Ia adalah penutup amalan hari itu: apa sahaja yang seseorang peroleh dari kebaikan atau keburukan pada hari itu dirangkumkan oleh solat ini. Tiga rakaatnya menjadikannya "witir siang"  –  Allah memelihara satu solat ganjil di siang hari supaya hari, seperti malam, berakhir dengan satu pengakuan tunggal yang tidak boleh dibahagi tentang keesaan-Nya. Nabi ﷺ bersegera kepadanya dan melarang melengahkannya tanpa sebab yang sah.`, tur: `Akşam, "oruçluya iftar veren namaz"dır (salâtü's-sâim)  –  oruçlunun iftar açtığı, çalışanın eve döndüğü, akşamın başladığı namazdır. Günün amellerinin mührüdür: kişinin o gün hayır veya şer adına kazandığı her şey bu namazla kuşatılır. Üç rekât oluşu onu "gündüzün vitri" kılar  –  Allah, gündüz tek rekâtlı bir namaz korumuştur ki gün, gece gibi, O'nun birliğinin tek ve bölünmez bir tasdikiyle bitsin. Peygamber ﷺ ona koşar ve geçerli mazeret olmaksızın geciktirmeyi yasaklardı.`, urd: `مغرب "روزہ دار کی نماز" (صلاۃ الصائم) ہے  –  وہ نماز جس پر روزہ دار افطار کرتا ہے، وہ نماز جس پر مزدور گھر لوٹتا ہے، وہ نماز جس پر شام شروع ہوتی ہے۔ یہ دن کے اعمال کی مہر ہے: انسان نے اس دن جو بھی خیر یا شر کمایا ہو، یہ نماز اسے سمیٹ لیتی ہے۔ اس کی تین رکعتیں اسے "دن کا وتر" بناتی ہیں  –  اللہ نے دن میں ایک طاق نماز محفوظ رکھی تاکہ دن، رات کی طرح، اس کی توحید کی ایک واحد، ناقابلِ تقسیم تصدیق پر ختم ہو۔ نبی ﷺ اس کی طرف لپکتے اور بلا عذرِ صحیح اسے موخر کرنے سے منع فرماتے۔`, ben: `মাগরিব হলো "রোজাদারের নামাজ" (সালাতুস সায়িম)  –  যে নামাজে রোজাদার ইফতার করে, যে নামাজে কর্মী বাড়ি ফেরে, যে নামাজে সন্ধ্যা শুরু হয়। এটি দিনের আমলের মোহর: কেউ সেদিন কল্যাণ বা অকল্যাণ যা কিছু অর্জন করেছে এই নামাজ তা ঘিরে রাখে। এর তিন রাকাত একে "দিনের বিতর" করে  –  আল্লাহ দিনের মধ্যে একটি বিজোড় নামাজ সংরক্ষণ করেছেন যাতে দিন, রাতের মতো, তাঁর একত্বের এক একক, অবিভাজ্য নিশ্চয়তায় শেষ হয়। নবী ﷺ এর দিকে দ্রুত যেতেন এবং বৈধ কারণ ছাড়া এটি বিলম্বিত করতে নিষেধ করেছেন।`, fas: `مغرب "نماز روزه‌گشا" (صلاة الصائم) است  –  نمازی که روزه‌دار با آن افطار می‌کند، نمازی که کارگر با آن به خانه بازمی‌گردد، نمازی که شب با آن آغاز می‌شود. مهرِ اعمال روز است: هرچه شخص آن روز از نیک یا بد به دست آورده، این نماز آن را در بر می‌گیرد. سه رکعت بودنش آن را "وتر روز" می‌سازد  –  خداوند یک نماز فرد را در روز نگه داشت تا روز نیز چون شب، با تصدیق یگانه و تقسیم‌ناپذیر یگانگی او پایان یابد. پیامبر ﷺ به آن می‌شتافت و بدون عذر صحیح از تأخیر آن نهی می‌فرمود.`, zh: `昏礼乃「封斋者之拜」（salat al-saim）  –  封斋者于此开斋之拜，劳作者归家之拜，黄昏始降之拜。乃一日功过之封：人于此日所获之善与恶皆被此拜所封。三拜之数使其成为「白昼之单」  –  真主于白昼保留一奇数拜，俾使一日如同夜晚，以对真主独一不可分割之单一确认而结束。先知ﷺ常急赴之，并禁无故延误。`, yue: `昏禮乃「封齋者之拜」（salat al-saim）  –  封齋者於此開齋之拜，勞作者歸家之拜，黃昏始降之拜。乃一日功過之封：人於此日所獲之善與惡皆被此拜所封。三拜之數使其成為「白晝之單」  –  真主於白晝保留一奇數拜，俾使一日如同夜晚，以對真主獨一不可分割之單一確認而結束。先知ﷺ常急赴之，並禁無故延誤。`, ja: `マグリブは「断食者の礼拝」（サラート・アッ＝サーイム）である  –  断食者が断食を解く礼拝、労働者が家に帰る礼拝、夕べが始まる礼拝。一日の行いの封である：その日に人が善か悪かのいずれを得ようとも、この礼拝に包まれる。三ラクアという数がそれを「昼のウィトル」とする  –  アッラーは昼に奇数の礼拝を保たれ、夜と同じく昼もまた、御自身の唯一性への単一かつ不可分の確言で終わるようにされた。預言者ﷺは急いでこれに向かい、正当な理由なく遅らせることを禁じられた。`, ru: `Магриб  –  «молитва разговляющегося» (салят ас-саим)  –  молитва, на которой постящийся разговляется, молитва, на которой работник возвращается домой, молитва, на которой начинается вечер. Это печать дневных деяний: всё, что человек заработал доброго или дурного за день, заключается этой молитвой. Три раката делают её «витром дня»  –  Аллах сохранил нечётную молитву днём, чтобы день, как и ночь, заканчивался единственным, неделимым подтверждением Его единства. Пророк ﷺ спешил к ней и запрещал откладывать без уважительной причины.`, es: `El Maghrib es "la oración del que rompe el ayuno" (salat al-sa'im)  –  la oración con la que el ayunante rompe su ayuno, la oración con la que el trabajador regresa a casa, la oración con la que comienza la tarde. Es el sello de las obras del día: todo cuanto una persona ha ganado de bien o de mal ese día queda enmarcado por esta oración. Sus tres rak'ahs la convierten en "el witr del día"  –  Allah preservó una oración impar en el día para que el día, como la noche, termine con una afirmación única e indivisible de Su unicidad. El Profeta ﷺ se apresuraba a ella y prohibía retrasarla sin razón válida.`, ko: `마그립은 "단식하는 자의 예배"(살라트 알사임)이다  –  단식자가 단식을 깨는 예배, 일꾼이 집으로 돌아오는 예배, 저녁이 시작되는 예배. 하루 행위의 봉인이다: 그날 사람이 선이든 악이든 얻은 모든 것이 이 예배에 둘러싸인다. 세 라카는 그것을 "낮의 위트르"로 만든다  –  알라께서 낮에 홀수 예배를 보존하셔서, 낮도 밤처럼 그분의 유일성에 대한 단일하고 분리될 수 없는 확언으로 끝나도록 하셨다. 예언자 ﷺ께서는 이를 향해 서두르셨고 정당한 이유 없이 지연시키는 것을 금하셨다.`, ta: `மக்ரிப் "நோன்பாளியின் தொழுகை" (ஸலாத்துல் ஸாயிம்)  –  நோன்பாளி தம் நோன்பை திறக்கும் தொழுகை, தொழிலாளி வீடு திரும்பும் தொழுகை, மாலை தொடங்கும் தொழுகை. நாளின் செயல்களின் முத்திரை இது: அன்று ஒருவர் நன்மை அல்லது தீமையில் எதையெல்லாம் ஈட்டியிருந்தாலும், இத்தொழுகை அதை சூழ்ந்துகொள்கிறது. மூன்று ரக்அத்கள் இதை "பகலின் வித்ர்" ஆக்குகிறது  –  அல்லாஹ் பகலில் ஒரு ஒற்றை எண் தொழுகையைப் பாதுகாத்தான், இதனால் இரவைப் போல் பகலும் அவனின் ஏகத்துவத்தின் ஒற்றை, பிரிக்க முடியாத உறுதிப்படுத்தலுடன் முடிகிறது. நபி ﷺ இதை நோக்கி விரைந்தார், செல்லத்தக்க காரணமின்றி தாமதப்படுத்த தடைசெய்தார்.`, si: `මග්රිබ් යනු "උපවාසය බිඳින්නාගේ සලාතය" (සලාත් අල්-සාඉම්) ය  –  උපවාසය රකින්නා උපවාසය බිඳින සලාතය, කම්කරුවා ගෙදර එන සලාතය, සැන්දෑව ආරම්භ වන සලාතය. දිනයේ ක්‍රියාවන්ගේ මුද්‍රාව මෙයයි: එම දිනයේ පුද්ගලයෙක් යහපතින් හෝ අයහපතින් යමක් උපයාගෙන ඇත්නම්, මෙම සලාතය එය වැළඳ ගනී. රකඅත් තුන එය "දිවාකාලයේ විත්ර්" කරයි  –  අල්ලාහ් දිවාකාලයේ ඔත්තේ සලාතයක් රැක ගත් අතර, එමඟින් රාත්‍රිය මෙන් දිවාකාලයද උන්වහන්සේගේ ඒකීයත්වයේ තනි, බෙදිය නොහැකි ස්ථිර කිරීමකින් අවසන් වේ. නබි ﷺ ඒ වෙත ඉක්මන් වූ අතර, වලංගු හේතුවක් නැතිව එය ප්‍රමාද කිරීම තහනම් කළහ.` },
  maghrib_proof_q: { en: `"...and the recitation of dawn  –  indeed, the recitation of dawn is ever witnessed." (Al-Isra' 17:78). The preceding phrase "from the decline of the sun until the darkness of the night" covers Dhuhr, Asr, Maghrib, and Isha together. Also: "Glory be to Allah when you reach the evening (tumsun) and when you reach the morning. To Him is all praise in the heavens and the earth, and in the late afternoon (ashiyy) and when you are at noon." (Ar-Rum 30:17–18)  –  classical commentators identify "tumsun" as Maghrib and Isha specifically.`, ms: `"...dan bacaan fajar  –  sesungguhnya bacaan fajar itu sentiasa disaksikan." (Al-Isra' 17:78). Ungkapan sebelumnya "sejak gelincirnya matahari sehingga kegelapan malam" merangkumi Zuhur, Asar, Maghrib, dan Isyak bersama. Juga: "Maha Suci Allah ketika kamu memasuki waktu petang (tumsun) dan ketika kamu memasuki waktu pagi. Bagi-Nya segala puji di langit dan di bumi, dan pada waktu petang akhir (ashiyy) dan ketika kamu berada di tengah hari." (Ar-Rum 30:17–18)  –  mufassir klasik mengenal pasti "tumsun" sebagai Maghrib dan Isyak khususnya.`, tur: `"...ve sabah Kur'an'ı  –  şüphesiz sabah Kur'an'ı şahit olunmuş bir okumadır." (İsrâ 17:78). Önceki ifade olan "güneşin batıya kaymasından gecenin karanlığına dek" Öğle, İkindi, Akşam ve Yatsı'yı birlikte kapsar. Ayrıca: "Akşama girdiğinizde ve sabaha girdiğinizde Allah'ı tesbih edin. Göklerde ve yerde, gün sonunda ve öğleyin de hamd O'na mahsustur." (Rûm 30:17–18)  –  klasik müfessirler "tumsun"u özellikle Akşam ve Yatsı olarak tanımlar.`, urd: `"...اور فجر کی قراءت  –  بے شک فجر کی قراءت پر گواہی دی جاتی ہے۔" (الاسراء ۱۷:۷۸)۔ اس سے پہلے کا فقرہ "سورج کے ڈھلنے سے رات کی تاریکی تک" ظہر، عصر، مغرب اور عشاء کو ایک ساتھ شامل کرتا ہے۔ نیز: "اللہ کی تسبیح کرو جب تم شام میں داخل ہو (تمسون) اور جب صبح میں داخل ہو۔ اور آسمانوں اور زمین میں اسی کے لیے ہر تعریف ہے، اور پچھلے پہر (عشی) اور جب تم دوپہر میں ہو۔" (الروم ۳۰:۱۷-۱۸)  –  کلاسیکی مفسرین "تمسون" کو خاص طور پر مغرب اور عشاء سے پہچانتے ہیں۔`, ben: `"...এবং ফজরের কেরাত  –  নিশ্চয়ই ফজরের কেরাত সাক্ষীযুক্ত।" (আল-ইসরা ১৭:৭৮)। পূর্ববর্তী বাক্যাংশ "সূর্য ঢলে পড়া থেকে রাতের অন্ধকার পর্যন্ত" যোহর, আসর, মাগরিব ও ইশাকে একসঙ্গে অন্তর্ভুক্ত করে। আরও: "আল্লাহর পবিত্রতা ঘোষণা করো যখন তোমরা সন্ধ্যায় উপনীত হও (তুমসুন) এবং যখন তোমরা সকালে উপনীত হও। আর আকাশসমূহ ও পৃথিবীতে যাবতীয় প্রশংসা তাঁরই, এবং বিকেলে (আশিয়্যি) এবং যখন তোমরা দুপুরে।" (আর-রূম ৩০:১৭-১৮)  –  ধ্রুপদী মুফাসসিরগণ "তুমসুন"-কে বিশেষভাবে মাগরিব ও ইশা হিসেবে চিহ্নিত করেন।`, fas: `"...و قرائت فجر  –  همانا قرائت فجر مشهود است." (الإسراء ۱۷:۷۸). عبارت پیشین "از زوال خورشید تا تاریکی شب" ظهر، عصر، مغرب و عشاء را با هم در بر می‌گیرد. همچنین: "خدا را تسبیح گویید آنگاه که به شامگاه می‌رسید و آنگاه که به بامداد. و در آسمان‌ها و زمین، در پسین و آنگاه که در نیمروزید، ستایش از آنِ اوست." (الروم ۳۰:۱۷-۱۸)  –  مفسران کلاسیک "تمسون" را به‌ویژه مغرب و عشاء می‌دانند.`, zh: `「……及晨礼之诵读  –  晨礼之诵读必被见证。」（夜行章17:78）。其前句「自日西斜直到夜暗」涵盖晌、晡、昏、宵四时之拜。又：「当你们进入暮时（tumsun）和进入晨时，你们应当赞颂真主超绝。在天地间、薄暮和你们正午之时，一切赞颂皆归于他。」（罗马人章30:17-18）  –  古典经注家以「tumsun」专指昏礼与宵礼。`, yue: `「……及晨禮之誦讀  –  晨禮之誦讀必被見證。」（夜行章17:78）。其前句「自日西斜直到夜暗」涵蓋晌、晡、昏、宵四時之拜。又：「當你哋進入暮時（tumsun）同進入晨時，你哋應當讚頌真主超絕。喺天地間、薄暮同你哋正午之時，一切讚頌皆歸於佢。」（羅馬人章30:17-18）  –  古典經注家以「tumsun」專指昏禮與宵禮。`, ja: `「……そして夜明けの朗誦  –  まことに夜明けの朗誦は常に立ち会われている。」（夜の旅章 17:78）。その前の句「太陽の傾きから夜の暗闇まで」はズフル、アスル、マグリブ、イシャーを共に包む。また：「あなたがたが夕方を迎えるとき（トゥムスーン）と朝を迎えるとき、アッラーを称え給え。諸天と大地の中で、夕暮れにも、あなたがたが昼下がりにあるときにも、すべての讃美は彼に帰す。」（ローマ章 30:17-18）  –  古典の注釈家は「トゥムスーン」を特にマグリブとイシャーと同定する。`, ru: `«…и чтение на рассвете  –  поистине, чтение на рассвете всегда засвидетельствовано.» (Аль-Исра 17:78). Предшествующая фраза «от склонения солнца до ночной тьмы» охватывает Зухр, Аср, Магриб и Иша вместе. Также: «Слава Аллаху, когда вы вступаете в вечер (тумсун) и когда вступаете в утро. Ему принадлежит хвала на небесах и на земле, в пору заката и когда вы в полудне.» (Ар-Рум 30:17–18)  –  классические комментаторы определяют «тумсун» именно как Магриб и Иша.`, es: `"…y la recitación del alba  –  en verdad, la recitación del alba siempre es atestiguada." (Al-Isra' 17:78). La frase anterior "desde la declinación del sol hasta la oscuridad de la noche" abarca Dhuhr, Asr, Maghrib e Isha juntos. También: "Glorificad a Allah cuando entráis en la tarde (tumsun) y cuando entráis en la mañana. A Él pertenece toda alabanza en los cielos y en la tierra, y al caer de la tarde (ashiyy) y cuando estáis al mediodía." (Ar-Rum 30:17–18)  –  los exegetas clásicos identifican "tumsun" específicamente con el Maghrib y el Isha.`, ko: `"…그리고 새벽의 낭송  –  진실로 새벽의 낭송은 항상 증언되니라." (알이스라 17:78). 앞 구절 "태양이 기울 때부터 밤의 어둠까지"는 주흐르·아스르·마그립·이샤를 함께 포함한다. 또한: "너희가 저녁(툼순)에 이르고 아침에 이르거든 알라를 찬미하라. 하늘과 땅에서, 그리고 늦은 오후(아쉬이)와 너희가 한낮에 있을 때 모든 찬미가 그분께 있도다." (앗룸 30:17-18)  –  고전 주석가들은 "툼순"을 특별히 마그립과 이샤로 본다.`, ta: `"...விடியலின் ஓதலையும்  –  நிச்சயமாக விடியலின் ஓதல் சாட்சியளிக்கப்படுவதாகும்." (அல்-இஸ்ரா 17:78). முந்தைய சொற்றொடர் "சூரியன் சாயத் தொடங்குவதிலிருந்து இரவின் இருள் வரை" ளுஹர், அஸ்ர், மக்ரிப், இஷாவை ஒன்றாக உள்ளடக்குகிறது. மேலும்: "நீங்கள் மாலையை அடையும்போது (துமுசூன்) மற்றும் காலையை அடையும்போது அல்லாஹ்வை மகிமைப்படுத்துங்கள். வானங்களிலும் பூமியிலும், பின் மாலையிலும் (அஷிய்) நண்பகலில் இருக்கும்போதும், அனைத்துப் புகழும் அவனுக்கே." (அர்-ரூம் 30:17-18)  –  கிளாசிக்கல் தஃப்ஸீர் அறிஞர்கள் "துமுசூன்" என்பதை குறிப்பாக மக்ரிப் மற்றும் இஷாவாக அடையாளம் காண்கின்றனர்.`, si: `"...සහ අරුණෝදයේ පාරායනය  –  සැබැවින්ම අරුණෝදයේ පාරායනය සැමවිටම සාක්ෂි දරනු ලැබේ." (අල්-ඉස්රා 17:78). පෙර වැකිය "හිරුගේ බැසීමේ සිට රාත්‍රියේ අන්ධකාරය දක්වා" සුහ්ර්, අස්ර්, මග්රිබ් සහ ඉෂා එක්ව ආවරණය කරයි. තවද: "ඔබ සැන්දෑවට පැමිණෙන විට (තුම්සූන්) සහ උදෑසනට පැමිණෙන විට අල්ලාහ්ව මහිමයට පත් කරන්න. ස්වර්ග හා පෘථිවියේ, සවස පිටතේ (අෂිය්ය්) සහ ඔබ මධ්‍යාහ්නයේදී, සියලු ප්‍රශංසා උන්වහන්සේටය." (අර්-රූම් 30:17-18)  –  සම්භාව්‍ය විවරණකරුවන් "තුම්සූන්" විශේෂයෙන් මග්රිබ් සහ ඉෂා ලෙස හඳුනා ගනිති.` },
  maghrib_proof_h: { en: `Jibril (as) led the Prophet ﷺ in Maghrib at the Ka'bah the instant the sun set on both days, saying: "Its time is one." (Tirmidhi 149). The Prophet ﷺ also said: "My nation will remain in goodness as long as they do not delay Maghrib until the stars become tangled" (Abu Dawud 418)  –  i.e. until full night. And concerning the moment of sunset itself: "When night approaches from this side, day departs from this side, and the sun has set  –  then the fasting person breaks his fast." (Bukhari 1954, Muslim 1100). Maghrib is therefore the formal boundary marker that the new Islamic day begins.`, ms: `Jibril (as) mengimamkan Nabi ﷺ pada Maghrib di Kaabah sebaik sahaja matahari terbenam pada kedua-dua hari, dan bersabda: "Waktunya satu." (Tirmidhi 149). Nabi ﷺ juga bersabda: "Umatku akan kekal dalam kebaikan selagi mereka tidak melengahkan Maghrib hingga bintang-bintang berkelumun-kelumun" (Abu Dawud 418)  –  iaitu hingga malam penuh. Dan tentang detik matahari terbenam itu sendiri: "Apabila malam datang dari arah ini, siang berlepas dari arah ini, dan matahari telah terbenam  –  maka orang berpuasa berbuka." (Bukhari 1954, Muslim 1100). Maghrib oleh itu adalah penanda sempadan rasmi bahawa hari Islam yang baru bermula.`, tur: `Cibril (as), Kâbe'de güneşin battığı an iki gün boyunca Peygamber'i ﷺ Akşam'a kıldırdı ve "Vakti birdir." dedi (Tirmizî 149). Peygamber ﷺ ayrıca buyurdu: "Ümmetim, Akşam'ı yıldızlar dolaşıp toplanana kadar geciktirmedikleri sürece hayır üzere kalır." (Ebû Dâvûd 418)  –  yani tam geceye kadar. Gün batımı anının kendisi hakkında: "Gece şu taraftan gelip gündüz şu taraftan gittiğinde ve güneş battığında  –  oruçlu iftarını açar." (Buhârî 1954, Müslim 1100). Akşam, böylece yeni İslami günün başladığı resmî sınır işaretidir.`, urd: `جبریل (ع) نے کعبہ کے پاس دونوں دن سورج کے غروب ہوتے ہی نبی ﷺ کو مغرب کی نماز پڑھائی، اور فرمایا: "اس کا وقت ایک ہے۔" (ترمذی ۱۴۹)۔ نبی ﷺ نے یہ بھی فرمایا: "میری امت خیر پر باقی رہے گی جب تک وہ مغرب کو ستاروں کے گتھم گتھا ہونے تک موخر نہ کریں" (ابو داؤد ۴۱۸)  –  یعنی پوری رات تک۔ غروبِ آفتاب کے لمحے کے بارے میں: "جب رات ادھر سے آ جائے اور دن ادھر سے چلا جائے اور سورج غروب ہو جائے  –  تو روزہ دار افطار کر لے۔" (بخاری ۱۹۵۴، مسلم ۱۱۰۰)۔ مغرب اس لیے رسمی حدِّ فاصل ہے کہ نیا اسلامی دن شروع ہوتا ہے۔`, ben: `জিবরিল (আ) কাবার পাশে উভয় দিন সূর্যাস্তের মুহূর্তেই নবী ﷺ-কে মাগরিবে ইমামতি করালেন, এবং বললেন: "এর সময় একটি।" (তিরমিযি ১৪৯)। নবী ﷺ আরও বলেছেন: "আমার উম্মত কল্যাণে অটল থাকবে যতক্ষণ না তারা মাগরিবকে নক্ষত্রগুলো জড়িয়ে যাওয়া পর্যন্ত বিলম্বিত করে" (আবু দাউদ ৪১৮)  –  অর্থাৎ পূর্ণ রাত পর্যন্ত। সূর্যাস্তের মুহূর্ত সম্পর্কে: "যখন রাত এদিক থেকে এগিয়ে আসে এবং দিন ওদিক থেকে চলে যায় এবং সূর্য অস্ত যায়  –  তখন রোজাদার ইফতার করে।" (বুখারি ১৯৫৪, মুসলিম ১১০০)। তাই মাগরিব হলো সেই আনুষ্ঠানিক সীমানা চিহ্নিতকরণ যেখানে নতুন ইসলামি দিন শুরু হয়।`, fas: `جبرئیل (ع) در کنار کعبه در هر دو روز همان لحظه که خورشید فرو نشست، پیامبر ﷺ را بر نماز مغرب پیشوایی کرد و فرمود: "وقت آن یکی است." (ترمذی ۱۴۹). پیامبر ﷺ همچنین فرمود: "امت من تا زمانی که مغرب را تا درهم پیچیدن ستارگان به تأخیر نیندازند، در خیر باقی می‌مانند" (ابوداود ۴۱۸)  –  یعنی تا شب کامل. درباره خود لحظه غروب: "چون شب از این سو فرارسد و روز از این سو برود و خورشید فرو نشیند  –  روزه‌دار افطار می‌کند." (بخاری ۱۹۵۴، مسلم ۱۱۰۰). بنابراین مغرب نشانه مرز رسمی است که روز نوین اسلامی آغاز می‌شود.`, zh: `吉卜利里（愿主赐他平安）于天房旁，于两日皆于日落之刻带先知ﷺ礼昏礼，并言：「其时段为一。」（提尔米兹149）。先知ﷺ又言：「我的民众将常处于善中，只要他们不将昏礼延至星辰交错之时」（艾布·达伍德418）  –  即直至全夜。关于日落之刻本身：「当夜从此方来，昼从此方去，太阳没下  –  封斋者即开斋。」（布哈里1954，穆斯林1100）。故昏礼乃新伊斯兰日开始之正式界标。`, yue: `吉卜利里（願主賜佢平安）於天房旁，於兩日皆於日落之刻帶先知ﷺ禮昏禮，並話：「其時段為一。」（提爾米茲149）。先知ﷺ又話：「我嘅民眾將常處於善中，只要佢哋唔將昏禮延至星辰交錯之時」（艾布·達伍德418）  –  即直至全夜。關於日落之刻本身：「當夜由此方嚟，晝由此方去，太陽冇低  –  封齋者即開齋。」（布哈里1954，穆斯林1100）。故昏禮乃新伊斯蘭日開始之正式界標。`, ja: `ジブリール（に平安あれ）はカアバの傍で両日とも太陽が沈んだその瞬間に預言者ﷺのマグリブ礼拝のイマームとなり、「その時は一つである」と仰せられた（ティルミズィー149）。預言者ﷺはまた仰せられた：「わが民は、マグリブを星々が絡まり合うまで遅らせない限り、善にとどまる」（アブー・ダーウード418）  –  すなわち完全な夜になるまで。日没の瞬間そのものについて：「夜がこちら側から訪れ、昼がこちら側から去り、太陽が沈んだとき  –  断食者は断食を解く。」（ブハーリー1954、ムスリム1100）。マグリブはこうして新たなイスラム暦日が始まる正式な境界の標である。`, ru: `Джибриль (мир ему) у Каабы оба дня возглавил Пророка ﷺ в Магрибе в тот самый момент, когда зашло солнце, сказав: «Его время одно.» (Тирмизи 149). Пророк ﷺ также сказал: «Моя умма пребудет в добре, пока не отложит Магриб до того, как звёзды переплетутся» (Абу Дауд 418)  –  то есть до полной ночи. О самом моменте заката: «Когда ночь приходит с этой стороны, день уходит с той стороны, и солнце село  –  постящийся разговляется.» (Бухари 1954, Муслим 1100). Магриб, таким образом, формальный пограничный знак того, что начался новый исламский день.`, es: `Yibril (as) dirigió al Profeta ﷺ en el Maghrib junto a la Ka'bah en el instante en que se puso el sol los dos días, y dijo: "Su tiempo es uno." (Tirmidhi 149). El Profeta ﷺ también dijo: "Mi nación permanecerá en el bien mientras no retrase el Maghrib hasta que las estrellas se entrelacen" (Abu Dawud 418)  –  es decir, hasta la noche cerrada. Sobre el instante del ocaso mismo: "Cuando la noche se acerca por este lado, el día se va por aquel, y el sol se ha puesto  –  entonces el ayunante rompe su ayuno." (Bujari 1954, Muslim 1100). El Maghrib es por tanto el marcador formal de frontera con que comienza el nuevo día islámico.`, ko: `지브릴(평화가 그에게)께서는 카바 옆에서 두 날 모두 태양이 진 바로 그 순간 예언자 ﷺ의 마그립 예배 이맘이 되시며 말씀하셨다: "그것의 시간은 하나이다." (티르미디 149). 예언자 ﷺ께서는 또한 말씀하셨다: "내 움마는 별들이 얽힐 때까지 마그립을 지연시키지 않는 한 선함에 머무를 것이다" (아부 다우드 418)  –  즉 완전한 밤까지. 일몰 그 순간에 대하여: "밤이 이쪽에서 다가오고 낮이 저쪽에서 떠나며 태양이 졌을 때  –  단식자는 단식을 깬다." (부카리 1954, 무슬림 1100). 따라서 마그립은 새로운 이슬람 날이 시작되는 공식 경계 표지이다.`, ta: `ஜிப்ரீல் (அலை) கஅபாவின் அருகே இரு நாட்களும் சூரியன் அஸ்தமித்த தருணத்திலேயே நபி ﷺ அவர்களுக்கு மக்ரிபில் இமாமாக நின்று, "அதன் வேளை ஒன்றே" எனக் கூறினார் (திர்மிதி 149). நபி ﷺ மேலும் கூறினார்: "என் சமுதாயம் மக்ரிபை நட்சத்திரங்கள் சிக்கிக்கொள்ளும் வரை தாமதப்படுத்தாதவரை நன்மையில் நிலைத்திருக்கும்" (அபூ தாவூத் 418)  –  அதாவது முழு இரவு வரை. சூரிய அஸ்தமனத்தின் தருணத்தைப் பற்றி: "இரவு இந்த திசையிலிருந்து வந்து, பகல் அந்த திசையிலிருந்து புறப்பட்டு, சூரியன் அஸ்தமித்துவிட்டால்  –  நோன்பாளி நோன்பைத் திறக்கிறார்." (புகாரி 1954, முஸ்லிம் 1100). ஆகவே மக்ரிப் புதிய இஸ்லாமிய நாள் தொடங்கும் முறையான எல்லைக் குறியீடாக உள்ளது.`, si: `ජිබ්රීල් (ඔහුට සාමය) කඃබාව අසළ දින දෙකේදීම හිරු බැසී ගිය මොහොතේම නබි ﷺ සමඟ මග්රිබ් සලාතයේ ඉමාම් වශයෙන් සිට, "එහි කාලය එකකි" යැයි පැවසූහ (තිර්මිදී 149). නබි ﷺ තවද පැවසූහ: "තාරකා එකිනෙකට බැඳෙන තෙක් මග්රිබ් ප්‍රමාද නොකරන තාක්, මාගේ සමාජය යහපතේ පවතිනු ඇත" (අබූ දාවූද් 418)  –  එනම් සම්පූර්ණ රාත්‍රිය තෙක්. හිරු බැසීමේ මොහොත ගැනම: "රාත්‍රිය මෙතැනින් පැමිණ, දවස ඒ පැත්තෙන් යන විට, හිරු බැසී ඇත්නම්  –  උපවාසය රකින්නා උපවාසය බිඳී." (බුහාරි 1954, මුස්ලිම් 1100). එම නිසා මග්රිබ් යනු නව ඉස්ලාමීය දිනය ආරම්භවන විධිමත් සීමා ලකුණයි.` },
  maghrib_recitation: { en: `Recited aloud (jahri) in the first two rak'ahs and silently in the third. The Sunnah length is the shortest of the five  –  the Prophet ﷺ often selected from the short Mufassal (Surah ad-Duha 93 onward, the final juz') in keeping with people's hunger and the day's transition; he also sometimes recited the longest of the long, such as Surah al-A'raf (7) split between the two rak'ahs. Both are Sunnah, but the shorter is the prevailing daily practice. In the third rak'ah only Surah al-Fatihah is recited.`, ms: `Bacaan kuat (jahri) pada dua rakaat pertama dan perlahan pada rakaat ketiga. Panjang sunnah adalah yang paling pendek antara lima  –  Nabi ﷺ sering memilih daripada Mufassal pendek (Surah ad-Duha 93 dan seterusnya, juzuk akhir) mengambil kira lapar orang ramai dan peralihan hari; baginda juga kadang-kadang membaca yang paling panjang, seperti Surah al-A'raf (7) yang dibahagikan antara dua rakaat. Kedua-duanya sunnah, tetapi yang lebih pendek adalah amalan harian yang lazim. Pada rakaat ketiga hanya Surah al-Fatihah dibaca.`, tur: `İlk iki rekâtta cehrî (sesli), üçüncüde sirrî (sessiz) okunur. Sünnet uzunluk beşin en kısasıdır  –  Peygamber ﷺ insanların açlığı ve günün geçişi gözetilerek sıkça kısa Mufassal'dan (Duhâ 93 ve sonrası, son cüz) seçerdi; bazen de A'râf (7) gibi en uzunları iki rekâta bölerek okurdu. İkisi de sünnettir, ancak günlük yaygın uygulama kısasıdır. Üçüncü rekâtta yalnızca Fâtiha okunur.`, urd: `پہلی دو رکعتوں میں جہراً (بلند) اور تیسری میں سرّاً (آہستہ)۔ سنّت طوالت پانچوں میں سب سے مختصر  –  نبی ﷺ اکثر مختصر مفصل سے (سورۃ الضحیٰ ۹۳ سے آگے، آخری پارہ) چنتے، لوگوں کی بھوک اور دن کی منتقلی کا لحاظ کرتے ہوئے؛ کبھی سب سے طویل بھی پڑھتے، جیسے سورۃ الأعراف (۷) دو رکعتوں میں تقسیم کر کے۔ دونوں سنّت ہیں، مگر روزمرہ کا غالب معمول مختصر ہے۔ تیسری رکعت میں صرف سورۃ الفاتحہ پڑھی جاتی ہے۔`, ben: `প্রথম দুই রাকাতে উচ্চস্বরে (জাহরি) এবং তৃতীয়টিতে নীরবে। সুন্নাহ দৈর্ঘ্য পাঁচের মধ্যে সবচেয়ে সংক্ষিপ্ত  –  মানুষের ক্ষুধা ও দিনের পরিবর্তন বিবেচনায় নবী ﷺ প্রায়ই সংক্ষিপ্ত মুফাসসাল থেকে (সূরা আদ-দুহা ৯৩ এবং পরবর্তী, শেষ পারা) বেছে নিতেন; কখনো কখনো দীর্ঘতমও পড়তেন, যেমন সূরা আল-আ'রাফ (৭) দুই রাকাতে বিভক্ত করে। উভয়ই সুন্নাহ, তবে দৈনন্দিন প্রচলিত অনুশীলন সংক্ষিপ্ততরটি। তৃতীয় রাকাতে শুধু সূরা আল-ফাতিহা পড়া হয়।`, fas: `در دو رکعت اول جهری (بلند) و در رکعت سوم سرّی (آرام). درازای سنت کوتاه‌ترین در میان پنج است  –  پیامبر ﷺ اغلب با توجه به گرسنگی مردم و گذار روز از مفصل کوتاه (سوره ضحی ۹۳ به بعد، جزء آخر) برمی‌گزید؛ گاه نیز بلندترین را می‌خواند، مانند سوره اعراف (۷) که میان دو رکعت تقسیم می‌شد. هر دو سنت‌اند، اما رویه روزمره غالب همان کوتاه‌تر است. در رکعت سوم تنها سوره فاتحه خوانده می‌شود.`, zh: `前两拜诵读高声（贾赫里），第三拜低声。圣行长度为五时之中最短  –  先知ﷺ顾及众人之饥与一日之过渡，常自短《细分章》（自《晨光章》93起，最后一卷）选取；亦有时诵最长者，如《高处章》（7）分诵于两拜之间。二者皆属圣行，惟日常通行者为短诵。第三拜仅诵《开端章》。`, yue: `前兩拜誦讀高聲（賈赫里），第三拜低聲。聖行長度為五時之中最短  –  先知ﷺ顧及眾人之饑與一日之過渡，常自短《細分章》（自《晨光章》93起，最後一卷）選取；亦有時誦最長者，如《高處章》（7）分誦於兩拜之間。二者皆屬聖行，惟日常通行者為短誦。第三拜僅誦《開端章》。`, ja: `最初の二ラクアで音読（ジャフリー）、第三ラクアで無声。スンナの長さは五つの中で最短  –  人々の空腹と日の移り変わりを考慮し、預言者ﷺは短いムファッサル（ドゥハー章 93 以降の最後の一ジュズ）から選ばれることが多かった。一方で時にはアアラーフ章（7）のような最長のものを二ラクアに分けて朗誦された。両者ともスンナだが、日常の通常実践は短い方。第三ラクアではファーティハ章のみ朗誦する。`, ru: `Вслух (джахрий) в первых двух ракатах и тихо в третьем. Сунновская длина  –  самая короткая из пяти  –  Пророк ﷺ часто выбирал из короткого Муфассал (с суры ад-Духа 93 и далее, последний джуз), учитывая голод людей и переход дня; иногда же читал и самые длинные, как сура аль-А'раф (7), разделённую между двумя ракатами. То и другое  –  сунна, но повседневная практика  –  более короткое. В третьем ракате читается только сура аль-Фатиха.`, es: `Recitada en voz alta (jahri) en los dos primeros rak'ahs y en silencio en el tercero. La longitud Sunnah es la más breve de las cinco  –  el Profeta ﷺ solía elegir del Mufassal corto (Sura ad-Duha 93 en adelante, el último juz') en consideración al hambre de la gente y la transición del día; también recitaba a veces los más largos, como la Sura al-A'raf (7) dividida entre los dos rak'ahs. Ambos son Sunnah, pero la práctica diaria predominante es la más corta. En el tercer rak'ah solo se recita la Sura al-Fatiha.`, ko: `처음 두 라카에서 소리 내어(자흐리), 셋째 라카에서 무성. 순나 길이는 다섯 중 가장 짧다  –  예언자 ﷺ께서는 사람들의 허기와 하루의 전환을 고려하여 종종 짧은 무팟살(앗두하 장 93 이후, 마지막 주즈)에서 고르셨다; 때로는 알아라프 장(7)처럼 가장 긴 것을 두 라카에 나누어 낭송하시기도 했다. 둘 다 순나이지만 일상의 일반 관행은 짧은 쪽이다. 셋째 라카에서는 알파티하만 낭송한다.`, ta: `முதல் இரு ரக்அத்களில் உரக்க (ஜஹ்ரி) ஓதல், மூன்றாவதில் அமைதியாக. சுன்னா நீளம் ஐந்தில் மிகக் குறுகியது  –  நபி ﷺ மக்களின் பசியையும் நாளின் மாற்றத்தையும் கருதி அடிக்கடி குறுகிய முஃபஸ்ஸலிலிருந்து (சூரத்துத்-துஹா 93 முதலானவை, இறுதி ஜுஸ்உ) தேர்ந்தெடுத்தார்; சில சமயம் சூரத்துல்-அஃராஃப் (7) போன்ற மிக நீண்டவற்றையும் இரு ரக்அத்களுக்கிடையே பிரித்து ஓதினார். இரண்டுமே சுன்னா, ஆனால் தினசரி பொதுவான பழக்கம் குறுகியது. மூன்றாவது ரக்அத்தில் ஃபாதிஹா மட்டுமே ஓதப்படுகிறது.`, si: `පළමු රකඅත් දෙකේදී හඬ නඟා (ජහ්රී) සහ තෙවැන්නේදී නිහඬව. සුන්නා දිග පහෙන් කෙටිම  –  ජනතාවගේ බඩගින්න සහ දවසේ සංක්‍රාන්තිය සැලකිල්ලට ගනිමින් නබි ﷺ බොහෝ විට කෙටි මුෆස්සල් (අඩ්-දුහා සූරාව 93 සිට, අවසන් ජුස්උ) වෙතින් තෝරාගත්හ; සමහර විට අල්-අඃරාෆ් (7) වැනි දිගුම ඒවාද රකඅත් දෙකකට බෙදා කියවූහ. දෙකම සුන්නාවය, නමුත් දෛනික පවතින පුරුද්ද කෙටි එක. තෙවන රකඅතේදී අල්-ෆාතිහා පමණක් කියවයි.` },
} satisfies Record<string, LangMap>;
